


SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SELECT pg_catalog.set_config('search_path', '', false);
SET check_function_bodies = false;
SET xmloption = content;
SET client_min_messages = warning;
SET row_security = off;


CREATE SCHEMA IF NOT EXISTS "public";


ALTER SCHEMA "public" OWNER TO "pg_database_owner";


COMMENT ON SCHEMA "public" IS 'standard public schema';



CREATE TYPE "public"."app_role" AS ENUM (
    'admin',
    'director',
    'manager',
    'sales',
    'nurse',
    'coordinator',
    'program-assistant',
    'staff'
);


ALTER TYPE "public"."app_role" OWNER TO "postgres";


CREATE TYPE "public"."lead_status" AS ENUM (
    'open',
    'won',
    'lost'
);


ALTER TYPE "public"."lead_status" OWNER TO "postgres";


CREATE TYPE "public"."punch_type" AS ENUM (
    'in',
    'out'
);


ALTER TYPE "public"."punch_type" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."apply_lead_stage_transition_with_member_upsert"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text" DEFAULT NULL::"text", "p_member_display_name" "text" DEFAULT NULL::"text", "p_member_dob" "date" DEFAULT NULL::"date", "p_member_enrollment_date" "date" DEFAULT NULL::"date", "p_existing_member_id" "uuid" DEFAULT NULL::"uuid", "p_additional_lead_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_now" timestamp with time zone DEFAULT "now"(), "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("lead_id" "uuid", "member_id" "uuid", "from_stage" "text", "to_stage" "text", "from_status" "text", "to_status" "text", "business_status" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_from_stage text;
  v_from_status text;
  v_closed_date date;
  v_lost_reason text;
  v_member_id uuid;
  v_stage_changed boolean;
  v_patch jsonb := coalesce(p_additional_lead_patch, '{}'::jsonb);
  v_member_enrollment_date date;
  v_member_display_name text;
  v_actor_name text;
begin
  if p_lead_id is null then
    raise exception 'Lead id is required.';
  end if;
  if nullif(trim(coalesce(p_to_stage, '')), '') is null then
    raise exception 'Target stage is required.';
  end if;
  if p_to_status not in ('open', 'won', 'lost') then
    raise exception 'Target status must be open, won, or lost.';
  end if;
  if p_business_status not in ('Open', 'Won', 'Lost', 'Nurture') then
    raise exception 'Business status is invalid.';
  end if;

  select l.stage, l.status::text
  into v_from_stage, v_from_status
  from public.leads l
  where l.id = p_lead_id
  for update;

  if not found then
    raise exception 'Lead not found.';
  end if;

  if p_business_status = 'Lost' then
    if v_patch ? 'closed_date' then
      v_closed_date := nullif(v_patch->>'closed_date', '')::date;
    else
      v_closed_date := p_today;
    end if;
    if v_patch ? 'lost_reason' then
      v_lost_reason := nullif(v_patch->>'lost_reason', '');
    else
      v_lost_reason := null;
    end if;
  elsif p_business_status = 'Won' then
    if v_patch ? 'closed_date' then
      v_closed_date := nullif(v_patch->>'closed_date', '')::date;
    else
      v_closed_date := p_today;
    end if;
    if v_patch ? 'lost_reason' then
      v_lost_reason := nullif(v_patch->>'lost_reason', '');
    else
      v_lost_reason := null;
    end if;
  else
    if v_patch ? 'closed_date' then
      v_closed_date := nullif(v_patch->>'closed_date', '')::date;
    else
      v_closed_date := null;
    end if;
    if v_patch ? 'lost_reason' then
      v_lost_reason := nullif(v_patch->>'lost_reason', '');
    else
      v_lost_reason := null;
    end if;
  end if;

  update public.leads l
  set
    stage = p_to_stage,
    status = p_to_status::public.lead_status,
    stage_updated_at = p_now,
    inquiry_date = case when v_patch ? 'inquiry_date' then nullif(v_patch->>'inquiry_date', '')::date else l.inquiry_date end,
    tour_date = case when v_patch ? 'tour_date' then nullif(v_patch->>'tour_date', '')::date else l.tour_date end,
    tour_completed = case when v_patch ? 'tour_completed' then coalesce((v_patch->>'tour_completed')::boolean, false) else l.tour_completed end,
    discovery_date = case when v_patch ? 'discovery_date' then nullif(v_patch->>'discovery_date', '')::date else l.discovery_date end,
    member_start_date = case when v_patch ? 'member_start_date' then nullif(v_patch->>'member_start_date', '')::date else l.member_start_date end,
    caregiver_name = case when v_patch ? 'caregiver_name' then nullif(v_patch->>'caregiver_name', '') else l.caregiver_name end,
    caregiver_relationship = case when v_patch ? 'caregiver_relationship' then nullif(v_patch->>'caregiver_relationship', '') else l.caregiver_relationship end,
    caregiver_email = case when v_patch ? 'caregiver_email' then nullif(v_patch->>'caregiver_email', '') else l.caregiver_email end,
    caregiver_phone = case when v_patch ? 'caregiver_phone' then nullif(v_patch->>'caregiver_phone', '') else l.caregiver_phone end,
    member_name = case when v_patch ? 'member_name' then coalesce(nullif(v_patch->>'member_name', ''), l.member_name) else l.member_name end,
    member_dob = case when v_patch ? 'member_dob' then nullif(v_patch->>'member_dob', '')::date else l.member_dob end,
    lead_source = case when v_patch ? 'lead_source' then nullif(v_patch->>'lead_source', '') else l.lead_source end,
    lead_source_other = case when v_patch ? 'lead_source_other' then nullif(v_patch->>'lead_source_other', '') else l.lead_source_other end,
    partner_id = case when v_patch ? 'partner_id' then nullif(v_patch->>'partner_id', '') else l.partner_id end,
    referral_source_id = case when v_patch ? 'referral_source_id' then nullif(v_patch->>'referral_source_id', '') else l.referral_source_id end,
    referral_name = case when v_patch ? 'referral_name' then nullif(v_patch->>'referral_name', '') else l.referral_name end,
    likelihood = case when v_patch ? 'likelihood' then nullif(v_patch->>'likelihood', '') else l.likelihood end,
    next_follow_up_date = case when v_patch ? 'next_follow_up_date' then nullif(v_patch->>'next_follow_up_date', '')::date else l.next_follow_up_date end,
    next_follow_up_type = case when v_patch ? 'next_follow_up_type' then nullif(v_patch->>'next_follow_up_type', '') else l.next_follow_up_type end,
    notes_summary = case when v_patch ? 'notes_summary' then nullif(v_patch->>'notes_summary', '') else l.notes_summary end,
    lost_reason = v_lost_reason,
    closed_date = v_closed_date,
    updated_at = p_now
  where l.id = p_lead_id;

  v_member_display_name := nullif(trim(coalesce(p_member_display_name, '')), '');
  if v_member_display_name is null then
    raise exception 'Member display name is required for conversion.';
  end if;

  v_member_enrollment_date := coalesce(
    p_member_enrollment_date,
    nullif(v_patch->>'member_start_date', '')::date,
    p_today
  );
  v_actor_name := nullif(trim(coalesce(p_actor_name, '')), '');

  if p_existing_member_id is not null then
    update public.members m
    set
      display_name = v_member_display_name,
      status = 'active',
      enrollment_date = v_member_enrollment_date,
      dob = p_member_dob,
      source_lead_id = p_lead_id,
      updated_at = p_now
    where m.id = p_existing_member_id;

    if not found then
      raise exception 'Linked member not found.';
    end if;
    v_member_id := p_existing_member_id;
  else
    select m.id
    into v_member_id
    from public.members m
    where m.source_lead_id = p_lead_id
    order by m.created_at asc, m.id asc
    limit 1
    for update;

    if v_member_id is null then
      insert into public.members (
        display_name,
        status,
        enrollment_date,
        dob,
        source_lead_id,
        updated_at
      )
      values (
        v_member_display_name,
        'active',
        v_member_enrollment_date,
        p_member_dob,
        p_lead_id,
        p_now
      )
      returning id into v_member_id;
    else
      update public.members m
      set
        display_name = v_member_display_name,
        status = 'active',
        enrollment_date = v_member_enrollment_date,
        dob = p_member_dob,
        source_lead_id = p_lead_id,
        updated_at = p_now
      where m.id = v_member_id;
    end if;
  end if;

  insert into public.member_command_centers (
    id,
    member_id,
    primary_language,
    diet_type,
    diet_texture,
    updated_by_user_id,
    updated_by_name,
    created_at,
    updated_at
  )
  values (
    'mcc-' || v_member_id::text,
    v_member_id,
    'English',
    'Regular',
    'Regular',
    p_actor_user_id,
    v_actor_name,
    p_now,
    p_now
  )
  on conflict on constraint member_command_centers_member_id_key do nothing;

  insert into public.member_attendance_schedules (
    id,
    member_id,
    enrollment_date,
    full_day,
    transportation_billing_status,
    billing_rate_effective_date,
    attendance_days_per_week,
    use_custom_daily_rate,
    make_up_days_available,
    updated_by_user_id,
    updated_by_name,
    created_at,
    updated_at
  )
  values (
    'attendance-' || v_member_id::text,
    v_member_id,
    v_member_enrollment_date,
    true,
    'BillNormally',
    v_member_enrollment_date,
    0,
    false,
    0,
    p_actor_user_id,
    v_actor_name,
    p_now,
    p_now
  )
  on conflict on constraint member_attendance_schedules_member_id_key do nothing;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    v_member_id,
    p_now,
    p_now,
    p_actor_user_id,
    v_actor_name
  )
  on conflict on constraint member_health_profiles_member_id_key do nothing;

  if not exists (
    select 1
    from public.member_command_centers as member_command_centers
    where member_command_centers.member_id = v_member_id
  ) then
    raise exception 'Lead conversion cannot complete without a member_command_centers row for member %.', v_member_id;
  end if;

  if not exists (
    select 1
    from public.member_attendance_schedules as member_attendance_schedules
    where member_attendance_schedules.member_id = v_member_id
  ) then
    raise exception 'Lead conversion cannot complete without a member_attendance_schedules row for member %.', v_member_id;
  end if;

  if not exists (
    select 1
    from public.member_health_profiles as member_health_profiles
    where member_health_profiles.member_id = v_member_id
  ) then
    raise exception 'Lead conversion cannot complete without a member_health_profiles row for member %.', v_member_id;
  end if;

  v_stage_changed := coalesce(v_from_stage, '') <> p_to_stage
    or lower(coalesce(v_from_status, '')) <> lower(p_to_status);

  if v_stage_changed then
    insert into public.lead_stage_history (
      lead_id,
      from_stage,
      to_stage,
      from_status,
      to_status,
      changed_by_user_id,
      changed_by_name,
      reason,
      source,
      changed_at,
      created_at
    )
    values (
      p_lead_id,
      nullif(v_from_stage, ''),
      p_to_stage,
      nullif(v_from_status, ''),
      p_to_status,
      p_actor_user_id,
      p_actor_name,
      p_reason,
      p_source,
      p_now,
      p_now
    );
  end if;

  return query
  select
    p_lead_id,
    v_member_id,
    nullif(v_from_stage, ''),
    p_to_stage,
    nullif(v_from_status, ''),
    p_to_status,
    p_business_status;
end;
$$;


ALTER FUNCTION "public"."apply_lead_stage_transition_with_member_upsert"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text", "p_member_display_name" "text", "p_member_dob" "date", "p_member_enrollment_date" "date", "p_existing_member_id" "uuid", "p_additional_lead_patch" "jsonb", "p_now" timestamp with time zone, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."apply_makeup_balance_delta_with_audit"("p_schedule_id" "text", "p_member_id" "uuid", "p_attendance_date" "date", "p_delta_days" integer, "p_source" "text", "p_actor_user_id" "uuid", "p_actor_role" "public"."app_role", "p_actor_name" "text", "p_at" timestamp with time zone DEFAULT "now"(), "p_fail_if_insufficient" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_current_balance integer;
  v_next_balance integer;
begin
  if p_delta_days = 0 then
    return jsonb_build_object(
      'applied', false,
      'previousBalance', null,
      'nextBalance', null
    );
  end if;

  select coalesce(s.make_up_days_available, 0)
    into v_current_balance
  from public.member_attendance_schedules s
  where s.id = p_schedule_id
  for update;

  if not found then
    raise exception 'Attendance schedule not found for makeup update: %', p_schedule_id;
  end if;

  if p_fail_if_insufficient and p_delta_days < 0 and (v_current_balance + p_delta_days) < 0 then
    raise exception 'No makeup days are currently available for this member.';
  end if;

  v_next_balance := greatest(0, v_current_balance + p_delta_days);

  if v_next_balance = v_current_balance then
    return jsonb_build_object(
      'applied', false,
      'previousBalance', v_current_balance,
      'nextBalance', v_next_balance
    );
  end if;

  update public.member_attendance_schedules
  set make_up_days_available = v_next_balance,
      updated_by_user_id = p_actor_user_id,
      updated_by_name = p_actor_name,
      updated_at = coalesce(p_at, now())
  where id = p_schedule_id;

  insert into public.audit_logs (
    actor_user_id,
    actor_role,
    action,
    entity_type,
    entity_id,
    details
  )
  values (
    p_actor_user_id,
    p_actor_role,
    'manager_review',
    'makeup_day',
    p_member_id::text,
    jsonb_build_object(
      'attendanceDate', p_attendance_date,
      'deltaDays', p_delta_days,
      'source', p_source,
      'scheduleId', p_schedule_id,
      'previousBalance', v_current_balance,
      'nextBalance', v_next_balance
    )
  );

  return jsonb_build_object(
    'applied', true,
    'previousBalance', v_current_balance,
    'nextBalance', v_next_balance
  );
end;
$$;


ALTER FUNCTION "public"."apply_makeup_balance_delta_with_audit"("p_schedule_id" "text", "p_member_id" "uuid", "p_attendance_date" "date", "p_delta_days" integer, "p_source" "text", "p_actor_user_id" "uuid", "p_actor_role" "public"."app_role", "p_actor_name" "text", "p_at" timestamp with time zone, "p_fail_if_insufficient" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_access_enrollment_packet_child"("p_packet_id" "uuid", "p_member_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.enrollment_packet_requests req
    where req.id = p_packet_id
      and (p_member_id is null or req.member_id = p_member_id)
      and (
        public.is_enrollment_packet_internal_viewer()
        or req.sender_user_id = public.current_profile_id()
      )
  )
$$;


ALTER FUNCTION "public"."can_access_enrollment_packet_child"("p_packet_id" "uuid", "p_member_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_write_enrollment_packet_child"("p_packet_id" "uuid", "p_member_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.enrollment_packet_requests req
    where req.id = p_packet_id
      and (p_member_id is null or req.member_id = p_member_id)
  )
$$;


ALTER FUNCTION "public"."can_write_enrollment_packet_child"("p_packet_id" "uuid", "p_member_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_write_enrollment_packet_request"("p_member_id" "uuid", "p_lead_id" "uuid", "p_sender_user_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.members m
    where m.id = p_member_id
  )
  and (
    p_lead_id is null
    or exists (
      select 1
      from public.leads l
      where l.id = p_lead_id
    )
  )
  and exists (
    select 1
    from public.profiles p
    where p.id = p_sender_user_id
      and p.role in ('admin', 'manager', 'director', 'sales')
  )
$$;


ALTER FUNCTION "public"."can_write_enrollment_packet_request"("p_member_id" "uuid", "p_lead_id" "uuid", "p_sender_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."convert_enrollment_packet_to_member"("p_packet_id" "uuid", "p_member_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_actor_email" "text" DEFAULT NULL::"text", "p_started_at" timestamp with time zone DEFAULT "now"(), "p_member_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_mcc_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_attendance_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_contacts" "jsonb" DEFAULT '[]'::"jsonb", "p_mhp_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_pof_stage_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_record_rows" "jsonb" DEFAULT '[]'::"jsonb", "p_summary" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("packet_id" "uuid", "member_id" "uuid", "lead_id" "uuid", "conversion_status" "text", "mapping_run_id" "uuid", "systems" "jsonb", "downstream_systems_updated" "text"[], "conflicts_requiring_review" integer, "records_persisted" integer, "conflict_ids" "uuid"[], "entity_references" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.enrollment_packet_requests%rowtype;
  v_summary jsonb := coalesce(p_summary, '{}'::jsonb);
  v_existing_summary jsonb := '{}'::jsonb;
  v_mapping_run_id uuid;
  v_completed_at timestamptz := now();
  v_records_persisted integer := jsonb_array_length(coalesce(p_record_rows, '[]'::jsonb));
  v_conflict_ids uuid[] := array[]::uuid[];
  v_contact jsonb;
  v_existing_contact_id text;
  v_resolved_contact_id text;
  v_payor_contact_id text := null;
  v_created_contact_ids text[] := array[]::text[];
  v_contact_ids text[] := array[]::text[];
  v_member_file_ids text[] := array[]::text[];
  v_mcc_id text;
  v_attendance_id text;
  v_mhp_id uuid;
  v_pof_stage_id uuid;
  v_systems jsonb := '{}'::jsonb;
  v_downstream_systems_updated text[] := array[]::text[];
  v_conflicts_requiring_review integer := 0;
  v_entity_references jsonb := '{}'::jsonb;
begin
  if p_packet_id is null then
    raise exception 'convert_enrollment_packet_to_member requires p_packet_id';
  end if;
  if p_member_id is null then
    raise exception 'convert_enrollment_packet_to_member requires p_member_id';
  end if;

  select *
  into v_request
  from public.enrollment_packet_requests
  where id = p_packet_id
  for update;

  if not found then
    raise exception 'Enrollment packet request % was not found.', p_packet_id;
  end if;
  if v_request.member_id <> p_member_id then
    raise exception 'Enrollment packet request % does not belong to member %.', p_packet_id, p_member_id;
  end if;
  if coalesce(v_request.status, '') not in ('filed', 'completed') then
    raise exception 'Enrollment packet request % must be filed before downstream conversion.', p_packet_id;
  end if;

  perform 1
  from public.members
  where id = p_member_id
  for update;
  if not found then
    raise exception 'Member % was not found for enrollment conversion.', p_member_id;
  end if;

  if coalesce(v_request.mapping_sync_status, '') = 'completed' and v_request.latest_mapping_run_id is not null then
    select coalesce(epmr.summary, '{}'::jsonb)
    into v_existing_summary
    from public.enrollment_packet_mapping_runs as epmr
    where epmr.id = v_request.latest_mapping_run_id;

    select mcc.id into v_mcc_id from public.member_command_centers as mcc where mcc.member_id = p_member_id;
    select mas.id into v_attendance_id from public.member_attendance_schedules as mas where mas.member_id = p_member_id;
    select mhp.id into v_mhp_id from public.member_health_profiles as mhp where mhp.member_id = p_member_id;
    select epps.id into v_pof_stage_id from public.enrollment_packet_pof_staging as epps where epps.packet_id = p_packet_id;
    select coalesce(array_agg(mc.id order by mc.updated_at desc), array[]::text[]) into v_contact_ids
    from public.member_contacts as mc
    where mc.member_id = p_member_id
      and lower(btrim(mc.category)) in ('responsible party', 'emergency contact');
    select coalesce(array_agg(epu.member_file_id order by epu.uploaded_at asc), array[]::text[]) into v_member_file_ids
    from public.enrollment_packet_uploads as epu
    where epu.packet_id = p_packet_id
      and epu.member_file_id is not null;

    v_systems := coalesce(v_existing_summary -> 'systems', '{}'::jsonb);
    v_downstream_systems_updated := array(
      select jsonb_array_elements_text(coalesce(v_existing_summary -> 'downstreamSystemsUpdated', '[]'::jsonb))
    );
    v_conflicts_requiring_review := coalesce(nullif(v_existing_summary ->> 'conflictsRequiringReview', '')::integer, 0);
    v_records_persisted := coalesce(nullif(v_existing_summary ->> 'recordsPersisted', '')::integer, 0);
    v_conflict_ids := array(
      select value::uuid
      from jsonb_array_elements_text(coalesce(v_existing_summary -> 'conflictIds', '[]'::jsonb)) value
    );
    v_entity_references := jsonb_build_object(
      'memberId', p_member_id,
      'leadId', v_request.lead_id,
      'mccProfileId', v_mcc_id,
      'attendanceScheduleId', v_attendance_id,
      'memberHealthProfileId', v_mhp_id,
      'pofStagingId', v_pof_stage_id,
      'contactIds', to_jsonb(v_contact_ids),
      'createdContactIds', to_jsonb(array[]::text[]),
      'memberFileIds', to_jsonb(v_member_file_ids)
    );

    return query
    select
      v_request.id,
      p_member_id,
      v_request.lead_id,
      'already_completed',
      v_request.latest_mapping_run_id,
      v_systems,
      v_downstream_systems_updated,
      v_conflicts_requiring_review,
      v_records_persisted,
      v_conflict_ids,
      v_entity_references;
    return;
  end if;

