    source_value, destination_value, note, created_at
  )
  select
    v_mapping_run_id,
    p_packet_id,
    p_member_id,
    row.target_system,
    row.target_table,
    row.target_field,
    row.source_field,
    row.status,
    row.source_value,
    row.destination_value,
    row.note,
    coalesce(p_started_at, now())
  from jsonb_to_recordset(coalesce(p_record_rows, '[]'::jsonb)) as row(
    target_system text,
    target_table text,
    target_field text,
    source_field text,
    status text,
    source_value text,
    destination_value text,
    note text
  );

  with inserted as (
    insert into public.enrollment_packet_field_conflicts (
      mapping_run_id, packet_id, member_id, target_system, target_table, target_field, source_field,
      source_value, destination_value, status, created_at
    )
    select
      v_mapping_run_id,
      p_packet_id,
      p_member_id,
      row.target_system,
      row.target_table,
      row.target_field,
      row.source_field,
      row.source_value,
      row.destination_value,
      'open',
      coalesce(p_started_at, now())
    from jsonb_to_recordset(coalesce(p_record_rows, '[]'::jsonb)) as row(
      target_system text,
      target_table text,
      target_field text,
      source_field text,
      status text,
      source_value text,
      destination_value text,
      note text
    )
    where row.status = 'conflict'
    returning id
  )
  select coalesce(array_agg(id), array[]::uuid[]) into v_conflict_ids from inserted;

  select mcc.id into v_mcc_id from public.member_command_centers as mcc where mcc.member_id = p_member_id;
  select mas.id into v_attendance_id from public.member_attendance_schedules as mas where mas.member_id = p_member_id;
  select mhp.id into v_mhp_id from public.member_health_profiles as mhp where mhp.member_id = p_member_id;
  select epps.id into v_pof_stage_id from public.enrollment_packet_pof_staging as epps where epps.packet_id = p_packet_id;
  select coalesce(array_agg(mc.id order by mc.updated_at desc), array[]::text[]) into v_contact_ids
  from public.member_contacts as mc
  where mc.member_id = p_member_id
    and lower(btrim(mc.category)) in ('responsible party', 'emergency contact');
  select coalesce(array_agg(epu.member_file_id order by epu.uploaded_at asc), array[]::text[]) into v_member_file_ids
  from public.enrollment_packet_uploads as epu
  where epu.packet_id = p_packet_id
    and epu.member_file_id is not null;

  v_systems := coalesce(v_summary -> 'systems', '{}'::jsonb);
  v_downstream_systems_updated := array(
    select jsonb_array_elements_text(coalesce(v_summary -> 'downstreamSystemsUpdated', '[]'::jsonb))
  );
  v_conflicts_requiring_review := coalesce(nullif(v_summary ->> 'conflictsRequiringReview', '')::integer, 0);
  v_entity_references := jsonb_build_object(
    'memberId', p_member_id,
    'leadId', v_request.lead_id,
    'mccProfileId', v_mcc_id,
    'attendanceScheduleId', v_attendance_id,
    'memberHealthProfileId', v_mhp_id,
    'pofStagingId', v_pof_stage_id,
    'contactIds', to_jsonb(v_contact_ids),
    'createdContactIds', to_jsonb(v_created_contact_ids),
    'memberFileIds', to_jsonb(v_member_file_ids)
  );

  update public.enrollment_packet_mapping_runs
  set
    status = 'completed',
    summary = jsonb_build_object(
      'systems', v_systems,
      'downstreamSystemsUpdated', to_jsonb(v_downstream_systems_updated),
      'conflictsRequiringReview', v_conflicts_requiring_review,
      'recordsPersisted', v_records_persisted,
      'conflictIds', to_jsonb(v_conflict_ids),
      'entityReferences', v_entity_references
    ),
    completed_at = v_completed_at
  where id = v_mapping_run_id;

  update public.enrollment_packet_requests
  set
    mapping_sync_status = 'completed',
    mapping_sync_error = null,
    mapping_sync_attempted_at = v_completed_at,
    latest_mapping_run_id = v_mapping_run_id,
    updated_at = v_completed_at
  where id = p_packet_id;

  return query
  select
    p_packet_id,
    p_member_id,
    v_request.lead_id,
    'completed',
    v_mapping_run_id,
    v_systems,
    v_downstream_systems_updated,
    v_conflicts_requiring_review,
    v_records_persisted,
    v_conflict_ids,
    v_entity_references;
end;
$$;


ALTER FUNCTION "public"."convert_enrollment_packet_to_member"("p_packet_id" "uuid", "p_member_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_actor_email" "text", "p_started_at" timestamp with time zone, "p_member_patch" "jsonb", "p_mcc_patch" "jsonb", "p_attendance_patch" "jsonb", "p_contacts" "jsonb", "p_mhp_patch" "jsonb", "p_pof_stage_payload" "jsonb", "p_record_rows" "jsonb", "p_summary" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_lead_with_member_conversion"("p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_created_by_user_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text" DEFAULT NULL::"text", "p_member_display_name" "text" DEFAULT NULL::"text", "p_member_dob" "date" DEFAULT NULL::"date", "p_member_enrollment_date" "date" DEFAULT NULL::"date", "p_lead_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_idempotency_key" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"(), "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("lead_id" "uuid", "member_id" "uuid", "from_stage" "text", "to_stage" "text", "from_status" "text", "to_status" "text", "business_status" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_lead_id uuid;
  v_patch jsonb := coalesce(p_lead_patch, '{}'::jsonb);
  v_idempotency_key text := nullif(trim(coalesce(p_idempotency_key, '')), '');
begin
  if nullif(trim(coalesce(p_to_stage, '')), '') is null then
    raise exception 'Target stage is required.';
  end if;
  if p_to_status not in ('open', 'won', 'lost') then
    raise exception 'Target status must be open, won, or lost.';
  end if;
  if p_business_status not in ('Open', 'Won', 'Lost', 'Nurture') then
    raise exception 'Business status is invalid.';
  end if;

  if v_idempotency_key is not null then
    select l.id
    into v_lead_id
    from public.leads l
    where l.idempotency_key = v_idempotency_key
    order by l.created_at asc, l.id asc
    limit 1
    for update;
  end if;

  if v_lead_id is null then
    begin
      insert into public.leads (
        status,
        stage,
        stage_updated_at,
        inquiry_date,
        tour_date,
        tour_completed,
        discovery_date,
        member_start_date,
        caregiver_name,
        caregiver_relationship,
        caregiver_email,
        caregiver_phone,
        member_name,
        member_dob,
        lead_source,
        lead_source_other,
        partner_id,
        referral_source_id,
        referral_name,
        likelihood,
        next_follow_up_date,
        next_follow_up_type,
        notes_summary,
        lost_reason,
        closed_date,
        created_by_user_id,
        updated_at,
        idempotency_key
      )
      values (
        p_to_status::public.lead_status,
        p_to_stage,
        coalesce(nullif(v_patch->>'stage_updated_at', '')::timestamptz, p_now),
        nullif(v_patch->>'inquiry_date', '')::date,
        nullif(v_patch->>'tour_date', '')::date,
        coalesce((v_patch->>'tour_completed')::boolean, false),
        nullif(v_patch->>'discovery_date', '')::date,
        nullif(v_patch->>'member_start_date', '')::date,
        nullif(v_patch->>'caregiver_name', ''),
        nullif(v_patch->>'caregiver_relationship', ''),
        nullif(v_patch->>'caregiver_email', ''),
        nullif(v_patch->>'caregiver_phone', ''),
        coalesce(nullif(v_patch->>'member_name', ''), nullif(trim(coalesce(p_member_display_name, '')), ''), 'Unknown Member'),
        nullif(v_patch->>'member_dob', '')::date,
        nullif(v_patch->>'lead_source', ''),
        nullif(v_patch->>'lead_source_other', ''),
        nullif(v_patch->>'partner_id', ''),
        nullif(v_patch->>'referral_source_id', ''),
        nullif(v_patch->>'referral_name', ''),
        nullif(v_patch->>'likelihood', ''),
        nullif(v_patch->>'next_follow_up_date', '')::date,
        nullif(v_patch->>'next_follow_up_type', ''),
        nullif(v_patch->>'notes_summary', ''),
        nullif(v_patch->>'lost_reason', ''),
        nullif(v_patch->>'closed_date', '')::date,
        p_created_by_user_id,
        coalesce(nullif(v_patch->>'updated_at', '')::timestamptz, p_now),
        v_idempotency_key
      )
      returning id into v_lead_id;
    exception
      when unique_violation then
        if v_idempotency_key is null then
          raise;
        end if;

        select l.id
        into v_lead_id
        from public.leads l
        where l.idempotency_key = v_idempotency_key
        order by l.created_at asc, l.id asc
        limit 1
        for update;

        if v_lead_id is null then
          raise;
        end if;
    end;
  end if;

  return query
  select transition.lead_id, transition.member_id, transition.from_stage, transition.to_stage, transition.from_status, transition.to_status, transition.business_status
  from public.apply_lead_stage_transition_with_member_upsert(
    p_lead_id => v_lead_id,
    p_to_stage => p_to_stage,
    p_to_status => p_to_status,
    p_business_status => p_business_status,
    p_actor_user_id => p_actor_user_id,
    p_actor_name => p_actor_name,
    p_source => p_source,
    p_reason => p_reason,
    p_member_display_name => p_member_display_name,
    p_member_dob => p_member_dob,
    p_member_enrollment_date => p_member_enrollment_date,
    p_existing_member_id => null,
    p_additional_lead_patch => '{}'::jsonb,
    p_now => p_now,
    p_today => p_today
  ) as transition;
end;
$$;


ALTER FUNCTION "public"."create_lead_with_member_conversion"("p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_created_by_user_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text", "p_member_display_name" "text", "p_member_dob" "date", "p_member_enrollment_date" "date", "p_lead_patch" "jsonb", "p_idempotency_key" "text", "p_now" timestamp with time zone, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."current_profile_id"() RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select p.id
  from public.profiles p
  where p.auth_user_id = auth.uid()
     or p.id = auth.uid()
  order by
    case when p.auth_user_id = auth.uid() then 0 else 1 end,
    p.updated_at desc nulls last
  limit 1
$$;


ALTER FUNCTION "public"."current_profile_id"() OWNER TO "postgres";


