CREATE OR REPLACE FUNCTION "public"."log_documentation_event"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_payload jsonb;
  v_member_id uuid;
  v_staff_user_id uuid;
  v_event_at timestamptz;
begin
  v_payload := to_jsonb(new);

  v_member_id := nullif(v_payload->>'member_id', '')::uuid;
  v_staff_user_id := coalesce(
    nullif(v_payload->>'staff_user_id', '')::uuid,
    nullif(v_payload->>'nurse_user_id', '')::uuid,
    nullif(v_payload->>'uploaded_by', '')::uuid
  );
  v_event_at := coalesce(
    nullif(v_payload->>'created_at', '')::timestamptz,
    nullif(v_payload->>'event_at', '')::timestamptz,
    nullif(v_payload->>'checked_at', '')::timestamptz,
    nullif(v_payload->>'uploaded_at', '')::timestamptz,
    now()
  );

  insert into public.documentation_events (
    event_type,
    event_table,
    event_row_id,
    member_id,
    staff_user_id,
    event_at,
    created_at
  )
  values (
    tg_table_name,
    tg_table_name,
    new.id,
    v_member_id,
    v_staff_user_id,
    v_event_at,
    v_event_at
  );

  return new;
end;
$$;


ALTER FUNCTION "public"."log_documentation_event"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."member_contacts_auto_seed_payor"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if lower(btrim(coalesce(new.category, ''))) in ('responsible party', 'guarantor')
    and coalesce(new.is_payor, false) = false
    and not exists (
      select 1
      from public.member_contacts existing
      where existing.member_id = new.member_id
        and existing.is_payor = true
        and existing.id <> new.id
    ) then
    update public.member_contacts
    set
      is_payor = true,
      updated_at = coalesce(new.updated_at, now())
    where id = new.id;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."member_contacts_auto_seed_payor"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rls_auto_enable"() RETURNS "event_trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog'
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."rls_auto_enable"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_claim_enrollment_packet_follow_up_task"("p_packet_id" "uuid", "p_task_type" "text", "p_now" timestamp with time zone DEFAULT "now"(), "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "packet_id" "uuid", "member_id" "uuid", "lead_id" "uuid", "task_type" "text", "status" "text", "title" "text", "message" "text", "action_url" "text", "payload" "jsonb", "attempt_count" integer, "last_error" "text", "last_attempted_at" timestamp with time zone, "claimed_at" timestamp with time zone, "claimed_by_user_id" "uuid", "claimed_by_name" "text", "resolved_at" timestamp with time zone, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
begin
  return query
  with claimable as (
    select q.id
    from public.enrollment_packet_follow_up_queue q
    where q.packet_id = p_packet_id
      and q.task_type = p_task_type
      and q.status = 'action_required'
      and (
        q.claimed_at is null
        or q.claimed_at <= (p_now - interval '10 minutes')
      )
    for update skip locked
  )
  update public.enrollment_packet_follow_up_queue q
  set
    claimed_at = p_now,
    claimed_by_user_id = p_actor_user_id,
    claimed_by_name = v_actor_name,
    updated_at = p_now
  from claimable
  where q.id = claimable.id
  returning
    q.id,
    q.packet_id,
    q.member_id,
    q.lead_id,
    q.task_type,
    q.status,
    q.title,
    q.message,
    q.action_url,
    q.payload,
    q.attempt_count,
    q.last_error,
    q.last_attempted_at,
    q.claimed_at,
    q.claimed_by_user_id,
    q.claimed_by_name,
    q.resolved_at,
    q.created_at,
    q.updated_at;
end;
$$;


ALTER FUNCTION "public"."rpc_claim_enrollment_packet_follow_up_task"("p_packet_id" "uuid", "p_task_type" "text", "p_now" timestamp with time zone, "p_actor_user_id" "uuid", "p_actor_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_claim_enrollment_packet_mapping_retries"("p_limit" integer DEFAULT 25, "p_now" timestamp with time zone DEFAULT "now"(), "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "member_id" "uuid", "lead_id" "uuid", "sender_user_id" "uuid", "caregiver_email" "text", "status" "text", "mapping_sync_status" "text", "mapping_sync_error" "text", "mapping_sync_attempted_at" timestamp with time zone, "latest_mapping_run_id" "uuid")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_limit integer := greatest(1, least(coalesce(p_limit, 25), 100));
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
begin
  return query
  with claimable as (
    select q.id
    from public.enrollment_packet_requests q
    where q.mapping_sync_status = 'failed'
      and q.status in ('completed', 'filed')
      and (
        q.mapping_sync_claimed_at is null
        or q.mapping_sync_claimed_at <= (p_now - interval '10 minutes')
      )
    order by coalesce(q.mapping_sync_attempted_at, q.updated_at, q.created_at), q.created_at, q.id
    for update skip locked
    limit v_limit
  )
  update public.enrollment_packet_requests q
  set
    mapping_sync_claimed_at = p_now,
    mapping_sync_claimed_by_user_id = p_actor_user_id,
    mapping_sync_claimed_by_name = v_actor_name,
    updated_at = p_now
  from claimable
  where q.id = claimable.id
  returning
    q.id,
    q.member_id,
    q.lead_id,
    q.sender_user_id,
    q.caregiver_email,
    q.status,
    q.mapping_sync_status,
    q.mapping_sync_error,
    q.mapping_sync_attempted_at,
    q.latest_mapping_run_id;
end;
$$;


ALTER FUNCTION "public"."rpc_claim_enrollment_packet_mapping_retries"("p_limit" integer, "p_now" timestamp with time zone, "p_actor_user_id" "uuid", "p_actor_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_claim_intake_post_sign_follow_up_task"("p_assessment_id" "uuid", "p_task_type" "text", "p_now" timestamp with time zone DEFAULT "now"(), "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "assessment_id" "uuid", "member_id" "uuid", "task_type" "text", "status" "text", "title" "text", "message" "text", "action_url" "text", "attempt_count" integer, "last_error" "text", "last_attempted_at" timestamp with time zone, "claimed_at" timestamp with time zone, "claimed_by_user_id" "uuid", "claimed_by_name" "text", "resolved_at" timestamp with time zone, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
begin
  return query
  with claimable as (
    select q.id
    from public.intake_post_sign_follow_up_queue q
    where q.assessment_id = p_assessment_id
      and q.task_type = p_task_type
      and q.status = 'action_required'
      and (
        q.claimed_at is null
        or q.claimed_at <= (p_now - interval '10 minutes')
      )
    for update skip locked
  )
  update public.intake_post_sign_follow_up_queue q
  set
    claimed_at = p_now,
    claimed_by_user_id = p_actor_user_id,
    claimed_by_name = v_actor_name,
    updated_at = p_now
  from claimable
  where q.id = claimable.id
  returning
    q.id,
    q.assessment_id,
    q.member_id,
    q.task_type,
    q.status,
    q.title,
    q.message,
    q.action_url,
    q.attempt_count,
    q.last_error,
    q.last_attempted_at,
    q.claimed_at,
    q.claimed_by_user_id,
    q.claimed_by_name,
    q.resolved_at,
    q.created_at,
    q.updated_at;
end;
$$;


ALTER FUNCTION "public"."rpc_claim_intake_post_sign_follow_up_task"("p_assessment_id" "uuid", "p_task_type" "text", "p_now" timestamp with time zone, "p_actor_user_id" "uuid", "p_actor_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_claim_pof_post_sign_sync_queue"("p_limit" integer DEFAULT 25, "p_now" timestamp with time zone DEFAULT "now"(), "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "physician_order_id" "uuid", "member_id" "uuid", "pof_request_id" "uuid", "status" "text", "attempt_count" integer, "next_retry_at" timestamp with time zone, "signature_completed_at" timestamp with time zone, "queued_at" timestamp with time zone, "last_error" "text", "last_failed_step" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_limit integer := greatest(1, least(coalesce(p_limit, 25), 100));
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
begin
  return query
  with claimable as (
    select q.id
    from public.pof_post_sign_sync_queue q
    where
      (
        q.status = 'queued'
        and (q.next_retry_at is null or q.next_retry_at <= p_now)
      )
      or (
        q.status = 'processing'
        and q.claimed_at is not null
        and q.claimed_at <= (p_now - interval '10 minutes')
      )
    order by coalesce(q.next_retry_at, q.signature_completed_at, q.queued_at, q.created_at), q.created_at, q.id
    for update skip locked
    limit v_limit
  )
  update public.pof_post_sign_sync_queue q
  set
    status = 'processing',
    claimed_at = p_now,
    claimed_by_user_id = p_actor_user_id,
    claimed_by_name = v_actor_name,
    updated_at = p_now
  from claimable
  where q.id = claimable.id
  returning
    q.id,
    q.physician_order_id,
    q.member_id,
    q.pof_request_id,
    q.status,
    q.attempt_count,
    q.next_retry_at,
    q.signature_completed_at,
    q.queued_at,
    q.last_error,
    q.last_failed_step;
end;
$$;


ALTER FUNCTION "public"."rpc_claim_pof_post_sign_sync_queue"("p_limit" integer, "p_now" timestamp with time zone, "p_actor_user_id" "uuid", "p_actor_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_complete_prn_administration_followup"("p_log_id" "uuid", "p_effectiveness_result" "text", "p_followup_notes" "text" DEFAULT NULL::"text", "p_assessed_at" timestamp with time zone DEFAULT "now"(), "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("log_id" "uuid", "member_id" "uuid", "medication_order_id" "uuid", "followup_due_at" timestamp with time zone, "followup_status" "text", "duplicate_safe" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_assessed_at timestamptz := coalesce(p_assessed_at, v_now);
  v_followup_notes text := nullif(trim(coalesce(p_followup_notes, '')), '');
  v_existing public.med_administration_logs%rowtype;
begin
  if p_log_id is null then
    raise exception 'PRN follow-up requires log_id';
  end if;
  if p_effectiveness_result not in ('Effective', 'Ineffective') then
    raise exception 'PRN follow-up result must be Effective or Ineffective.';
  end if;
  if p_effectiveness_result = 'Ineffective' and v_followup_notes is null then
    raise exception 'Follow-up note is required when PRN outcome is Ineffective.';
  end if;

  select *
  into v_existing
  from public.med_administration_logs logs
  where logs.id = p_log_id
    and logs.admin_type = 'prn'
  for update;

  if not found then
    raise exception 'PRN follow-up can only be completed for existing PRN administrations.';
  end if;
  if v_existing.status <> 'Given' or v_existing.followup_status = 'not_required' then
    raise exception 'PRN follow-up can only be completed for given PRN administrations that require follow-up.';
  end if;

  if v_existing.followup_status = 'completed' then
    if coalesce(v_existing.effectiveness_result, '') = p_effectiveness_result
       and coalesce(v_existing.followup_notes, '') = coalesce(v_followup_notes, '') then
      log_id := v_existing.id;
      member_id := v_existing.member_id;
      medication_order_id := v_existing.medication_order_id;
      followup_due_at := v_existing.followup_due_at;
      followup_status := v_existing.followup_status;
      duplicate_safe := true;
      return next;
      return;
    end if;

    raise exception 'PRN follow-up has already been completed and cannot be overwritten.';
  end if;

  update public.med_administration_logs logs
  set
    followup_due_at = coalesce(logs.followup_due_at, v_assessed_at),
    followup_status = 'completed',
    effectiveness_result = p_effectiveness_result,
    followup_notes = v_followup_notes,
    updated_at = v_now
  where logs.id = p_log_id
    and logs.admin_type = 'prn'
    and logs.status = 'Given'
    and logs.followup_status in ('due', 'overdue')
  returning
    logs.id,
    logs.member_id,
    logs.medication_order_id,
    logs.followup_due_at,
    logs.followup_status
  into
    log_id,
    member_id,
    medication_order_id,
    followup_due_at,
    followup_status;

  if log_id is null then
    raise exception 'PRN follow-up can only be completed for due PRN administrations.';
  end if;

  duplicate_safe := false;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_complete_prn_administration_followup"("p_log_id" "uuid", "p_effectiveness_result" "text", "p_followup_notes" "text", "p_assessed_at" timestamp with time zone, "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_convert_lead_to_member"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text" DEFAULT NULL::"text", "p_member_display_name" "text" DEFAULT NULL::"text", "p_member_dob" "date" DEFAULT NULL::"date", "p_member_enrollment_date" "date" DEFAULT NULL::"date", "p_existing_member_id" "uuid" DEFAULT NULL::"uuid", "p_additional_lead_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_now" timestamp with time zone DEFAULT "now"(), "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("lead_id" "uuid", "member_id" "uuid", "from_stage" "text", "to_stage" "text", "from_status" "text", "to_status" "text", "business_status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_converted record;
  v_current_role public.app_role;
  v_current_profile_id uuid;
begin
  if auth.role() <> 'service_role' then
    v_current_role := public.current_role();
    v_current_profile_id := public.current_profile_id();

    if v_current_role is null or v_current_role not in ('admin', 'director', 'sales') then
      raise exception 'rpc_convert_lead_to_member is not permitted for role %.', coalesce(v_current_role::text, 'unknown')
        using errcode = '42501';
    end if;

    if p_actor_user_id is null or v_current_profile_id is null or p_actor_user_id <> v_current_profile_id then
      raise exception 'rpc_convert_lead_to_member requires p_actor_user_id to match the authenticated profile.'
        using errcode = '42501';
    end if;
  end if;

  select *
  into v_converted
  from public.apply_lead_stage_transition_with_member_upsert(
    p_lead_id => p_lead_id,
    p_to_stage => p_to_stage,
    p_to_status => p_to_status,
    p_business_status => p_business_status,
    p_actor_user_id => p_actor_user_id,
    p_actor_name => p_actor_name,
    p_source => p_source,
    p_reason => p_reason,
    p_member_display_name => p_member_display_name,
    p_member_dob => p_member_dob,
    p_member_enrollment_date => p_member_enrollment_date,
    p_existing_member_id => p_existing_member_id,
    p_additional_lead_patch => p_additional_lead_patch,
    p_now => p_now,
    p_today => p_today
  ) as converted;

  if v_converted.member_id is null then
    raise exception 'Lead conversion did not return a canonical member_id.';
  end if;

  perform 1
  from public.member_command_centers as member_command_centers
  where member_command_centers.member_id = v_converted.member_id;
  if not found then
    raise exception 'Lead conversion did not persist member_command_centers for member %.', v_converted.member_id;
  end if;

  perform 1
  from public.member_attendance_schedules as member_attendance_schedules
  where member_attendance_schedules.member_id = v_converted.member_id;
  if not found then
    raise exception 'Lead conversion did not persist member_attendance_schedules for member %.', v_converted.member_id;
  end if;

  perform 1
  from public.member_health_profiles as member_health_profiles
  where member_health_profiles.member_id = v_converted.member_id;
  if not found then
    raise exception 'Lead conversion did not persist member_health_profiles for member %.', v_converted.member_id;
  end if;

  lead_id := v_converted.lead_id;
  member_id := v_converted.member_id;
  from_stage := v_converted.from_stage;
  to_stage := v_converted.to_stage;
  from_status := v_converted.from_status;
  to_status := v_converted.to_status;
  business_status := v_converted.business_status;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_convert_lead_to_member"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text", "p_member_display_name" "text", "p_member_dob" "date", "p_member_enrollment_date" "date", "p_existing_member_id" "uuid", "p_additional_lead_patch" "jsonb", "p_now" timestamp with time zone, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_create_billing_export"("p_export_job" "jsonb", "p_invoice_ids" "uuid"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_export_id uuid := nullif(p_export_job ->> 'id', '')::uuid;
  v_batch_id uuid := nullif(p_export_job ->> 'billing_batch_id', '')::uuid;
  v_now timestamptz := coalesce(nullif(p_export_job ->> 'updated_at', '')::timestamptz, now());
  v_idempotency_key text := nullif(trim(coalesce(p_export_job ->> 'idempotency_key', '')), '');
begin
  if v_export_id is null then
    raise exception 'billing export id is required';
  end if;
  if v_batch_id is null then
    raise exception 'billing batch id is required for export generation';
  end if;

  if v_idempotency_key is not null then
    select id
    into v_export_id
    from public.billing_export_jobs
    where idempotency_key = v_idempotency_key
    order by created_at asc, id asc
    limit 1;

    if found then
      return v_export_id;
    end if;
  end if;

  v_export_id := nullif(p_export_job ->> 'id', '')::uuid;

  begin
    insert into public.billing_export_jobs (
      id,
      billing_batch_id,
      export_type,
      quickbooks_detail_level,
      file_name,
      file_data_url,
      generated_at,
      generated_by,
      status,
      notes,
      created_at,
      updated_at,
      idempotency_key
    )
    values (
      v_export_id,
      v_batch_id,
      nullif(p_export_job ->> 'export_type', ''),
      coalesce(nullif(p_export_job ->> 'quickbooks_detail_level', ''), 'Summary'),
      nullif(p_export_job ->> 'file_name', ''),
      nullif(p_export_job ->> 'file_data_url', ''),
      coalesce(nullif(p_export_job ->> 'generated_at', '')::timestamptz, now()),
      nullif(p_export_job ->> 'generated_by', ''),
      coalesce(nullif(p_export_job ->> 'status', ''), 'Generated'),
      nullif(p_export_job ->> 'notes', ''),
      coalesce(nullif(p_export_job ->> 'created_at', '')::timestamptz, now()),
      v_now,
      v_idempotency_key
    );
  exception
    when unique_violation then
      if v_idempotency_key is null then
        raise;
      end if;

      select id
      into v_export_id
      from public.billing_export_jobs
      where idempotency_key = v_idempotency_key
      order by created_at asc, id asc
      limit 1;

      if found then
        return v_export_id;
      end if;

      raise;
  end;

  update public.billing_batches
  set
    batch_status = 'Exported',
    updated_at = v_now
  where id = v_batch_id;
  if not found then
    raise exception 'billing batch % was not found for export generation', v_batch_id;
  end if;

  update public.billing_invoices
  set
    export_status = 'Exported',
    updated_at = v_now
  where id = any(coalesce(p_invoice_ids, array[]::uuid[]));

  return v_export_id;
end;
$$;


ALTER FUNCTION "public"."rpc_create_billing_export"("p_export_job" "jsonb", "p_invoice_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_create_custom_invoice"("p_invoice" "jsonb", "p_invoice_lines" "jsonb" DEFAULT '[]'::"jsonb", "p_coverages" "jsonb" DEFAULT '[]'::"jsonb", "p_source_updates" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_invoice_id uuid;
  v_member_id uuid;
  v_payor_id text;
  v_invoice_month date;
  v_invoice_number text;
  v_source_update jsonb;
  v_line_request jsonb;
  v_source_table text;
  v_source_record_id uuid;
  v_line_id uuid;
  v_line_number integer;
  v_line_created_at timestamptz;
  v_line_updated_at timestamptz;
  v_line_service_date date;
  v_line_service_period_start date;
  v_line_service_period_end date;
  v_line_type text;
  v_line_description text;
  v_line_quantity numeric(10,2);
  v_line_unit_rate numeric(10,2);
  v_line_amount numeric(12,2);
  v_line_product_or_service text;
begin
  v_invoice_id := nullif(p_invoice ->> 'id', '')::uuid;
  if v_invoice_id is null then
    raise exception 'custom invoice id is required';
  end if;

  v_member_id := nullif(p_invoice ->> 'member_id', '')::uuid;
  if v_member_id is null then
    raise exception 'custom invoice member is required';
  end if;

  v_payor_id := nullif(p_invoice ->> 'payor_id', '');

  v_invoice_month := date_trunc(
    'month',
    coalesce(
      nullif(p_invoice ->> 'invoice_month', '')::date,
      nullif(p_invoice ->> 'base_period_start', '')::date
    )
  )::date;
  if v_invoice_month is null then
    raise exception 'custom invoice month is required';
  end if;

  perform pg_advisory_xact_lock(
    hashtext('billing_custom_invoice_number'),
    hashtext(v_invoice_month::text)
  );

  select format(
    'CINV-%s-%s',
    to_char(v_invoice_month, 'YYYYMM'),
    lpad(
      (
        coalesce(
          max(
            case
              when invoice_number ~ ('^CINV-' || to_char(v_invoice_month, 'YYYYMM') || '-[0-9]{4}$')
                then right(invoice_number, 4)::integer
              else null
            end
          ),
          0
        ) + 1
      )::text,
      4,
      '0'
    )
  )
  into v_invoice_number
  from public.billing_invoices
  where invoice_source = 'Custom'
    and invoice_month = v_invoice_month;

  insert into public.billing_invoices (
    id,
    billing_batch_id,
    member_id,
    payor_id,
    invoice_number,
    invoice_month,
    invoice_source,
    invoice_status,
    export_status,
    billing_mode_snapshot,
    monthly_billing_basis_snapshot,
    transportation_billing_status_snapshot,
    billing_method_snapshot,
    base_period_start,
    base_period_end,
    variable_charge_period_start,
    variable_charge_period_end,
    invoice_date,
    due_date,
    base_program_billed_days,
    member_daily_rate_snapshot,
    base_program_amount,
    transportation_amount,
    ancillary_amount,
    adjustment_amount,
    total_amount,
    payments_amount,
    balance_due_amount,
    bill_to_name_snapshot,
    bill_to_address_line_1_snapshot,
    bill_to_address_line_2_snapshot,
    bill_to_address_line_3_snapshot,
    bill_to_email_snapshot,
    bill_to_phone_snapshot,
    bill_to_message_snapshot,
    notes,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_at
  )
  values (
    v_invoice_id,
    nullif(p_invoice ->> 'billing_batch_id', '')::uuid,
    v_member_id,
    v_payor_id,
    v_invoice_number,
    v_invoice_month,
    coalesce(nullif(p_invoice ->> 'invoice_source', ''), 'Custom'),
    coalesce(nullif(p_invoice ->> 'invoice_status', ''), 'Draft'),
    coalesce(nullif(p_invoice ->> 'export_status', ''), 'NotExported'),
    nullif(p_invoice ->> 'billing_mode_snapshot', ''),
    nullif(p_invoice ->> 'monthly_billing_basis_snapshot', ''),
    nullif(p_invoice ->> 'transportation_billing_status_snapshot', ''),
    nullif(p_invoice ->> 'billing_method_snapshot', ''),
    nullif(p_invoice ->> 'base_period_start', '')::date,
    nullif(p_invoice ->> 'base_period_end', '')::date,
    nullif(p_invoice ->> 'variable_charge_period_start', '')::date,
    nullif(p_invoice ->> 'variable_charge_period_end', '')::date,
    nullif(p_invoice ->> 'invoice_date', '')::date,
    nullif(p_invoice ->> 'due_date', '')::date,
    coalesce(nullif(p_invoice ->> 'base_program_billed_days', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'member_daily_rate_snapshot', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'base_program_amount', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'transportation_amount', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'ancillary_amount', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'adjustment_amount', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'total_amount', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'payments_amount', '')::numeric, 0),
    coalesce(nullif(p_invoice ->> 'balance_due_amount', '')::numeric, coalesce(nullif(p_invoice ->> 'total_amount', '')::numeric, 0)),
    nullif(p_invoice ->> 'bill_to_name_snapshot', ''),
    nullif(p_invoice ->> 'bill_to_address_line_1_snapshot', ''),
    nullif(p_invoice ->> 'bill_to_address_line_2_snapshot', ''),
    nullif(p_invoice ->> 'bill_to_address_line_3_snapshot', ''),
    nullif(p_invoice ->> 'bill_to_email_snapshot', ''),
    nullif(p_invoice ->> 'bill_to_phone_snapshot', ''),
    nullif(p_invoice ->> 'bill_to_message_snapshot', ''),
    nullif(p_invoice ->> 'notes', ''),
    nullif(p_invoice ->> 'created_by_user_id', '')::uuid,
    nullif(p_invoice ->> 'created_by_name', ''),
    coalesce(nullif(p_invoice ->> 'created_at', '')::timestamptz, now()),
    coalesce(nullif(p_invoice ->> 'updated_at', '')::timestamptz, now())
  );

  insert into public.billing_invoice_lines (
    id,
    invoice_id,
    member_id,
    payor_id,
    line_number,
    product_or_service,
    service_date,
    service_period_start,
    service_period_end,
    line_type,
    description,
    quantity,
    unit_rate,
    amount,
    source_table,
    source_record_id,
    billing_status,
    created_at,
    updated_at
  )
  select
    nullif(value ->> 'id', '')::uuid,
    v_invoice_id,
    v_member_id,
    v_payor_id,
    coalesce(nullif(value ->> 'line_number', '')::integer, 1),
    coalesce(nullif(value ->> 'product_or_service', ''), 'Member Fees'),
    nullif(value ->> 'service_date', '')::date,
    nullif(value ->> 'service_period_start', '')::date,
    nullif(value ->> 'service_period_end', '')::date,
    nullif(value ->> 'line_type', ''),
    nullif(value ->> 'description', ''),
    coalesce(nullif(value ->> 'quantity', '')::numeric, 0),
    coalesce(nullif(value ->> 'unit_rate', '')::numeric, 0),
    coalesce(nullif(value ->> 'amount', '')::numeric, 0),
    nullif(value ->> 'source_table', ''),
    nullif(value ->> 'source_record_id', ''),
    coalesce(nullif(value ->> 'billing_status', ''), 'Billed'),
    coalesce(nullif(value ->> 'created_at', '')::timestamptz, now()),
    coalesce(nullif(value ->> 'updated_at', '')::timestamptz, now())
  from jsonb_array_elements(coalesce(p_invoice_lines, '[]'::jsonb)) value
  where coalesce(nullif(value ->> 'source_table', ''), '') not in ('transportation_logs', 'ancillary_charge_logs', 'billing_adjustments');

  insert into public.billing_coverages (
    member_id,
    coverage_type,
    coverage_start_date,
    coverage_end_date,
    source_invoice_id,
    source_invoice_line_id,
    source_table,
    source_record_id,
    created_at
  )
  select
    v_member_id,
    nullif(value ->> 'coverage_type', ''),
    nullif(value ->> 'coverage_start_date', '')::date,
    nullif(value ->> 'coverage_end_date', '')::date,
    v_invoice_id,
    nullif(value ->> 'source_invoice_line_id', '')::uuid,
    nullif(value ->> 'source_table', ''),
    nullif(value ->> 'source_record_id', ''),
    coalesce(nullif(value ->> 'created_at', '')::timestamptz, now())
  from jsonb_array_elements(coalesce(p_coverages, '[]'::jsonb)) value
  where coalesce(nullif(value ->> 'source_table', ''), '') not in ('transportation_logs', 'ancillary_charge_logs', 'billing_adjustments');

  for v_source_update in
    select value
    from jsonb_array_elements(coalesce(p_source_updates, '[]'::jsonb)) value
  loop
    v_source_table := coalesce(v_source_update ->> 'source_table', '');
    v_source_record_id := nullif(v_source_update ->> 'source_record_id', '')::uuid;

    if v_source_record_id is null then
      raise exception 'custom invoice source record id is required for source table %', coalesce(v_source_table, 'null');
    end if;

    select value
    into v_line_request
    from jsonb_array_elements(coalesce(p_invoice_lines, '[]'::jsonb)) value
    where coalesce(value ->> 'source_table', '') = v_source_table
      and nullif(value ->> 'source_record_id', '')::uuid = v_source_record_id
    order by coalesce(nullif(value ->> 'line_number', '')::integer, 2147483647)
    limit 1;

    if v_line_request is null then
      raise exception 'custom invoice line payload missing for source table % and record %', v_source_table, v_source_record_id;
    end if;

    v_line_id := coalesce(nullif(v_line_request ->> 'id', '')::uuid, gen_random_uuid());
    v_line_number := coalesce(nullif(v_line_request ->> 'line_number', '')::integer, 1);
    v_line_created_at := coalesce(nullif(v_line_request ->> 'created_at', '')::timestamptz, now());
    v_line_updated_at := coalesce(
      nullif(v_source_update ->> 'updated_at', '')::timestamptz,
      nullif(v_line_request ->> 'updated_at', '')::timestamptz,
      now()
    );

    if v_source_table = 'transportation_logs' then
      select
        tl.service_date,
        coalesce(tl.quantity, 1),
        coalesce(tl.unit_rate, 0),
        case
          when coalesce(tl.total_amount, 0) > 0 then tl.total_amount
          else round(coalesce(tl.quantity, 1) * coalesce(tl.unit_rate, 0), 2)
        end,
        format('Transportation (%s)', coalesce(tl.transport_type, 'Trip'))
      into
        v_line_service_date,
        v_line_quantity,
        v_line_unit_rate,
        v_line_amount,
        v_line_description
      from public.transportation_logs tl
      where tl.id = v_source_record_id
        and tl.member_id = v_member_id
        and coalesce(tl.billing_status, 'Unbilled') = 'Unbilled'
        and tl.invoice_id is null
        and tl.billable is not false
      for update of tl;

      if not found then
        raise exception 'transportation log % is no longer unbilled during custom invoice creation', v_source_record_id;
      end if;

      if v_line_service_date is null then
        raise exception 'transportation log % is missing service_date during custom invoice creation', v_source_record_id;
      end if;

      v_line_type := 'Transportation';
      v_line_service_period_start := v_line_service_date;
      v_line_service_period_end := v_line_service_date;
      v_line_product_or_service := 'Transportation';

      update public.transportation_logs
      set
        billing_status = 'Billed',
        billing_exclusion_reason = null,
        invoice_id = v_invoice_id,
        updated_at = v_line_updated_at
      where id = v_source_record_id;
    elsif v_source_table = 'ancillary_charge_logs' then
      select
        acl.service_date,
        coalesce(acl.quantity, 1),
        case
          when coalesce(acl.unit_rate, 0) > 0 then acl.unit_rate
          else round(coalesce(acc.price_cents, 0)::numeric / 100, 2)
        end,
        case
          when coalesce(acl.amount, 0) > 0 then acl.amount
          else round(
            coalesce(acl.quantity, 1) * (
              case
                when coalesce(acl.unit_rate, 0) > 0 then acl.unit_rate
                else round(coalesce(acc.price_cents, 0)::numeric / 100, 2)
              end
            ),
            2
          )
        end,
        coalesce(nullif(acc.name, ''), 'Ancillary Charge')
      into
        v_line_service_date,
        v_line_quantity,
        v_line_unit_rate,
        v_line_amount,
        v_line_description
      from public.ancillary_charge_logs acl
      left join public.ancillary_charge_categories acc on acc.id = acl.category_id
      where acl.id = v_source_record_id
        and acl.member_id = v_member_id
        and coalesce(acl.billing_status, 'Unbilled') = 'Unbilled'
        and acl.invoice_id is null
      for update of acl;

      if not found then
        raise exception 'ancillary charge log % is no longer unbilled during custom invoice creation', v_source_record_id;
      end if;

      if v_line_service_date is null then
        raise exception 'ancillary charge log % is missing service_date during custom invoice creation', v_source_record_id;
      end if;

      v_line_type := 'Ancillary';
      v_line_service_period_start := v_line_service_date;
      v_line_service_period_end := v_line_service_date;
      v_line_product_or_service := 'Ancillary';

      update public.ancillary_charge_logs
      set
        billing_status = 'Billed',
        billing_exclusion_reason = null,
        invoice_id = v_invoice_id,
        updated_at = v_line_updated_at
      where id = v_source_record_id;
    elsif v_source_table = 'billing_adjustments' then
      select
        ba.adjustment_date,
        coalesce(ba.quantity, 1),
        coalesce(ba.unit_rate, 0),
        coalesce(ba.amount, 0),
        coalesce(nullif(ba.description, ''), 'Adjustment'),
        case
          when coalesce(ba.amount, 0) < 0 then 'Credit'
          else 'Adjustment'
        end
      into
        v_line_service_date,
        v_line_quantity,
        v_line_unit_rate,
        v_line_amount,
        v_line_description,
        v_line_type
      from public.billing_adjustments ba
      where ba.id = v_source_record_id
        and ba.member_id = v_member_id
        and coalesce(ba.billing_status, 'Unbilled') = 'Unbilled'
        and ba.invoice_id is null
      for update of ba;

      if not found then
        raise exception 'billing adjustment % is no longer unbilled during custom invoice creation', v_source_record_id;
      end if;

      if v_line_service_date is null then
        raise exception 'billing adjustment % is missing adjustment_date during custom invoice creation', v_source_record_id;
      end if;

      v_line_service_period_start := v_line_service_date;
      v_line_service_period_end := v_line_service_date;
      v_line_product_or_service := case when v_line_type = 'Credit' then 'Credit' else 'Adjustment' end;

      update public.billing_adjustments
      set
        billing_status = 'Billed',
        exclusion_reason = null,
        invoice_id = v_invoice_id,
        updated_at = v_line_updated_at
      where id = v_source_record_id;
    else
      raise exception 'unsupported custom invoice source table %', coalesce(v_source_table, 'null');
    end if;

    insert into public.billing_invoice_lines (
      id,
      invoice_id,
      member_id,
      payor_id,
      line_number,
      product_or_service,
      service_date,
      service_period_start,
      service_period_end,
      line_type,
      description,
      quantity,
      unit_rate,
      amount,
      source_table,
      source_record_id,
      billing_status,
      created_at,
      updated_at
    )
    values (
      v_line_id,
      v_invoice_id,
      v_member_id,
      v_payor_id,
      v_line_number,
      v_line_product_or_service,
      v_line_service_date,
      v_line_service_period_start,
      v_line_service_period_end,
      v_line_type,
      v_line_description,
      v_line_quantity,
      v_line_unit_rate,
      v_line_amount,
      v_source_table,
      v_source_record_id::text,
      'Billed',
      v_line_created_at,
      v_line_updated_at
    );

    insert into public.billing_coverages (
      member_id,
      coverage_type,
      coverage_start_date,
      coverage_end_date,
      source_invoice_id,
      source_invoice_line_id,
      source_table,
      source_record_id,
      created_at
    )
    values (
      v_member_id,
      case
        when v_line_type = 'Transportation' then 'Transportation'
        when v_line_type = 'Ancillary' then 'Ancillary'
        when v_line_type = 'BaseProgram' then 'BaseProgram'
        else 'Adjustment'
      end,
      v_line_service_period_start,
      v_line_service_period_end,
      v_invoice_id,
      v_line_id,
      v_source_table,
      v_source_record_id::text,
      v_line_created_at
    );
  end loop;

  update public.billing_invoices bi
  set
    base_program_amount = totals.base_program_amount,
    transportation_amount = totals.transportation_amount,
    ancillary_amount = totals.ancillary_amount,
    adjustment_amount = totals.adjustment_amount,
    total_amount = totals.total_amount,
    balance_due_amount = totals.total_amount - coalesce(bi.payments_amount, 0),
    updated_at = now()
  from (
    select
      coalesce(sum(case when line_type = 'BaseProgram' then amount else 0 end), 0)::numeric(12,2) as base_program_amount,
      coalesce(sum(case when line_type = 'Transportation' then amount else 0 end), 0)::numeric(12,2) as transportation_amount,
      coalesce(sum(case when line_type = 'Ancillary' then amount else 0 end), 0)::numeric(12,2) as ancillary_amount,
      coalesce(sum(case when line_type in ('Adjustment', 'Credit', 'PriorBalance') then amount else 0 end), 0)::numeric(12,2) as adjustment_amount,
      coalesce(sum(amount), 0)::numeric(12,2) as total_amount
    from public.billing_invoice_lines
    where invoice_id = v_invoice_id
  ) totals
  where bi.id = v_invoice_id;

  return v_invoice_id;
end;
$_$;


ALTER FUNCTION "public"."rpc_create_custom_invoice"("p_invoice" "jsonb", "p_invoice_lines" "jsonb", "p_coverages" "jsonb", "p_source_updates" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_create_draft_physician_order_from_intake"("p_assessment_id" "uuid", "p_member_id" "uuid", "p_payload" "jsonb", "p_attempted_at" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("physician_order_id" "uuid", "draft_pof_status" "text", "was_existing" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_assessment public.intake_assessments%rowtype;
  v_existing public.physician_orders%rowtype;
  v_member public.members%rowtype;
  v_order public.physician_orders%rowtype;
  v_attempted_at timestamptz := coalesce(p_attempted_at, now());
  v_version_number integer;
begin
  if p_assessment_id is null then
    raise exception 'assessment id is required';
  end if;
  if p_member_id is null then
    raise exception 'member id is required';
  end if;
  if p_payload is null or jsonb_typeof(p_payload) <> 'object' then
    raise exception 'p_payload must be a JSON object';
  end if;

  select *
  into v_assessment
  from public.intake_assessments
  where id = p_assessment_id
  for update;

  if not found then
    raise exception 'Intake assessment % was not found.', p_assessment_id;
  end if;

  if v_assessment.member_id is distinct from p_member_id then
    raise exception 'Intake assessment % does not belong to member %.', p_assessment_id, p_member_id;
  end if;

  if coalesce(lower(v_assessment.signature_status), '') <> 'signed' then
    raise exception 'Intake assessment % must be signed before draft POF creation.', p_assessment_id;
  end if;

  select *
  into v_member
  from public.members
  where id = p_member_id
  for update;

  if not found then
    raise exception 'Member % was not found.', p_member_id;
  end if;

  perform pg_advisory_xact_lock(hashtext(format('physician-order-member:%s', p_member_id))::bigint);

  select *
  into v_existing
  from public.physician_orders
  where intake_assessment_id = p_assessment_id
    and status in ('draft', 'sent')
  order by created_at desc
  limit 1
  for update;

  if found then
    update public.intake_assessments
    set
      draft_pof_status = 'created',
      draft_pof_attempted_at = v_attempted_at,
      draft_pof_error = null,
      updated_at = v_attempted_at
    where id = p_assessment_id;

    return query
    select
      v_existing.id,
      'created',
      true;
    return;
  end if;

  select coalesce(max(po.version_number), 0) + 1
  into v_version_number
  from public.physician_orders po
  where po.member_id = p_member_id;

  v_order := jsonb_populate_record(null::public.physician_orders, p_payload);
  v_order.id := coalesce(v_order.id, gen_random_uuid());
  v_order.member_id := p_member_id;
  v_order.intake_assessment_id := p_assessment_id;
  v_order.version_number := v_version_number;
  v_order.status := coalesce(nullif(trim(coalesce(v_order.status, '')), ''), 'draft');
  v_order.is_active_signed := false;
  v_order.superseded_by := null;
  v_order.superseded_at := null;
  v_order.sent_at := null;
  v_order.signed_at := null;
  v_order.effective_at := null;
  v_order.next_renewal_due_date := null;
  v_order.created_at := coalesce(v_order.created_at, v_attempted_at);
  v_order.updated_at := coalesce(v_order.updated_at, v_attempted_at);

  begin
    insert into public.physician_orders
    select (v_order).*;
  exception
    when unique_violation then
      select *
      into v_existing
      from public.physician_orders
      where intake_assessment_id = p_assessment_id
        and status in ('draft', 'sent')
      order by created_at desc
      limit 1
      for update;

      if found then
        update public.intake_assessments
        set
          draft_pof_status = 'created',
          draft_pof_attempted_at = v_attempted_at,
          draft_pof_error = null,
          updated_at = v_attempted_at
        where id = p_assessment_id;

        return query
        select
          v_existing.id,
          'created',
          true;
        return;
      end if;

      raise;
  end;

  update public.intake_assessments
  set
    draft_pof_status = 'created',
    draft_pof_attempted_at = v_attempted_at,
    draft_pof_error = null,
    updated_at = v_attempted_at
  where id = p_assessment_id;

  return query
  select
    v_order.id,
    'created',
    false;
end;
$$;


ALTER FUNCTION "public"."rpc_create_draft_physician_order_from_intake"("p_assessment_id" "uuid", "p_member_id" "uuid", "p_payload" "jsonb", "p_attempted_at" timestamp with time zone) OWNER TO "postgres";

SET default_tablespace = '';

SET default_table_access_method = "heap";


CREATE TABLE IF NOT EXISTS "public"."intake_assessments" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "member_id" "uuid" NOT NULL,
    "lead_id" "uuid",
    "assessment_date" "date" NOT NULL,
    "status" "text" DEFAULT 'completed'::"text" NOT NULL,
    "completed_by_user_id" "uuid",
    "completed_by" "text",
    "signed_by" "text",
    "complete" boolean DEFAULT true NOT NULL,
    "feeling_today" "text",
    "health_lately" "text",
    "allergies" "text",
    "code_status" "text",
    "orientation_dob_verified" boolean,
    "orientation_city_verified" boolean,
    "orientation_year_verified" boolean,
    "orientation_occupation_verified" boolean,
    "orientation_notes" "text",
    "medication_management_status" "text",
    "dressing_support_status" "text",
    "assistive_devices" "text",
    "incontinence_products" "text",
    "on_site_medication_use" "text",
    "on_site_medication_list" "text",
    "independence_notes" "text",
    "diet_type" "text",
    "diet_other" "text",
    "diet_restrictions_notes" "text",
    "mobility_steadiness" "text",
    "falls_history" "text",
    "mobility_aids" "text",
    "mobility_safety_notes" "text",
    "overwhelmed_by_noise" boolean,
    "social_triggers" "text",
    "emotional_wellness_notes" "text",
    "joy_sparks" "text",
    "personal_notes" "text",
    "score_orientation_general_health" smallint,
    "score_daily_routines_independence" smallint,
    "score_nutrition_dietary_needs" smallint,
    "score_mobility_safety" smallint,
    "score_social_emotional_wellness" smallint,
    "total_score" smallint,
    "recommended_track" "text",
    "admission_review_required" boolean,
    "transport_can_enter_exit_vehicle" "text",
    "transport_assistance_level" "text",
    "transport_mobility_aid" "text",
    "transport_can_remain_seated_buckled" boolean,
    "transport_behavior_concern" "text",
    "transport_appropriate" boolean,
    "transport_notes" "text",
    "vitals_hr" integer,
    "vitals_bp" "text",
    "vitals_o2_percent" integer,
    "vitals_rr" integer,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "signed_by_user_id" "uuid",
    "signed_at" timestamp with time zone,
    "signature_status" "text" DEFAULT 'unsigned'::"text" NOT NULL,
    "signature_metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "draft_pof_status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "draft_pof_attempted_at" timestamp with time zone,
    "draft_pof_error" "text",
    "creation_idempotency_key" "text",
    CONSTRAINT "intake_assessments_draft_pof_status_check" CHECK (("draft_pof_status" = ANY (ARRAY['pending'::"text", 'created'::"text", 'failed'::"text"]))),
    CONSTRAINT "intake_assessments_signature_status_check" CHECK (("signature_status" = ANY (ARRAY['unsigned'::"text", 'signed'::"text", 'voided'::"text"]))),
    CONSTRAINT "intake_assessments_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'completed'::"text", 'archived'::"text"])))
);


ALTER TABLE "public"."intake_assessments" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_create_intake_assessment_with_responses"("p_assessment" "jsonb", "p_response_rows" "jsonb" DEFAULT '[]'::"jsonb") RETURNS SETOF "public"."intake_assessments"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_assessment public.intake_assessments%rowtype;
  v_creation_idempotency_key text := nullif(trim(coalesce(p_assessment ->> 'creation_idempotency_key', '')), '');
begin
  if p_assessment is null or jsonb_typeof(p_assessment) <> 'object' then
    raise exception 'p_assessment must be a JSON object';
  end if;
  if p_response_rows is not null and jsonb_typeof(p_response_rows) <> 'array' then
    raise exception 'p_response_rows must be a JSON array';
  end if;

  if v_creation_idempotency_key is not null then
    select *
    into v_assessment
    from public.intake_assessments
    where creation_idempotency_key = v_creation_idempotency_key
    order by created_at asc, id asc
    limit 1
    for update;

    if found then
      return next v_assessment;
      return;
    end if;
  end if;

  begin
    insert into public.intake_assessments (
      member_id,
      lead_id,
      assessment_date,
      status,
      completed_by_user_id,
      completed_by,
      signed_by,
      signed_by_user_id,
      signed_at,
      signature_status,
      signature_metadata,
      draft_pof_status,
      draft_pof_attempted_at,
      draft_pof_error,
      complete,
      feeling_today,
      health_lately,
      allergies,
      code_status,
      orientation_dob_verified,
      orientation_city_verified,
      orientation_year_verified,
      orientation_occupation_verified,
      orientation_notes,
      medication_management_status,
      dressing_support_status,
      assistive_devices,
      incontinence_products,
      on_site_medication_use,
      on_site_medication_list,
      independence_notes,
      diet_type,
      diet_other,
      diet_restrictions_notes,
      mobility_steadiness,
      falls_history,
      mobility_aids,
      mobility_safety_notes,
      overwhelmed_by_noise,
      social_triggers,
      emotional_wellness_notes,
      joy_sparks,
      personal_notes,
      score_orientation_general_health,
      score_daily_routines_independence,
      score_nutrition_dietary_needs,
      score_mobility_safety,
      score_social_emotional_wellness,
      total_score,
      recommended_track,
      admission_review_required,
      transport_can_enter_exit_vehicle,
      transport_assistance_level,
      transport_mobility_aid,
      transport_can_remain_seated_buckled,
      transport_behavior_concern,
      transport_appropriate,
      transport_notes,
      vitals_hr,
      vitals_bp,
      vitals_o2_percent,
      vitals_rr,
      notes,
      created_at,
      updated_at,
      creation_idempotency_key
    )
    values (
      (p_assessment->>'member_id')::uuid,
      nullif(trim(coalesce(p_assessment->>'lead_id', '')), '')::uuid,
      (p_assessment->>'assessment_date')::date,
      coalesce(nullif(trim(p_assessment->>'status'), ''), 'completed'),
      (p_assessment->>'completed_by_user_id')::uuid,
      p_assessment->>'completed_by',
      nullif(trim(coalesce(p_assessment->>'signed_by', '')), ''),
      nullif(trim(coalesce(p_assessment->>'signed_by_user_id', '')), '')::uuid,
      nullif(trim(coalesce(p_assessment->>'signed_at', '')), '')::timestamptz,
      coalesce(nullif(trim(p_assessment->>'signature_status'), ''), 'unsigned'),
      coalesce(p_assessment->'signature_metadata', '{}'::jsonb),
      coalesce(nullif(trim(p_assessment->>'draft_pof_status'), ''), 'pending'),
      nullif(trim(coalesce(p_assessment->>'draft_pof_attempted_at', '')), '')::timestamptz,
      nullif(trim(coalesce(p_assessment->>'draft_pof_error', '')), ''),
      coalesce((p_assessment->>'complete')::boolean, true),
      p_assessment->>'feeling_today',
      p_assessment->>'health_lately',
      p_assessment->>'allergies',
      p_assessment->>'code_status',
      coalesce((p_assessment->>'orientation_dob_verified')::boolean, false),
      coalesce((p_assessment->>'orientation_city_verified')::boolean, false),
      coalesce((p_assessment->>'orientation_year_verified')::boolean, false),
      coalesce((p_assessment->>'orientation_occupation_verified')::boolean, false),
      p_assessment->>'orientation_notes',
      p_assessment->>'medication_management_status',
      p_assessment->>'dressing_support_status',
      p_assessment->>'assistive_devices',
      p_assessment->>'incontinence_products',
      p_assessment->>'on_site_medication_use',
      p_assessment->>'on_site_medication_list',
      p_assessment->>'independence_notes',
      p_assessment->>'diet_type',
      p_assessment->>'diet_other',
      p_assessment->>'diet_restrictions_notes',
      p_assessment->>'mobility_steadiness',
      p_assessment->>'falls_history',
      p_assessment->>'mobility_aids',
      p_assessment->>'mobility_safety_notes',
      coalesce((p_assessment->>'overwhelmed_by_noise')::boolean, false),
      p_assessment->>'social_triggers',
      p_assessment->>'emotional_wellness_notes',
      p_assessment->>'joy_sparks',
      p_assessment->>'personal_notes',
      nullif(trim(coalesce(p_assessment->>'score_orientation_general_health', '')), '')::smallint,
      nullif(trim(coalesce(p_assessment->>'score_daily_routines_independence', '')), '')::smallint,
      nullif(trim(coalesce(p_assessment->>'score_nutrition_dietary_needs', '')), '')::smallint,
      nullif(trim(coalesce(p_assessment->>'score_mobility_safety', '')), '')::smallint,
      nullif(trim(coalesce(p_assessment->>'score_social_emotional_wellness', '')), '')::smallint,
      nullif(trim(coalesce(p_assessment->>'total_score', '')), '')::smallint,
      p_assessment->>'recommended_track',
      coalesce((p_assessment->>'admission_review_required')::boolean, false),
      p_assessment->>'transport_can_enter_exit_vehicle',
      p_assessment->>'transport_assistance_level',
      p_assessment->>'transport_mobility_aid',
      coalesce((p_assessment->>'transport_can_remain_seated_buckled')::boolean, false),
      p_assessment->>'transport_behavior_concern',
      coalesce((p_assessment->>'transport_appropriate')::boolean, false),
      p_assessment->>'transport_notes',
      nullif(trim(coalesce(p_assessment->>'vitals_hr', '')), '')::integer,
      p_assessment->>'vitals_bp',
      nullif(trim(coalesce(p_assessment->>'vitals_o2_percent', '')), '')::integer,
      nullif(trim(coalesce(p_assessment->>'vitals_rr', '')), '')::integer,
      p_assessment->>'notes',
      coalesce(nullif(trim(coalesce(p_assessment->>'created_at', '')), '')::timestamptz, now()),
      coalesce(nullif(trim(coalesce(p_assessment->>'updated_at', '')), '')::timestamptz, now()),
      v_creation_idempotency_key
    )
    returning * into v_assessment;
  exception
    when unique_violation then
      if v_creation_idempotency_key is null then
        raise;
      end if;

      select *
      into v_assessment
      from public.intake_assessments
      where creation_idempotency_key = v_creation_idempotency_key
      order by created_at asc, id asc
      limit 1
      for update;

      if not found then
        raise;
      end if;

      return next v_assessment;
      return;
  end;

  if p_response_rows is not null and jsonb_typeof(p_response_rows) = 'array' and jsonb_array_length(p_response_rows) > 0 then
    insert into public.assessment_responses (
      assessment_id,
      member_id,
      field_key,
      field_label,
      section_type,
      field_value,
      field_value_type,
      created_at
    )
    select
      v_assessment.id,
      v_assessment.member_id,
      row.field_key,
      row.field_label,
      row.section_type,
      row.field_value,
      row.field_value_type,
      coalesce(row.created_at, v_assessment.created_at, now())
    from jsonb_to_recordset(p_response_rows) as row(
      field_key text,
      field_label text,
      section_type text,
      field_value text,
      field_value_type text,
      created_at timestamptz
    );
  end if;

  return next v_assessment;
end;
$$;


ALTER FUNCTION "public"."rpc_create_intake_assessment_with_responses"("p_assessment" "jsonb", "p_response_rows" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_create_lead_with_member_conversion"("p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_created_by_user_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text" DEFAULT NULL::"text", "p_member_display_name" "text" DEFAULT NULL::"text", "p_member_dob" "date" DEFAULT NULL::"date", "p_member_enrollment_date" "date" DEFAULT NULL::"date", "p_lead_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_idempotency_key" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"(), "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("lead_id" "uuid", "member_id" "uuid", "from_stage" "text", "to_stage" "text", "from_status" "text", "to_status" "text", "business_status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_created record;
  v_current_role public.app_role;
  v_current_profile_id uuid;
begin
  if auth.role() <> 'service_role' then
    v_current_role := public.current_role();
    v_current_profile_id := public.current_profile_id();

    if v_current_role is null or v_current_role not in ('admin', 'director', 'sales') then
      raise exception 'rpc_create_lead_with_member_conversion is not permitted for role %.', coalesce(v_current_role::text, 'unknown')
        using errcode = '42501';
    end if;

    if p_actor_user_id is null or v_current_profile_id is null or p_actor_user_id <> v_current_profile_id then
      raise exception 'rpc_create_lead_with_member_conversion requires p_actor_user_id to match the authenticated profile.'
        using errcode = '42501';
    end if;

    if p_created_by_user_id is null or p_created_by_user_id <> v_current_profile_id then
      raise exception 'rpc_create_lead_with_member_conversion requires p_created_by_user_id to match the authenticated profile.'
        using errcode = '42501';
    end if;
  end if;

  select *
  into v_created
  from public.create_lead_with_member_conversion(
    p_to_stage => p_to_stage,
    p_to_status => p_to_status,
    p_business_status => p_business_status,
    p_created_by_user_id => p_created_by_user_id,
    p_actor_user_id => p_actor_user_id,
    p_actor_name => p_actor_name,
    p_source => p_source,
    p_reason => p_reason,
    p_member_display_name => p_member_display_name,
    p_member_dob => p_member_dob,
    p_member_enrollment_date => p_member_enrollment_date,
    p_lead_patch => p_lead_patch,
    p_idempotency_key => p_idempotency_key,
    p_now => p_now,
    p_today => p_today
  ) as created;

  if v_created.member_id is null then
    raise exception 'Lead creation with conversion did not return a canonical member_id.';
  end if;

  perform 1 from public.member_command_centers where member_id = v_created.member_id;
  if not found then
    raise exception 'Lead creation with conversion did not persist member_command_centers for member %.', v_created.member_id;
  end if;

  perform 1 from public.member_attendance_schedules where member_id = v_created.member_id;
  if not found then
    raise exception 'Lead creation with conversion did not persist member_attendance_schedules for member %.', v_created.member_id;
  end if;

  perform 1 from public.member_health_profiles where member_id = v_created.member_id;
  if not found then
    raise exception 'Lead creation with conversion did not persist member_health_profiles for member %.', v_created.member_id;
  end if;

  lead_id := v_created.lead_id;
  member_id := v_created.member_id;
  from_stage := v_created.from_stage;
  to_stage := v_created.to_stage;
  from_status := v_created.from_status;
  to_status := v_created.to_status;
  business_status := v_created.business_status;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_create_lead_with_member_conversion"("p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_created_by_user_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text", "p_member_display_name" "text", "p_member_dob" "date", "p_member_enrollment_date" "date", "p_lead_patch" "jsonb", "p_idempotency_key" "text", "p_now" timestamp with time zone, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_create_prn_medication_order_and_administer"("p_member_id" "uuid", "p_order_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_admin_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("medication_order_id" "uuid", "log_id" "uuid", "member_id" "uuid", "followup_due_at" timestamp with time zone, "followup_status" "text", "duplicate_safe" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_order public.medication_orders%rowtype;
  v_requires_review boolean := coalesce((p_order_payload ->> 'requires_review')::boolean, true);
  v_requires_followup boolean := coalesce((p_order_payload ->> 'requires_effectiveness_followup')::boolean, true);
  v_creation_idempotency_key text := nullif(trim(coalesce(p_order_payload ->> 'creation_idempotency_key', '')), '');
begin
  if p_member_id is null then
    raise exception 'PRN medication order creation requires member_id';
  end if;
  if nullif(trim(coalesce(p_order_payload ->> 'medication_name', '')), '') is null then
    raise exception 'Medication name is required for new PRN orders.';
  end if;
  if nullif(trim(coalesce(p_order_payload ->> 'provider_name', '')), '') is null then
    raise exception 'Provider name is required for new PRN orders.';
  end if;
  if nullif(trim(coalesce(p_order_payload ->> 'directions', '')), '') is null then
    raise exception 'Directions are required for new PRN orders.';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_member_id::text)::bigint);

  if v_creation_idempotency_key is not null then
    select *
    into v_order
    from public.medication_orders
    where creation_idempotency_key = v_creation_idempotency_key
    order by created_at asc, id asc
    limit 1
    for update;
  end if;

  if v_order.id is null then
    begin
      insert into public.medication_orders (
        member_id,
        physician_order_id,
        pof_medication_id,
        source_medication_id,
        order_type,
        medication_name,
        strength,
        form,
        route,
        directions,
        prn_reason,
        frequency_text,
        min_interval_minutes,
        max_doses_per_24h,
        max_daily_dose,
        start_date,
        end_date,
        provider_name,
        order_source,
        status,
        created_by,
        verified_by,
        requires_review,
        requires_effectiveness_followup,
        created_by_name,
        verified_by_name,
        source_payload,
        created_at,
        updated_at,
        creation_idempotency_key
      )
      values (
        p_member_id,
        nullif(trim(coalesce(p_order_payload ->> 'physician_order_id', '')), '')::uuid,
        nullif(trim(coalesce(p_order_payload ->> 'pof_medication_id', '')), '')::uuid,
        nullif(trim(coalesce(p_order_payload ->> 'source_medication_id', '')), ''),
        'prn',
        nullif(trim(coalesce(p_order_payload ->> 'medication_name', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'strength', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'form', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'route', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'directions', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'prn_reason', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'frequency_text', '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'min_interval_minutes', '')), '')::integer,
        nullif(trim(coalesce(p_order_payload ->> 'max_doses_per_24h', '')), '')::integer,
        nullif(trim(coalesce(p_order_payload ->> 'max_daily_dose', '')), '')::numeric,
        nullif(trim(coalesce(p_order_payload ->> 'start_date', '')), '')::date,
        nullif(trim(coalesce(p_order_payload ->> 'end_date', '')), '')::date,
        nullif(trim(coalesce(p_order_payload ->> 'provider_name', '')), ''),
        'manual_provider_order',
        coalesce(nullif(trim(coalesce(p_order_payload ->> 'status', '')), ''), 'active'),
        p_actor_user_id,
        nullif(trim(coalesce(p_order_payload ->> 'verified_by', '')), '')::uuid,
        v_requires_review,
        v_requires_followup,
        nullif(trim(coalesce(p_actor_name, '')), ''),
        nullif(trim(coalesce(p_order_payload ->> 'verified_by_name', '')), ''),
        jsonb_build_object(
          'source', 'manual_provider_order',
          'order_payload', p_order_payload,
          'creation_idempotency_key', v_creation_idempotency_key
        ),
        v_now,
        v_now,
        v_creation_idempotency_key
      )
      returning * into v_order;
    exception
      when unique_violation then
        if v_creation_idempotency_key is null then
          raise;
        end if;

        select *
        into v_order
        from public.medication_orders
        where creation_idempotency_key = v_creation_idempotency_key
        order by created_at asc, id asc
        limit 1
        for update;

        if v_order.id is null then
          raise;
        end if;
    end;
  end if;

  select
    logged.medication_order_id,
    logged.log_id,
    logged.member_id,
    logged.followup_due_at,
    logged.followup_status,
    logged.duplicate_safe
  into
    medication_order_id,
    log_id,
    member_id,
    followup_due_at,
    followup_status,
    duplicate_safe
  from public.rpc_record_prn_medication_administration(
    v_order.id,
    nullif(trim(coalesce(p_admin_payload ->> 'admin_datetime', '')), '')::timestamptz,
    nullif(trim(coalesce(p_admin_payload ->> 'dose_given', '')), ''),
    nullif(trim(coalesce(p_admin_payload ->> 'route_given', '')), ''),
    nullif(trim(coalesce(p_admin_payload ->> 'indication', '')), ''),
    nullif(trim(coalesce(p_admin_payload ->> 'symptom_score_before', '')), '')::integer,
    nullif(trim(coalesce(p_admin_payload ->> 'followup_due_at', '')), '')::timestamptz,
    coalesce(nullif(trim(coalesce(p_admin_payload ->> 'status', '')), ''), 'Given'),
    nullif(trim(coalesce(p_admin_payload ->> 'notes', '')), ''),
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    nullif(trim(coalesce(p_admin_payload ->> 'idempotency_key', '')), ''),
    v_now
  ) as logged;

  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_create_prn_medication_order_and_administer"("p_member_id" "uuid", "p_order_payload" "jsonb", "p_admin_payload" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_delete_member_file_record"("p_member_file_id" "text") RETURNS TABLE("member_file_id" "text", "member_id" "uuid", "deleted" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_file public.member_files%rowtype;
begin
  if nullif(trim(coalesce(p_member_file_id, '')), '') is null then
    raise exception 'rpc_delete_member_file_record requires p_member_file_id';
  end if;

  select *
  into v_file
  from public.member_files
  where id = trim(p_member_file_id)
  for update;

  if not found then
    member_file_id := trim(p_member_file_id);
    member_id := null;
    deleted := false;
    return next;
    return;
  end if;

  delete from public.member_files
  where id = v_file.id;

  member_file_id := v_file.id;
  member_id := v_file.member_id;
  deleted := true;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_delete_member_file_record"("p_member_file_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_document_scheduled_mar_administration"("p_mar_schedule_id" "uuid", "p_member_id" "uuid", "p_pof_medication_id" "uuid", "p_medication_name" "text", "p_dose" "text" DEFAULT NULL::"text", "p_route" "text" DEFAULT NULL::"text", "p_scheduled_time" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_administration_date" "date" DEFAULT NULL::"date", "p_status" "text" DEFAULT 'Given'::"text", "p_not_given_reason" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_administered_by" "uuid" DEFAULT NULL::"uuid", "p_administered_by_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("administration_id" "uuid", "member_id" "uuid", "administered_at" timestamp with time zone, "duplicate_safe" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_status text := coalesce(nullif(trim(p_status), ''), 'Given');
  v_administered_at timestamptz := v_now;
  v_administration_date date := coalesce(p_administration_date, (v_now at time zone 'America/New_York')::date);
  v_scheduled_time timestamptz := p_scheduled_time;
  v_not_given_reason text := nullif(trim(coalesce(p_not_given_reason, '')), '');
  v_row record;
  v_notes text := nullif(trim(coalesce(p_notes, '')), '');
begin
  if p_mar_schedule_id is null then
    raise exception 'MAR schedule is required.';
  end if;
  if p_member_id is null then
    raise exception 'Member is required for scheduled MAR documentation.';
  end if;
  if p_pof_medication_id is null then
    raise exception 'Scheduled MAR documentation requires a linked medication.';
  end if;
  if nullif(trim(coalesce(p_medication_name, '')), '') is null then
    raise exception 'Medication name is required for scheduled MAR documentation.';
  end if;

  if v_status not in ('Given', 'Not Given') then
    raise exception 'Scheduled MAR status must be Given or Not Given.';
  end if;
  if v_status = 'Not Given' and v_not_given_reason is null then
    raise exception 'Not Given reason is required.';
  end if;
  if v_status = 'Given' then
    v_not_given_reason := null;
  end if;

  perform pg_advisory_xact_lock(hashtext(p_mar_schedule_id::text)::bigint);

  with inserted as (
    insert into public.mar_administrations as ma (
      member_id,
      pof_medication_id,
      mar_schedule_id,
      administration_date,
      scheduled_time,
      medication_name,
      dose,
      route,
      status,
      not_given_reason,
      prn_reason,
      notes,
      administered_by,
      administered_by_user_id,
      administered_at,
      source,
      prn_outcome,
      prn_outcome_assessed_at,
      prn_followup_note
    )
    values (
      p_member_id,
      p_pof_medication_id,
      p_mar_schedule_id,
      v_administration_date,
      v_scheduled_time,
      trim(p_medication_name),
      nullif(trim(coalesce(p_dose, '')), ''),
      nullif(trim(p_route), ''),
      v_status,
      v_not_given_reason,
      null,
      v_notes,
      p_administered_by_name,
      p_administered_by,
      v_administered_at,
      'scheduled',
      null,
      null,
      null
    )
    on conflict (mar_schedule_id) do nothing
    returning ma.id, ma.member_id, ma.administered_at
  )
  select inserted.id, inserted.member_id, inserted.administered_at
  into v_row
  from inserted;

  if v_row is not null then
    administration_id := v_row.id;
    member_id := v_row.member_id;
    administered_at := v_row.administered_at;
    duplicate_safe := false;
    return next;
    return;
  end if;

  select ma.id, ma.member_id, ma.administered_at
  into v_row
  from public.mar_administrations ma
  where ma.mar_schedule_id = p_mar_schedule_id
    and ma.source = 'scheduled'
  order by ma.administered_at desc, ma.created_at desc
  limit 1;

  if v_row is null then
    raise exception 'Unable to save or retrieve scheduled MAR administration.';
  end if;

  administration_id := v_row.id;
  member_id := v_row.member_id;
  administered_at := v_row.administered_at;
  duplicate_safe := true;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_document_scheduled_mar_administration"("p_mar_schedule_id" "uuid", "p_member_id" "uuid", "p_pof_medication_id" "uuid", "p_medication_name" "text", "p_dose" "text", "p_route" "text", "p_scheduled_time" timestamp with time zone, "p_administration_date" "date", "p_status" "text", "p_not_given_reason" "text", "p_notes" "text", "p_administered_by" "uuid", "p_administered_by_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_care_plan_caregiver_signature"("p_care_plan_id" "uuid", "p_rotated_token" "text", "p_signed_at" timestamp with time zone, "p_updated_at" timestamp with time zone, "p_final_member_file_id" "text", "p_actor_name" "text", "p_actor_email" "text", "p_actor_ip" "text", "p_actor_user_agent" "text", "p_signature_image_url" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_care_plan public.care_plans%rowtype;
begin
  if p_care_plan_id is null then
    raise exception 'care plan id is required';
  end if;

  select *
  into v_care_plan
  from public.care_plans
  where id = p_care_plan_id
  for update;

  if not found then
    raise exception 'Care plan % was not found.', p_care_plan_id;
  end if;

  if coalesce(v_care_plan.caregiver_signature_status, '') = 'signed' then
    raise exception 'Care plan % caregiver signature is already finalized.', p_care_plan_id;
  end if;

  if coalesce(v_care_plan.caregiver_signature_status, '') not in ('sent', 'viewed') then
    raise exception 'Care plan % caregiver signature cannot be finalized from status %.', p_care_plan_id, coalesce(v_care_plan.caregiver_signature_status, 'null');
  end if;

  update public.care_plans
  set
    caregiver_signature_status = 'signed',
    caregiver_signed_at = coalesce(p_signed_at, now()),
    caregiver_signature_request_token = p_rotated_token,
    caregiver_signature_request_url = null,
    final_member_file_id = nullif(p_final_member_file_id, ''),
    caregiver_signature_error = null,
    updated_at = coalesce(p_updated_at, now())
  where id = p_care_plan_id;

  insert into public.care_plan_signature_events (
    care_plan_id,
    member_id,
    event_type,
    actor_type,
    actor_name,
    actor_email,
    actor_ip,
    actor_user_agent,
    metadata,
    created_at
  )
  values (
    p_care_plan_id,
    v_care_plan.member_id,
    'signed',
    'caregiver',
    nullif(p_actor_name, ''),
    nullif(p_actor_email, ''),
    nullif(p_actor_ip, ''),
    nullif(p_actor_user_agent, ''),
    jsonb_strip_nulls(
      jsonb_build_object(
        'finalMemberFileId', nullif(p_final_member_file_id, ''),
        'signatureImageUrl', nullif(p_signature_image_url, '')
      )
    ) || coalesce(p_metadata, '{}'::jsonb),
    coalesce(p_signed_at, now())
  );

  return p_care_plan_id;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_care_plan_caregiver_signature"("p_care_plan_id" "uuid", "p_rotated_token" "text", "p_signed_at" timestamp with time zone, "p_updated_at" timestamp with time zone, "p_final_member_file_id" "text", "p_actor_name" "text", "p_actor_email" "text", "p_actor_ip" "text", "p_actor_user_agent" "text", "p_signature_image_url" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_care_plan_caregiver_signature"("p_care_plan_id" "uuid", "p_rotated_token" "text", "p_consumed_signature_token_hash" "text", "p_signed_at" timestamp with time zone, "p_updated_at" timestamp with time zone, "p_final_member_file_id" "text", "p_final_member_file_name" "text", "p_final_member_file_data_url" "text", "p_final_member_file_storage_object_path" "text", "p_uploaded_by_user_id" "uuid", "p_uploaded_by_name" "text", "p_actor_name" "text", "p_actor_email" "text", "p_actor_ip" "text", "p_actor_user_agent" "text", "p_signature_image_url" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("care_plan_id" "uuid", "member_id" "uuid", "final_member_file_id" "text", "was_already_signed" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_care_plan public.care_plans%rowtype;
  v_final_member_file_id text;
  v_signed_at timestamptz := coalesce(p_signed_at, now());
  v_updated_at timestamptz := coalesce(p_updated_at, v_signed_at);
  v_consumed_signature_token_hash text := nullif(trim(coalesce(p_consumed_signature_token_hash, '')), '');
begin
  if p_care_plan_id is null then
    raise exception 'care plan id is required';
  end if;
  if nullif(trim(coalesce(p_actor_name, '')), '') is null then
    raise exception 'actor name is required';
  end if;
  if nullif(trim(coalesce(p_signature_image_url, '')), '') is null then
    raise exception 'signature image url is required';
  end if;
  if nullif(trim(coalesce(p_final_member_file_name, '')), '') is null then
    raise exception 'final member file name is required';
  end if;
  if nullif(trim(coalesce(p_final_member_file_data_url, '')), '') is null then
    raise exception 'final member file payload is required';
  end if;

  select *
  into v_care_plan
  from public.care_plans
  where id = p_care_plan_id
  for update;

  if not found then
    raise exception 'Care plan % was not found.', p_care_plan_id;
  end if;

  if coalesce(v_care_plan.caregiver_signature_status, '') = 'signed' then
    if v_consumed_signature_token_hash is not null
       and v_care_plan.last_consumed_caregiver_signature_token_hash = v_consumed_signature_token_hash then
      return query
      select
        v_care_plan.id,
        v_care_plan.member_id,
        v_care_plan.final_member_file_id,
        true;
      return;
    end if;
    raise exception 'Care plan % caregiver signature is already finalized.', p_care_plan_id;
  end if;

  if coalesce(v_care_plan.caregiver_signature_status, '') not in ('sent', 'viewed') then
    raise exception 'Care plan % caregiver signature cannot be finalized from status %.', p_care_plan_id, coalesce(v_care_plan.caregiver_signature_status, 'null');
  end if;

  v_final_member_file_id := nullif(trim(coalesce(v_care_plan.final_member_file_id, '')), '');
  if v_final_member_file_id is null then
    v_final_member_file_id := nullif(trim(coalesce(p_final_member_file_id, '')), '');
  end if;
  if v_final_member_file_id is null then
    v_final_member_file_id := 'mf_' || replace(gen_random_uuid()::text, '-', '');
  end if;

  insert into public.member_files (
    id,
    member_id,
    file_name,
    file_type,
    file_data_url,
    category,
    category_other,
    document_source,
    care_plan_id,
    storage_object_path,
    uploaded_by_user_id,
    uploaded_by_name,
    uploaded_at,
    updated_at
  )
  values (
    v_final_member_file_id,
    v_care_plan.member_id,
    p_final_member_file_name,
    'application/pdf',
    p_final_member_file_data_url,
    'Care Plan',
    null,
    'Care Plan Final Signed',
    p_care_plan_id,
    nullif(trim(coalesce(p_final_member_file_storage_object_path, '')), ''),
    p_uploaded_by_user_id,
    nullif(trim(coalesce(p_uploaded_by_name, '')), ''),
    v_signed_at,
    v_updated_at
  )
  on conflict (id)
  do update
  set
    member_id = excluded.member_id,
    file_name = excluded.file_name,
    file_type = excluded.file_type,
    file_data_url = excluded.file_data_url,
    category = excluded.category,
    category_other = excluded.category_other,
    document_source = excluded.document_source,
    care_plan_id = excluded.care_plan_id,
    storage_object_path = excluded.storage_object_path,
    uploaded_by_user_id = excluded.uploaded_by_user_id,
    uploaded_by_name = excluded.uploaded_by_name,
    uploaded_at = excluded.uploaded_at,
    updated_at = excluded.updated_at;

  update public.care_plans
  set
    caregiver_signature_status = 'signed',
    caregiver_signed_at = v_signed_at,
    caregiver_signature_request_token = p_rotated_token,
    caregiver_signature_request_url = null,
    caregiver_signed_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    caregiver_signature_image_url = nullif(trim(coalesce(p_signature_image_url, '')), ''),
    caregiver_signature_ip = nullif(trim(coalesce(p_actor_ip, '')), ''),
    caregiver_signature_user_agent = nullif(trim(coalesce(p_actor_user_agent, '')), ''),
    responsible_party_signature = nullif(trim(coalesce(p_actor_name, '')), ''),
    responsible_party_signature_date = (v_signed_at at time zone 'America/New_York')::date,
    final_member_file_id = v_final_member_file_id,
    caregiver_signature_error = null,
    last_consumed_caregiver_signature_token_hash = coalesce(v_consumed_signature_token_hash, last_consumed_caregiver_signature_token_hash),
    updated_at = v_updated_at
  where id = p_care_plan_id;

  insert into public.care_plan_signature_events (
    care_plan_id,
    member_id,
    event_type,
    actor_type,
    actor_name,
    actor_email,
    actor_ip,
    actor_user_agent,
    metadata,
    created_at
  )
  values (
    p_care_plan_id,
    v_care_plan.member_id,
    'signed',
    'caregiver',
    nullif(trim(coalesce(p_actor_name, '')), ''),
    nullif(trim(coalesce(p_actor_email, '')), ''),
    nullif(trim(coalesce(p_actor_ip, '')), ''),
    nullif(trim(coalesce(p_actor_user_agent, '')), ''),
    jsonb_strip_nulls(
      jsonb_build_object(
        'finalMemberFileId', v_final_member_file_id,
        'signatureImageUrl', nullif(trim(coalesce(p_signature_image_url, '')), '')
      )
    ) || coalesce(p_metadata, '{}'::jsonb),
    v_signed_at
  );

  return query
  select
    p_care_plan_id,
    v_care_plan.member_id,
    v_final_member_file_id,
    false;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_care_plan_caregiver_signature"("p_care_plan_id" "uuid", "p_rotated_token" "text", "p_consumed_signature_token_hash" "text", "p_signed_at" timestamp with time zone, "p_updated_at" timestamp with time zone, "p_final_member_file_id" "text", "p_final_member_file_name" "text", "p_final_member_file_data_url" "text", "p_final_member_file_storage_object_path" "text", "p_uploaded_by_user_id" "uuid", "p_uploaded_by_name" "text", "p_actor_name" "text", "p_actor_email" "text", "p_actor_ip" "text", "p_actor_user_agent" "text", "p_signature_image_url" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_care_plan_nurse_signature"("p_care_plan_id" "uuid", "p_member_id" "uuid", "p_signed_by_user_id" "uuid", "p_signed_by_name" "text", "p_signed_at" timestamp with time zone, "p_signature_artifact_storage_path" "text" DEFAULT NULL::"text", "p_signature_artifact_member_file_id" "text" DEFAULT NULL::"text", "p_signature_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("care_plan_id" "uuid", "member_id" "uuid", "signed_by_user_id" "uuid", "signed_by_name" "text", "signed_at" timestamp with time zone, "status" "text", "signature_artifact_storage_path" "text", "signature_artifact_member_file_id" "text", "signature_metadata" "jsonb", "caregiver_signature_status" "text", "was_already_signed" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_care_plan public.care_plans%rowtype;
  v_signature public.care_plan_nurse_signatures%rowtype;
  v_signed_by_name text := nullif(trim(coalesce(p_signed_by_name, '')), '');
  v_signed_at timestamptz := coalesce(p_signed_at, now());
  v_signature_artifact_storage_path text := nullif(trim(coalesce(p_signature_artifact_storage_path, '')), '');
  v_signature_artifact_member_file_id text := nullif(trim(coalesce(p_signature_artifact_member_file_id, '')), '');
  v_signature_metadata jsonb := coalesce(p_signature_metadata, '{}'::jsonb);
  v_completion_date date;
  v_next_caregiver_status text;
begin
  if p_care_plan_id is null then
    raise exception 'care plan id is required';
  end if;
  if p_member_id is null then
    raise exception 'member id is required';
  end if;
  if p_signed_by_user_id is null then
    raise exception 'signed by user id is required';
  end if;
  if v_signed_by_name is null then
    raise exception 'signed by name is required';
  end if;

  select *
  into v_care_plan
  from public.care_plans
  where id = p_care_plan_id
  for update;

  if not found then
    raise exception 'Care plan % was not found.', p_care_plan_id;
  end if;

  if v_care_plan.member_id is distinct from p_member_id then
    raise exception 'Care plan % does not belong to member %.', p_care_plan_id, p_member_id;
  end if;

  select *
  into v_signature
  from public.care_plan_nurse_signatures as cpns
  where cpns.care_plan_id = p_care_plan_id
  for update;

  if found and coalesce(v_signature.status, '') = 'voided' then
    raise exception 'Care plan % nurse signature has been voided.', p_care_plan_id;
  end if;

  if coalesce(v_care_plan.nurse_signature_status, '') = 'voided' then
    raise exception 'Care plan % nurse signature is voided.', p_care_plan_id;
  end if;

  v_next_caregiver_status := case
    when coalesce(v_care_plan.caregiver_signature_status, '') = 'signed' then 'signed'
    else 'ready_to_send'
  end;

  if found and coalesce(v_signature.status, '') = 'signed' then
    update public.care_plans
    set
      nurse_signature_status = 'signed',
      nurse_signed_by_user_id = v_signature.signed_by_user_id,
      nurse_signed_by_name = v_signature.signed_by_name,
      nurse_signed_at = v_signature.signed_at,
      nurse_signature_artifact_storage_path = v_signature.signature_artifact_storage_path,
      nurse_signature_artifact_member_file_id = v_signature.signature_artifact_member_file_id,
      nurse_signature_metadata = coalesce(v_signature.signature_metadata, '{}'::jsonb),
      completed_by = v_signature.signed_by_name,
      administrator_signature = v_signature.signed_by_name,
      nurse_designee_user_id = v_signature.signed_by_user_id,
      nurse_designee_name = v_signature.signed_by_name,
      legacy_cleanup_flag = false,
      caregiver_signature_status = v_next_caregiver_status,
      updated_at = coalesce(v_signature.signed_at, v_signed_at, now())
    where id = p_care_plan_id;

    return query
    select
      v_signature.care_plan_id,
      v_signature.member_id,
      v_signature.signed_by_user_id,
      v_signature.signed_by_name,
      v_signature.signed_at,
      v_signature.status,
      v_signature.signature_artifact_storage_path,
      v_signature.signature_artifact_member_file_id,
      coalesce(v_signature.signature_metadata, '{}'::jsonb),
      v_next_caregiver_status,
      true;
    return;
  end if;

  if coalesce(v_care_plan.nurse_signature_status, '') = 'signed' then
    insert into public.care_plan_nurse_signatures (
      care_plan_id,
      member_id,
      signed_by_user_id,
      signed_by_name,
      signed_at,
      status,
      signature_artifact_storage_path,
      signature_artifact_member_file_id,
      signature_metadata,
      created_at,
      updated_at
    )
    values (
      v_care_plan.id,
      v_care_plan.member_id,
      coalesce(v_care_plan.nurse_signed_by_user_id, p_signed_by_user_id),
      coalesce(nullif(trim(coalesce(v_care_plan.nurse_signed_by_name, '')), ''), v_signed_by_name),
      coalesce(v_care_plan.nurse_signed_at, v_signed_at),
      'signed',
      coalesce(v_care_plan.nurse_signature_artifact_storage_path, v_signature_artifact_storage_path),
      coalesce(v_care_plan.nurse_signature_artifact_member_file_id, v_signature_artifact_member_file_id),
      coalesce(v_care_plan.nurse_signature_metadata, v_signature_metadata, '{}'::jsonb),
      coalesce(v_care_plan.created_at, now()),
      coalesce(v_care_plan.updated_at, v_signed_at, now())
    )
    on conflict on constraint care_plan_nurse_signatures_pkey do update
    set
      signed_by_user_id = excluded.signed_by_user_id,
      signed_by_name = excluded.signed_by_name,
      signed_at = excluded.signed_at,
      status = 'signed',
      signature_artifact_storage_path = coalesce(excluded.signature_artifact_storage_path, public.care_plan_nurse_signatures.signature_artifact_storage_path),
      signature_artifact_member_file_id = coalesce(excluded.signature_artifact_member_file_id, public.care_plan_nurse_signatures.signature_artifact_member_file_id),
      signature_metadata = coalesce(excluded.signature_metadata, public.care_plan_nurse_signatures.signature_metadata),
      updated_at = excluded.updated_at
    returning * into v_signature;

    return query
    select
      v_signature.care_plan_id,
      v_signature.member_id,
      v_signature.signed_by_user_id,
      v_signature.signed_by_name,
      v_signature.signed_at,
      v_signature.status,
      v_signature.signature_artifact_storage_path,
      v_signature.signature_artifact_member_file_id,
      coalesce(v_signature.signature_metadata, '{}'::jsonb),
      v_next_caregiver_status,
      true;
    return;
  end if;

  v_completion_date := coalesce(v_care_plan.review_date, (v_signed_at at time zone 'America/New_York')::date);

  insert into public.care_plan_nurse_signatures (
    care_plan_id,
    member_id,
    signed_by_user_id,
    signed_by_name,
    signed_at,
    status,
    signature_artifact_storage_path,
    signature_artifact_member_file_id,
    signature_metadata,
    created_at,
    updated_at
  )
  values (
    p_care_plan_id,
    p_member_id,
    p_signed_by_user_id,
    v_signed_by_name,
    v_signed_at,
    'signed',
    v_signature_artifact_storage_path,
    v_signature_artifact_member_file_id,
    v_signature_metadata,
    v_signed_at,
    v_signed_at
  )
  on conflict on constraint care_plan_nurse_signatures_pkey do update
  set
    signed_by_user_id = excluded.signed_by_user_id,
    signed_by_name = excluded.signed_by_name,
    signed_at = excluded.signed_at,
    status = 'signed',
    signature_artifact_storage_path = coalesce(excluded.signature_artifact_storage_path, public.care_plan_nurse_signatures.signature_artifact_storage_path),
    signature_artifact_member_file_id = coalesce(excluded.signature_artifact_member_file_id, public.care_plan_nurse_signatures.signature_artifact_member_file_id),
    signature_metadata = coalesce(excluded.signature_metadata, public.care_plan_nurse_signatures.signature_metadata),
    updated_at = excluded.updated_at
  returning * into v_signature;

  update public.care_plans
  set
    nurse_signature_status = 'signed',
    nurse_signed_by_user_id = p_signed_by_user_id,
    nurse_signed_by_name = v_signed_by_name,
    nurse_signed_at = v_signed_at,
    nurse_signature_artifact_storage_path = v_signature_artifact_storage_path,
    nurse_signature_artifact_member_file_id = v_signature_artifact_member_file_id,
    nurse_signature_metadata = v_signature_metadata,
    completed_by = v_signed_by_name,
    date_of_completion = v_completion_date,
    administrator_signature = v_signed_by_name,
    administrator_signature_date = v_completion_date,
    nurse_designee_user_id = p_signed_by_user_id,
    nurse_designee_name = v_signed_by_name,
    legacy_cleanup_flag = false,
    caregiver_signature_status = v_next_caregiver_status,
    updated_at = v_signed_at
  where id = p_care_plan_id;

  return query
  select
    v_signature.care_plan_id,
    v_signature.member_id,
    v_signature.signed_by_user_id,
    v_signature.signed_by_name,
    v_signature.signed_at,
    v_signature.status,
    v_signature.signature_artifact_storage_path,
    v_signature.signature_artifact_member_file_id,
    coalesce(v_signature.signature_metadata, '{}'::jsonb),
    v_next_caregiver_status,
    false;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_care_plan_nurse_signature"("p_care_plan_id" "uuid", "p_member_id" "uuid", "p_signed_by_user_id" "uuid", "p_signed_by_name" "text", "p_signed_at" timestamp with time zone, "p_signature_artifact_storage_path" "text", "p_signature_artifact_member_file_id" "text", "p_signature_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_enrollment_packet_submission"("p_packet_id" "uuid", "p_rotated_token" "text", "p_consumed_submission_token_hash" "text", "p_completed_at" timestamp with time zone, "p_filed_at" timestamp with time zone, "p_signer_name" "text", "p_signer_email" "text", "p_signature_blob" "text", "p_ip_address" "text", "p_actor_user_id" "uuid", "p_actor_email" "text", "p_upload_batch_id" "uuid", "p_completed_metadata" "jsonb" DEFAULT '{}'::"jsonb", "p_filed_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("packet_id" "uuid", "status" "text", "mapping_sync_status" "text", "was_already_filed" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.enrollment_packet_requests%rowtype;
  v_consumed_submission_token_hash text := nullif(trim(coalesce(p_consumed_submission_token_hash, '')), '');
  v_completed_at timestamptz := coalesce(p_completed_at, now());
  v_updated_at timestamptz := coalesce(p_filed_at, p_completed_at, now());
begin
  if p_packet_id is null then
    raise exception 'packet id is required';
  end if;

  select *
  into v_request
  from public.enrollment_packet_requests
  where id = p_packet_id
  for update;

  if not found then
    raise exception 'Enrollment packet request % was not found.', p_packet_id;
  end if;

  if coalesce(v_request.status, '') = 'completed' then
    if v_consumed_submission_token_hash is not null
       and v_request.last_consumed_submission_token_hash = v_consumed_submission_token_hash then
      return query
      select
        v_request.id,
        v_request.status,
        v_request.mapping_sync_status,
        true;
      return;
    end if;
    raise exception 'Enrollment packet request % has already been finalized.', p_packet_id;
  end if;

  if coalesce(v_request.status, '') not in ('draft', 'sent', 'in_progress') then
    raise exception 'Enrollment packet request % cannot be finalized from status %.', p_packet_id, coalesce(v_request.status, 'null');
  end if;

  insert into public.enrollment_packet_signatures (
    packet_id,
    signer_name,
    signer_email,
    signer_role,
    signature_blob,
    ip_address,
    signed_at,
    created_at,
    updated_at
  )
  values (
    p_packet_id,
    p_signer_name,
    nullif(trim(coalesce(p_signer_email, '')), ''),
    'caregiver',
    p_signature_blob,
    nullif(trim(coalesce(p_ip_address, '')), ''),
    v_completed_at,
    v_completed_at,
    v_completed_at
  );

  update public.enrollment_packet_uploads as epu
  set
    finalization_status = 'finalized',
    finalized_at = v_updated_at
  where epu.packet_id = p_packet_id
    and epu.finalization_status = 'staged'
    and (
      p_upload_batch_id is null
      or epu.finalization_batch_id = p_upload_batch_id
    );

  update public.enrollment_packet_requests
  set
    status = 'completed',
    opened_at = coalesce(opened_at, v_completed_at),
    completed_at = v_completed_at,
    token = p_rotated_token,
    last_consumed_submission_token_hash = coalesce(v_consumed_submission_token_hash, last_consumed_submission_token_hash),
    mapping_sync_status = 'pending',
    mapping_sync_error = null,
    mapping_sync_attempted_at = null,
    completion_follow_up_status = 'pending',
    completion_follow_up_error = null,
    completion_follow_up_checked_at = null,
    last_family_activity_at = v_completed_at,
    updated_at = v_updated_at
  where id = p_packet_id;

  insert into public.enrollment_packet_events (
    packet_id,
    event_type,
    actor_user_id,
    actor_email,
    timestamp,
    metadata
  )
  values (
    p_packet_id,
    'completed',
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_email, '')), ''),
    v_completed_at,
    coalesce(p_completed_metadata, '{}'::jsonb) || coalesce(p_filed_metadata, '{}'::jsonb)
  );

  return query
  select
    p_packet_id,
    'completed',
    'pending',
    false;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_enrollment_packet_submission"("p_packet_id" "uuid", "p_rotated_token" "text", "p_consumed_submission_token_hash" "text", "p_completed_at" timestamp with time zone, "p_filed_at" timestamp with time zone, "p_signer_name" "text", "p_signer_email" "text", "p_signature_blob" "text", "p_ip_address" "text", "p_actor_user_id" "uuid", "p_actor_email" "text", "p_upload_batch_id" "uuid", "p_completed_metadata" "jsonb", "p_filed_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_intake_assessment_signature"("p_assessment_id" "uuid", "p_member_id" "uuid", "p_signed_by_user_id" "uuid", "p_signed_by_name" "text", "p_signed_at" timestamp with time zone, "p_signature_artifact_storage_path" "text" DEFAULT NULL::"text", "p_signature_artifact_member_file_id" "text" DEFAULT NULL::"text", "p_signature_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("assessment_id" "uuid", "member_id" "uuid", "signed_by_user_id" "uuid", "signed_by_name" "text", "signed_at" timestamp with time zone, "status" "text", "signature_artifact_storage_path" "text", "signature_artifact_member_file_id" "text", "signature_metadata" "jsonb", "was_already_signed" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_assessment public.intake_assessments%rowtype;
  v_signature public.intake_assessment_signatures%rowtype;
  v_signed_by_name text := nullif(trim(coalesce(p_signed_by_name, '')), '');
  v_signed_at timestamptz := coalesce(p_signed_at, now());
  v_signature_artifact_storage_path text := nullif(trim(coalesce(p_signature_artifact_storage_path, '')), '');
  v_signature_artifact_member_file_id text := nullif(trim(coalesce(p_signature_artifact_member_file_id, '')), '');
  v_signature_metadata jsonb := coalesce(p_signature_metadata, '{}'::jsonb);
begin
  if p_assessment_id is null then
    raise exception 'assessment id is required';
  end if;
  if p_member_id is null then
    raise exception 'member id is required';
  end if;
  if p_signed_by_user_id is null then
    raise exception 'signed by user id is required';
  end if;
  if v_signed_by_name is null then
    raise exception 'signed by name is required';
  end if;

  select *
  into v_assessment
  from public.intake_assessments ia
  where ia.id = p_assessment_id
  for update;

  if not found then
    raise exception 'Intake assessment % was not found.', p_assessment_id;
  end if;

  if v_assessment.member_id is distinct from p_member_id then
    raise exception 'Intake assessment % does not belong to member %.', p_assessment_id, p_member_id;
  end if;

  select *
  into v_signature
  from public.intake_assessment_signatures ias
  where ias.assessment_id = p_assessment_id
  for update;

  if found and coalesce(v_signature.status, '') = 'voided' then
    raise exception 'Intake assessment % signature has been voided.', p_assessment_id;
  end if;

  if coalesce(v_assessment.signature_status, '') = 'voided' then
    raise exception 'Intake assessment % cannot be signed because it is voided.', p_assessment_id;
  end if;

  if found and coalesce(v_signature.status, '') = 'signed' then
    update public.intake_assessments ia
    set
      signed_by = v_signature.signed_by_name,
      signed_by_user_id = v_signature.signed_by_user_id,
      signed_at = v_signature.signed_at,
      signature_status = 'signed',
      signature_metadata = coalesce(v_signature.signature_metadata, '{}'::jsonb),
      updated_at = coalesce(v_signature.signed_at, v_signed_at, now())
    where ia.id = p_assessment_id;

    return query
    select
      v_signature.assessment_id,
      v_signature.member_id,
      v_signature.signed_by_user_id,
      v_signature.signed_by_name,
      v_signature.signed_at,
      v_signature.status,
      v_signature.signature_artifact_storage_path,
      v_signature.signature_artifact_member_file_id,
      coalesce(v_signature.signature_metadata, '{}'::jsonb),
      true;
    return;
  end if;

  if coalesce(v_assessment.signature_status, '') = 'signed' then
    insert into public.intake_assessment_signatures (
      assessment_id,
      member_id,
      signed_by_user_id,
      signed_by_name,
      signed_at,
      status,
      signature_artifact_storage_path,
      signature_artifact_member_file_id,
      signature_metadata,
      created_at,
      updated_at
    )
    values (
      v_assessment.id,
      v_assessment.member_id,
      coalesce(v_assessment.signed_by_user_id, p_signed_by_user_id),
      coalesce(nullif(trim(coalesce(v_assessment.signed_by, '')), ''), v_signed_by_name),
      coalesce(v_assessment.signed_at, v_signed_at),
      'signed',
      v_signature_artifact_storage_path,
      v_signature_artifact_member_file_id,
      coalesce(v_assessment.signature_metadata, v_signature_metadata, '{}'::jsonb),
      coalesce(v_assessment.created_at, now()),
      coalesce(v_assessment.updated_at, v_signed_at, now())
    )
    on conflict on constraint intake_assessment_signatures_assessment_id_key do update
    set
      signed_by_user_id = excluded.signed_by_user_id,
      signed_by_name = excluded.signed_by_name,
      signed_at = excluded.signed_at,
      status = 'signed',
      signature_artifact_storage_path = coalesce(
        excluded.signature_artifact_storage_path,
        public.intake_assessment_signatures.signature_artifact_storage_path
      ),
      signature_artifact_member_file_id = coalesce(
        excluded.signature_artifact_member_file_id,
        public.intake_assessment_signatures.signature_artifact_member_file_id
      ),
      signature_metadata = coalesce(excluded.signature_metadata, public.intake_assessment_signatures.signature_metadata),
      updated_at = excluded.updated_at
    returning * into v_signature;

    return query
    select
      v_signature.assessment_id,
      v_signature.member_id,
      v_signature.signed_by_user_id,
      v_signature.signed_by_name,
      v_signature.signed_at,
      v_signature.status,
      v_signature.signature_artifact_storage_path,
      v_signature.signature_artifact_member_file_id,
      coalesce(v_signature.signature_metadata, '{}'::jsonb),
      true;
    return;
  end if;

  insert into public.intake_assessment_signatures (
    assessment_id,
    member_id,
    signed_by_user_id,
    signed_by_name,
    signed_at,
    status,
    signature_artifact_storage_path,
    signature_artifact_member_file_id,
    signature_metadata,
    created_at,
    updated_at
  )
  values (
    p_assessment_id,
    p_member_id,
    p_signed_by_user_id,
    v_signed_by_name,
    v_signed_at,
    'signed',
    v_signature_artifact_storage_path,
    v_signature_artifact_member_file_id,
    v_signature_metadata,
    v_signed_at,
    v_signed_at
  )
  on conflict on constraint intake_assessment_signatures_assessment_id_key do update
  set
    signed_by_user_id = excluded.signed_by_user_id,
    signed_by_name = excluded.signed_by_name,
    signed_at = excluded.signed_at,
    status = 'signed',
    signature_artifact_storage_path = coalesce(
      excluded.signature_artifact_storage_path,
      public.intake_assessment_signatures.signature_artifact_storage_path
    ),
    signature_artifact_member_file_id = coalesce(
      excluded.signature_artifact_member_file_id,
      public.intake_assessment_signatures.signature_artifact_member_file_id
    ),
    signature_metadata = coalesce(excluded.signature_metadata, public.intake_assessment_signatures.signature_metadata),
    updated_at = excluded.updated_at
  returning * into v_signature;

  update public.intake_assessments ia
  set
    signed_by = v_signed_by_name,
    signed_by_user_id = p_signed_by_user_id,
    signed_at = v_signed_at,
    signature_status = 'signed',
    signature_metadata = v_signature_metadata,
    updated_at = v_signed_at
  where ia.id = p_assessment_id;

  return query
  select
    v_signature.assessment_id,
    v_signature.member_id,
    v_signature.signed_by_user_id,
    v_signature.signed_by_name,
    v_signature.signed_at,
    v_signature.status,
    v_signature.signature_artifact_storage_path,
    v_signature.signature_artifact_member_file_id,
    coalesce(v_signature.signature_metadata, '{}'::jsonb),
    false;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_intake_assessment_signature"("p_assessment_id" "uuid", "p_member_id" "uuid", "p_signed_by_user_id" "uuid", "p_signed_by_name" "text", "p_signed_at" timestamp with time zone, "p_signature_artifact_storage_path" "text", "p_signature_artifact_member_file_id" "text", "p_signature_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_pof_post_sign_sync_queue"("p_queue_id" "uuid", "p_status" "text", "p_attempt_count" integer, "p_last_attempt_at" timestamp with time zone, "p_next_retry_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_last_error" "text" DEFAULT NULL::"text", "p_last_error_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_last_failed_step" "text" DEFAULT NULL::"text", "p_pof_request_id" "uuid" DEFAULT NULL::"uuid", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text") RETURNS TABLE("queue_id" "uuid", "status" "text", "attempt_count" integer, "next_retry_at" timestamp with time zone, "last_error" "text", "last_failed_step" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.pof_post_sign_sync_queue%rowtype;
  v_status text := lower(trim(coalesce(p_status, '')));
  v_last_failed_step text := nullif(trim(coalesce(p_last_failed_step, '')), '');
begin
  if p_queue_id is null then
    raise exception 'rpc_finalize_pof_post_sign_sync_queue requires p_queue_id';
  end if;
  if v_status not in ('queued', 'completed') then
    raise exception 'rpc_finalize_pof_post_sign_sync_queue requires queued or completed status';
  end if;
  if coalesce(p_attempt_count, -1) < 0 then
    raise exception 'rpc_finalize_pof_post_sign_sync_queue requires non-negative p_attempt_count';
  end if;
  if v_status = 'queued' and p_next_retry_at is null then
    raise exception 'rpc_finalize_pof_post_sign_sync_queue requires p_next_retry_at when queueing';
  end if;
  if v_status = 'queued' and v_last_failed_step is null then
    raise exception 'rpc_finalize_pof_post_sign_sync_queue requires p_last_failed_step when queueing';
  end if;

  select *
  into v_row
  from public.pof_post_sign_sync_queue
  where id = p_queue_id
  for update;

  if not found then
    raise exception 'POF post-sign sync queue row % was not found.', p_queue_id;
  end if;

  update public.pof_post_sign_sync_queue
  set
    status = v_status,
    attempt_count = p_attempt_count,
    last_attempt_at = p_last_attempt_at,
    next_retry_at = case when v_status = 'completed' then null else p_next_retry_at end,
    last_error = case when v_status = 'completed' then null else nullif(trim(coalesce(p_last_error, '')), '') end,
    last_error_at = case when v_status = 'completed' then null else p_last_error_at end,
    last_failed_step = case when v_status = 'completed' then null else v_last_failed_step end,
    pof_request_id = coalesce(p_pof_request_id, pof_request_id),
    claimed_at = null,
    claimed_by_user_id = null,
    claimed_by_name = null,
    queued_by_user_id = case when v_status = 'queued' then p_actor_user_id else queued_by_user_id end,
    queued_by_name = case when v_status = 'queued' then nullif(trim(coalesce(p_actor_name, '')), '') else queued_by_name end,
    resolved_at = case when v_status = 'completed' then p_last_attempt_at else null end,
    resolved_by_user_id = case when v_status = 'completed' then p_actor_user_id else null end,
    resolved_by_name = case when v_status = 'completed' then nullif(trim(coalesce(p_actor_name, '')), '') else null end
  where id = p_queue_id;

  return query
  select
    v_row.id,
    v_status,
    p_attempt_count,
    case when v_status = 'completed' then null else p_next_retry_at end,
    case when v_status = 'completed' then null else nullif(trim(coalesce(p_last_error, '')), '') end,
    case when v_status = 'completed' then null else v_last_failed_step end;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_pof_post_sign_sync_queue"("p_queue_id" "uuid", "p_status" "text", "p_attempt_count" integer, "p_last_attempt_at" timestamp with time zone, "p_next_retry_at" timestamp with time zone, "p_last_error" "text", "p_last_error_at" timestamp with time zone, "p_last_failed_step" "text", "p_pof_request_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_pof_signature"("p_request_id" "uuid", "p_provider_typed_name" "text", "p_provider_signature_image_url" "text", "p_provider_ip" "text" DEFAULT NULL::"text", "p_provider_user_agent" "text" DEFAULT NULL::"text", "p_signed_pdf_url" "text" DEFAULT NULL::"text", "p_member_file_id" "text" DEFAULT NULL::"text", "p_member_file_name" "text" DEFAULT NULL::"text", "p_member_file_data_url" "text" DEFAULT NULL::"text", "p_member_file_storage_object_path" "text" DEFAULT NULL::"text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_signed_at" timestamp with time zone DEFAULT "now"(), "p_opened_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_signature_request_token" "text" DEFAULT NULL::"text", "p_signature_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("request_id" "uuid", "physician_order_id" "uuid", "member_id" "uuid", "member_file_id" "text", "queue_id" "uuid", "queue_attempt_count" integer, "queue_next_retry_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.pof_requests%rowtype;
  v_actor_user_id uuid;
  v_actor_name text;
  v_member_file_id text;
  v_signature_metadata jsonb := coalesce(p_signature_metadata, '{}'::jsonb);
  v_signed_at timestamptz := coalesce(p_signed_at, now());
  v_sign record;
begin
  if p_request_id is null then
    raise exception 'POF request id is required.';
  end if;
  if nullif(trim(coalesce(p_provider_typed_name, '')), '') is null then
    raise exception 'Typed provider name is required.';
  end if;
  if nullif(trim(coalesce(p_provider_signature_image_url, '')), '') is null then
    raise exception 'Provider signature image URL is required.';
  end if;
  if nullif(trim(coalesce(p_member_file_name, '')), '') is null then
    raise exception 'Member file name is required.';
  end if;
  if nullif(trim(coalesce(p_member_file_data_url, '')), '') is null then
    raise exception 'Member file payload is required.';
  end if;
  if nullif(trim(coalesce(p_signed_pdf_url, '')), '') is null then
    raise exception 'Signed PDF storage URL is required.';
  end if;

  select *
  into v_request
  from public.pof_requests pr
  where pr.id = p_request_id
  for update;

  if not found then
    raise exception 'POF signature request was not found.';
  end if;
  if v_request.status = 'signed' then
    raise exception 'This signature link has already been used.';
  end if;
  if v_request.status = 'declined' then
    raise exception 'This signature request was voided.';
  end if;
  if v_request.status = 'expired' or v_request.expires_at < v_signed_at then
    raise exception 'This signature link has expired.';
  end if;

  v_actor_user_id := coalesce(p_actor_user_id, v_request.sent_by_user_id);
  v_actor_name := coalesce(nullif(trim(coalesce(p_actor_name, '')), ''), v_request.nurse_name);

  select mf.id
  into v_member_file_id
  from public.member_files mf
  where mf.pof_request_id = p_request_id
  for update;

  if v_member_file_id is null then
    v_member_file_id := coalesce(
      nullif(trim(coalesce(p_member_file_id, '')), ''),
      'mf_' || replace(gen_random_uuid()::text, '-', '')
    );
    insert into public.member_files (
      id,
      member_id,
      file_name,
      file_type,
      file_data_url,
      category,
      category_other,
      document_source,
      pof_request_id,
      storage_object_path,
      uploaded_by_user_id,
      uploaded_by_name,
      uploaded_at,
      updated_at
    )
    values (
      v_member_file_id,
      v_request.member_id,
      p_member_file_name,
      'application/pdf',
      p_member_file_data_url,
      'Orders / POF',
      null,
      'POF E-Sign Signed',
      p_request_id,
      p_member_file_storage_object_path,
      v_actor_user_id,
      v_actor_name,
      v_signed_at,
      v_signed_at
    );
  else
    update public.member_files mf
    set
      file_name = p_member_file_name,
      file_type = 'application/pdf',
      file_data_url = p_member_file_data_url,
      category = 'Orders / POF',
      category_other = null,
      document_source = 'POF E-Sign Signed',
      pof_request_id = p_request_id,
      storage_object_path = p_member_file_storage_object_path,
      uploaded_by_user_id = v_actor_user_id,
      uploaded_by_name = v_actor_name,
      uploaded_at = v_signed_at,
      updated_at = v_signed_at
    where mf.id = v_member_file_id;
  end if;

  insert into public.pof_signatures (
    pof_request_id,
    provider_typed_name,
    provider_signature_image_url,
    provider_ip,
    provider_user_agent,
    signed_at,
    created_at,
    updated_at
  )
  values (
    p_request_id,
    p_provider_typed_name,
    p_provider_signature_image_url,
    nullif(trim(coalesce(p_provider_ip, '')), ''),
    nullif(trim(coalesce(p_provider_user_agent, '')), ''),
    v_signed_at,
    v_signed_at,
    v_signed_at
  )
  on conflict (pof_request_id)
  do update
  set
    provider_typed_name = excluded.provider_typed_name,
    provider_signature_image_url = excluded.provider_signature_image_url,
    provider_ip = excluded.provider_ip,
    provider_user_agent = excluded.provider_user_agent,
    signed_at = excluded.signed_at,
    updated_at = excluded.updated_at;

  update public.physician_orders po
  set
    provider_name = p_provider_typed_name,
    provider_signature = p_provider_typed_name,
    provider_signature_date = (v_signed_at at time zone 'America/New_York')::date,
    signature_metadata = v_signature_metadata,
    updated_by_user_id = v_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = v_signed_at
  where po.id = v_request.physician_order_id;

  select *
  into v_sign
  from public.rpc_sign_physician_order(
    p_pof_id => v_request.physician_order_id,
    p_actor_user_id => v_actor_user_id,
    p_actor_name => v_actor_name,
    p_signed_at => v_signed_at,
    p_pof_request_id => p_request_id
  );

  update public.pof_requests pr
  set
    status = 'signed',
    opened_at = coalesce(pr.opened_at, p_opened_at, v_signed_at),
    signed_at = v_signed_at,
    signed_pdf_url = p_signed_pdf_url,
    member_file_id = v_member_file_id,
    signature_request_token = coalesce(nullif(trim(coalesce(p_signature_request_token, '')), ''), pr.signature_request_token),
    updated_by_user_id = v_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = v_signed_at
  where pr.id = p_request_id;

  insert into public.document_events (
    document_type,
    document_id,
    member_id,
    physician_order_id,
    event_type,
    actor_type,
    actor_user_id,
    actor_name,
    actor_email,
    actor_ip,
    actor_user_agent,
    metadata,
    created_at
  )
  values (
    'pof_request',
    p_request_id,
    v_request.member_id,
    v_request.physician_order_id,
    'signed',
    'provider',
    null,
    p_provider_typed_name,
    v_request.provider_email,
    nullif(trim(coalesce(p_provider_ip, '')), ''),
    nullif(trim(coalesce(p_provider_user_agent, '')), ''),
    jsonb_build_object(
      'postSignStatus', 'queued',
      'postSignQueueId', v_sign.queue_id,
      'postSignAttemptCount', coalesce(v_sign.queue_attempt_count, 0),
      'postSignNextRetryAt', v_sign.queue_next_retry_at,
      'postSignLastError', null
    ),
    v_signed_at
  );

  return query
  select
    p_request_id,
    v_request.physician_order_id,
    v_request.member_id,
    v_member_file_id,
    v_sign.queue_id,
    coalesce(v_sign.queue_attempt_count, 0),
    v_sign.queue_next_retry_at;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_pof_signature"("p_request_id" "uuid", "p_provider_typed_name" "text", "p_provider_signature_image_url" "text", "p_provider_ip" "text", "p_provider_user_agent" "text", "p_signed_pdf_url" "text", "p_member_file_id" "text", "p_member_file_name" "text", "p_member_file_data_url" "text", "p_member_file_storage_object_path" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_signed_at" timestamp with time zone, "p_opened_at" timestamp with time zone, "p_signature_request_token" "text", "p_signature_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_finalize_pof_signature"("p_request_id" "uuid", "p_provider_typed_name" "text", "p_provider_signature_image_url" "text", "p_provider_ip" "text" DEFAULT NULL::"text", "p_provider_user_agent" "text" DEFAULT NULL::"text", "p_signed_pdf_url" "text" DEFAULT NULL::"text", "p_member_file_id" "text" DEFAULT NULL::"text", "p_member_file_name" "text" DEFAULT NULL::"text", "p_member_file_data_url" "text" DEFAULT NULL::"text", "p_member_file_storage_object_path" "text" DEFAULT NULL::"text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_signed_at" timestamp with time zone DEFAULT "now"(), "p_opened_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_signature_request_token" "text" DEFAULT NULL::"text", "p_signature_metadata" "jsonb" DEFAULT '{}'::"jsonb", "p_consumed_signature_token_hash" "text" DEFAULT NULL::"text") RETURNS TABLE("request_id" "uuid", "physician_order_id" "uuid", "member_id" "uuid", "member_file_id" "text", "queue_id" "uuid", "queue_attempt_count" integer, "queue_next_retry_at" timestamp with time zone, "was_already_signed" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.pof_requests%rowtype;
  v_actor_user_id uuid;
  v_actor_name text;
  v_member_file_id text;
  v_signature_metadata jsonb := coalesce(p_signature_metadata, '{}'::jsonb);
  v_signed_at timestamptz := coalesce(p_signed_at, now());
  v_sign record;
  v_queue public.pof_post_sign_sync_queue%rowtype;
  v_consumed_signature_token_hash text := nullif(trim(coalesce(p_consumed_signature_token_hash, '')), '');
begin
  if p_request_id is null then
    raise exception 'POF request id is required.';
  end if;
  if nullif(trim(coalesce(p_provider_typed_name, '')), '') is null then
    raise exception 'Typed provider name is required.';
  end if;
  if nullif(trim(coalesce(p_provider_signature_image_url, '')), '') is null then
    raise exception 'Provider signature image URL is required.';
  end if;
  if nullif(trim(coalesce(p_member_file_name, '')), '') is null then
    raise exception 'Member file name is required.';
  end if;
  if nullif(trim(coalesce(p_member_file_data_url, '')), '') is null then
    raise exception 'Member file payload is required.';
  end if;
  if nullif(trim(coalesce(p_signed_pdf_url, '')), '') is null then
    raise exception 'Signed PDF storage URL is required.';
  end if;

  select *
  into v_request
  from public.pof_requests pr
  where pr.id = p_request_id
  for update;

  if not found then
    raise exception 'POF signature request was not found.';
  end if;
  if v_request.status = 'signed' then
    if v_consumed_signature_token_hash is not null
       and v_request.last_consumed_signature_token_hash = v_consumed_signature_token_hash then
      select q.*
      into v_queue
      from public.pof_post_sign_sync_queue q
      where q.physician_order_id = v_request.physician_order_id
      for update;

      return query
      select
        v_request.id,
        v_request.physician_order_id,
        v_request.member_id,
        v_request.member_file_id,
        v_queue.id,
        coalesce(v_queue.attempt_count, 0),
        v_queue.next_retry_at,
        true;
      return;
    end if;
    raise exception 'This signature link has already been used.';
  end if;
  if v_request.status = 'declined' then
    raise exception 'This signature request was voided.';
  end if;
  if v_request.status = 'expired' or v_request.expires_at < v_signed_at then
    raise exception 'This signature link has expired.';
  end if;

  v_actor_user_id := coalesce(p_actor_user_id, v_request.sent_by_user_id);
  v_actor_name := coalesce(nullif(trim(coalesce(p_actor_name, '')), ''), v_request.nurse_name);

  select mf.id
  into v_member_file_id
  from public.member_files mf
  where mf.pof_request_id = p_request_id
  for update;

  if v_member_file_id is null then
    v_member_file_id := coalesce(
      nullif(trim(coalesce(p_member_file_id, '')), ''),
      'mf_' || replace(gen_random_uuid()::text, '-', '')
    );
    insert into public.member_files (
      id,
      member_id,
      file_name,
      file_type,
      file_data_url,
      category,
      category_other,
      document_source,
      pof_request_id,
      storage_object_path,
      uploaded_by_user_id,
      uploaded_by_name,
      uploaded_at,
      updated_at
    )
    values (
      v_member_file_id,
      v_request.member_id,
      p_member_file_name,
      'application/pdf',
      p_member_file_data_url,
      'Orders / POF',
      null,
      'POF E-Sign Signed',
      p_request_id,
      p_member_file_storage_object_path,
      v_actor_user_id,
      v_actor_name,
      v_signed_at,
      v_signed_at
    );
  else
    update public.member_files mf
    set
      file_name = p_member_file_name,
      file_type = 'application/pdf',
      file_data_url = p_member_file_data_url,
      category = 'Orders / POF',
      category_other = null,
      document_source = 'POF E-Sign Signed',
      pof_request_id = p_request_id,
      storage_object_path = p_member_file_storage_object_path,
      uploaded_by_user_id = v_actor_user_id,
      uploaded_by_name = v_actor_name,
      uploaded_at = v_signed_at,
      updated_at = v_signed_at
    where mf.id = v_member_file_id;
  end if;

  insert into public.pof_signatures (
    pof_request_id,
    provider_typed_name,
    provider_signature_image_url,
    provider_ip,
    provider_user_agent,
    signed_at,
    created_at,
    updated_at
  )
  values (
    p_request_id,
    p_provider_typed_name,
    p_provider_signature_image_url,
    nullif(trim(coalesce(p_provider_ip, '')), ''),
    nullif(trim(coalesce(p_provider_user_agent, '')), ''),
    v_signed_at,
    v_signed_at,
    v_signed_at
  )
  on conflict (pof_request_id)
  do update
  set
    provider_typed_name = excluded.provider_typed_name,
    provider_signature_image_url = excluded.provider_signature_image_url,
    provider_ip = excluded.provider_ip,
    provider_user_agent = excluded.provider_user_agent,
    signed_at = excluded.signed_at,
    updated_at = excluded.updated_at;

  update public.physician_orders po
  set
    provider_name = p_provider_typed_name,
    provider_signature = p_provider_typed_name,
    provider_signature_date = (v_signed_at at time zone 'America/New_York')::date,
    signature_metadata = v_signature_metadata,
    updated_by_user_id = v_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = v_signed_at
  where po.id = v_request.physician_order_id;

  select *
  into v_sign
  from public.rpc_sign_physician_order(
    p_pof_id => v_request.physician_order_id,
    p_actor_user_id => v_actor_user_id,
    p_actor_name => v_actor_name,
    p_signed_at => v_signed_at,
    p_pof_request_id => p_request_id
  );

  update public.pof_requests pr
  set
    status = 'signed',
    opened_at = coalesce(pr.opened_at, p_opened_at, v_signed_at),
    signed_at = v_signed_at,
    signed_pdf_url = p_signed_pdf_url,
    member_file_id = v_member_file_id,
    signature_request_token = coalesce(nullif(trim(coalesce(p_signature_request_token, '')), ''), pr.signature_request_token),
    last_consumed_signature_token_hash = coalesce(v_consumed_signature_token_hash, pr.last_consumed_signature_token_hash),
    updated_by_user_id = v_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = v_signed_at
  where pr.id = p_request_id;

  insert into public.document_events (
    document_type,
    document_id,
    member_id,
    physician_order_id,
    event_type,
    actor_type,
    actor_user_id,
    actor_name,
    actor_email,
    actor_ip,
    actor_user_agent,
    metadata,
    created_at
  )
  values (
    'pof_request',
    p_request_id,
    v_request.member_id,
    v_request.physician_order_id,
    'signed',
    'provider',
    null,
    p_provider_typed_name,
    v_request.provider_email,
    nullif(trim(coalesce(p_provider_ip, '')), ''),
    nullif(trim(coalesce(p_provider_user_agent, '')), ''),
    jsonb_strip_nulls(
      jsonb_build_object(
        'memberFileId', v_member_file_id,
        'queueId', v_sign.queue_id,
        'providerSignatureImageUrl', p_provider_signature_image_url
      )
    ) || v_signature_metadata,
    v_signed_at
  );

  return query
  select
    p_request_id,
    v_request.physician_order_id,
    v_request.member_id,
    v_member_file_id,
    v_sign.queue_id,
    v_sign.queue_attempt_count,
    v_sign.queue_next_retry_at,
    false;
end;
$$;


ALTER FUNCTION "public"."rpc_finalize_pof_signature"("p_request_id" "uuid", "p_provider_typed_name" "text", "p_provider_signature_image_url" "text", "p_provider_ip" "text", "p_provider_user_agent" "text", "p_signed_pdf_url" "text", "p_member_file_id" "text", "p_member_file_name" "text", "p_member_file_data_url" "text", "p_member_file_storage_object_path" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_signed_at" timestamp with time zone, "p_opened_at" timestamp with time zone, "p_signature_request_token" "text", "p_signature_metadata" "jsonb", "p_consumed_signature_token_hash" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_generate_billing_batch"("p_batch" "jsonb", "p_invoices" "jsonb" DEFAULT '[]'::"jsonb", "p_invoice_lines" "jsonb" DEFAULT '[]'::"jsonb", "p_coverages" "jsonb" DEFAULT '[]'::"jsonb", "p_source_updates" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_batch_id uuid;
  v_source_update jsonb;
begin
  v_batch_id := nullif(p_batch ->> 'id', '')::uuid;
  if v_batch_id is null then
    raise exception 'billing batch id is required';
  end if;

  insert into public.billing_batches (
    id,
    batch_type,
    billing_month,
    run_date,
    batch_status,
    invoice_count,
    total_amount,
    completion_date,
    next_due_date,
    generated_by_user_id,
    generated_by_name,
    created_at,
    updated_at
  )
  values (
    v_batch_id,
    nullif(p_batch ->> 'batch_type', ''),
    nullif(p_batch ->> 'billing_month', '')::date,
    nullif(p_batch ->> 'run_date', '')::date,
    coalesce(nullif(p_batch ->> 'batch_status', ''), 'Draft'),
    coalesce(nullif(p_batch ->> 'invoice_count', '')::integer, 0),
    coalesce(nullif(p_batch ->> 'total_amount', '')::numeric, 0),
    nullif(p_batch ->> 'completion_date', '')::date,
    nullif(p_batch ->> 'next_due_date', '')::date,
    nullif(p_batch ->> 'generated_by_user_id', '')::uuid,
    nullif(p_batch ->> 'generated_by_name', ''),
    coalesce(nullif(p_batch ->> 'created_at', '')::timestamptz, now()),
    coalesce(nullif(p_batch ->> 'updated_at', '')::timestamptz, now())
  );

  insert into public.billing_invoices (
    id,
    billing_batch_id,
    member_id,
    payor_id,
    invoice_number,
    invoice_month,
    invoice_source,
    invoice_status,
    export_status,
    billing_mode_snapshot,
    monthly_billing_basis_snapshot,
    transportation_billing_status_snapshot,
    billing_method_snapshot,
    base_period_start,
    base_period_end,
    variable_charge_period_start,
    variable_charge_period_end,
    invoice_date,
    due_date,
    base_program_billed_days,
    member_daily_rate_snapshot,
    base_program_amount,
    transportation_amount,
    ancillary_amount,
    adjustment_amount,
    total_amount,
    payments_amount,
    balance_due_amount,
    bill_to_name_snapshot,
    bill_to_address_line_1_snapshot,
    bill_to_address_line_2_snapshot,
    bill_to_address_line_3_snapshot,
    bill_to_email_snapshot,
    bill_to_phone_snapshot,
    bill_to_message_snapshot,
    notes,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_at
  )
  select
    nullif(value ->> 'id', '')::uuid,
    v_batch_id,
    nullif(value ->> 'member_id', '')::uuid,
    nullif(value ->> 'payor_id', ''),
    nullif(value ->> 'invoice_number', ''),
    nullif(value ->> 'invoice_month', '')::date,
    coalesce(nullif(value ->> 'invoice_source', ''), 'BatchGenerated'),
    coalesce(nullif(value ->> 'invoice_status', ''), 'Draft'),
    coalesce(nullif(value ->> 'export_status', ''), 'NotExported'),
    nullif(value ->> 'billing_mode_snapshot', ''),
    nullif(value ->> 'monthly_billing_basis_snapshot', ''),
    nullif(value ->> 'transportation_billing_status_snapshot', ''),
    nullif(value ->> 'billing_method_snapshot', ''),
    nullif(value ->> 'base_period_start', '')::date,
    nullif(value ->> 'base_period_end', '')::date,
    nullif(value ->> 'variable_charge_period_start', '')::date,
    nullif(value ->> 'variable_charge_period_end', '')::date,
    nullif(value ->> 'invoice_date', '')::date,
    nullif(value ->> 'due_date', '')::date,
    coalesce(nullif(value ->> 'base_program_billed_days', '')::numeric, 0),
    coalesce(nullif(value ->> 'member_daily_rate_snapshot', '')::numeric, 0),
    coalesce(nullif(value ->> 'base_program_amount', '')::numeric, 0),
    coalesce(nullif(value ->> 'transportation_amount', '')::numeric, 0),
    coalesce(nullif(value ->> 'ancillary_amount', '')::numeric, 0),
    coalesce(nullif(value ->> 'adjustment_amount', '')::numeric, 0),
    coalesce(nullif(value ->> 'total_amount', '')::numeric, 0),
    coalesce(nullif(value ->> 'payments_amount', '')::numeric, 0),
    coalesce(nullif(value ->> 'balance_due_amount', '')::numeric, coalesce(nullif(value ->> 'total_amount', '')::numeric, 0)),
    nullif(value ->> 'bill_to_name_snapshot', ''),
    nullif(value ->> 'bill_to_address_line_1_snapshot', ''),
    nullif(value ->> 'bill_to_address_line_2_snapshot', ''),
    nullif(value ->> 'bill_to_address_line_3_snapshot', ''),
    nullif(value ->> 'bill_to_email_snapshot', ''),
    nullif(value ->> 'bill_to_phone_snapshot', ''),
    nullif(value ->> 'bill_to_message_snapshot', ''),
    nullif(value ->> 'notes', ''),
    nullif(value ->> 'created_by_user_id', '')::uuid,
    nullif(value ->> 'created_by_name', ''),
    coalesce(nullif(value ->> 'created_at', '')::timestamptz, now()),
    coalesce(nullif(value ->> 'updated_at', '')::timestamptz, now())
  from jsonb_array_elements(coalesce(p_invoices, '[]'::jsonb)) value;

  insert into public.billing_invoice_lines (
    id,
    invoice_id,
    member_id,
    payor_id,
    line_number,
    product_or_service,
    service_date,
    service_period_start,
    service_period_end,
    line_type,
    description,
    quantity,
    unit_rate,
    amount,
    source_table,
    source_record_id,
    billing_status,
    created_at,
    updated_at
  )
  select
    nullif(value ->> 'id', '')::uuid,
    nullif(value ->> 'invoice_id', '')::uuid,
    nullif(value ->> 'member_id', '')::uuid,
    nullif(value ->> 'payor_id', ''),
    coalesce(nullif(value ->> 'line_number', '')::integer, 1),
    coalesce(nullif(value ->> 'product_or_service', ''), 'Member Fees'),
    nullif(value ->> 'service_date', '')::date,
    nullif(value ->> 'service_period_start', '')::date,
    nullif(value ->> 'service_period_end', '')::date,
    nullif(value ->> 'line_type', ''),
    nullif(value ->> 'description', ''),
    coalesce(nullif(value ->> 'quantity', '')::numeric, 0),
    coalesce(nullif(value ->> 'unit_rate', '')::numeric, 0),
    coalesce(nullif(value ->> 'amount', '')::numeric, 0),
    nullif(value ->> 'source_table', ''),
    nullif(value ->> 'source_record_id', ''),
    coalesce(nullif(value ->> 'billing_status', ''), 'Billed'),
    coalesce(nullif(value ->> 'created_at', '')::timestamptz, now()),
    coalesce(nullif(value ->> 'updated_at', '')::timestamptz, now())
  from jsonb_array_elements(coalesce(p_invoice_lines, '[]'::jsonb)) value;

  for v_source_update in
    select value
    from jsonb_array_elements(coalesce(p_source_updates, '[]'::jsonb)) value
  loop
    if v_source_update ->> 'source_table' = 'transportation_logs' then
      update public.transportation_logs
      set
        billing_status = 'Billed',
        billing_exclusion_reason = null,
        invoice_id = nullif(v_source_update ->> 'invoice_id', '')::uuid,
        updated_at = coalesce(nullif(v_source_update ->> 'updated_at', '')::timestamptz, now())
      where id = nullif(v_source_update ->> 'source_record_id', '')::uuid;
      if not found then
        raise exception 'transportation log % was not found during billing batch generation', v_source_update ->> 'source_record_id';
      end if;
    elsif v_source_update ->> 'source_table' = 'ancillary_charge_logs' then
      update public.ancillary_charge_logs
      set
        billing_status = 'Billed',
        billing_exclusion_reason = null,
        invoice_id = nullif(v_source_update ->> 'invoice_id', '')::uuid,
        updated_at = coalesce(nullif(v_source_update ->> 'updated_at', '')::timestamptz, now())
      where id = nullif(v_source_update ->> 'source_record_id', '')::uuid;
      if not found then
        raise exception 'ancillary charge log % was not found during billing batch generation', v_source_update ->> 'source_record_id';
      end if;
    elsif v_source_update ->> 'source_table' = 'billing_adjustments' then
      update public.billing_adjustments
      set
        billing_status = 'Billed',
        exclusion_reason = null,
        invoice_id = nullif(v_source_update ->> 'invoice_id', '')::uuid,
        updated_at = coalesce(nullif(v_source_update ->> 'updated_at', '')::timestamptz, now())
      where id = nullif(v_source_update ->> 'source_record_id', '')::uuid;
      if not found then
        raise exception 'billing adjustment % was not found during billing batch generation', v_source_update ->> 'source_record_id';
      end if;
    else
      raise exception 'unsupported billing source table %', coalesce(v_source_update ->> 'source_table', 'null');
    end if;
  end loop;

  insert into public.billing_coverages (
    member_id,
    coverage_type,
    coverage_start_date,
    coverage_end_date,
    source_invoice_id,
    source_invoice_line_id,
    source_table,
    source_record_id,
    created_at
  )
  select
    nullif(value ->> 'member_id', '')::uuid,
    nullif(value ->> 'coverage_type', ''),
    nullif(value ->> 'coverage_start_date', '')::date,
    nullif(value ->> 'coverage_end_date', '')::date,
    nullif(value ->> 'source_invoice_id', '')::uuid,
    nullif(value ->> 'source_invoice_line_id', '')::uuid,
    nullif(value ->> 'source_table', ''),
    nullif(value ->> 'source_record_id', ''),
    coalesce(nullif(value ->> 'created_at', '')::timestamptz, now())
  from jsonb_array_elements(coalesce(p_coverages, '[]'::jsonb)) value;

  return v_batch_id;
end;
$$;


ALTER FUNCTION "public"."rpc_generate_billing_batch"("p_batch" "jsonb", "p_invoices" "jsonb", "p_invoice_lines" "jsonb", "p_coverages" "jsonb", "p_source_updates" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_care_plan_list"("p_member_id" "uuid" DEFAULT NULL::"uuid", "p_track" "text" DEFAULT NULL::"text", "p_query_member_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_status_filter" "text" DEFAULT 'All'::"text", "p_page" integer DEFAULT 1, "p_page_size" integer DEFAULT 25, "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("total_count" bigint, "due_soon_count" bigint, "due_now_count" bigint, "overdue_count" bigint, "completed_recently_count" bigint, "total_rows" bigint, "page_rows" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with bounds as (
    select
      p_today as today,
      (p_today + 14) as due_soon_end
  ),
  base as (
    select
      cp.id,
      cp.member_id,
      cp.track,
      cp.enrollment_date,
      cp.review_date,
      cp.last_completed_date,
      cp.next_due_date,
      cp.status,
      cp.completed_by,
      cp.post_sign_readiness_status,
      cp.post_sign_readiness_reason,
      m.display_name as member_name
    from public.care_plans cp
    join public.members m on m.id = cp.member_id
    cross join bounds b
    where (p_member_id is null or cp.member_id = p_member_id)
      and (nullif(trim(coalesce(p_track, '')), '') is null or cp.track = trim(p_track))
      and (
        p_query_member_ids is null
        or cardinality(p_query_member_ids) = 0
        or cp.member_id = any(p_query_member_ids)
      )
  ),
  summary as (
    select
      count(*)::bigint as total_count,
      count(*) filter (where base.next_due_date > b.today and base.next_due_date <= b.due_soon_end)::bigint as due_soon_count,
      count(*) filter (where base.next_due_date = b.today)::bigint as due_now_count,
      count(*) filter (where base.next_due_date < b.today)::bigint as overdue_count,
      count(*) filter (where base.next_due_date > b.due_soon_end)::bigint as completed_recently_count
    from base
    cross join bounds b
  ),
  filtered as (
    select *
    from base
    cross join bounds b
    where case
      when p_status_filter = 'Overdue' then base.next_due_date < b.today
      when p_status_filter = 'Due Now' then base.next_due_date = b.today
      when p_status_filter = 'Due Soon' then base.next_due_date > b.today and base.next_due_date <= b.due_soon_end
      when p_status_filter = 'Completed' then base.next_due_date > b.due_soon_end
      else true
    end
  ),
  total_rows as (
    select count(*)::bigint as total_rows
    from filtered
  ),
  paged as (
    select
      id,
      member_id,
      track,
      enrollment_date,
      review_date,
      last_completed_date,
      next_due_date,
      status,
      completed_by,
      post_sign_readiness_status,
      post_sign_readiness_reason,
      member_name
    from filtered
    order by next_due_date asc, id asc
    offset (greatest(coalesce(p_page, 1), 1) - 1) * greatest(coalesce(p_page_size, 25), 1)
    limit greatest(coalesce(p_page_size, 25), 1)
  ),
  row_payload as (
    select coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', paged.id,
          'member_id', paged.member_id,
          'member_name', paged.member_name,
          'track', paged.track,
          'enrollment_date', paged.enrollment_date,
          'review_date', paged.review_date,
          'last_completed_date', paged.last_completed_date,
          'next_due_date', paged.next_due_date,
          'status', paged.status,
          'completed_by', paged.completed_by,
          'post_sign_readiness_status', paged.post_sign_readiness_status,
          'post_sign_readiness_reason', paged.post_sign_readiness_reason
        )
        order by paged.next_due_date asc, paged.id asc
      ),
      '[]'::jsonb
    ) as page_rows
    from paged
  )
  select
    summary.total_count,
    summary.due_soon_count,
    summary.due_now_count,
    summary.overdue_count,
    summary.completed_recently_count,
    total_rows.total_rows,
    row_payload.page_rows
  from summary
  cross join total_rows
  cross join row_payload;
$$;


ALTER FUNCTION "public"."rpc_get_care_plan_list"("p_member_id" "uuid", "p_track" "text", "p_query_member_ids" "uuid"[], "p_status_filter" "text", "p_page" integer, "p_page_size" integer, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_care_plan_participation_summary"("p_member_id" "uuid", "p_window_start_date" "date", "p_window_end_date" "date") RETURNS TABLE("attendance_days" bigint, "participation_days" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with attendance_count as (
    select count(*)::bigint as attendance_days
    from public.attendance_records ar
    where ar.member_id = p_member_id
      and ar.attendance_date >= p_window_start_date
      and ar.attendance_date <= p_window_end_date
  ),
  participation_count as (
    select count(distinct dal.activity_date)::bigint as participation_days
    from public.daily_activity_logs dal
    where dal.member_id = p_member_id
      and dal.activity_date >= p_window_start_date
      and dal.activity_date <= p_window_end_date
  )
  select
    attendance_count.attendance_days,
    participation_count.participation_days
  from attendance_count, participation_count;
$$;


ALTER FUNCTION "public"."rpc_get_care_plan_participation_summary"("p_member_id" "uuid", "p_window_start_date" "date", "p_window_end_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_documentation_workflows"("p_staff_user_id" "uuid" DEFAULT NULL::"uuid", "p_staff_only" boolean DEFAULT false, "p_limit" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "source_kind" "text", "occurred_at" timestamp with time zone, "member_name" "text", "staff_name" "text", "payload" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
with bounds as (
  select greatest(coalesce(p_limit, 50), 0) as row_limit
),
daily_rows as (
  select
    dal.id,
    'daily_activity'::text as source_kind,
    coalesce(dal.created_at, timezone('America/New_York', dal.activity_date::timestamp)) as occurred_at,
    nullif(trim(m.display_name), '') as member_name,
    nullif(trim(p.full_name), '') as staff_name,
    jsonb_build_object(
      'activity_date', dal.activity_date::text,
      'created_at', coalesce(dal.created_at, timezone('America/New_York', dal.activity_date::timestamp))::text,
      'activity_1_level', dal.activity_1_level,
      'activity_2_level', dal.activity_2_level,
      'activity_3_level', dal.activity_3_level,
      'activity_4_level', dal.activity_4_level,
      'activity_5_level', dal.activity_5_level,
      'missing_reason_1', dal.missing_reason_1,
      'missing_reason_2', dal.missing_reason_2,
      'missing_reason_3', dal.missing_reason_3,
      'missing_reason_4', dal.missing_reason_4,
      'missing_reason_5', dal.missing_reason_5,
      'notes', dal.notes
    ) as payload
  from public.daily_activity_logs dal
  left join public.members m on m.id = dal.member_id
  left join public.profiles p on p.id = dal.staff_user_id
  cross join bounds b
  where not p_staff_only
    or dal.staff_user_id = p_staff_user_id
  order by coalesce(dal.created_at, timezone('America/New_York', dal.activity_date::timestamp)) desc
  limit (select row_limit from bounds)
),
toilet_rows as (
  select
    tl.id,
    'toilet_log'::text as source_kind,
    coalesce(tl.event_at, timezone('America/New_York', now()::timestamp)) as occurred_at,
    nullif(trim(m.display_name), '') as member_name,
    nullif(trim(p.full_name), '') as staff_name,
    jsonb_build_object(
      'event_at', coalesce(tl.event_at, timezone('America/New_York', now()::timestamp))::text,
      'use_type', tl.use_type,
      'briefs', tl.briefs,
      'member_supplied', tl.member_supplied,
      'notes', tl.notes
    ) as payload
  from public.toilet_logs tl
  left join public.members m on m.id = tl.member_id
  left join public.profiles p on p.id = tl.staff_user_id
  cross join bounds b
  where not p_staff_only
    or tl.staff_user_id = p_staff_user_id
  order by coalesce(tl.event_at, timezone('America/New_York', now()::timestamp)) desc
  limit (select row_limit from bounds)
),
shower_rows as (
  select
    sl.id,
    'shower_log'::text as source_kind,
    coalesce(sl.event_at, timezone('America/New_York', now()::timestamp)) as occurred_at,
    nullif(trim(m.display_name), '') as member_name,
    nullif(trim(p.full_name), '') as staff_name,
    jsonb_build_object(
      'event_at', coalesce(sl.event_at, timezone('America/New_York', now()::timestamp))::text,
      'laundry', sl.laundry,
      'briefs', sl.briefs
    ) as payload
  from public.shower_logs sl
  left join public.members m on m.id = sl.member_id
  left join public.profiles p on p.id = sl.staff_user_id
  cross join bounds b
  where not p_staff_only
    or sl.staff_user_id = p_staff_user_id
  order by coalesce(sl.event_at, timezone('America/New_York', now()::timestamp)) desc
  limit (select row_limit from bounds)
),
transport_rows as (
  select
    tl.id,
    'transportation'::text as source_kind,
    coalesce(tl.created_at, timezone('America/New_York', tl.service_date::timestamp)) as occurred_at,
    nullif(trim(coalesce(m.display_name, tl.first_name)), '') as member_name,
    nullif(trim(p.full_name), '') as staff_name,
    jsonb_build_object(
      'service_date', tl.service_date::text,
      'period', tl.period,
      'transport_type', tl.transport_type
    ) as payload
  from public.transportation_logs tl
  left join public.members m on m.id = tl.member_id
  left join public.profiles p on p.id = tl.staff_user_id
  cross join bounds b
  where not p_staff_only
    or tl.staff_user_id = p_staff_user_id
  order by coalesce(tl.created_at, timezone('America/New_York', tl.service_date::timestamp)) desc
  limit (select row_limit from bounds)
),
photo_rows as (
  select
    mpu.id,
    'photo_upload'::text as source_kind,
    mpu.uploaded_at as occurred_at,
    nullif(trim(m.display_name), '') as member_name,
    nullif(trim(p.full_name), '') as staff_name,
    jsonb_build_object(
      'uploaded_at', mpu.uploaded_at::text,
      'photo_url', mpu.photo_url
    ) as payload
  from public.member_photo_uploads mpu
  left join public.members m on m.id = mpu.member_id
  left join public.profiles p on p.id = mpu.uploaded_by
  cross join bounds b
  where not p_staff_only
    or mpu.uploaded_by = p_staff_user_id
  order by mpu.uploaded_at desc
  limit (select row_limit from bounds)
),
assessment_rows as (
  select
    ia.id,
    'assessment'::text as source_kind,
    coalesce(ia.created_at, timezone('America/New_York', ia.assessment_date::timestamp)) as occurred_at,
    nullif(trim(m.display_name), '') as member_name,
    nullif(trim(p.full_name), '') as staff_name,
    jsonb_build_object(
      'assessment_date', ia.assessment_date::text,
      'total_score', ia.total_score,
      'recommended_track', ia.recommended_track,
      'admission_review_required', ia.admission_review_required,
      'transport_appropriate', ia.transport_appropriate,
      'complete', ia.complete,
      'completed_by', ia.completed_by,
      'signature_status', ia.signature_status,
      'signed_by', ia.signed_by,
      'signed_at', ia.signed_at::text,
      'draft_pof_status', ia.draft_pof_status,
      'created_at', ia.created_at::text
    ) as payload
  from public.intake_assessments ia
  left join public.members m on m.id = ia.member_id
  left join public.profiles p on p.id = ia.completed_by_user_id
  cross join bounds b
  where not p_staff_only
    or ia.completed_by_user_id = p_staff_user_id
  order by coalesce(ia.created_at, timezone('America/New_York', ia.assessment_date::timestamp)) desc
  limit (select row_limit from bounds)
),
combined as (
  select * from daily_rows
  union all
  select * from toilet_rows
  union all
  select * from shower_rows
  union all
  select * from transport_rows
  union all
  select * from photo_rows
  union all
  select * from assessment_rows
)
select *
from combined
order by occurred_at desc, source_kind asc, id asc;
$$;


ALTER FUNCTION "public"."rpc_get_documentation_workflows"("p_staff_user_id" "uuid", "p_staff_only" boolean, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_health_dashboard_care_alerts"("p_limit" integer DEFAULT 12) RETURNS TABLE("member_id" "uuid", "member_name" "text", "flags" "text"[], "summary" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select
    m.id as member_id,
    m.display_name as member_name,
    array_remove(
      array[
        case
          when nullif(
            trim(
              concat_ws(
                ' ',
                nullif(trim(coalesce(mcc.food_allergies, '')), ''),
                nullif(trim(coalesce(mcc.medication_allergies, '')), ''),
                nullif(trim(coalesce(mcc.environmental_allergies, '')), '')
              )
            ),
            ''
          ) is not null then 'Allergies'
          else null
        end,
        case
          when lower(trim(coalesce(mcc.diet_type, mhp.diet_type, ''))) <> ''
               and lower(trim(coalesce(mcc.diet_type, mhp.diet_type, ''))) <> 'regular'
            then 'Special diet'
          when nullif(
            trim(
              concat_ws(
                ' ',
                nullif(trim(coalesce(mcc.dietary_preferences_restrictions, '')), ''),
                nullif(trim(coalesce(mhp.dietary_restrictions, '')), '')
              )
            ),
            ''
          ) is not null then 'Special diet'
          else null
        end,
        case
          when trim(coalesce(mcc.code_status, mhp.code_status, m.code_status, '')) = 'DNR' then 'DNR'
          else null
        end,
        case
          when nullif(trim(coalesce(mhp.important_alerts, '')), '') is not null
            or nullif(trim(coalesce(mcc.command_center_notes, '')), '') is not null
            then 'Care alert'
          else null
        end,
        case
          when nullif(trim(coalesce(mhp.cognitive_behavior_comments, '')), '') is not null then 'Behavior notes'
          else null
        end
      ],
      null
    ) as flags,
    coalesce(
      nullif(
        trim(
          concat_ws(
            ' ',
            nullif(trim(coalesce(mhp.important_alerts, '')), ''),
            nullif(trim(coalesce(mcc.command_center_notes, '')), ''),
            nullif(
              trim(
                concat_ws(
                  ' ',
                  nullif(trim(coalesce(mcc.dietary_preferences_restrictions, '')), ''),
                  nullif(trim(coalesce(mhp.dietary_restrictions, '')), '')
                )
              ),
              ''
            ),
            nullif(trim(coalesce(mhp.cognitive_behavior_comments, '')), '')
          )
        ),
        ''
      ),
      '-'
    ) as summary
  from public.members m
  left join public.member_command_centers mcc on mcc.member_id = m.id
  left join public.member_health_profiles mhp on mhp.member_id = m.id
  where coalesce(m.status, '') = 'active'
    and array_length(
      array_remove(
        array[
          case
            when nullif(
              trim(
                concat_ws(
                  ' ',
                  nullif(trim(coalesce(mcc.food_allergies, '')), ''),
                  nullif(trim(coalesce(mcc.medication_allergies, '')), ''),
                  nullif(trim(coalesce(mcc.environmental_allergies, '')), '')
                )
              ),
              ''
            ) is not null then 'Allergies'
            else null
          end,
          case
            when lower(trim(coalesce(mcc.diet_type, mhp.diet_type, ''))) <> ''
                 and lower(trim(coalesce(mcc.diet_type, mhp.diet_type, ''))) <> 'regular'
              then 'Special diet'
            when nullif(
              trim(
                concat_ws(
                  ' ',
                  nullif(trim(coalesce(mcc.dietary_preferences_restrictions, '')), ''),
                  nullif(trim(coalesce(mhp.dietary_restrictions, '')), '')
                )
              ),
              ''
            ) is not null then 'Special diet'
            else null
          end,
          case
            when trim(coalesce(mcc.code_status, mhp.code_status, m.code_status, '')) = 'DNR' then 'DNR'
            else null
          end,
          case
            when nullif(trim(coalesce(mhp.important_alerts, '')), '') is not null
              or nullif(trim(coalesce(mcc.command_center_notes, '')), '') is not null
              then 'Care alert'
            else null
          end,
          case
            when nullif(trim(coalesce(mhp.cognitive_behavior_comments, '')), '') is not null then 'Behavior notes'
            else null
          end
        ],
        null
      ),
      1
    ) > 0
  order by m.display_name asc, m.id asc
  limit greatest(coalesce(p_limit, 12), 1)::integer;
$$;


ALTER FUNCTION "public"."rpc_get_health_dashboard_care_alerts"("p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_member_activity_snapshot"("p_member_id" "uuid", "p_from_ts" timestamp with time zone, "p_to_ts" timestamp with time zone, "p_from_date" "date", "p_to_date" "date", "p_source_limit" integer DEFAULT 200) RETURNS TABLE("daily_activity" bigint, "toilet" bigint, "shower" bigint, "transportation" bigint, "blood_sugar" bigint, "photos" bigint, "ancillary" bigint, "assessments" bigint, "ancillary_total_cents" bigint, "activity_rows" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $_$
with bounds as (
  select
    least(p_from_ts, p_to_ts) as from_ts,
    greatest(p_from_ts, p_to_ts) as to_ts,
    least(p_from_date, p_to_date) as from_date,
    greatest(p_from_date, p_to_date) as to_date,
    greatest(coalesce(p_source_limit, 200), 0) as source_limit
),
summary as (
  select
    (select count(*) from public.daily_activity_logs where member_id = p_member_id and created_at >= b.from_ts and created_at <= b.to_ts)::bigint as daily_activity,
    (select count(*) from public.toilet_logs where member_id = p_member_id and event_at >= b.from_ts and event_at <= b.to_ts)::bigint as toilet,
    (select count(*) from public.shower_logs where member_id = p_member_id and event_at >= b.from_ts and event_at <= b.to_ts)::bigint as shower,
    (select count(*) from public.transportation_logs where member_id = p_member_id and service_date >= b.from_date and service_date <= b.to_date)::bigint as transportation,
    (select count(*) from public.v_blood_sugar_logs_detailed where member_id = p_member_id and checked_at >= b.from_ts and checked_at <= b.to_ts)::bigint as blood_sugar,
    (select count(*) from public.member_photo_uploads where member_id = p_member_id and uploaded_at >= b.from_ts and uploaded_at <= b.to_ts)::bigint as photos,
    (select count(*) from public.v_ancillary_charge_logs_detailed where member_id = p_member_id and service_date >= b.from_date and service_date <= b.to_date)::bigint as ancillary,
    (select count(*) from public.intake_assessments where member_id = p_member_id and created_at >= b.from_ts and created_at <= b.to_ts)::bigint as assessments,
    (select coalesce(sum(amount_cents), 0) from public.v_ancillary_charge_logs_detailed where member_id = p_member_id and service_date >= b.from_date and service_date <= b.to_date)::bigint as ancillary_total_cents
  from bounds b
),
daily_rows as (
  select *
  from (
    select
      dal.id,
      'Participation Log'::text as activity_type,
      coalesce(dal.created_at, timezone('America/New_York', dal.activity_date::timestamp)) as occurred_at,
      dal.member_id,
      nullif(trim(m.display_name), '') as member_name,
      dal.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(nullif(trim(p.full_name), ''), 'Staff') || ' | Participation log' as details_summary,
      '/documentation/activity'::text as source_href,
      'daily_activity_logs'::text as source_table,
      'daily_activity'::text as source_kind
    from public.daily_activity_logs dal
    left join public.members m on m.id = dal.member_id
    left join public.profiles p on p.id = dal.staff_user_id
    cross join bounds b
    where dal.member_id = p_member_id
      and dal.created_at >= b.from_ts
      and dal.created_at <= b.to_ts
    order by dal.created_at desc
    limit (select source_limit from bounds)
  ) daily_rows
),
toilet_rows as (
  select *
  from (
    select
      tl.id,
      'Toilet Log'::text as activity_type,
      coalesce(tl.event_at, timezone('America/New_York', now()::timestamp)) as occurred_at,
      tl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      tl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(nullif(trim(p.full_name), 'Staff'), 'Staff') || ' | ' || coalesce(tl.use_type, 'Toilet') as details_summary,
      '/documentation/toilet'::text as source_href,
      'toilet_logs'::text as source_table,
      'toilet_log'::text as source_kind
    from public.toilet_logs tl
    left join public.members m on m.id = tl.member_id
    left join public.profiles p on p.id = tl.staff_user_id
    cross join bounds b
    where tl.member_id = p_member_id
      and tl.event_at >= b.from_ts
      and tl.event_at <= b.to_ts
    order by tl.event_at desc
    limit (select source_limit from bounds)
  ) toilet_rows
),
shower_rows as (
  select *
  from (
    select
      sl.id,
      'Shower Log'::text as activity_type,
      coalesce(sl.event_at, timezone('America/New_York', now()::timestamp)) as occurred_at,
      sl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      sl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(nullif(trim(p.full_name), 'Staff'), 'Staff') || case when sl.laundry then ' | Laundry' else '' end as details_summary,
      '/documentation/shower'::text as source_href,
      'shower_logs'::text as source_table,
      'shower_log'::text as source_kind
    from public.shower_logs sl
    left join public.members m on m.id = sl.member_id
    left join public.profiles p on p.id = sl.staff_user_id
    cross join bounds b
    where sl.member_id = p_member_id
      and sl.event_at >= b.from_ts
      and sl.event_at <= b.to_ts
    order by sl.event_at desc
    limit (select source_limit from bounds)
  ) shower_rows
),
transport_rows as (
  select *
  from (
    select
      tl.id,
      'Transportation'::text as activity_type,
      coalesce(tl.created_at, timezone('America/New_York', tl.service_date::timestamp)) as occurred_at,
      tl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      tl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(nullif(trim(p.full_name), 'Staff'), 'Staff') || ' | ' || coalesce(tl.transport_type, 'Transportation') as details_summary,
      '/documentation/transportation'::text as source_href,
      'transportation_logs'::text as source_table,
      'transportation'::text as source_kind
    from public.transportation_logs tl
    left join public.members m on m.id = tl.member_id
    left join public.profiles p on p.id = tl.staff_user_id
    cross join bounds b
    where tl.member_id = p_member_id
      and tl.service_date >= b.from_date
      and tl.service_date <= b.to_date
    order by tl.service_date desc
    limit (select source_limit from bounds)
  ) transport_rows
),
blood_rows as (
  select *
  from (
    select
      bsl.id,
      'Blood Sugar'::text as activity_type,
      bsl.checked_at as occurred_at,
      bsl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      bsl.nurse_user_id as staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(bsl.reading_mg_dl::text, '0') || ' mg/dL | ' || coalesce(nullif(trim(p.full_name), ''), 'Nurse') as details_summary,
      '/documentation/blood-sugar'::text as source_href,
      'blood_sugar_logs'::text as source_table,
      'blood_sugar'::text as source_kind
    from public.blood_sugar_logs bsl
    left join public.members m on m.id = bsl.member_id
    left join public.profiles p on p.id = bsl.nurse_user_id
    cross join bounds b
    where bsl.member_id = p_member_id
      and bsl.checked_at >= b.from_ts
      and bsl.checked_at <= b.to_ts
    order by bsl.checked_at desc
    limit (select source_limit from bounds)
  ) blood_rows
),
photo_rows as (
  select *
  from (
    select
      mpu.id,
      'Photo Upload'::text as activity_type,
      mpu.uploaded_at as occurred_at,
      mpu.member_id,
      nullif(trim(m.display_name), '') as member_name,
      mpu.uploaded_by as staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(nullif(trim(p.full_name), ''), 'Staff') || ' | Photo upload' as details_summary,
      '/documentation/photo-upload'::text as source_href,
      'member_photo_uploads'::text as source_table,
      'photo_upload'::text as source_kind
    from public.member_photo_uploads mpu
    left join public.members m on m.id = mpu.member_id
    left join public.profiles p on p.id = mpu.uploaded_by
    cross join bounds b
    where mpu.member_id = p_member_id
      and mpu.uploaded_at >= b.from_ts
      and mpu.uploaded_at <= b.to_ts
    order by mpu.uploaded_at desc
    limit (select source_limit from bounds)
  ) photo_rows
),
ancillary_rows as (
  select *
  from (
    select
      acl.id,
      'Ancillary Charge'::text as activity_type,
      coalesce(acl.created_at, timezone('America/New_York', acl.service_date::timestamp)) as occurred_at,
      acl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      acl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(c.name, 'Ancillary') || ' | $' || to_char((coalesce(c.price_cents, 0)::numeric / 100), 'FM999999990.00') as details_summary,
      '/reports/monthly-ancillary'::text as source_href,
      'ancillary_charge_logs'::text as source_table,
      'ancillary_charge'::text as source_kind
    from public.ancillary_charge_logs acl
    left join public.ancillary_charge_categories c on c.id = acl.category_id
    left join public.members m on m.id = acl.member_id
    left join public.profiles p on p.id = acl.staff_user_id
    cross join bounds b
    where acl.member_id = p_member_id
      and acl.service_date >= b.from_date
      and acl.service_date <= b.to_date
    order by acl.service_date desc
    limit (select source_limit from bounds)
  ) ancillary_rows
),
assessment_rows as (
  select *
  from (
    select
      ia.id,
      'Assessment'::text as activity_type,
      coalesce(ia.created_at, timezone('America/New_York', ia.assessment_date::timestamp)) as occurred_at,
      ia.member_id,
      nullif(trim(m.display_name), '') as member_name,
      ia.completed_by_user_id as staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      'Intake assessment completed'::text as details_summary,
      '/health/assessment/' || ia.id::text as source_href,
      'intake_assessments'::text as source_table,
      'intake_assessment'::text as source_kind
    from public.intake_assessments ia
    left join public.members m on m.id = ia.member_id
    left join public.profiles p on p.id = ia.completed_by_user_id
    cross join bounds b
    where ia.member_id = p_member_id
      and ia.created_at >= b.from_ts
      and ia.created_at <= b.to_ts
    order by ia.created_at desc
    limit (select source_limit from bounds)
  ) assessment_rows
),
combined as (
  select * from daily_rows
  union all select * from toilet_rows
  union all select * from shower_rows
  union all select * from transport_rows
  union all select * from blood_rows
  union all select * from photo_rows
  union all select * from ancillary_rows
  union all select * from assessment_rows
),
row_payload as (
  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'id', combined.id,
        'activity_type', combined.activity_type,
        'occurred_at', combined.occurred_at,
        'member_id', combined.member_id,
        'member_name', combined.member_name,
        'staff_user_id', combined.staff_user_id,
        'staff_name', combined.staff_name,
        'details_summary', combined.details_summary,
        'source_href', combined.source_href,
        'source_table', combined.source_table,
        'source_kind', combined.source_kind
      )
      order by combined.occurred_at desc, combined.source_kind asc, combined.activity_type asc, combined.id asc
    ),
    '[]'::jsonb
  ) as activity_rows
  from combined
)
select
  summary.daily_activity,
  summary.toilet,
  summary.shower,
  summary.transportation,
  summary.blood_sugar,
  summary.photos,
  summary.ancillary,
  summary.assessments,
  summary.ancillary_total_cents,
  row_payload.activity_rows
from summary
cross join row_payload;
$_$;


ALTER FUNCTION "public"."rpc_get_member_activity_snapshot"("p_member_id" "uuid", "p_from_ts" timestamp with time zone, "p_to_ts" timestamp with time zone, "p_from_date" "date", "p_to_date" "date", "p_source_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_member_detail_counts"("p_member_id" "uuid", "p_staff_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("daily_activities" bigint, "toilets" bigint, "showers" bigint, "transportation" bigint, "blood_sugar" bigint, "ancillary" bigint, "assessments" bigint, "photos" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with scoped_counts as (
    select
      (select count(*)
       from public.daily_activity_logs dal
       where dal.member_id = p_member_id
         and (p_staff_user_id is null or dal.staff_user_id = p_staff_user_id)) as daily_activities,
      (select count(*)
       from public.toilet_logs tl
       where tl.member_id = p_member_id
         and (p_staff_user_id is null or tl.staff_user_id = p_staff_user_id)) as toilets,
      (select count(*)
       from public.shower_logs sl
       where sl.member_id = p_member_id
         and (p_staff_user_id is null or sl.staff_user_id = p_staff_user_id)) as showers,
      (select count(*)
       from public.transportation_logs trl
       where trl.member_id = p_member_id
         and (p_staff_user_id is null or trl.staff_user_id = p_staff_user_id)) as transportation,
      (select count(*)
       from public.blood_sugar_logs bsl
       where bsl.member_id = p_member_id
         and (p_staff_user_id is null or bsl.nurse_user_id = p_staff_user_id)) as blood_sugar,
      (select count(*)
       from public.ancillary_charge_logs acl
       where acl.member_id = p_member_id
         and (p_staff_user_id is null or acl.staff_user_id = p_staff_user_id)) as ancillary,
      (select count(*)
       from public.intake_assessments ia
       where ia.member_id = p_member_id
         and (p_staff_user_id is null or ia.completed_by_user_id = p_staff_user_id)) as assessments,
      (select count(*)
       from public.member_photo_uploads mpu
       where mpu.member_id = p_member_id
         and (p_staff_user_id is null or mpu.uploaded_by = p_staff_user_id)) as photos
  )
  select
    scoped_counts.daily_activities,
    scoped_counts.toilets,
    scoped_counts.showers,
    scoped_counts.transportation,
    scoped_counts.blood_sugar,
    scoped_counts.ancillary,
    scoped_counts.assessments,
    scoped_counts.photos
  from scoped_counts;
$$;


ALTER FUNCTION "public"."rpc_get_member_detail_counts"("p_member_id" "uuid", "p_staff_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_member_documentation_summary"("p_start_date" "date", "p_end_date" "date") RETURNS TABLE("member_id" "uuid", "member_name" "text", "participation_count" bigint, "toileting_count" bigint, "shower_count" bigint, "transportation_count" bigint)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with bounds as (
    select
      least(p_start_date, p_end_date) as start_date,
      greatest(p_start_date, p_end_date) as end_date,
      ((least(p_start_date, p_end_date)::text || ' 00:00:00 America/New_York')::timestamptz) as start_ts,
      ((greatest(p_start_date, p_end_date)::text || ' 23:59:59 America/New_York')::timestamptz) as end_ts
  ),
  activity as (
    select dal.member_id, 'daily_activity'::text as source
    from public.daily_activity_logs dal
    cross join bounds b
    where dal.member_id is not null
      and dal.activity_date >= b.start_date
      and dal.activity_date <= b.end_date

    union all

    select tl.member_id, 'toilet'::text as source
    from public.toilet_logs tl
    cross join bounds b
    where tl.member_id is not null
      and tl.event_at >= b.start_ts
      and tl.event_at <= b.end_ts

    union all

    select sl.member_id, 'shower'::text as source
    from public.shower_logs sl
    cross join bounds b
    where sl.member_id is not null
      and sl.event_at >= b.start_ts
      and sl.event_at <= b.end_ts

    union all

    select tr.member_id, 'transportation'::text as source
    from public.transportation_logs tr
    cross join bounds b
    where tr.member_id is not null
      and tr.service_date >= b.start_date
      and tr.service_date <= b.end_date
  ),
  member_counts as (
    select
      activity.member_id,
      count(*) filter (where activity.source = 'daily_activity') as participation_count,
      count(*) filter (where activity.source = 'toilet') as toileting_count,
      count(*) filter (where activity.source = 'shower') as shower_count,
      count(*) filter (where activity.source = 'transportation') as transportation_count
    from activity
    group by activity.member_id
  )
  select
    member_counts.member_id,
    coalesce(nullif(trim(m.display_name), ''), 'Unknown Member') as member_name,
    member_counts.participation_count,
    member_counts.toileting_count,
    member_counts.shower_count,
    member_counts.transportation_count
  from member_counts
  left join public.members m
    on m.id = member_counts.member_id
  order by coalesce(nullif(trim(m.display_name), ''), 'Unknown Member') asc;
$$;


ALTER FUNCTION "public"."rpc_get_member_documentation_summary"("p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_member_health_profile_summary_counts"("p_status" "text" DEFAULT NULL::"text", "p_query" "text" DEFAULT NULL::"text") RETURNS TABLE("active_count" bigint, "with_alerts_count" bigint)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with filtered_members as (
    select m.id, m.status
    from public.members m
    where (
      nullif(trim(coalesce(p_status, '')), '') is null
      or m.status = trim(p_status)
    )
      and (
        nullif(trim(coalesce(p_query, '')), '') is null
        or m.display_name ilike ('%' || trim(p_query) || '%')
      )
  ),
  latest_assessments as (
    select distinct on (ia.member_id)
      ia.member_id,
      coalesce(ia.admission_review_required, false) as admission_review_required
    from public.intake_assessments ia
    join filtered_members fm on fm.id = ia.member_id
    order by ia.member_id, ia.assessment_date desc nulls last, ia.created_at desc nulls last, ia.id desc
  ),
  profile_alerts as (
    select
      mhp.member_id,
      nullif(btrim(coalesce(mhp.important_alerts, '')), '') as important_alerts
    from public.member_health_profiles mhp
    join filtered_members fm on fm.id = mhp.member_id
  )
  select
    count(*) filter (where fm.status = 'active')::bigint as active_count,
    count(*) filter (
      where coalesce(la.admission_review_required, false)
        or pa.important_alerts is not null
    )::bigint as with_alerts_count
  from filtered_members fm
  left join latest_assessments la on la.member_id = fm.id
  left join profile_alerts pa on pa.member_id = fm.id;
$$;


ALTER FUNCTION "public"."rpc_get_member_health_profile_summary_counts"("p_status" "text", "p_query" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_progress_note_tracker"("p_status_filter" "text" DEFAULT 'All'::"text", "p_member_id" "uuid" DEFAULT NULL::"uuid", "p_query_pattern" "text" DEFAULT NULL::"text", "p_page" integer DEFAULT 1, "p_page_size" integer DEFAULT 25) RETURNS TABLE("total" bigint, "overdue" bigint, "due_today" bigint, "due_soon" bigint, "upcoming" bigint, "data_issues" bigint, "total_rows" bigint, "page_rows" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with latest_signed as (
    select distinct on (pn.member_id)
      pn.member_id,
      pn.id as latest_signed_note_id,
      timezone('America/New_York', pn.signed_at)::date as last_signed_progress_note_date
    from public.progress_notes pn
    where pn.status = 'signed'
      and pn.signed_at is not null
    order by pn.member_id, pn.signed_at desc, pn.updated_at desc, pn.id desc
  ),
  latest_draft as (
    select distinct on (pn.member_id)
      pn.member_id,
      pn.id as latest_draft_id
    from public.progress_notes pn
    where pn.status = 'draft'
    order by pn.member_id, pn.updated_at desc, pn.id desc
  ),
  tracker_base as (
    select
      m.id as member_id,
      m.display_name as member_name,
      nullif(trim(m.status), '') as member_status,
      m.enrollment_date,
      ls.last_signed_progress_note_date,
      ld.latest_draft_id,
      ls.latest_signed_note_id,
      coalesce(ls.last_signed_progress_note_date, m.enrollment_date) as anchor_date,
      timezone('America/New_York', now())::date as today_eastern
    from public.members m
    left join latest_signed ls on ls.member_id = m.id
    left join latest_draft ld on ld.member_id = m.id
    where (p_member_id is null or m.id = p_member_id)
      and (
        p_query_pattern is null
        or m.display_name ilike p_query_pattern
      )
  ),
  tracker as (
    select
      member_id,
      member_name,
      member_status,
      enrollment_date,
      last_signed_progress_note_date,
      case
        when anchor_date is null then null
        else anchor_date + 90
      end as next_progress_note_due_date,
      case
        when anchor_date is null then null
        else (anchor_date + 90) - today_eastern
      end as days_until_due,
      case
        when anchor_date is null then 'data_issue'
        when anchor_date + 90 < today_eastern then 'overdue'
        when anchor_date + 90 = today_eastern then 'due'
        when anchor_date + 90 <= today_eastern + 14 then 'due_soon'
        else 'upcoming'
      end as compliance_status,
      (latest_draft_id is not null) as has_draft_in_progress,
      latest_draft_id,
      latest_signed_note_id,
      case
        when anchor_date is null then 'Enrollment date missing'
        else null
      end as data_issue
    from tracker_base
  ),
  summary as (
    select
      count(*)::bigint as total,
      count(*) filter (where compliance_status = 'overdue')::bigint as overdue,
      count(*) filter (where compliance_status = 'due')::bigint as due_today,
      count(*) filter (where compliance_status = 'due_soon')::bigint as due_soon,
      count(*) filter (where compliance_status = 'upcoming')::bigint as upcoming,
      count(*) filter (where compliance_status = 'data_issue')::bigint as data_issues
    from tracker
  ),
  filtered as (
    select
      t.*,
      case t.compliance_status
        when 'data_issue' then 0
        when 'overdue' then 1
        when 'due' then 2
        when 'due_soon' then 3
        else 4
      end as status_rank
    from tracker t
    where case
      when p_status_filter = 'Overdue' then t.compliance_status = 'overdue'
      when p_status_filter = 'Due Today' then t.compliance_status = 'due'
      when p_status_filter = 'Due Soon' then t.compliance_status = 'due_soon'
      when p_status_filter = 'Completed/Upcoming' then t.compliance_status = 'upcoming'
      else true
    end
  ),
  paged as (
    select *
    from filtered
    order by status_rank asc, next_progress_note_due_date asc nulls last, member_name asc, member_id asc
    offset (greatest(coalesce(p_page, 1), 1) - 1) * greatest(coalesce(p_page_size, 25), 1)
    limit greatest(coalesce(p_page_size, 25), 1)
  ),
  total_rows as (
    select count(*)::bigint as total_rows
    from filtered
  ),
  row_payload as (
    select coalesce(
      jsonb_agg(
        jsonb_build_object(
          'member_id', paged.member_id,
          'member_name', paged.member_name,
          'member_status', paged.member_status,
          'enrollment_date', paged.enrollment_date,
          'last_signed_progress_note_date', paged.last_signed_progress_note_date,
          'next_progress_note_due_date', paged.next_progress_note_due_date,
          'days_until_due', paged.days_until_due,
          'compliance_status', paged.compliance_status,
          'has_draft_in_progress', paged.has_draft_in_progress,
          'latest_draft_id', paged.latest_draft_id,
          'latest_signed_note_id', paged.latest_signed_note_id,
          'data_issue', paged.data_issue
        )
        order by paged.status_rank asc, paged.next_progress_note_due_date asc nulls last, paged.member_name asc, paged.member_id asc
      ),
      '[]'::jsonb
    ) as page_rows
    from paged
  )
  select
    summary.total,
    summary.overdue,
    summary.due_today,
    summary.due_soon,
    summary.upcoming,
    summary.data_issues,
    total_rows.total_rows,
    row_payload.page_rows
  from summary
  cross join total_rows
  cross join row_payload;
$$;


ALTER FUNCTION "public"."rpc_get_progress_note_tracker"("p_status_filter" "text", "p_member_id" "uuid", "p_query_pattern" "text", "p_page" integer, "p_page_size" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_reports_home_staff_aggregates"() RETURNS TABLE("staff_productivity" "jsonb", "time_summary" "jsonb")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with documentation_counts as (
    select
      de.staff_user_id,
      count(*) filter (where de.event_table = 'daily_activity_logs')::bigint as activity_logs,
      count(*) filter (where de.event_table = 'toilet_logs')::bigint as toilet_logs,
      count(*) filter (where de.event_table = 'shower_logs')::bigint as shower_logs,
      count(*) filter (where de.event_table = 'transportation_logs')::bigint as transportation_logs
    from public.documentation_events de
    where de.staff_user_id is not null
    group by de.staff_user_id
  ),
  punch_counts as (
    select
      tp.staff_user_id,
      count(*)::bigint as punches,
      count(*) filter (where tp.within_fence = false)::bigint as outside_fence
    from public.time_punches tp
    where tp.staff_user_id is not null
    group by tp.staff_user_id
  ),
  report_staff as (
    select p.id as staff_user_id, coalesce(nullif(trim(p.full_name), ''), 'Unknown Staff') as staff_name
    from public.profiles p
    where p.active = true
    union
    select dc.staff_user_id, coalesce(nullif(trim(p.full_name), ''), 'Unknown Staff') as staff_name
    from documentation_counts dc
    left join public.profiles p on p.id = dc.staff_user_id
    union
    select pc.staff_user_id, coalesce(nullif(trim(p.full_name), ''), 'Unknown Staff') as staff_name
    from punch_counts pc
    left join public.profiles p on p.id = pc.staff_user_id
  ),
  staff_productivity_rows as (
    select
      rs.staff_name,
      coalesce(dc.activity_logs, 0)::bigint as activity_logs,
      coalesce(dc.toilet_logs, 0)::bigint as toilet_logs,
      coalesce(dc.shower_logs, 0)::bigint as shower_logs,
      coalesce(dc.transportation_logs, 0)::bigint as transportation_logs
    from report_staff rs
    left join documentation_counts dc on dc.staff_user_id = rs.staff_user_id
  ),
  time_summary_rows as (
    select
      rs.staff_name,
      coalesce(pc.punches, 0)::bigint as punches,
      coalesce(pc.outside_fence, 0)::bigint as outside_fence
    from report_staff rs
    left join punch_counts pc on pc.staff_user_id = rs.staff_user_id
  )
  select
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'staff_name', spr.staff_name,
            'activity_logs', spr.activity_logs,
            'toilet_logs', spr.toilet_logs,
            'shower_logs', spr.shower_logs,
            'transportation_logs', spr.transportation_logs
          )
          order by spr.staff_name
        )
        from staff_productivity_rows spr
      ),
      '[]'::jsonb
    ) as staff_productivity,
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'staff_name', tsr.staff_name,
            'punches', tsr.punches,
            'outside_fence', tsr.outside_fence
          )
          order by tsr.staff_name
        )
        from time_summary_rows tsr
      ),
      '[]'::jsonb
    ) as time_summary;
$$;


ALTER FUNCTION "public"."rpc_get_reports_home_staff_aggregates"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_sales_dashboard_summary"("p_recent_inquiry_start_date" "date" DEFAULT NULL::"date") RETURNS TABLE("open_lead_count" bigint, "won_lead_count" bigint, "lost_lead_count" bigint, "unresolved_inquiry_lead_count" bigint, "eip_lead_count" bigint, "total_lead_count" bigint, "converted_or_enrolled_count" bigint, "recent_inquiry_activity_count" bigint, "lead_activity_count" bigint, "partner_count" bigint, "referral_source_count" bigint, "partner_activity_count" bigint, "stage_counts" "jsonb", "recent_inquiries" "jsonb")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with stage_order as (
    select *
    from (values
      (1, 'Inquiry'::text),
      (2, 'Tour'::text),
      (3, 'Enrollment in Progress'::text),
      (4, 'Nurture'::text),
      (5, 'Referrals Only'::text),
      (6, 'Closed - Won'::text),
      (7, 'Closed - Lost'::text)
    ) as stage_order(ord, stage)
  ),
  canonical_leads as (
    select
      l.id,
      l.created_at,
      l.inquiry_date,
      l.member_name,
      l.caregiver_name,
      l.caregiver_relationship,
      l.caregiver_phone,
      l.caregiver_email,
      l.member_dob,
      l.lead_source,
      l.lead_source_other,
      l.partner_id,
      l.referral_source_id,
      l.referral_name,
      l.likelihood,
      l.next_follow_up_date,
      l.next_follow_up_type,
      l.tour_date,
      l.tour_completed,
      l.discovery_date,
      l.member_start_date,
      l.notes_summary,
      l.lost_reason,
      l.closed_date,
      l.created_by_name,
      case
        when lower(trim(coalesce(l.stage, ''))) = 'eip' then 'Enrollment in Progress'
        when lower(trim(coalesce(l.stage, ''))) = 'closed - enrolled' then 'Closed - Won'
        when trim(coalesce(l.stage, '')) = '' then 'Inquiry'
        when trim(coalesce(l.stage, '')) in (
          'Inquiry',
          'Tour',
          'Enrollment in Progress',
          'Nurture',
          'Closed - Won',
          'Closed - Lost'
        ) then trim(coalesce(l.stage, ''))
        else 'Inquiry'
      end as canonical_stage,
      case
        when lower(trim(coalesce(l.stage, ''))) in ('closed - won', 'closed - enrolled') then 'Won'
        when lower(trim(coalesce(l.stage, ''))) = 'closed - lost' then 'Lost'
        when lower(trim(coalesce(l.stage, ''))) = 'nurture' then 'Nurture'
        when lower(trim(coalesce(l.status::text, ''))) = 'won' then 'Won'
        when lower(trim(coalesce(l.status::text, ''))) = 'lost' then 'Lost'
        when lower(trim(coalesce(l.status::text, ''))) = 'nurture' then 'Nurture'
        else 'Open'
      end as canonical_status,
      lower(trim(coalesce(l.lead_source, ''))) as normalized_lead_source
    from public.leads l
  ),
  resolved_leads as (
    select
      cl.*,
      case
        when cl.canonical_status = 'Lost' then 'Closed - Lost'
        when cl.canonical_status = 'Won' then 'Closed - Won'
        when cl.canonical_status = 'Nurture' and cl.canonical_stage <> 'Nurture' then 'Nurture'
        else cl.canonical_stage
      end as resolved_stage
    from canonical_leads cl
  ),
  summary_counts as (
    select
      count(*) filter (where canonical_status in ('Open', 'Nurture'))::bigint as open_lead_count,
      count(*) filter (where canonical_status = 'Won')::bigint as won_lead_count,
      count(*) filter (where canonical_status = 'Lost')::bigint as lost_lead_count,
      count(*) filter (
        where canonical_status in ('Open', 'Nurture')
          and resolved_stage = 'Inquiry'
      )::bigint as unresolved_inquiry_lead_count,
      count(*) filter (
        where canonical_status in ('Open', 'Nurture')
          and resolved_stage = 'Enrollment in Progress'
      )::bigint as eip_lead_count
    from resolved_leads
  ),
  stage_totals as (
    select resolved_stage as stage, count(*)::bigint as count
    from resolved_leads
    group by resolved_stage
  ),
  referral_only as (
    select count(*)::bigint as count
    from resolved_leads
    where canonical_status in ('Open', 'Nurture')
      and normalized_lead_source like '%referral%'
  ),
  stage_count_rows as (
    select
      so.ord,
      so.stage,
      case
        when so.stage = 'Referrals Only' then ro.count
        else coalesce(st.count, 0)::bigint
      end as count
    from stage_order so
    cross join referral_only ro
    left join stage_totals st on st.stage = so.stage
  ),
  stage_count_payload as (
    select coalesce(
      jsonb_agg(
        jsonb_build_object(
          'stage', stage_count_rows.stage,
          'count', stage_count_rows.count
        )
        order by stage_count_rows.ord
      ),
      '[]'::jsonb
    ) as stage_counts
    from stage_count_rows
  ),
  recent_inquiry_rows as (
    select
      rl.id,
      rl.resolved_stage as stage,
      rl.canonical_status as status,
      rl.created_at,
      rl.inquiry_date,
      rl.member_name,
      rl.caregiver_name,
      rl.caregiver_relationship,
      rl.caregiver_phone,
      rl.caregiver_email,
      rl.member_dob,
      rl.lead_source,
      rl.lead_source_other,
      rl.partner_id,
      rl.referral_source_id,
      rl.referral_name,
      rl.likelihood,
      rl.next_follow_up_date,
      rl.next_follow_up_type,
      rl.tour_date,
      rl.tour_completed,
      rl.discovery_date,
      rl.member_start_date,
      rl.notes_summary,
      rl.lost_reason,
      rl.closed_date,
      rl.created_by_name
    from resolved_leads rl
    where p_recent_inquiry_start_date is not null
      and rl.inquiry_date >= p_recent_inquiry_start_date
    order by rl.inquiry_date desc nulls last, rl.created_at desc
    limit 10
  ),
  recent_inquiry_payload as (
    select coalesce(
      jsonb_agg(
        jsonb_build_object(
          'id', recent_inquiry_rows.id,
          'stage', recent_inquiry_rows.stage,
          'status', recent_inquiry_rows.status,
          'created_at', recent_inquiry_rows.created_at,
          'inquiry_date', recent_inquiry_rows.inquiry_date,
          'member_name', recent_inquiry_rows.member_name,
          'caregiver_name', recent_inquiry_rows.caregiver_name,
          'caregiver_relationship', recent_inquiry_rows.caregiver_relationship,
          'caregiver_phone', recent_inquiry_rows.caregiver_phone,
          'caregiver_email', recent_inquiry_rows.caregiver_email,
          'member_dob', recent_inquiry_rows.member_dob,
          'lead_source', recent_inquiry_rows.lead_source,
          'lead_source_other', recent_inquiry_rows.lead_source_other,
          'partner_id', recent_inquiry_rows.partner_id,
          'referral_source_id', recent_inquiry_rows.referral_source_id,
          'referral_name', recent_inquiry_rows.referral_name,
          'likelihood', recent_inquiry_rows.likelihood,
          'next_follow_up_date', recent_inquiry_rows.next_follow_up_date,
          'next_follow_up_type', recent_inquiry_rows.next_follow_up_type,
          'tour_date', recent_inquiry_rows.tour_date,
          'tour_completed', recent_inquiry_rows.tour_completed,
          'discovery_date', recent_inquiry_rows.discovery_date,
          'member_start_date', recent_inquiry_rows.member_start_date,
          'notes_summary', recent_inquiry_rows.notes_summary,
          'lost_reason', recent_inquiry_rows.lost_reason,
          'closed_date', recent_inquiry_rows.closed_date,
          'created_by_name', recent_inquiry_rows.created_by_name
        )
        order by recent_inquiry_rows.inquiry_date desc nulls last, recent_inquiry_rows.created_at desc
      ),
      '[]'::jsonb
    ) as recent_inquiries
    from recent_inquiry_rows
  )
  select
    summary_counts.open_lead_count,
    summary_counts.won_lead_count,
    summary_counts.lost_lead_count,
    summary_counts.unresolved_inquiry_lead_count,
    summary_counts.eip_lead_count,
    (select count(*)::bigint from public.leads) as total_lead_count,
    (
      select count(*)::bigint
      from public.leads
      where status = 'won' or member_start_date is not null
    ) as converted_or_enrolled_count,
    (
      select count(*)::bigint
      from public.leads
      where p_recent_inquiry_start_date is not null
        and inquiry_date >= p_recent_inquiry_start_date
    ) as recent_inquiry_activity_count,
    (select count(*)::bigint from public.lead_activities) as lead_activity_count,
    (select count(*)::bigint from public.community_partner_organizations) as partner_count,
    (select count(*)::bigint from public.referral_sources) as referral_source_count,
    (select count(*)::bigint from public.partner_activities) as partner_activity_count,
    stage_count_payload.stage_counts,
    recent_inquiry_payload.recent_inquiries
  from summary_counts
  cross join stage_count_payload
  cross join recent_inquiry_payload;
$$;


ALTER FUNCTION "public"."rpc_get_sales_dashboard_summary"("p_recent_inquiry_start_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_sales_summary_report"("p_start_date" "date", "p_end_date" "date", "p_location" "text" DEFAULT NULL::"text") RETURNS TABLE("available_locations" "jsonb", "summary_sales_metrics_rows" "jsonb", "summary_sales_metrics_totals" "jsonb", "total_leads_status_rows" "jsonb", "total_leads_status_totals" "jsonb", "closed_lead_disposition_rows" "jsonb", "closed_lead_disposition_totals" "jsonb")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with canonical_leads as (
    select
      l.id,
      coalesce(l.inquiry_date, (l.created_at at time zone 'America/New_York')::date) as inquiry_or_created_date,
      l.discovery_date,
      l.tour_date,
      l.tour_completed,
      l.member_start_date,
      l.lost_reason,
      l.closed_date,
      lower(trim(coalesce(l.likelihood, ''))) as likelihood,
      case
        when lower(trim(coalesce(l.stage, ''))) = 'eip' then 'Enrollment in Progress'
        when lower(trim(coalesce(l.stage, ''))) = 'closed - enrolled' then 'Closed - Won'
        when trim(coalesce(l.stage, '')) = '' then 'Inquiry'
        when trim(coalesce(l.stage, '')) in (
          'Inquiry',
          'Tour',
          'Enrollment in Progress',
          'Nurture',
          'Closed - Won',
          'Closed - Lost'
        ) then trim(coalesce(l.stage, ''))
        else 'Inquiry'
      end as canonical_stage,
      case
        when lower(trim(coalesce(l.stage, ''))) in ('closed - won', 'closed - enrolled') then 'Won'
        when lower(trim(coalesce(l.stage, ''))) = 'closed - lost' then 'Lost'
        when lower(trim(coalesce(l.stage, ''))) = 'nurture' then 'Nurture'
        when lower(trim(coalesce(l.status::text, ''))) = 'won' then 'Won'
        when lower(trim(coalesce(l.status::text, ''))) = 'lost' then 'Lost'
        when lower(trim(coalesce(l.status::text, ''))) = 'nurture' then 'Nurture'
        else 'Open'
      end as canonical_status
    from public.leads l
  ),
  linked_member_locations as (
    select
      m.source_lead_id as lead_id,
      coalesce(nullif(trim(mcc.location), ''), 'Unassigned') as location
    from public.members m
    left join public.member_command_centers mcc on mcc.member_id = m.id
    where m.source_lead_id is not null
  ),
  located_leads as (
    select
      cl.*,
      coalesce(lml.location, 'Unassigned') as location
    from canonical_leads cl
    left join linked_member_locations lml on lml.lead_id = cl.id
  ),
  discharge_rows as (
    select
      coalesce(nullif(trim(mcc.location), ''), 'Unassigned') as location,
      m.discharge_date
    from public.members m
    left join public.member_command_centers mcc on mcc.member_id = m.id
    where m.source_lead_id is not null
      and m.discharge_date is not null
  ),
  available_location_rows as (
    select distinct location from located_leads
    union
    select distinct location from discharge_rows
  ),
  visible_locations as (
    select distinct location
    from (
      select location from available_location_rows where p_location is null
      union all
      select p_location as location where p_location is not null
    ) visible
    where location is not null
  ),
  summary_rows as (
    select
      vl.location,
      count(*) filter (
        where ll.discovery_date between p_start_date and p_end_date
      )::bigint as osa,
      count(*) filter (
        where ll.inquiry_or_created_date between p_start_date and p_end_date
      )::bigint as inquiries,
      count(*) filter (
        where ll.tour_date between p_start_date and p_end_date
          and ll.tour_completed is distinct from false
      )::bigint as tours,
      count(*) filter (
        where ll.member_start_date between p_start_date and p_end_date
      )::bigint as enrollments,
      (
        select count(*)::bigint
        from discharge_rows dr
        where dr.location = vl.location
          and dr.discharge_date between p_start_date and p_end_date
      ) as discharges
    from visible_locations vl
    left join located_leads ll on ll.location = vl.location
    group by vl.location
  ),
  summary_rows_enriched as (
    select
      location,
      osa,
      inquiries,
      case when inquiries = 0 then 0 else round((osa::numeric * 100) / inquiries, 2) end as osa_inquiry_rate,
      tours,
      case when inquiries = 0 then 0 else round((tours::numeric * 100) / inquiries, 2) end as inquiry_tour_rate,
      enrollments,
      case when tours = 0 then 0 else round((enrollments::numeric * 100) / tours, 2) end as tour_enrollment_rate,
      discharges,
      enrollments - discharges as net_growth
    from summary_rows
  ),
  summary_totals as (
    select
      'Totals'::text as location,
      coalesce(sum(osa), 0)::bigint as osa,
      coalesce(sum(inquiries), 0)::bigint as inquiries,
      case when coalesce(sum(inquiries), 0) = 0 then 0 else round((coalesce(sum(osa), 0)::numeric * 100) / coalesce(sum(inquiries), 0), 2) end as osa_inquiry_rate,
      coalesce(sum(tours), 0)::bigint as tours,
      case when coalesce(sum(inquiries), 0) = 0 then 0 else round((coalesce(sum(tours), 0)::numeric * 100) / coalesce(sum(inquiries), 0), 2) end as inquiry_tour_rate,
      coalesce(sum(enrollments), 0)::bigint as enrollments,
      case when coalesce(sum(tours), 0) = 0 then 0 else round((coalesce(sum(enrollments), 0)::numeric * 100) / coalesce(sum(tours), 0), 2) end as tour_enrollment_rate,
      coalesce(sum(discharges), 0)::bigint as discharges,
      coalesce(sum(net_growth), 0)::bigint as net_growth
    from summary_rows_enriched
  ),
  status_source as (
    select *
    from located_leads
    where inquiry_or_created_date <= p_end_date
      and (p_location is null or location = p_location)
  ),
  status_rows as (
    select
      vl.location,
      count(*) filter (
        where ss.location = vl.location
          and ss.canonical_status in ('Open', 'Nurture')
          and ss.canonical_stage = 'Enrollment in Progress'
      )::bigint as eip,
      count(*) filter (
        where ss.location = vl.location
          and ss.canonical_status in ('Open', 'Nurture')
          and ss.likelihood = 'hot'
      )::bigint as hot,
      count(*) filter (
        where ss.location = vl.location
          and ss.canonical_status in ('Open', 'Nurture')
          and ss.likelihood = 'warm'
      )::bigint as warm,
      count(*) filter (
        where ss.location = vl.location
          and ss.canonical_status in ('Open', 'Nurture')
          and ss.likelihood = 'cold'
      )::bigint as cold,
      count(*) filter (
        where ss.location = vl.location
          and (
            (ss.member_start_date is not null and ss.member_start_date <= p_end_date)
            or ss.canonical_status = 'Won'
          )
      )::bigint as enrolled,
      round(
        avg(
          case
            when ss.location = vl.location
              and ss.member_start_date is not null
              and ss.member_start_date <= p_end_date
            then greatest(ss.member_start_date - ss.inquiry_or_created_date, 0)
            else null
          end
        )
      )::bigint as avg_sales_cycle
    from visible_locations vl
    left join status_source ss on ss.location = vl.location
    group by vl.location
  ),
  status_totals as (
    select
      'Totals'::text as location,
      count(*) filter (
        where canonical_status in ('Open', 'Nurture')
          and canonical_stage = 'Enrollment in Progress'
      )::bigint as eip,
      count(*) filter (
        where canonical_status in ('Open', 'Nurture')
          and likelihood = 'hot'
      )::bigint as hot,
      count(*) filter (
        where canonical_status in ('Open', 'Nurture')
          and likelihood = 'warm'
      )::bigint as warm,
      count(*) filter (
        where canonical_status in ('Open', 'Nurture')
          and likelihood = 'cold'
      )::bigint as cold,
      count(*) filter (
        where (member_start_date is not null and member_start_date <= p_end_date)
          or canonical_status = 'Won'
      )::bigint as enrolled,
      round(
        avg(
          case
            when member_start_date is not null
              and member_start_date <= p_end_date
            then greatest(member_start_date - inquiry_or_created_date, 0)
            else null
          end
        )
      )::bigint as avg_sales_cycle
    from status_source
  ),
  disposition_source as (
    select
      location,
      case
        when lower(trim(coalesce(lost_reason, ''))) like '%spam%'
          or lower(trim(coalesce(lost_reason, ''))) like '%wrong number%'
          or lower(trim(coalesce(lost_reason, ''))) like '%test%'
          then 'spam'
        when lower(trim(coalesce(lost_reason, ''))) like '%deceas%'
          or lower(trim(coalesce(lost_reason, ''))) like '%passed%'
          then 'deceased'
        when lower(trim(coalesce(lost_reason, ''))) like '%price%'
          or lower(trim(coalesce(lost_reason, ''))) like '%cost%'
          or lower(trim(coalesce(lost_reason, ''))) like '%financial%'
          or lower(trim(coalesce(lost_reason, ''))) like '%afford%'
          then 'cost'
        when lower(trim(coalesce(lost_reason, ''))) like '%respond%'
          or lower(trim(coalesce(lost_reason, ''))) like '%reach%'
          or lower(trim(coalesce(lost_reason, ''))) like '%voicemail%'
          or lower(trim(coalesce(lost_reason, ''))) like '%ghost%'
          then 'did_not_respond'
        when lower(trim(coalesce(lost_reason, ''))) like '%distance%'
          or lower(trim(coalesce(lost_reason, ''))) like '%too far%'
          or lower(trim(coalesce(lost_reason, ''))) like '%service area%'
          or lower(trim(coalesce(lost_reason, ''))) like '%out of area%'
          then 'distance_to_center'
        when lower(trim(coalesce(lost_reason, ''))) like '%high acuity%'
          or lower(trim(coalesce(lost_reason, ''))) like '%acuity%'
          or lower(trim(coalesce(lost_reason, ''))) like '%not eligible%'
          or lower(trim(coalesce(lost_reason, ''))) like '%care needs%'
          or lower(trim(coalesce(lost_reason, ''))) like '%medical%'
          then 'high_acuity'
        when lower(trim(coalesce(lost_reason, ''))) like '%home care%'
          or lower(trim(coalesce(lost_reason, ''))) like '%home health%'
          then 'opted_for_home_care'
        when lower(trim(coalesce(lost_reason, ''))) like '%placed%'
          or lower(trim(coalesce(lost_reason, ''))) like '%assisted living%'
          or lower(trim(coalesce(lost_reason, ''))) like '%memory care%'
          or lower(trim(coalesce(lost_reason, ''))) like '%skilled nursing%'
          or lower(trim(coalesce(lost_reason, ''))) like '%facility%'
          or lower(trim(coalesce(lost_reason, ''))) like '%hospice%'
          then 'placed'
        when lower(trim(coalesce(lost_reason, ''))) like '%transport%'
          then 'transportation_issues'
        else 'declined_enrollment'
      end as bucket
    from located_leads
    where canonical_status = 'Lost'
      and closed_date between p_start_date and p_end_date
      and (p_location is null or location = p_location)
  ),
  disposition_rows as (
    select
      vl.location,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'cost')::bigint as cost,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'deceased')::bigint as deceased,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'declined_enrollment')::bigint as declined_enrollment,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'did_not_respond')::bigint as did_not_respond,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'distance_to_center')::bigint as distance_to_center,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'high_acuity')::bigint as high_acuity,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'opted_for_home_care')::bigint as opted_for_home_care,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'placed')::bigint as placed,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'transportation_issues')::bigint as transportation_issues,
      count(*) filter (where ds.location = vl.location and ds.bucket = 'spam')::bigint as spam,
      count(*) filter (where ds.location = vl.location)::bigint as total_closed_leads
    from visible_locations vl
    left join disposition_source ds on ds.location = vl.location
    group by vl.location
  ),
  disposition_totals as (
    select
      'Totals'::text as location,
      coalesce(sum(cost), 0)::bigint as cost,
      coalesce(sum(deceased), 0)::bigint as deceased,
      coalesce(sum(declined_enrollment), 0)::bigint as declined_enrollment,
      coalesce(sum(did_not_respond), 0)::bigint as did_not_respond,
      coalesce(sum(distance_to_center), 0)::bigint as distance_to_center,
      coalesce(sum(high_acuity), 0)::bigint as high_acuity,
      coalesce(sum(opted_for_home_care), 0)::bigint as opted_for_home_care,
      coalesce(sum(placed), 0)::bigint as placed,
      coalesce(sum(transportation_issues), 0)::bigint as transportation_issues,
      coalesce(sum(spam), 0)::bigint as spam,
      coalesce(sum(total_closed_leads), 0)::bigint as total_closed_leads
    from disposition_rows
  )
  select
    coalesce(
      (
        select jsonb_agg(location order by case when location = 'Unassigned' then 1 else 0 end, location)
        from available_location_rows
      ),
      '[]'::jsonb
    ) as available_locations,
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'location', location,
            'osa', osa,
            'inquiries', inquiries,
            'osa_inquiry_rate', osa_inquiry_rate,
            'tours', tours,
            'inquiry_tour_rate', inquiry_tour_rate,
            'enrollments', enrollments,
            'tour_enrollment_rate', tour_enrollment_rate,
            'discharges', discharges,
            'net_growth', net_growth
          )
          order by case when location = 'Unassigned' then 1 else 0 end, location
        )
        from summary_rows_enriched
      ),
      '[]'::jsonb
    ) as summary_sales_metrics_rows,
    (
      select jsonb_build_object(
        'location', location,
        'osa', osa,
        'inquiries', inquiries,
        'osa_inquiry_rate', osa_inquiry_rate,
        'tours', tours,
        'inquiry_tour_rate', inquiry_tour_rate,
        'enrollments', enrollments,
        'tour_enrollment_rate', tour_enrollment_rate,
        'discharges', discharges,
        'net_growth', net_growth
      )
      from summary_totals
    ) as summary_sales_metrics_totals,
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'location', location,
            'eip', eip,
            'hot', hot,
            'warm', warm,
            'cold', cold,
            'enrolled', enrolled,
            'avg_sales_cycle', avg_sales_cycle
          )
          order by case when location = 'Unassigned' then 1 else 0 end, location
        )
        from status_rows
      ),
      '[]'::jsonb
    ) as total_leads_status_rows,
    (
      select jsonb_build_object(
        'location', location,
        'eip', eip,
        'hot', hot,
        'warm', warm,
        'cold', cold,
        'enrolled', enrolled,
        'avg_sales_cycle', avg_sales_cycle
      )
      from status_totals
    ) as total_leads_status_totals,
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'location', location,
            'cost', cost,
            'deceased', deceased,
            'declined_enrollment', declined_enrollment,
            'did_not_respond', did_not_respond,
            'distance_to_center', distance_to_center,
            'high_acuity', high_acuity,
            'opted_for_home_care', opted_for_home_care,
            'placed', placed,
            'transportation_issues', transportation_issues,
            'spam', spam,
            'total_closed_leads', total_closed_leads
          )
          order by case when location = 'Unassigned' then 1 else 0 end, location
        )
        from disposition_rows
      ),
      '[]'::jsonb
    ) as closed_lead_disposition_rows,
    (
      select jsonb_build_object(
        'location', location,
        'cost', cost,
        'deceased', deceased,
        'declined_enrollment', declined_enrollment,
        'did_not_respond', did_not_respond,
        'distance_to_center', distance_to_center,
        'high_acuity', high_acuity,
        'opted_for_home_care', opted_for_home_care,
        'placed', placed,
        'transportation_issues', transportation_issues,
        'spam', spam,
        'total_closed_leads', total_closed_leads
      )
      from disposition_totals
    ) as closed_lead_disposition_totals;
$$;


ALTER FUNCTION "public"."rpc_get_sales_summary_report"("p_start_date" "date", "p_end_date" "date", "p_location" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_get_staff_activity_snapshot"("p_staff_user_id" "uuid", "p_staff_name" "text", "p_from_ts" timestamp with time zone, "p_to_ts" timestamp with time zone, "p_from_date" "date", "p_to_date" "date", "p_source_limit" integer DEFAULT 200) RETURNS TABLE("daily_activity" bigint, "toilet" bigint, "shower" bigint, "transportation" bigint, "blood_sugar" bigint, "photo_upload" bigint, "assessments" bigint, "time_punches" bigint, "lead_activities" bigint, "partner_activities" bigint, "activity_rows" "jsonb")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
with bounds as (
  select
    least(p_from_ts, p_to_ts) as from_ts,
    greatest(p_from_ts, p_to_ts) as to_ts,
    least(p_from_date, p_to_date) as from_date,
    greatest(p_from_date, p_to_date) as to_date,
    greatest(coalesce(p_source_limit, 200), 0) as source_limit,
    nullif(trim(p_staff_name), '') as normalized_staff_name
),
summary as (
  select
    (select count(*) from public.daily_activity_logs where staff_user_id = p_staff_user_id and created_at >= b.from_ts and created_at <= b.to_ts)::bigint as daily_activity,
    (select count(*) from public.toilet_logs where staff_user_id = p_staff_user_id and event_at >= b.from_ts and event_at <= b.to_ts)::bigint as toilet,
    (select count(*) from public.shower_logs where staff_user_id = p_staff_user_id and event_at >= b.from_ts and event_at <= b.to_ts)::bigint as shower,
    (select count(*) from public.transportation_logs where staff_user_id = p_staff_user_id and service_date >= b.from_date and service_date <= b.to_date)::bigint as transportation,
    (select count(*) from public.v_blood_sugar_logs_detailed where nurse_user_id = p_staff_user_id and checked_at >= b.from_ts and checked_at <= b.to_ts)::bigint as blood_sugar,
    (select count(*) from public.member_photo_uploads where uploaded_by = p_staff_user_id and uploaded_at >= b.from_ts and uploaded_at <= b.to_ts)::bigint as photo_upload,
    (select count(*) from public.intake_assessments where completed_by_user_id = p_staff_user_id and created_at >= b.from_ts and created_at <= b.to_ts)::bigint as assessments,
    (select count(*) from public.time_punches where staff_user_id = p_staff_user_id and punch_at >= b.from_ts and punch_at <= b.to_ts)::bigint as time_punches,
    (select count(*) from public.lead_activities where completed_by_user_id = p_staff_user_id and activity_at >= b.from_ts and activity_at <= b.to_ts)::bigint as lead_activities,
    (select count(*) from public.partner_activities where completed_by_name = b.normalized_staff_name and activity_at >= b.from_ts and activity_at <= b.to_ts)::bigint as partner_activities
  from bounds b
),
daily_rows as (
  select *
  from (
    select
      dal.id,
      'Participation Log'::text as activity_type,
      coalesce(dal.created_at, timezone('America/New_York', dal.activity_date::timestamp)) as occurred_at,
      dal.member_id,
      nullif(trim(m.display_name), '') as member_name,
      dal.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      'Participation log submitted'::text as details_summary,
      '/documentation/activity'::text as source_href,
      'daily_activity_logs'::text as source_table,
      'daily_activity'::text as source_kind
    from public.daily_activity_logs dal
    left join public.members m on m.id = dal.member_id
    left join public.profiles p on p.id = dal.staff_user_id
    cross join bounds b
    where dal.staff_user_id = p_staff_user_id
      and dal.created_at >= b.from_ts
      and dal.created_at <= b.to_ts
    order by dal.created_at desc
    limit (select source_limit from bounds)
  ) daily_rows
),
toilet_rows as (
  select *
  from (
    select
      tl.id,
      'Toilet Log'::text as activity_type,
      coalesce(tl.event_at, timezone('America/New_York', now()::timestamp)) as occurred_at,
      tl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      tl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(tl.use_type, 'Toilet') || case when tl.briefs then ' | Briefs changed' else '' end as details_summary,
      '/documentation/toilet'::text as source_href,
      'toilet_logs'::text as source_table,
      'toilet_log'::text as source_kind
    from public.toilet_logs tl
    left join public.members m on m.id = tl.member_id
    left join public.profiles p on p.id = tl.staff_user_id
    cross join bounds b
    where tl.staff_user_id = p_staff_user_id
      and tl.event_at >= b.from_ts
      and tl.event_at <= b.to_ts
    order by tl.event_at desc
    limit (select source_limit from bounds)
  ) toilet_rows
),
shower_rows as (
  select *
  from (
    select
      sl.id,
      'Shower Log'::text as activity_type,
      coalesce(sl.event_at, timezone('America/New_York', now()::timestamp)) as occurred_at,
      sl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      sl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      case when sl.laundry then 'Laundry included' else 'Shower only' end as details_summary,
      '/documentation/shower'::text as source_href,
      'shower_logs'::text as source_table,
      'shower_log'::text as source_kind
    from public.shower_logs sl
    left join public.members m on m.id = sl.member_id
    left join public.profiles p on p.id = sl.staff_user_id
    cross join bounds b
    where sl.staff_user_id = p_staff_user_id
      and sl.event_at >= b.from_ts
      and sl.event_at <= b.to_ts
    order by sl.event_at desc
    limit (select source_limit from bounds)
  ) shower_rows
),
transport_rows as (
  select *
  from (
    select
      tl.id,
      'Transportation'::text as activity_type,
      coalesce(tl.created_at, timezone('America/New_York', tl.service_date::timestamp)) as occurred_at,
      tl.member_id,
      nullif(trim(coalesce(m.display_name, tl.first_name)), '') as member_name,
      tl.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      trim(coalesce(tl.period, '') || ' ' || coalesce(tl.transport_type, 'Transportation')) as details_summary,
      '/documentation/transportation'::text as source_href,
      'transportation_logs'::text as source_table,
      'transportation'::text as source_kind
    from public.transportation_logs tl
    left join public.members m on m.id = tl.member_id
    left join public.profiles p on p.id = tl.staff_user_id
    cross join bounds b
    where tl.staff_user_id = p_staff_user_id
      and tl.service_date >= b.from_date
      and tl.service_date <= b.to_date
    order by tl.service_date desc
    limit (select source_limit from bounds)
  ) transport_rows
),
blood_rows as (
  select *
  from (
    select
      bsl.id,
      'Blood Sugar'::text as activity_type,
      bsl.checked_at as occurred_at,
      bsl.member_id,
      nullif(trim(m.display_name), '') as member_name,
      bsl.nurse_user_id as staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(bsl.reading_mg_dl::text, '0') || ' mg/dL' as details_summary,
      '/documentation/blood-sugar'::text as source_href,
      'blood_sugar_logs'::text as source_table,
      'blood_sugar'::text as source_kind
    from public.blood_sugar_logs bsl
    left join public.members m on m.id = bsl.member_id
    left join public.profiles p on p.id = bsl.nurse_user_id
    cross join bounds b
    where bsl.nurse_user_id = p_staff_user_id
      and bsl.checked_at >= b.from_ts
      and bsl.checked_at <= b.to_ts
    order by bsl.checked_at desc
    limit (select source_limit from bounds)
  ) blood_rows
),
photo_rows as (
  select *
  from (
    select
      mpu.id,
      'Photo Upload'::text as activity_type,
      mpu.uploaded_at as occurred_at,
      mpu.member_id,
      nullif(trim(m.display_name), '') as member_name,
      mpu.uploaded_by as staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      'Member photo uploaded'::text as details_summary,
      '/documentation/photo-upload'::text as source_href,
      'member_photo_uploads'::text as source_table,
      'photo_upload'::text as source_kind
    from public.member_photo_uploads mpu
    left join public.members m on m.id = mpu.member_id
    left join public.profiles p on p.id = mpu.uploaded_by
    cross join bounds b
    where mpu.uploaded_by = p_staff_user_id
      and mpu.uploaded_at >= b.from_ts
      and mpu.uploaded_at <= b.to_ts
    order by mpu.uploaded_at desc
    limit (select source_limit from bounds)
  ) photo_rows
),
punch_rows as (
  select *
  from (
    select
      tp.id,
      'Time Punch'::text as activity_type,
      tp.punch_at as occurred_at,
      null::uuid as member_id,
      case
        when tp.within_fence is null then 'Unknown'
        when tp.within_fence then 'Yes'
        else 'No'
      end as member_name,
      tp.staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      coalesce(upper(tp.punch_type::text), '') as details_summary,
      '/time-card'::text as source_href,
      'time_punches'::text as source_table,
      'time_punch'::text as source_kind
    from public.time_punches tp
    left join public.profiles p on p.id = tp.staff_user_id
    cross join bounds b
    where tp.staff_user_id = p_staff_user_id
      and tp.punch_at >= b.from_ts
      and tp.punch_at <= b.to_ts
    order by tp.punch_at desc
    limit (select source_limit from bounds)
  ) punch_rows
),
lead_rows as (
  select *
  from (
    select
      la.id,
      'Lead Activity'::text as activity_type,
      la.activity_at as occurred_at,
      null::uuid as member_id,
      nullif(trim(coalesce(la.member_name, 'Unknown Prospect')), '') as member_name,
      la.completed_by_user_id as staff_user_id,
      nullif(trim(la.completed_by_name), '') as staff_name,
      coalesce(la.activity_type, 'Activity') || coalesce(' | ' || nullif(trim(la.outcome), ''), '') as details_summary,
      case
        when la.lead_id is null then '/sales'
        else '/sales/leads/' || la.lead_id::text
      end as source_href,
      'lead_activities'::text as source_table,
      'lead_activity'::text as source_kind
    from public.lead_activities la
    cross join bounds b
    where la.completed_by_user_id = p_staff_user_id
      and la.activity_at >= b.from_ts
      and la.activity_at <= b.to_ts
    order by la.activity_at desc
    limit (select source_limit from bounds)
  ) lead_rows
),
partner_rows as (
  select *
  from (
    select
      pa.id,
      'Partner Activity'::text as activity_type,
      pa.activity_at as occurred_at,
      null::uuid as member_id,
      nullif(trim(coalesce(pa.organization_name, 'Community Partner')), '') as member_name,
      null::uuid as staff_user_id,
      nullif(trim(pa.completed_by_name), '') as staff_name,
      coalesce(pa.activity_type, 'Partner activity') as details_summary,
      '/sales/new-entries/log-partner-activities'::text as source_href,
      'partner_activities'::text as source_table,
      'partner_activity'::text as source_kind
    from public.partner_activities pa
    cross join bounds b
    where pa.completed_by_name = b.normalized_staff_name
      and pa.activity_at >= b.from_ts
      and pa.activity_at <= b.to_ts
    order by pa.activity_at desc
    limit (select source_limit from bounds)
  ) partner_rows
),
assessment_rows as (
  select *
  from (
    select
      ia.id,
      'Assessment'::text as activity_type,
      coalesce(ia.created_at, timezone('America/New_York', ia.assessment_date::timestamp)) as occurred_at,
      ia.member_id,
      nullif(trim(m.display_name), '') as member_name,
      ia.completed_by_user_id as staff_user_id,
      nullif(trim(p.full_name), '') as staff_name,
      'Intake assessment completed'::text as details_summary,
      '/health/assessment/' || ia.id::text as source_href,
      'intake_assessments'::text as source_table,
      'intake_assessment'::text as source_kind
    from public.intake_assessments ia
    left join public.members m on m.id = ia.member_id
    left join public.profiles p on p.id = ia.completed_by_user_id
    cross join bounds b
    where ia.completed_by_user_id = p_staff_user_id
      and ia.created_at >= b.from_ts
      and ia.created_at <= b.to_ts
    order by ia.created_at desc
    limit (select source_limit from bounds)
  ) assessment_rows
),
combined as (
  select * from daily_rows
  union all select * from toilet_rows
  union all select * from shower_rows
  union all select * from transport_rows
  union all select * from blood_rows
  union all select * from photo_rows
  union all select * from punch_rows
  union all select * from lead_rows
  union all select * from partner_rows
  union all select * from assessment_rows
),
row_payload as (
  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'id', combined.id,
        'activity_type', combined.activity_type,
        'occurred_at', combined.occurred_at,
        'member_id', combined.member_id,
        'member_name', combined.member_name,
        'staff_user_id', combined.staff_user_id,
        'staff_name', combined.staff_name,
        'details_summary', combined.details_summary,
        'source_href', combined.source_href,
        'source_table', combined.source_table,
        'source_kind', combined.source_kind
      )
      order by combined.occurred_at desc, combined.source_kind asc, combined.activity_type asc, combined.id asc
    ),
    '[]'::jsonb
  ) as activity_rows
  from combined
)
select
  summary.daily_activity,
  summary.toilet,
  summary.shower,
  summary.transportation,
  summary.blood_sugar,
  summary.photo_upload,
  summary.assessments,
  summary.time_punches,
  summary.lead_activities,
  summary.partner_activities,
  row_payload.activity_rows
from summary
cross join row_payload;
$$;


ALTER FUNCTION "public"."rpc_get_staff_activity_snapshot"("p_staff_user_id" "uuid", "p_staff_name" "text", "p_from_ts" timestamp with time zone, "p_to_ts" timestamp with time zone, "p_from_date" "date", "p_to_date" "date", "p_source_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_list_mar_monthly_report_member_options"() RETURNS TABLE("member_id" "uuid", "member_name" "text", "member_dob" "date", "member_identifier" "text", "member_status" "text", "active_for_workflow" boolean, "eligible_for_report" boolean)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with eligible_members as (
    select distinct m.id as member_id
    from public.members m
    where exists (
        select 1
        from public.pof_medications pm
        where pm.member_id = m.id
          and pm.member_id is not null
          and pm.given_at_center = true
      )
      or exists (
        select 1
        from public.mar_administrations ma
        where ma.member_id = m.id
          and ma.member_id is not null
      )
      or exists (
        select 1
        from public.medication_orders mo
        where mo.member_id = m.id
          and mo.member_id is not null
          and mo.order_type = 'prn'
      )
      or exists (
        select 1
        from public.med_administration_logs mal
        where mal.member_id = m.id
          and mal.member_id is not null
          and mal.admin_type = 'prn'
      )
  )
  select
    m.id as member_id,
    m.display_name as member_name,
    m.dob as member_dob,
    nullif(trim(m.qr_code), '') as member_identifier,
    nullif(trim(m.status), '') as member_status,
    (coalesce(m.status, '') = 'active') as active_for_workflow,
    (em.member_id is not null) as eligible_for_report
  from public.members m
  left join eligible_members em on em.member_id = m.id
  where coalesce(m.status, '') = 'active'
     or em.member_id is not null
  order by m.display_name asc, m.id asc;
$$;


ALTER FUNCTION "public"."rpc_list_mar_monthly_report_member_options"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_list_member_files"("p_member_id" "uuid") RETURNS TABLE("id" "text", "member_id" "uuid", "file_name" "text", "file_type" "text", "storage_object_path" "text", "category" "text", "category_other" "text", "document_source" "text", "pof_request_id" "uuid", "uploaded_by_user_id" "uuid", "uploaded_by_name" "text", "uploaded_at" timestamp with time zone, "updated_at" timestamp with time zone, "has_legacy_inline_data" boolean)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    mf.id,
    mf.member_id,
    mf.file_name,
    mf.file_type,
    mf.storage_object_path,
    mf.category,
    mf.category_other,
    mf.document_source,
    mf.pof_request_id,
    mf.uploaded_by_user_id,
    mf.uploaded_by_name,
    mf.uploaded_at,
    mf.updated_at,
    (mf.file_data_url is not null) as has_legacy_inline_data
  from public.member_files mf
  where mf.member_id = p_member_id
  order by mf.uploaded_at desc;
$$;


ALTER FUNCTION "public"."rpc_list_member_files"("p_member_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_lookup_hospital_preference_directory_normalized"("p_hospital_name" "text") RETURNS TABLE("id" "uuid", "hospital_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with normalized_input as (
    select
      nullif(btrim(coalesce(p_hospital_name, '')), '') as hospital_name_trimmed,
      lower(btrim(coalesce(p_hospital_name, ''))) as hospital_name_normalized
  )
  select
    directory.id,
    directory.hospital_name
  from public.hospital_preference_directory as directory
  cross join normalized_input as input
  where input.hospital_name_trimmed is not null
    and lower(btrim(directory.hospital_name)) = input.hospital_name_normalized;
$$;


ALTER FUNCTION "public"."rpc_lookup_hospital_preference_directory_normalized"("p_hospital_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_lookup_provider_directory_normalized"("p_provider_name" "text", "p_practice_name" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "provider_name" "text", "specialty" "text", "specialty_other" "text", "practice_name" "text", "provider_phone" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with normalized_input as (
    select
      nullif(btrim(coalesce(p_provider_name, '')), '') as provider_name_trimmed,
      lower(btrim(coalesce(p_provider_name, ''))) as provider_name_normalized,
      lower(btrim(coalesce(p_practice_name, ''))) as practice_name_normalized
  )
  select
    directory.id,
    directory.provider_name,
    directory.specialty,
    directory.specialty_other,
    directory.practice_name,
    directory.provider_phone
  from public.provider_directory as directory
  cross join normalized_input as input
  where input.provider_name_trimmed is not null
    and lower(btrim(directory.provider_name)) = input.provider_name_normalized
    and lower(btrim(coalesce(directory.practice_name, ''))) = input.practice_name_normalized;
$$;


ALTER FUNCTION "public"."rpc_lookup_provider_directory_normalized"("p_provider_name" "text", "p_practice_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_mutate_member_allergy_workflow"("p_member_id" "uuid", "p_operation" "text", "p_allergy_id" "text" DEFAULT NULL::"text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("entity_row" "jsonb", "changed" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_operation text := lower(coalesce(p_operation, ''));
  v_row public.member_allergies%rowtype;
  v_event_type text;
  v_status text;
begin
  if p_member_id is null then
    raise exception 'rpc_mutate_member_allergy_workflow requires p_member_id';
  end if;

  if v_operation not in ('create', 'update', 'delete') then
    raise exception 'rpc_mutate_member_allergy_workflow requires create/update/delete';
  end if;

  if v_operation = 'create' then
    insert into public.member_allergies (
      id,
      member_id,
      allergy_group,
      allergy_name,
      severity,
      comments,
      created_by_user_id,
      created_by_name,
      created_at,
      updated_at
    )
    values (
      'allergy-' || replace(gen_random_uuid()::text, '-', ''),
      p_member_id,
      nullif(trim(coalesce(p_payload ->> 'allergy_group', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'allergy_name', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'severity', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'comments', '')), ''),
      p_actor_user_id,
      nullif(trim(coalesce(p_actor_name, '')), ''),
      v_now,
      v_now
    )
    returning * into v_row;
  elsif v_operation = 'update' then
    update public.member_allergies
    set
      allergy_group = case when p_payload ? 'allergy_group' then nullif(trim(coalesce(p_payload ->> 'allergy_group', '')), '') else allergy_group end,
      allergy_name = case when p_payload ? 'allergy_name' then nullif(trim(coalesce(p_payload ->> 'allergy_name', '')), '') else allergy_name end,
      severity = case when p_payload ? 'severity' then nullif(trim(coalesce(p_payload ->> 'severity', '')), '') else severity end,
      comments = case when p_payload ? 'comments' then nullif(trim(coalesce(p_payload ->> 'comments', '')), '') else comments end,
      updated_at = v_now
    where id = p_allergy_id
      and member_id = p_member_id
    returning * into v_row;
  else
    delete from public.member_allergies
    where id = p_allergy_id
      and member_id = p_member_id
    returning * into v_row;
  end if;

  if v_row.id is null then
    entity_row := null;
    changed := false;
    return next;
    return;
  end if;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    p_member_id,
    v_now,
    v_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict (member_id) do update
  set
    updated_at = excluded.updated_at,
    updated_by_user_id = excluded.updated_by_user_id,
    updated_by_name = excluded.updated_by_name;

  v_event_type := case
    when v_operation = 'create' then 'member_allergy_created'
    when v_operation = 'update' then 'member_allergy_updated'
    else 'member_allergy_deleted'
  end;
  v_status := case
    when v_operation = 'create' then 'created'
    when v_operation = 'update' then 'updated'
    else 'deleted'
  end;

  insert into public.system_events (
    event_type,
    entity_type,
    entity_id,
    actor_type,
    actor_id,
    actor_user_id,
    metadata,
    status,
    severity,
    created_at
  )
  values (
    v_event_type,
    'member_allergy',
    null,
    'user',
    p_actor_user_id,
    p_actor_user_id,
    jsonb_build_object('member_id', p_member_id, 'entity_id_text', v_row.id),
    v_status,
    'low',
    v_now
  );

  entity_row := to_jsonb(v_row);
  changed := true;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_mutate_member_allergy_workflow"("p_member_id" "uuid", "p_operation" "text", "p_allergy_id" "text", "p_payload" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_mutate_member_diagnosis_workflow"("p_member_id" "uuid", "p_operation" "text", "p_diagnosis_id" "uuid" DEFAULT NULL::"uuid", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("entity_row" "jsonb", "changed" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_row public.member_diagnoses%rowtype;
  v_operation text := lower(coalesce(p_operation, ''));
  v_diagnosis_type text;
  v_event_type text;
  v_status text;
begin
  if p_member_id is null then
    raise exception 'rpc_mutate_member_diagnosis_workflow requires p_member_id';
  end if;

  if v_operation not in ('create', 'update', 'delete') then
    raise exception 'rpc_mutate_member_diagnosis_workflow requires create/update/delete';
  end if;

  perform pg_advisory_xact_lock(hashtext('mhp-diagnosis:' || p_member_id::text)::bigint);

  if v_operation = 'create' then
    select case when exists (
      select 1 from public.member_diagnoses where member_id = p_member_id
    ) then 'secondary' else 'primary' end
    into v_diagnosis_type;

    insert into public.member_diagnoses (
      member_id,
      diagnosis_type,
      diagnosis_name,
      diagnosis_code,
      date_added,
      comments,
      created_by_user_id,
      created_by_name,
      created_at,
      updated_at
    )
    values (
      p_member_id,
      v_diagnosis_type,
      nullif(trim(coalesce(p_payload ->> 'diagnosis_name', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'diagnosis_code', '')), ''),
      coalesce(nullif(p_payload ->> 'date_added', '')::date, v_now::date),
      nullif(trim(coalesce(p_payload ->> 'comments', '')), ''),
      p_actor_user_id,
      nullif(trim(coalesce(p_actor_name, '')), ''),
      v_now,
      v_now
    )
    returning * into v_row;
  elsif v_operation = 'update' then
    update public.member_diagnoses
    set
      diagnosis_name = case when p_payload ? 'diagnosis_name' then nullif(trim(coalesce(p_payload ->> 'diagnosis_name', '')), '') else diagnosis_name end,
      diagnosis_code = case when p_payload ? 'diagnosis_code' then nullif(trim(coalesce(p_payload ->> 'diagnosis_code', '')), '') else diagnosis_code end,
      date_added = case when p_payload ? 'date_added' then nullif(p_payload ->> 'date_added', '')::date else date_added end,
      comments = case when p_payload ? 'comments' then nullif(trim(coalesce(p_payload ->> 'comments', '')), '') else comments end,
      updated_at = v_now
    where id = p_diagnosis_id
      and member_id = p_member_id
    returning * into v_row;
  else
    delete from public.member_diagnoses
    where id = p_diagnosis_id
      and member_id = p_member_id
    returning * into v_row;
  end if;

  if v_row.id is null then
    entity_row := null;
    changed := false;
    return next;
    return;
  end if;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    p_member_id,
    v_now,
    v_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict (member_id) do update
  set
    updated_at = excluded.updated_at,
    updated_by_user_id = excluded.updated_by_user_id,
    updated_by_name = excluded.updated_by_name;

  v_event_type := case
    when v_operation = 'create' then 'member_diagnosis_created'
    when v_operation = 'update' then 'member_diagnosis_updated'
    else 'member_diagnosis_deleted'
  end;
  v_status := case
    when v_operation = 'create' then 'created'
    when v_operation = 'update' then 'updated'
    else 'deleted'
  end;

  insert into public.system_events (
    event_type,
    entity_type,
    entity_id,
    actor_type,
    actor_id,
    actor_user_id,
    metadata,
    status,
    severity,
    created_at
  )
  values (
    v_event_type,
    'member_diagnosis',
    v_row.id,
    'user',
    p_actor_user_id,
    p_actor_user_id,
    jsonb_build_object('member_id', p_member_id),
    v_status,
    'low',
    v_now
  );

  entity_row := to_jsonb(v_row);
  changed := true;
  return next;
end;
$$;


