$$;


ALTER FUNCTION "public"."rpc_mutate_member_note_workflow"("p_member_id" "uuid", "p_operation" "text", "p_note_id" "uuid", "p_payload" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_mutate_member_provider_workflow"("p_member_id" "uuid", "p_operation" "text", "p_provider_id" "uuid" DEFAULT NULL::"uuid", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("entity_row" "jsonb", "changed" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_operation text := lower(coalesce(p_operation, ''));
  v_row public.member_providers%rowtype;
  v_event_type text;
  v_status text;
  v_provider_name text;
  v_practice_name text;
begin
  if p_member_id is null then
    raise exception 'rpc_mutate_member_provider_workflow requires p_member_id';
  end if;

  if v_operation not in ('create', 'update', 'delete') then
    raise exception 'rpc_mutate_member_provider_workflow requires create/update/delete';
  end if;

  if v_operation = 'create' then
    insert into public.member_providers (
      member_id,
      provider_name,
      specialty,
      specialty_other,
      practice_name,
      provider_phone,
      created_by_user_id,
      created_by_name,
      created_at,
      updated_at
    )
    values (
      p_member_id,
      nullif(trim(coalesce(p_payload ->> 'provider_name', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'specialty', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'specialty_other', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'practice_name', '')), ''),
      nullif(trim(coalesce(p_payload ->> 'provider_phone', '')), ''),
      p_actor_user_id,
      nullif(trim(coalesce(p_actor_name, '')), ''),
      v_now,
      v_now
    )
    returning * into v_row;
  elsif v_operation = 'update' then
    update public.member_providers
    set
      provider_name = case when p_payload ? 'provider_name' then nullif(trim(coalesce(p_payload ->> 'provider_name', '')), '') else provider_name end,
      specialty = case when p_payload ? 'specialty' then nullif(trim(coalesce(p_payload ->> 'specialty', '')), '') else specialty end,
      specialty_other = case when p_payload ? 'specialty_other' then nullif(trim(coalesce(p_payload ->> 'specialty_other', '')), '') else specialty_other end,
      practice_name = case when p_payload ? 'practice_name' then nullif(trim(coalesce(p_payload ->> 'practice_name', '')), '') else practice_name end,
      provider_phone = case when p_payload ? 'provider_phone' then nullif(trim(coalesce(p_payload ->> 'provider_phone', '')), '') else provider_phone end,
      updated_at = v_now
    where id = p_provider_id
      and member_id = p_member_id
    returning * into v_row;
  else
    delete from public.member_providers
    where id = p_provider_id
      and member_id = p_member_id
    returning * into v_row;
  end if;

  if v_row.id is null then
    entity_row := null;
    changed := false;
    return next;
    return;
  end if;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    p_member_id,
    v_now,
    v_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict (member_id) do update
  set
    updated_at = excluded.updated_at,
    updated_by_user_id = excluded.updated_by_user_id,
    updated_by_name = excluded.updated_by_name;

  if v_operation in ('create', 'update') then
    v_provider_name := nullif(trim(coalesce(v_row.provider_name, '')), '');
    v_practice_name := nullif(trim(coalesce(v_row.practice_name, '')), '');
    if v_provider_name is not null then
      insert into public.provider_directory (
        id,
        provider_name,
        specialty,
        specialty_other,
        practice_name,
        provider_phone,
        created_by_user_id,
        created_by_name,
        created_at,
        updated_at
      )
      values (
        gen_random_uuid(),
        v_provider_name,
        nullif(trim(coalesce(v_row.specialty, '')), ''),
        nullif(trim(coalesce(v_row.specialty_other, '')), ''),
        v_practice_name,
        nullif(trim(coalesce(v_row.provider_phone, '')), ''),
        p_actor_user_id,
        nullif(trim(coalesce(p_actor_name, '')), ''),
        v_now,
        v_now
      )
      on conflict ((lower(btrim(provider_name))), (lower(btrim(coalesce(practice_name, '')))))
      do update
      set
        specialty = excluded.specialty,
        specialty_other = excluded.specialty_other,
        provider_phone = excluded.provider_phone,
        updated_at = excluded.updated_at;
    end if;
  end if;

  v_event_type := case
    when v_operation = 'create' then 'member_provider_created'
    when v_operation = 'update' then 'member_provider_updated'
    else 'member_provider_deleted'
  end;
  v_status := case
    when v_operation = 'create' then 'created'
    when v_operation = 'update' then 'updated'
    else 'deleted'
  end;

  insert into public.system_events (
    event_type,
    entity_type,
    entity_id,
    actor_type,
    actor_id,
    actor_user_id,
    metadata,
    status,
    severity,
    created_at
  )
  values (
    v_event_type,
    'member_provider',
    v_row.id,
    'user',
    p_actor_user_id,
    p_actor_user_id,
    jsonb_build_object('member_id', p_member_id),
    v_status,
    'low',
    v_now
  );

  entity_row := to_jsonb(v_row);
  changed := true;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_mutate_member_provider_workflow"("p_member_id" "uuid", "p_operation" "text", "p_provider_id" "uuid", "p_payload" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_post_transportation_run"("p_run" "jsonb", "p_result_rows" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_service_date date;
  v_shift text;
  v_bus_number text;
  v_submitted_by_user_id uuid;
  v_submitted_by_name text;
  v_submitted_at timestamptz;
  v_run_id uuid;
  v_expected_count integer := 0;
  v_posted_count integer := 0;
  v_excluded_count integer := 0;
  v_duplicate_count integer := 0;
  v_nonbillable_count integer := 0;
begin
  if jsonb_typeof(coalesce(p_result_rows, '[]'::jsonb)) <> 'array' then
    raise exception 'p_result_rows must be a JSON array';
  end if;

  v_service_date := nullif(trim(coalesce(p_run ->> 'service_date', '')), '')::date;
  v_shift := nullif(trim(coalesce(p_run ->> 'shift', '')), '');
  v_bus_number := nullif(trim(coalesce(p_run ->> 'bus_number', '')), '');
  v_submitted_by_user_id := nullif(trim(coalesce(p_run ->> 'submitted_by_user_id', '')), '')::uuid;
  v_submitted_by_name := nullif(trim(coalesce(p_run ->> 'submitted_by_name', '')), '');
  v_submitted_at := coalesce(nullif(trim(coalesce(p_run ->> 'submitted_at', '')), '')::timestamptz, now());

  if v_service_date is null then
    raise exception 'Transportation run service_date is required';
  end if;
  if v_shift not in ('AM', 'PM') then
    raise exception 'Transportation run shift must be AM or PM';
  end if;
  if v_bus_number is null then
    raise exception 'Transportation run bus_number is required';
  end if;

  create temporary table tmp_transportation_run_rows (
    member_id uuid not null,
    member_name text not null,
    first_name text,
    service_date date not null,
    shift text not null,
    bus_number text not null,
    result_status text not null,
    reason_code text,
    reason_notes text,
    rider_source text not null,
    transport_type text,
    bus_stop_name text,
    door_to_door_address text,
    caregiver_contact_id text,
    caregiver_contact_name_snapshot text,
    caregiver_contact_phone_snapshot text,
    caregiver_contact_address_snapshot text,
    transportation_billing_status_snapshot text not null,
    billable boolean not null,
    one_way_rate numeric(10,2) not null,
    round_trip_rate numeric(10,2) not null,
    posting_scope_key text
  ) on commit drop;

  insert into tmp_transportation_run_rows (
    member_id,
    member_name,
    first_name,
    service_date,
    shift,
    bus_number,
    result_status,
    reason_code,
    reason_notes,
    rider_source,
    transport_type,
    bus_stop_name,
    door_to_door_address,
    caregiver_contact_id,
    caregiver_contact_name_snapshot,
    caregiver_contact_phone_snapshot,
    caregiver_contact_address_snapshot,
    transportation_billing_status_snapshot,
    billable,
    one_way_rate,
    round_trip_rate,
    posting_scope_key
  )
  select
    row_data.member_id,
    row_data.member_name,
    row_data.first_name,
    row_data.service_date,
    row_data.shift,
    row_data.bus_number,
    row_data.result_status,
    nullif(trim(coalesce(row_data.reason_code, '')), ''),
    nullif(trim(coalesce(row_data.reason_notes, '')), ''),
    row_data.rider_source,
    nullif(trim(coalesce(row_data.transport_type, '')), ''),
    nullif(trim(coalesce(row_data.bus_stop_name, '')), ''),
    nullif(trim(coalesce(row_data.door_to_door_address, '')), ''),
    nullif(trim(coalesce(row_data.caregiver_contact_id, '')), ''),
    nullif(trim(coalesce(row_data.caregiver_contact_name_snapshot, '')), ''),
    nullif(trim(coalesce(row_data.caregiver_contact_phone_snapshot, '')), ''),
    nullif(trim(coalesce(row_data.caregiver_contact_address_snapshot, '')), ''),
    row_data.transportation_billing_status_snapshot,
    coalesce(row_data.billable, false),
    coalesce(row_data.one_way_rate, 0),
    coalesce(row_data.round_trip_rate, 0),
    nullif(trim(coalesce(row_data.posting_scope_key, '')), '')
  from jsonb_to_recordset(p_result_rows) as row_data(
    member_id uuid,
    member_name text,
    first_name text,
    service_date date,
    shift text,
    bus_number text,
    result_status text,
    reason_code text,
    reason_notes text,
    rider_source text,
    transport_type text,
    bus_stop_name text,
    door_to_door_address text,
    caregiver_contact_id text,
    caregiver_contact_name_snapshot text,
    caregiver_contact_phone_snapshot text,
    caregiver_contact_address_snapshot text,
    transportation_billing_status_snapshot text,
    billable boolean,
    one_way_rate numeric,
    round_trip_rate numeric,
    posting_scope_key text
  );

  if not exists (select 1 from tmp_transportation_run_rows) then
    raise exception 'Transportation run posting requires at least one manifest row';
  end if;

  if exists (
    select 1
    from tmp_transportation_run_rows
    where service_date <> v_service_date
       or shift <> v_shift
       or bus_number <> v_bus_number
       or result_status not in ('posted', 'excluded', 'duplicate_skipped')
       or rider_source not in ('schedule', 'manual-add')
       or transportation_billing_status_snapshot not in ('BillNormally', 'Waived', 'IncludedInProgramRate')
  ) then
    raise exception 'Transportation run payload contains invalid manifest rows';
  end if;

  insert into public.transportation_runs (
    service_date,
    shift,
    bus_number,
    status,
    submitted_by_user_id,
    submitted_by_name,
    posted_at,
    last_submitted_at,
    submission_count,
    total_expected,
    total_posted,
    total_excluded,
    total_duplicates,
    total_nonbillable,
    last_attempt_summary
  )
  values (
    v_service_date,
    v_shift,
    v_bus_number,
    'Posted',
    v_submitted_by_user_id,
    v_submitted_by_name,
    v_submitted_at,
    v_submitted_at,
    1,
    0,
    0,
    0,
    0,
    0,
    '{}'::jsonb
  )
  on conflict (service_date, shift, bus_number)
  do update set
    submitted_by_user_id = excluded.submitted_by_user_id,
    submitted_by_name = excluded.submitted_by_name,
    last_submitted_at = excluded.last_submitted_at,
    submission_count = public.transportation_runs.submission_count + 1,
    updated_at = now()
  returning id into v_run_id;

  create temporary table tmp_existing_transport_logs on commit drop as
  select
    row_data.member_id,
    row_data.service_date,
    row_data.shift,
    min(tl.id) as transport_log_id
  from tmp_transportation_run_rows as row_data
  join public.transportation_logs as tl
    on tl.member_id = row_data.member_id
   and tl.service_date = row_data.service_date
   and tl.period = row_data.shift
  group by row_data.member_id, row_data.service_date, row_data.shift;

  create temporary table tmp_transportation_logs_inserted on commit drop as
  with inserted_rows as (
    insert into public.transportation_logs (
      member_id,
      first_name,
      period,
      transport_type,
      trip_type,
      service_date,
      staff_user_id,
      billable,
      billing_status,
      billing_exclusion_reason,
      quantity,
      unit_rate,
      total_amount,
      transport_run_id,
      bus_number,
      posting_source,
      posting_scope_key,
      posted_by_user_id,
      posted_by_name,
      transportation_billing_status_snapshot,
      transport_one_way_rate_snapshot,
      transport_round_trip_rate_snapshot,
      created_at,
      updated_at
    )
    select
      row_data.member_id,
      nullif(trim(coalesce(row_data.first_name, split_part(row_data.member_name, ' ', 1))), ''),
      row_data.shift,
      row_data.transport_type,
      case when row_data.billable then 'OneWay' else 'NonBillableOperational' end,
      row_data.service_date,
      v_submitted_by_user_id,
      row_data.billable,
      case when row_data.billable then 'Unbilled' else 'Excluded' end,
      case
        when row_data.billable then null
        when row_data.transportation_billing_status_snapshot = 'Waived' then 'Waived'
        when row_data.transportation_billing_status_snapshot = 'IncludedInProgramRate' then 'IncludedInProgramRate'
        else coalesce(row_data.reason_code, 'Excluded')
      end,
      1,
      case when row_data.billable then row_data.one_way_rate else 0 end,
      case when row_data.billable then row_data.one_way_rate else 0 end,
      v_run_id,
      row_data.bus_number,
      'transportation-run-post',
      row_data.posting_scope_key,
      v_submitted_by_user_id,
      v_submitted_by_name,
      row_data.transportation_billing_status_snapshot,
      row_data.one_way_rate,
      row_data.round_trip_rate,
      v_submitted_at,
      v_submitted_at
    from tmp_transportation_run_rows as row_data
    where row_data.result_status = 'posted'
      and not exists (
        select 1
        from tmp_existing_transport_logs as existing_log
        where existing_log.member_id = row_data.member_id
          and existing_log.service_date = row_data.service_date
          and existing_log.shift = row_data.shift
      )
    on conflict (posting_scope_key) do nothing
    returning id, member_id, service_date, period, posting_scope_key
  )
  select * from inserted_rows;

  update public.transportation_logs as tl
  set trip_type = rate_payload.trip_type,
      unit_rate = rate_payload.unit_rate,
      total_amount = rate_payload.total_amount,
      updated_at = v_submitted_at
  from (
    select
      paired_logs.id,
      case when pair_summary.billable_leg_count >= 2 then 'RoundTrip' else 'OneWay' end as trip_type,
      case
        when pair_summary.billable_leg_count >= 2 and paired_logs.period = 'AM'
          then round(pair_summary.round_trip_rate / 2.0, 2)
        when pair_summary.billable_leg_count >= 2 and paired_logs.period = 'PM'
          then pair_summary.round_trip_rate - round(pair_summary.round_trip_rate / 2.0, 2)
        else pair_summary.one_way_rate
      end as unit_rate,
      case
        when pair_summary.billable_leg_count >= 2 and paired_logs.period = 'AM'
          then round(pair_summary.round_trip_rate / 2.0, 2)
        when pair_summary.billable_leg_count >= 2 and paired_logs.period = 'PM'
          then pair_summary.round_trip_rate - round(pair_summary.round_trip_rate / 2.0, 2)
        else pair_summary.one_way_rate
      end as total_amount
    from public.transportation_logs as paired_logs
    join (
      select
        member_id,
        service_date,
        max(transport_one_way_rate_snapshot) as one_way_rate,
        max(transport_round_trip_rate_snapshot) as round_trip_rate,
        count(*) filter (where billable = true and coalesce(billing_status, 'Unbilled') <> 'Billed') as billable_leg_count
      from public.transportation_logs
      where posting_source = 'transportation-run-post'
        and billable = true
        and coalesce(billing_status, 'Unbilled') <> 'Billed'
        and (member_id, service_date) in (
          select member_id, service_date
          from tmp_transportation_logs_inserted
        )
      group by member_id, service_date
    ) as pair_summary
      on pair_summary.member_id = paired_logs.member_id
     and pair_summary.service_date = paired_logs.service_date
    where paired_logs.posting_source = 'transportation-run-post'
      and paired_logs.billable = true
      and coalesce(paired_logs.billing_status, 'Unbilled') <> 'Billed'
  ) as rate_payload
  where tl.id = rate_payload.id;

  insert into public.transportation_run_results (
    run_id,
    member_id,
    service_date,
    shift,
    bus_number,
    result_status,
    reason_code,
    reason_notes,
    rider_source,
    transport_type,
    bus_stop_name,
    door_to_door_address,
    caregiver_contact_id,
    caregiver_contact_name_snapshot,
    caregiver_contact_phone_snapshot,
    caregiver_contact_address_snapshot,
    transportation_billing_status_snapshot,
    billable,
    transport_log_id,
    created_at,
    updated_at
  )
  select
    v_run_id,
    row_data.member_id,
    row_data.service_date,
    row_data.shift,
    row_data.bus_number,
    'posted',
    coalesce(row_data.reason_code, 'none'),
    row_data.reason_notes,
    row_data.rider_source,
    row_data.transport_type,
    row_data.bus_stop_name,
    row_data.door_to_door_address,
    row_data.caregiver_contact_id,
    row_data.caregiver_contact_name_snapshot,
    row_data.caregiver_contact_phone_snapshot,
    row_data.caregiver_contact_address_snapshot,
    row_data.transportation_billing_status_snapshot,
    row_data.billable,
    inserted_log.id,
    v_submitted_at,
    v_submitted_at
  from tmp_transportation_run_rows as row_data
  join tmp_transportation_logs_inserted as inserted_log
    on inserted_log.member_id = row_data.member_id
   and inserted_log.service_date = row_data.service_date
   and inserted_log.period = row_data.shift
  on conflict (run_id, member_id) do nothing;

  insert into public.transportation_run_results (
    run_id,
    member_id,
    service_date,
    shift,
    bus_number,
    result_status,
    reason_code,
    reason_notes,
    rider_source,
    transport_type,
    bus_stop_name,
    door_to_door_address,
    caregiver_contact_id,
    caregiver_contact_name_snapshot,
    caregiver_contact_phone_snapshot,
    caregiver_contact_address_snapshot,
    transportation_billing_status_snapshot,
    billable,
    transport_log_id,
    created_at,
    updated_at
  )
  select
    v_run_id,
    row_data.member_id,
    row_data.service_date,
    row_data.shift,
    row_data.bus_number,
    'excluded',
    coalesce(row_data.reason_code, 'excluded'),
    row_data.reason_notes,
    row_data.rider_source,
    row_data.transport_type,
    row_data.bus_stop_name,
    row_data.door_to_door_address,
    row_data.caregiver_contact_id,
    row_data.caregiver_contact_name_snapshot,
    row_data.caregiver_contact_phone_snapshot,
    row_data.caregiver_contact_address_snapshot,
    row_data.transportation_billing_status_snapshot,
    false,
    null,
    v_submitted_at,
    v_submitted_at
  from tmp_transportation_run_rows as row_data
  where row_data.result_status = 'excluded'
  on conflict (run_id, member_id) do nothing;

  insert into public.transportation_run_results (
    run_id,
    member_id,
    service_date,
    shift,
    bus_number,
    result_status,
    reason_code,
    reason_notes,
    rider_source,
    transport_type,
    bus_stop_name,
    door_to_door_address,
    caregiver_contact_id,
    caregiver_contact_name_snapshot,
    caregiver_contact_phone_snapshot,
    caregiver_contact_address_snapshot,
    transportation_billing_status_snapshot,
    billable,
    transport_log_id,
    created_at,
    updated_at
  )
  select
    v_run_id,
    row_data.member_id,
    row_data.service_date,
    row_data.shift,
    row_data.bus_number,
    'duplicate_skipped',
    'already-posted',
    row_data.reason_notes,
    row_data.rider_source,
    row_data.transport_type,
    row_data.bus_stop_name,
    row_data.door_to_door_address,
    row_data.caregiver_contact_id,
    row_data.caregiver_contact_name_snapshot,
    row_data.caregiver_contact_phone_snapshot,
    row_data.caregiver_contact_address_snapshot,
    row_data.transportation_billing_status_snapshot,
    false,
    existing_log.transport_log_id,
    v_submitted_at,
    v_submitted_at
  from tmp_transportation_run_rows as row_data
  left join tmp_existing_transport_logs as existing_log
    on existing_log.member_id = row_data.member_id
   and existing_log.service_date = row_data.service_date
   and existing_log.shift = row_data.shift
  where row_data.result_status = 'duplicate_skipped'
     or (
       row_data.result_status = 'posted'
       and not exists (
         select 1
         from tmp_transportation_logs_inserted as inserted_log
         where inserted_log.member_id = row_data.member_id
           and inserted_log.service_date = row_data.service_date
           and inserted_log.period = row_data.shift
       )
     )
  on conflict (run_id, member_id) do nothing;

  select count(*) into v_expected_count
  from tmp_transportation_run_rows;

  select count(*) into v_posted_count
  from tmp_transportation_logs_inserted;

  select count(*) into v_excluded_count
  from tmp_transportation_run_rows
  where result_status = 'excluded';

  select count(*) into v_duplicate_count
  from tmp_transportation_run_rows
  where result_status = 'duplicate_skipped'
     or (
       result_status = 'posted'
       and not exists (
         select 1
         from tmp_transportation_logs_inserted as inserted_log
         where inserted_log.member_id = tmp_transportation_run_rows.member_id
           and inserted_log.service_date = tmp_transportation_run_rows.service_date
           and inserted_log.period = tmp_transportation_run_rows.shift
       )
     );

  select count(*) into v_nonbillable_count
  from tmp_transportation_run_rows
  where result_status = 'posted'
    and billable = false;

  update public.transportation_runs
  set total_expected = v_expected_count,
      total_posted = v_posted_count,
      total_excluded = v_excluded_count,
      total_duplicates = v_duplicate_count,
      total_nonbillable = v_nonbillable_count,
      last_attempt_summary = jsonb_build_object(
        'expected_riders', v_expected_count,
        'posted_riders', v_posted_count,
        'excluded_riders', v_excluded_count,
        'skipped_duplicates', v_duplicate_count,
        'waived_nonbillable_riders', v_nonbillable_count
      ),
      updated_at = now()
  where id = v_run_id;

  return jsonb_build_object(
    'run_id', v_run_id,
    'expected_riders', v_expected_count,
    'posted_riders', v_posted_count,
    'excluded_riders', v_excluded_count,
    'skipped_duplicates', v_duplicate_count,
    'waived_nonbillable_riders', v_nonbillable_count
  );
end;
$$;


ALTER FUNCTION "public"."rpc_post_transportation_run"("p_run" "jsonb", "p_result_rows" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_prefill_member_command_center_from_assessment"("p_member_id" "uuid", "p_assessment_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("member_command_center_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_assessment record;
begin
  if p_member_id is null or p_assessment_id is null then
    raise exception 'rpc_prefill_member_command_center_from_assessment requires member and assessment ids';
  end if;

  select
    id,
    member_id,
    assessment_date,
    signed_at,
    code_status,
    diet_type,
    diet_other,
    diet_restrictions_notes,
    incontinence_products,
    social_triggers,
    emotional_wellness_notes,
    transport_notes,
    notes,
    total_score,
    recommended_track,
    admission_review_required
  into v_assessment
  from public.intake_assessments
  where id = p_assessment_id
  for update;

  if not found then
    raise exception 'Assessment % not found', p_assessment_id;
  end if;
  if v_assessment.member_id <> p_member_id then
    raise exception 'Assessment/member mismatch for assessment %', p_assessment_id;
  end if;

  insert into public.member_command_centers (
    id,
    member_id,
    primary_language,
    updated_by_user_id,
    updated_by_name,
    created_at,
    updated_at
  )
  values (
    'mcc-' || p_member_id::text,
    p_member_id,
    'English',
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    v_now,
    v_now
  )
  on conflict (member_id) do nothing;

  update public.member_command_centers
  set
    source_assessment_id = p_assessment_id,
    source_assessment_at = coalesce(
      (v_assessment.signed_at at time zone 'America/New_York')::date,
      v_assessment.assessment_date
    ),
    code_status = nullif(trim(coalesce(v_assessment.code_status, '')), ''),
    dnr = upper(coalesce(v_assessment.code_status, '')) = 'DNR',
    diet_type = nullif(trim(coalesce(v_assessment.diet_type, '')), ''),
    dietary_preferences_restrictions = nullif(
      concat_ws(
        ' | ',
        nullif(trim(coalesce(v_assessment.diet_restrictions_notes, '')), ''),
        nullif(trim(coalesce(v_assessment.diet_other, '')), '')
      ),
      ''
    ),
    swallowing_difficulty = nullif(trim(coalesce(v_assessment.incontinence_products, '')), ''),
    command_center_notes = nullif(
      concat_ws(
        ' | ',
        nullif(trim(coalesce(v_assessment.transport_notes, '')), ''),
        nullif(trim(coalesce(v_assessment.social_triggers, '')), ''),
        nullif(trim(coalesce(v_assessment.emotional_wellness_notes, '')), ''),
        nullif(trim(coalesce(v_assessment.notes, '')), '')
      ),
      ''
    ),
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  where member_id = p_member_id;

  update public.members
  set
    latest_assessment_id = p_assessment_id,
    latest_assessment_date = v_assessment.assessment_date,
    latest_assessment_score = v_assessment.total_score,
    latest_assessment_track = nullif(trim(coalesce(v_assessment.recommended_track, '')), ''),
    latest_assessment_admission_review_required = coalesce(v_assessment.admission_review_required, false),
    code_status = nullif(trim(coalesce(v_assessment.code_status, '')), '')
  where id = p_member_id;

  return query
  select mcc.id
  from public.member_command_centers mcc
  where mcc.member_id = p_member_id;
end;
$$;


ALTER FUNCTION "public"."rpc_prefill_member_command_center_from_assessment"("p_member_id" "uuid", "p_assessment_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_prepare_care_plan_caregiver_request"("p_care_plan_id" "uuid", "p_caregiver_name" "text", "p_caregiver_email" "text", "p_caregiver_sent_by_user_id" "uuid", "p_caregiver_signature_request_token" "text", "p_caregiver_signature_expires_at" timestamp with time zone, "p_caregiver_signature_request_url" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_updated_at" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("care_plan_id" "uuid", "caregiver_signature_status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_care_plan_id is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_care_plan_id';
  end if;
  if nullif(trim(coalesce(p_caregiver_name, '')), '') is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_caregiver_name';
  end if;
  if nullif(trim(coalesce(p_caregiver_email, '')), '') is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_caregiver_email';
  end if;
  if p_caregiver_sent_by_user_id is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_caregiver_sent_by_user_id';
  end if;
  if nullif(trim(coalesce(p_caregiver_signature_request_token, '')), '') is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_caregiver_signature_request_token';
  end if;
  if p_caregiver_signature_expires_at is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_caregiver_signature_expires_at';
  end if;
  if nullif(trim(coalesce(p_caregiver_signature_request_url, '')), '') is null then
    raise exception 'rpc_prepare_care_plan_caregiver_request requires p_caregiver_signature_request_url';
  end if;

  update public.care_plans
  set
    caregiver_name = trim(p_caregiver_name),
    caregiver_email = lower(trim(p_caregiver_email)),
    caregiver_signature_status = 'ready_to_send',
    caregiver_sent_at = null,
    caregiver_sent_by_user_id = p_caregiver_sent_by_user_id,
    caregiver_viewed_at = null,
    caregiver_signed_at = null,
    caregiver_signature_request_token = trim(p_caregiver_signature_request_token),
    caregiver_signature_expires_at = p_caregiver_signature_expires_at,
    caregiver_signature_request_url = trim(p_caregiver_signature_request_url),
    caregiver_signed_name = null,
    caregiver_signature_image_url = null,
    caregiver_signature_ip = null,
    caregiver_signature_user_agent = null,
    caregiver_signature_error = null,
    final_member_file_id = null,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = p_updated_at
  where id = p_care_plan_id;

  if not found then
    raise exception 'Care plan was not found.';
  end if;

  return query
  select
    p_care_plan_id,
    'ready_to_send'::text;
end;
$$;


ALTER FUNCTION "public"."rpc_prepare_care_plan_caregiver_request"("p_care_plan_id" "uuid", "p_caregiver_name" "text", "p_caregiver_email" "text", "p_caregiver_sent_by_user_id" "uuid", "p_caregiver_signature_request_token" "text", "p_caregiver_signature_expires_at" timestamp with time zone, "p_caregiver_signature_request_url" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_updated_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_prepare_enrollment_packet_request"("p_member_id" "uuid", "p_sender_user_id" "uuid", "p_caregiver_email" "text", "p_token" "text", "p_token_expires_at" timestamp with time zone, "p_requested_days" "text"[], "p_transportation" "text", "p_community_fee" numeric, "p_daily_rate" numeric, "p_signature_name" "text", "p_signature_blob" "text", "p_packet_id" "uuid" DEFAULT NULL::"uuid", "p_lead_id" "uuid" DEFAULT NULL::"uuid", "p_pricing_community_fee_id" "uuid" DEFAULT NULL::"uuid", "p_pricing_daily_rate_id" "uuid" DEFAULT NULL::"uuid", "p_pricing_snapshot" "jsonb" DEFAULT '{}'::"jsonb", "p_caregiver_name" "text" DEFAULT NULL::"text", "p_caregiver_phone" "text" DEFAULT NULL::"text", "p_intake_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_sender_email" "text" DEFAULT NULL::"text", "p_prepared_at" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("packet_id" "uuid", "was_created" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_packet_id uuid := coalesce(p_packet_id, gen_random_uuid());
begin
  if p_member_id is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_member_id';
  end if;
  if p_sender_user_id is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_sender_user_id';
  end if;
  if nullif(trim(coalesce(p_caregiver_email, '')), '') is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_caregiver_email';
  end if;
  if nullif(trim(coalesce(p_token, '')), '') is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_token';
  end if;
  if p_token_expires_at is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_token_expires_at';
  end if;
  if nullif(trim(coalesce(p_signature_name, '')), '') is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_signature_name';
  end if;
  if nullif(trim(coalesce(p_signature_blob, '')), '') is null then
    raise exception 'rpc_prepare_enrollment_packet_request requires p_signature_blob';
  end if;

  if p_packet_id is null then
    insert into public.enrollment_packet_requests (
      id,
      member_id,
      lead_id,
      sender_user_id,
      caregiver_email,
      status,
      delivery_status,
      token,
      token_expires_at,
      sent_at,
      opened_at,
      last_family_activity_at,
      completed_at,
      voided_at,
      voided_by_user_id,
      void_reason,
      delivery_error,
      delivery_failed_at,
      created_at,
      updated_at
    )
    values (
      v_packet_id,
      p_member_id,
      p_lead_id,
      p_sender_user_id,
      lower(trim(p_caregiver_email)),
      'draft',
      'ready_to_send',
      trim(p_token),
      p_token_expires_at,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      p_prepared_at,
      p_prepared_at
    );
    was_created := true;
  else
    update public.enrollment_packet_requests
    set
      member_id = p_member_id,
      lead_id = p_lead_id,
      sender_user_id = p_sender_user_id,
      caregiver_email = lower(trim(p_caregiver_email)),
      status = 'draft',
      delivery_status = 'ready_to_send',
      token = trim(p_token),
      token_expires_at = p_token_expires_at,
      sent_at = null,
      opened_at = null,
      last_family_activity_at = null,
      completed_at = null,
      voided_at = null,
      voided_by_user_id = null,
      void_reason = null,
      delivery_error = null,
      delivery_failed_at = null,
      updated_at = p_prepared_at
    where id = v_packet_id;

    if not found then
      raise exception 'Enrollment packet request % was not found.', v_packet_id;
    end if;
    was_created := false;
  end if;

  insert into public.enrollment_packet_fields (
    packet_id,
    requested_days,
    transportation,
    community_fee,
    daily_rate,
    pricing_community_fee_id,
    pricing_daily_rate_id,
    pricing_snapshot,
    caregiver_name,
    caregiver_phone,
    caregiver_email,
    intake_payload,
    updated_at
  )
  values (
    v_packet_id,
    coalesce(p_requested_days, array[]::text[]),
    p_transportation,
    p_community_fee,
    p_daily_rate,
    p_pricing_community_fee_id,
    p_pricing_daily_rate_id,
    coalesce(p_pricing_snapshot, '{}'::jsonb),
    nullif(trim(coalesce(p_caregiver_name, '')), ''),
    nullif(trim(coalesce(p_caregiver_phone, '')), ''),
    lower(trim(p_caregiver_email)),
    coalesce(p_intake_payload, '{}'::jsonb),
    p_prepared_at
  )
  on conflict on constraint enrollment_packet_fields_packet_id_key
  do update
  set
    requested_days = excluded.requested_days,
    transportation = excluded.transportation,
    community_fee = excluded.community_fee,
    daily_rate = excluded.daily_rate,
    pricing_community_fee_id = excluded.pricing_community_fee_id,
    pricing_daily_rate_id = excluded.pricing_daily_rate_id,
    pricing_snapshot = excluded.pricing_snapshot,
    caregiver_name = excluded.caregiver_name,
    caregiver_phone = excluded.caregiver_phone,
    caregiver_email = excluded.caregiver_email,
    intake_payload = excluded.intake_payload,
    updated_at = excluded.updated_at;

  insert into public.enrollment_packet_signatures (
    packet_id,
    signer_name,
    signer_email,
    signer_role,
    signature_blob,
    ip_address,
    signed_at,
    created_at,
    updated_at
  )
  values (
    v_packet_id,
    trim(p_signature_name),
    lower(nullif(trim(coalesce(p_sender_email, '')), '')),
    'sender_staff',
    trim(p_signature_blob),
    null,
    p_prepared_at,
    p_prepared_at,
    p_prepared_at
  );

  packet_id := v_packet_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_prepare_enrollment_packet_request"("p_member_id" "uuid", "p_sender_user_id" "uuid", "p_caregiver_email" "text", "p_token" "text", "p_token_expires_at" timestamp with time zone, "p_requested_days" "text"[], "p_transportation" "text", "p_community_fee" numeric, "p_daily_rate" numeric, "p_signature_name" "text", "p_signature_blob" "text", "p_packet_id" "uuid", "p_lead_id" "uuid", "p_pricing_community_fee_id" "uuid", "p_pricing_daily_rate_id" "uuid", "p_pricing_snapshot" "jsonb", "p_caregiver_name" "text", "p_caregiver_phone" "text", "p_intake_payload" "jsonb", "p_sender_email" "text", "p_prepared_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_prepare_pof_request_delivery"("p_physician_order_id" "uuid", "p_member_id" "uuid", "p_provider_name" "text", "p_provider_email" "text", "p_nurse_name" "text", "p_from_email" "text", "p_sent_by_user_id" "uuid", "p_expires_at" timestamp with time zone, "p_signature_request_token" "text", "p_signature_request_url" "text", "p_unsigned_pdf_url" "text", "p_pof_payload_json" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_request_id" "uuid" DEFAULT NULL::"uuid", "p_optional_message" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("request_id" "uuid", "was_created" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request_id uuid := coalesce(p_request_id, gen_random_uuid());
begin
  if p_physician_order_id is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_physician_order_id';
  end if;
  if p_member_id is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_member_id';
  end if;
  if nullif(trim(coalesce(p_provider_name, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_provider_name';
  end if;
  if nullif(trim(coalesce(p_provider_email, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_provider_email';
  end if;
  if nullif(trim(coalesce(p_nurse_name, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_nurse_name';
  end if;
  if nullif(trim(coalesce(p_from_email, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_from_email';
  end if;
  if p_sent_by_user_id is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_sent_by_user_id';
  end if;
  if p_expires_at is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_expires_at';
  end if;
  if nullif(trim(coalesce(p_signature_request_token, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_signature_request_token';
  end if;
  if nullif(trim(coalesce(p_signature_request_url, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_signature_request_url';
  end if;
  if nullif(trim(coalesce(p_unsigned_pdf_url, '')), '') is null then
    raise exception 'rpc_prepare_pof_request_delivery requires p_unsigned_pdf_url';
  end if;

  if p_request_id is not null then
    update public.pof_requests
    set
      physician_order_id = p_physician_order_id,
      member_id = p_member_id,
      provider_name = trim(p_provider_name),
      provider_email = trim(p_provider_email),
      nurse_name = trim(p_nurse_name),
      from_email = trim(p_from_email),
      sent_by_user_id = p_sent_by_user_id,
      status = 'draft',
      delivery_status = 'ready_to_send',
      optional_message = nullif(trim(coalesce(p_optional_message, '')), ''),
      sent_at = null,
      opened_at = null,
      signed_at = null,
      expires_at = p_expires_at,
      signature_request_token = trim(p_signature_request_token),
      signature_request_url = trim(p_signature_request_url),
      unsigned_pdf_url = trim(p_unsigned_pdf_url),
      pof_payload_json = coalesce(p_pof_payload_json, '{}'::jsonb),
      updated_by_user_id = p_actor_user_id,
      updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
      updated_at = p_now,
      delivery_error = null,
      delivery_failed_at = null,
      last_delivery_attempt_at = p_now
    where id = v_request_id;

    if found then
      was_created := false;
      request_id := v_request_id;
      return next;
      return;
    end if;
  end if;

  insert into public.pof_requests (
    id,
    physician_order_id,
    member_id,
    provider_name,
    provider_email,
    nurse_name,
    from_email,
    sent_by_user_id,
    status,
    delivery_status,
    optional_message,
    sent_at,
    opened_at,
    signed_at,
    expires_at,
    signature_request_token,
    signature_request_url,
    unsigned_pdf_url,
    signed_pdf_url,
    pof_payload_json,
    member_file_id,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_by_user_id,
    updated_by_name,
    updated_at,
    delivery_error,
    delivery_failed_at,
    last_delivery_attempt_at
  )
  values (
    v_request_id,
    p_physician_order_id,
    p_member_id,
    trim(p_provider_name),
    trim(p_provider_email),
    trim(p_nurse_name),
    trim(p_from_email),
    p_sent_by_user_id,
    'draft',
    'ready_to_send',
    nullif(trim(coalesce(p_optional_message, '')), ''),
    null,
    null,
    null,
    p_expires_at,
    trim(p_signature_request_token),
    trim(p_signature_request_url),
    trim(p_unsigned_pdf_url),
    null,
    coalesce(p_pof_payload_json, '{}'::jsonb),
    null,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    p_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    p_now,
    null,
    null,
    p_now
  );
  was_created := true;

  request_id := v_request_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_prepare_pof_request_delivery"("p_physician_order_id" "uuid", "p_member_id" "uuid", "p_provider_name" "text", "p_provider_email" "text", "p_nurse_name" "text", "p_from_email" "text", "p_sent_by_user_id" "uuid", "p_expires_at" timestamp with time zone, "p_signature_request_token" "text", "p_signature_request_url" "text", "p_unsigned_pdf_url" "text", "p_pof_payload_json" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_request_id" "uuid", "p_optional_message" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_reconcile_member_mar_state"("p_member_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_preferred_physician_order_id" "uuid" DEFAULT NULL::"uuid", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("anchor_physician_order_id" "uuid", "synced_medications" integer, "inserted_schedules" integer, "patched_schedules" integer, "reactivated_schedules" integer, "deactivated_schedules" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_start_date date := least(p_start_date, p_end_date);
  v_end_date date := greatest(p_start_date, p_end_date);
  v_start_ts timestamptz;
  v_end_ts timestamptz;
begin
  if p_member_id is null or p_start_date is null or p_end_date is null then
    raise exception 'rpc_reconcile_member_mar_state requires member, start date, and end date';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_member_id::text)::bigint);

  select
    sync.anchor_physician_order_id,
    sync.synced_medications
  into
    anchor_physician_order_id,
    synced_medications
  from public.rpc_sync_mar_medications_from_member_profile(
    p_member_id,
    p_preferred_physician_order_id,
    v_now
  ) as sync;

  v_start_ts := (v_start_date::text || ' 00:00:00 America/New_York')::timestamptz;
  v_end_ts := (v_end_date::text || ' 23:59:00 America/New_York')::timestamptz;

  create temporary table if not exists tmp_expected_mar_rows (
    pof_medication_id uuid not null,
    medication_name text not null,
    dose text,
    route text,
    scheduled_time timestamptz not null,
    frequency text,
    instructions text,
    prn boolean not null,
    start_date date,
    end_date date
  ) on commit drop;
  truncate table tmp_expected_mar_rows;

  insert into tmp_expected_mar_rows (
    pof_medication_id,
    medication_name,
    dose,
    route,
    scheduled_time,
    frequency,
    instructions,
    prn,
    start_date,
    end_date
  )
  select
    pm.id,
    pm.medication_name,
    pm.dose,
    pm.route,
    (((generated_day::date)::text || 'T' || scheduled_time.value)::timestamp at time zone 'America/New_York'),
    pm.frequency,
    pm.instructions,
    pm.prn,
    pm.start_date,
    pm.end_date
  from public.pof_medications pm
  cross join lateral unnest(pm.scheduled_times) as scheduled_time(value)
  cross join lateral generate_series(
    greatest(coalesce(pm.start_date, v_start_date), v_start_date),
    least(coalesce(pm.end_date, v_end_date), v_end_date),
    interval '1 day'
  ) as generated_day
  where pm.member_id = p_member_id
    and pm.active = true
    and pm.given_at_center = true
    and pm.prn = false
    and pm.source_medication_id like 'mhp-%'
    and array_length(pm.scheduled_times, 1) is not null;

  create temporary table if not exists tmp_documented_mar_schedule_ids (
    id uuid primary key
  ) on commit drop;
  truncate table tmp_documented_mar_schedule_ids;

  insert into tmp_documented_mar_schedule_ids (id)
  select distinct ms.id
  from public.mar_schedules ms
  join public.mar_administrations ma
    on ma.mar_schedule_id = ms.id
  where ms.member_id = p_member_id
    and ms.scheduled_time >= v_start_ts
    and ms.scheduled_time <= v_end_ts;

  with inserted as (
    insert into public.mar_schedules (
      member_id,
      pof_medication_id,
      medication_name,
      dose,
      route,
      scheduled_time,
      frequency,
      instructions,
      prn,
      active,
      start_date,
      end_date,
      created_at,
      updated_at
    )
    select
      p_member_id,
      expected.pof_medication_id,
      expected.medication_name,
      expected.dose,
      expected.route,
      expected.scheduled_time,
      expected.frequency,
      expected.instructions,
      expected.prn,
      true,
      expected.start_date,
      expected.end_date,
      v_now,
      v_now
    from tmp_expected_mar_rows expected
    left join public.mar_schedules existing
      on existing.member_id = p_member_id
     and existing.pof_medication_id = expected.pof_medication_id
     and existing.scheduled_time = expected.scheduled_time
    where existing.id is null
    on conflict (member_id, pof_medication_id, scheduled_time) do nothing
    returning 1
  )
  select count(*) into inserted_schedules from inserted;

  with patched as (
    update public.mar_schedules ms
    set
      medication_name = expected.medication_name,
      dose = expected.dose,
      route = expected.route,
      frequency = expected.frequency,
      instructions = expected.instructions,
      prn = expected.prn,
      start_date = expected.start_date,
      end_date = expected.end_date,
      updated_at = v_now
    from tmp_expected_mar_rows expected
    where ms.member_id = p_member_id
      and ms.pof_medication_id = expected.pof_medication_id
      and ms.scheduled_time = expected.scheduled_time
      and not exists (
        select 1 from tmp_documented_mar_schedule_ids documented where documented.id = ms.id
      )
      and (
        coalesce(ms.medication_name, '') <> coalesce(expected.medication_name, '')
        or coalesce(ms.dose, '') <> coalesce(expected.dose, '')
        or coalesce(ms.route, '') <> coalesce(expected.route, '')
        or coalesce(ms.frequency, '') <> coalesce(expected.frequency, '')
        or coalesce(ms.instructions, '') <> coalesce(expected.instructions, '')
        or coalesce(ms.prn, false) <> coalesce(expected.prn, false)
        or coalesce(ms.start_date, date '1900-01-01') <> coalesce(expected.start_date, date '1900-01-01')
        or coalesce(ms.end_date, date '1900-01-01') <> coalesce(expected.end_date, date '1900-01-01')
      )
    returning ms.id
  )
  select count(*) into patched_schedules from patched;

  with reactivated as (
    update public.mar_schedules ms
    set
      active = true,
      updated_at = v_now
    from tmp_expected_mar_rows expected
    where ms.member_id = p_member_id
      and ms.pof_medication_id = expected.pof_medication_id
      and ms.scheduled_time = expected.scheduled_time
      and ms.active = false
      and not exists (
        select 1 from tmp_documented_mar_schedule_ids documented where documented.id = ms.id
      )
    returning ms.id
  )
  select count(*) into reactivated_schedules from reactivated;

  with deactivated as (
    update public.mar_schedules ms
    set
      active = false,
      updated_at = v_now
    where ms.member_id = p_member_id
      and ms.active = true
      and ms.scheduled_time >= v_start_ts
      and ms.scheduled_time <= v_end_ts
      and not exists (
        select 1 from tmp_documented_mar_schedule_ids documented where documented.id = ms.id
      )
      and not exists (
        select 1
        from tmp_expected_mar_rows expected
        where expected.pof_medication_id = ms.pof_medication_id
          and expected.scheduled_time = ms.scheduled_time
      )
    returning ms.id
  )
  select count(*) into deactivated_schedules from deactivated;

  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_reconcile_member_mar_state"("p_member_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_preferred_physician_order_id" "uuid", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_record_care_plan_snapshot"("p_care_plan_id" "uuid", "p_snapshot_type" "text", "p_snapshot_date" "date", "p_reviewed_by" "text", "p_status" "text", "p_next_due_date" "date", "p_no_changes_needed" boolean, "p_modifications_required" boolean, "p_modifications_description" "text", "p_care_team_notes" "text", "p_sections_snapshot" "jsonb", "p_review_date" "date" DEFAULT NULL::"date", "p_review_summary" "text" DEFAULT NULL::"text", "p_review_changes_made" boolean DEFAULT NULL::boolean) RETURNS TABLE("version_id" "uuid", "version_number" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_care_plan public.care_plans%rowtype;
  v_version_id uuid;
  v_version_number integer;
  v_created_at timestamptz := now();
begin
  if p_care_plan_id is null then
    raise exception 'care plan id is required';
  end if;
  if nullif(trim(coalesce(p_snapshot_type, '')), '') is null then
    raise exception 'snapshot type is required';
  end if;
  if p_snapshot_date is null then
    raise exception 'snapshot date is required';
  end if;
  if nullif(trim(coalesce(p_status, '')), '') is null then
    raise exception 'status is required';
  end if;
  if p_next_due_date is null then
    raise exception 'next due date is required';
  end if;
  if p_sections_snapshot is null then
    raise exception 'sections snapshot is required';
  end if;

  select *
  into v_care_plan
  from public.care_plans
  where id = p_care_plan_id
  for update;

  if not found then
    raise exception 'Care plan % was not found.', p_care_plan_id;
  end if;

  select coalesce(max(cp.version_number), 0) + 1
  into v_version_number
  from public.care_plan_versions cp
  where cp.care_plan_id = p_care_plan_id;

  insert into public.care_plan_versions (
    care_plan_id,
    version_number,
    snapshot_type,
    snapshot_date,
    reviewed_by,
    status,
    next_due_date,
    no_changes_needed,
    modifications_required,
    modifications_description,
    care_team_notes,
    sections_snapshot,
    created_at
  )
  values (
    p_care_plan_id,
    v_version_number,
    p_snapshot_type,
    p_snapshot_date,
    nullif(trim(coalesce(p_reviewed_by, '')), ''),
    p_status,
    p_next_due_date,
    coalesce(p_no_changes_needed, false),
    coalesce(p_modifications_required, false),
    coalesce(p_modifications_description, ''),
    coalesce(p_care_team_notes, ''),
    p_sections_snapshot,
    v_created_at
  )
  returning id into v_version_id;

  if p_review_date is not null then
    insert into public.care_plan_review_history (
      care_plan_id,
      review_date,
      reviewed_by,
      summary,
      changes_made,
      next_due_date,
      version_id,
      created_at
    )
    values (
      p_care_plan_id,
      p_review_date,
      nullif(trim(coalesce(p_reviewed_by, '')), ''),
      coalesce(p_review_summary, ''),
      coalesce(p_review_changes_made, false),
      p_next_due_date,
      v_version_id,
      v_created_at
    );
  end if;

  return query
  select
    v_version_id,
    v_version_number;
end;
$$;


ALTER FUNCTION "public"."rpc_record_care_plan_snapshot"("p_care_plan_id" "uuid", "p_snapshot_type" "text", "p_snapshot_date" "date", "p_reviewed_by" "text", "p_status" "text", "p_next_due_date" "date", "p_no_changes_needed" boolean, "p_modifications_required" boolean, "p_modifications_description" "text", "p_care_team_notes" "text", "p_sections_snapshot" "jsonb", "p_review_date" "date", "p_review_summary" "text", "p_review_changes_made" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_record_prn_medication_administration"("p_medication_order_id" "uuid", "p_admin_datetime" timestamp with time zone, "p_dose_given" "text" DEFAULT NULL::"text", "p_route_given" "text" DEFAULT NULL::"text", "p_indication" "text" DEFAULT NULL::"text", "p_symptom_score_before" integer DEFAULT NULL::integer, "p_followup_due_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_status" "text" DEFAULT 'Given'::"text", "p_notes" "text" DEFAULT NULL::"text", "p_administered_by" "uuid" DEFAULT NULL::"uuid", "p_administered_by_name" "text" DEFAULT NULL::"text", "p_idempotency_key" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("log_id" "uuid", "member_id" "uuid", "medication_order_id" "uuid", "followup_due_at" timestamp with time zone, "followup_status" "text", "duplicate_safe" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_admin_datetime timestamptz := coalesce(p_admin_datetime, v_now);
  v_status text := coalesce(nullif(trim(p_status), ''), 'Given');
  v_order public.medication_orders%rowtype;
  v_existing_id uuid;
  v_last_given timestamptz;
  v_given_count integer := 0;
  v_current_dose numeric;
  v_previous_total numeric := 0;
  v_followup_due_at timestamptz;
begin
  if p_medication_order_id is null then
    raise exception 'PRN administration requires medication_order_id';
  end if;

  if v_status not in ('Given', 'Refused', 'Held', 'Omitted') then
    raise exception 'PRN administration status must be Given, Refused, Held, or Omitted';
  end if;

  if p_symptom_score_before is not null and (p_symptom_score_before < 0 or p_symptom_score_before > 10) then
    raise exception 'Symptom score must be between 0 and 10.';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_medication_order_id::text)::bigint);

  if nullif(trim(coalesce(p_idempotency_key, '')), '') is not null then
    select logs.id
    into v_existing_id
    from public.med_administration_logs logs
    where logs.idempotency_key = p_idempotency_key
    limit 1;

    if v_existing_id is not null then
      select
        logs.id,
        logs.member_id,
        logs.medication_order_id,
        logs.followup_due_at,
        logs.followup_status,
        true
      into
        log_id,
        member_id,
        medication_order_id,
        followup_due_at,
        followup_status,
        duplicate_safe
      from public.med_administration_logs logs
      where logs.id = v_existing_id;
      return next;
      return;
    end if;
  end if;

  select *
  into v_order
  from public.medication_orders
  where id = p_medication_order_id;

  if v_order.id is null then
    raise exception 'Selected PRN medication order was not found.';
  end if;

  if v_order.order_type <> 'prn' then
    raise exception 'Selected medication order is not a PRN order.';
  end if;

  if v_order.status <> 'active' then
    raise exception 'The selected PRN medication order is no longer active.';
  end if;

  if v_order.start_date is not null and v_admin_datetime::date < v_order.start_date then
    raise exception 'The selected PRN medication order is not active yet.';
  end if;

  if v_order.end_date is not null and v_admin_datetime::date > v_order.end_date then
    raise exception 'The selected PRN medication order has expired.';
  end if;

  if nullif(trim(coalesce(p_indication, '')), '') is null then
    raise exception 'Indication is required for PRN administration.';
  end if;

  if v_status = 'Given' then
    if v_order.min_interval_minutes is not null then
      select max(logs.admin_datetime)
      into v_last_given
      from public.med_administration_logs logs
      where logs.medication_order_id = v_order.id
        and logs.status = 'Given';

      if v_last_given is not null and v_admin_datetime < v_last_given + make_interval(mins => v_order.min_interval_minutes) then
        raise exception 'Minimum PRN interval has not been met for this medication order.';
      end if;
    end if;

    if v_order.max_doses_per_24h is not null then
      select count(*)
      into v_given_count
      from public.med_administration_logs logs
      where logs.medication_order_id = v_order.id
        and logs.status = 'Given'
        and logs.admin_datetime > v_admin_datetime - interval '24 hours'
        and logs.admin_datetime <= v_admin_datetime;

      if v_given_count >= v_order.max_doses_per_24h then
        raise exception 'Maximum PRN doses in 24 hours would be exceeded for this medication order.';
      end if;
    end if;

    if v_order.max_daily_dose is not null then
      v_current_dose := nullif(regexp_replace(coalesce(p_dose_given, ''), '[^0-9\.]+', '', 'g'), '')::numeric;

      if v_current_dose is not null then
        select coalesce(sum(nullif(regexp_replace(coalesce(logs.dose_given, ''), '[^0-9\.]+', '', 'g'), '')::numeric), 0)
        into v_previous_total
        from public.med_administration_logs logs
        where logs.medication_order_id = v_order.id
          and logs.status = 'Given'
          and logs.admin_datetime > v_admin_datetime - interval '24 hours'
          and logs.admin_datetime <= v_admin_datetime;

        if v_previous_total + v_current_dose > v_order.max_daily_dose then
          raise exception 'Maximum PRN daily dose would be exceeded for this medication order.';
        end if;
      end if;
    end if;
  end if;

  if v_status = 'Given' and v_order.requires_effectiveness_followup then
    v_followup_due_at := coalesce(p_followup_due_at, v_admin_datetime + interval '1 hour');
    followup_status := case when v_followup_due_at < v_now then 'overdue' else 'due' end;
  else
    v_followup_due_at := null;
    followup_status := 'not_required';
  end if;

  insert into public.med_administration_logs as logs (
    member_id,
    medication_order_id,
    admin_type,
    admin_datetime,
    dose_given,
    route_given,
    indication,
    symptom_score_before,
    followup_due_at,
    followup_status,
    effectiveness_result,
    followup_notes,
    administered_by,
    administered_by_name,
    status,
    notes,
    idempotency_key,
    created_at,
    updated_at
  )
  values (
    v_order.member_id,
    v_order.id,
    'prn',
    v_admin_datetime,
    nullif(trim(coalesce(p_dose_given, '')), ''),
    nullif(trim(coalesce(p_route_given, '')), ''),
    nullif(trim(coalesce(p_indication, '')), ''),
    p_symptom_score_before,
    v_followup_due_at,
    followup_status,
    null,
    null,
    p_administered_by,
    nullif(trim(coalesce(p_administered_by_name, '')), ''),
    v_status,
    nullif(trim(coalesce(p_notes, '')), ''),
    nullif(trim(coalesce(p_idempotency_key, '')), ''),
    v_now,
    v_now
  )
  returning
    logs.id,
    logs.member_id,
    logs.medication_order_id
  into
    log_id,
    member_id,
    medication_order_id;

  duplicate_safe := false;
  followup_due_at := v_followup_due_at;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_record_prn_medication_administration"("p_medication_order_id" "uuid", "p_admin_datetime" timestamp with time zone, "p_dose_given" "text", "p_route_given" "text", "p_indication" "text", "p_symptom_score_before" integer, "p_followup_due_at" timestamp with time zone, "p_status" "text", "p_notes" "text", "p_administered_by" "uuid", "p_administered_by_name" "text", "p_idempotency_key" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_run_signed_pof_post_sign_sync"("p_pof_id" "uuid", "p_sync_timestamp" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("member_id" "uuid", "member_health_profile_id" "uuid", "member_command_center_id" "text", "anchor_physician_order_id" "uuid", "synced_medications" integer, "inserted_schedules" integer, "patched_schedules" integer, "reactivated_schedules" integer, "deactivated_schedules" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order public.physician_orders%rowtype;
  v_sync_timestamp timestamptz := coalesce(p_sync_timestamp, now());
  v_schedule_start_date date;
  v_schedule_end_date date;
begin
  if p_pof_id is null then
    raise exception 'rpc_run_signed_pof_post_sign_sync requires p_pof_id';
  end if;

  select *
  into v_order
  from public.physician_orders as physician_orders
  where physician_orders.id = p_pof_id
  for update;

  if not found then
    raise exception 'Signed physician order % was not found for post-sign sync.', p_pof_id;
  end if;

  if coalesce(lower(v_order.status), '') <> 'signed' then
    raise exception 'Signed POF post-sign sync requires status=signed. Current status=%', coalesce(v_order.status, 'null');
  end if;

  perform pg_advisory_xact_lock(hashtext(v_order.member_id::text)::bigint);

  v_schedule_start_date := (v_sync_timestamp at time zone 'America/New_York')::date;
  v_schedule_end_date := v_schedule_start_date + 30;

  begin
    select
      sync.member_id,
      sync.member_health_profile_id,
      sync.member_command_center_id
    into
      member_id,
      member_health_profile_id,
      member_command_center_id
    from public.rpc_sync_signed_pof_to_member_clinical_profile(
      p_pof_id => p_pof_id,
      p_synced_at => v_sync_timestamp
    ) as sync;
  exception
    when others then
      raise exception 'mhp_mcc:%', SQLERRM using errcode = SQLSTATE;
  end;

  begin
    select
      reconcile.anchor_physician_order_id,
      reconcile.synced_medications,
      reconcile.inserted_schedules,
      reconcile.patched_schedules,
      reconcile.reactivated_schedules,
      reconcile.deactivated_schedules
    into
      anchor_physician_order_id,
      synced_medications,
      inserted_schedules,
      patched_schedules,
      reactivated_schedules,
      deactivated_schedules
    from public.rpc_reconcile_member_mar_state(
      p_member_id => v_order.member_id,
      p_start_date => v_schedule_start_date,
      p_end_date => v_schedule_end_date,
      p_preferred_physician_order_id => p_pof_id,
      p_now => v_sync_timestamp
    ) as reconcile;
  exception
    when others then
      raise exception 'mar_schedules:%', SQLERRM using errcode = SQLSTATE;
  end;

  if member_id is null or member_health_profile_id is null then
    raise exception 'Signed POF post-sign sync did not return canonical member/MHP identifiers for %.', p_pof_id;
  end if;

  if anchor_physician_order_id is null then
    raise exception 'Signed POF post-sign sync did not return a MAR anchor physician order for %.', p_pof_id;
  end if;

  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_run_signed_pof_post_sign_sync"("p_pof_id" "uuid", "p_sync_timestamp" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_save_enrollment_packet_progress"("p_packet_id" "uuid", "p_caregiver_name" "text" DEFAULT NULL::"text", "p_caregiver_phone" "text" DEFAULT NULL::"text", "p_caregiver_email" "text" DEFAULT NULL::"text", "p_caregiver_address_line1" "text" DEFAULT NULL::"text", "p_caregiver_address_line2" "text" DEFAULT NULL::"text", "p_caregiver_city" "text" DEFAULT NULL::"text", "p_caregiver_state" "text" DEFAULT NULL::"text", "p_caregiver_zip" "text" DEFAULT NULL::"text", "p_secondary_contact_name" "text" DEFAULT NULL::"text", "p_secondary_contact_phone" "text" DEFAULT NULL::"text", "p_secondary_contact_email" "text" DEFAULT NULL::"text", "p_secondary_contact_relationship" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_intake_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_updated_at" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("packet_id" "uuid", "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.enrollment_packet_requests%rowtype;
begin
  if p_packet_id is null then
    raise exception 'rpc_save_enrollment_packet_progress requires p_packet_id';
  end if;

  update public.enrollment_packet_fields as epf
  set
    caregiver_name = nullif(trim(coalesce(p_caregiver_name, '')), ''),
    caregiver_phone = nullif(trim(coalesce(p_caregiver_phone, '')), ''),
    caregiver_email = lower(nullif(trim(coalesce(p_caregiver_email, '')), '')),
    caregiver_address_line1 = nullif(trim(coalesce(p_caregiver_address_line1, '')), ''),
    caregiver_address_line2 = nullif(trim(coalesce(p_caregiver_address_line2, '')), ''),
    caregiver_city = nullif(trim(coalesce(p_caregiver_city, '')), ''),
    caregiver_state = nullif(trim(coalesce(p_caregiver_state, '')), ''),
    caregiver_zip = nullif(trim(coalesce(p_caregiver_zip, '')), ''),
    secondary_contact_name = nullif(trim(coalesce(p_secondary_contact_name, '')), ''),
    secondary_contact_phone = nullif(trim(coalesce(p_secondary_contact_phone, '')), ''),
    secondary_contact_email = lower(nullif(trim(coalesce(p_secondary_contact_email, '')), '')),
    secondary_contact_relationship = nullif(trim(coalesce(p_secondary_contact_relationship, '')), ''),
    notes = nullif(trim(coalesce(p_notes, '')), ''),
    intake_payload = coalesce(p_intake_payload, '{}'::jsonb),
    updated_at = p_updated_at
  where epf.packet_id = p_packet_id;

  if not found then
    raise exception 'Enrollment packet fields were not found.';
  end if;

  update public.enrollment_packet_requests as requests
  set
    status = 'in_progress',
    opened_at = coalesce(requests.opened_at, p_updated_at),
    last_family_activity_at = p_updated_at,
    updated_at = p_updated_at
  where requests.id = p_packet_id
    and requests.status in ('draft', 'sent', 'in_progress')
  returning *
  into v_request;

  if not found then
    raise exception 'Unable to save enrollment packet progress because the packet is no longer in an editable state.';
  end if;

  return query
  select
    p_packet_id,
    v_request.status;
end;
$$;


ALTER FUNCTION "public"."rpc_save_enrollment_packet_progress"("p_packet_id" "uuid", "p_caregiver_name" "text", "p_caregiver_phone" "text", "p_caregiver_email" "text", "p_caregiver_address_line1" "text", "p_caregiver_address_line2" "text", "p_caregiver_city" "text", "p_caregiver_state" "text", "p_caregiver_zip" "text", "p_secondary_contact_name" "text", "p_secondary_contact_phone" "text", "p_secondary_contact_email" "text", "p_secondary_contact_relationship" "text", "p_notes" "text", "p_intake_payload" "jsonb", "p_updated_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_save_member_command_center_attendance_billing"("p_member_id" "uuid", "p_schedule_patch" "jsonb", "p_member_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_billing_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_template_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("attendance_schedule_id" "text", "billing_setting_id" "text", "billing_schedule_template_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_member public.members%rowtype;
  v_schedule_patch public.member_attendance_schedules%rowtype;
  v_member_patch public.members%rowtype;
  v_billing_patch public.member_billing_settings%rowtype;
  v_template_patch public.billing_schedule_templates%rowtype;
  v_schedule_id text;
  v_billing_id text;
  v_template_id text;
begin
  if p_member_id is null then
    raise exception 'rpc_save_member_command_center_attendance_billing requires p_member_id';
  end if;

  select *
  into v_member
  from public.members
  where id = p_member_id
  for update;
  if not found then
    raise exception 'Member % not found', p_member_id;
  end if;

  insert into public.member_attendance_schedules (
    id, member_id, enrollment_date, monday, tuesday, wednesday, thursday, friday, full_day,
    transportation_required, transportation_billing_status, attendance_days_per_week, make_up_days_available,
    created_at, updated_at
  )
  values (
    'attendance-' || p_member_id::text, p_member_id, v_member.enrollment_date, false, false, false, false, false, true,
    null, 'BillNormally', 0, 0, v_now, v_now
  )
  on conflict (member_id) do nothing;

  select id
  into v_schedule_id
  from public.member_attendance_schedules
  where member_id = p_member_id
  for update;

  select * into v_schedule_patch
  from jsonb_populate_record(null::public.member_attendance_schedules, coalesce(p_schedule_patch, '{}'::jsonb));

  update public.member_attendance_schedules
  set
    enrollment_date = v_schedule_patch.enrollment_date,
    monday = v_schedule_patch.monday,
    tuesday = v_schedule_patch.tuesday,
    wednesday = v_schedule_patch.wednesday,
    thursday = v_schedule_patch.thursday,
    friday = v_schedule_patch.friday,
    full_day = v_schedule_patch.full_day,
    transport_monday_period = v_schedule_patch.transport_monday_period,
    transport_tuesday_period = v_schedule_patch.transport_tuesday_period,
    transport_wednesday_period = v_schedule_patch.transport_wednesday_period,
    transport_thursday_period = v_schedule_patch.transport_thursday_period,
    transport_friday_period = v_schedule_patch.transport_friday_period,
    transport_monday_am_mode = v_schedule_patch.transport_monday_am_mode,
    transport_monday_am_door_to_door_address = v_schedule_patch.transport_monday_am_door_to_door_address,
    transport_monday_am_bus_number = v_schedule_patch.transport_monday_am_bus_number,
    transport_monday_am_bus_stop = v_schedule_patch.transport_monday_am_bus_stop,
    transport_monday_pm_mode = v_schedule_patch.transport_monday_pm_mode,
    transport_monday_pm_door_to_door_address = v_schedule_patch.transport_monday_pm_door_to_door_address,
    transport_monday_pm_bus_number = v_schedule_patch.transport_monday_pm_bus_number,
    transport_monday_pm_bus_stop = v_schedule_patch.transport_monday_pm_bus_stop,
    transport_tuesday_am_mode = v_schedule_patch.transport_tuesday_am_mode,
    transport_tuesday_am_door_to_door_address = v_schedule_patch.transport_tuesday_am_door_to_door_address,
    transport_tuesday_am_bus_number = v_schedule_patch.transport_tuesday_am_bus_number,
    transport_tuesday_am_bus_stop = v_schedule_patch.transport_tuesday_am_bus_stop,
    transport_tuesday_pm_mode = v_schedule_patch.transport_tuesday_pm_mode,
    transport_tuesday_pm_door_to_door_address = v_schedule_patch.transport_tuesday_pm_door_to_door_address,
    transport_tuesday_pm_bus_number = v_schedule_patch.transport_tuesday_pm_bus_number,
    transport_tuesday_pm_bus_stop = v_schedule_patch.transport_tuesday_pm_bus_stop,
    transport_wednesday_am_mode = v_schedule_patch.transport_wednesday_am_mode,
    transport_wednesday_am_door_to_door_address = v_schedule_patch.transport_wednesday_am_door_to_door_address,
    transport_wednesday_am_bus_number = v_schedule_patch.transport_wednesday_am_bus_number,
    transport_wednesday_am_bus_stop = v_schedule_patch.transport_wednesday_am_bus_stop,
    transport_wednesday_pm_mode = v_schedule_patch.transport_wednesday_pm_mode,
    transport_wednesday_pm_door_to_door_address = v_schedule_patch.transport_wednesday_pm_door_to_door_address,
    transport_wednesday_pm_bus_number = v_schedule_patch.transport_wednesday_pm_bus_number,
    transport_wednesday_pm_bus_stop = v_schedule_patch.transport_wednesday_pm_bus_stop,
    transport_thursday_am_mode = v_schedule_patch.transport_thursday_am_mode,
    transport_thursday_am_door_to_door_address = v_schedule_patch.transport_thursday_am_door_to_door_address,
    transport_thursday_am_bus_number = v_schedule_patch.transport_thursday_am_bus_number,
    transport_thursday_am_bus_stop = v_schedule_patch.transport_thursday_am_bus_stop,
    transport_thursday_pm_mode = v_schedule_patch.transport_thursday_pm_mode,
    transport_thursday_pm_door_to_door_address = v_schedule_patch.transport_thursday_pm_door_to_door_address,
    transport_thursday_pm_bus_number = v_schedule_patch.transport_thursday_pm_bus_number,
    transport_thursday_pm_bus_stop = v_schedule_patch.transport_thursday_pm_bus_stop,
    transport_friday_am_mode = v_schedule_patch.transport_friday_am_mode,
    transport_friday_am_door_to_door_address = v_schedule_patch.transport_friday_am_door_to_door_address,
    transport_friday_am_bus_number = v_schedule_patch.transport_friday_am_bus_number,
    transport_friday_am_bus_stop = v_schedule_patch.transport_friday_am_bus_stop,
    transport_friday_pm_mode = v_schedule_patch.transport_friday_pm_mode,
    transport_friday_pm_door_to_door_address = v_schedule_patch.transport_friday_pm_door_to_door_address,
    transport_friday_pm_bus_number = v_schedule_patch.transport_friday_pm_bus_number,
    transport_friday_pm_bus_stop = v_schedule_patch.transport_friday_pm_bus_stop,
    daily_rate = v_schedule_patch.daily_rate,
    transportation_billing_status = v_schedule_patch.transportation_billing_status,
    billing_rate_effective_date = v_schedule_patch.billing_rate_effective_date,
    billing_notes = v_schedule_patch.billing_notes,
    attendance_days_per_week = v_schedule_patch.attendance_days_per_week,
    default_daily_rate = v_schedule_patch.default_daily_rate,
    use_custom_daily_rate = v_schedule_patch.use_custom_daily_rate,
    custom_daily_rate = v_schedule_patch.custom_daily_rate,
    make_up_days_available = v_schedule_patch.make_up_days_available,
    attendance_notes = v_schedule_patch.attendance_notes,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  where id = v_schedule_id;

  select * into v_member_patch
  from jsonb_populate_record(null::public.members, coalesce(p_member_patch, '{}'::jsonb));

  update public.members
  set
    enrollment_date = case when p_member_patch ? 'enrollment_date' then v_member_patch.enrollment_date else enrollment_date end
  where id = p_member_id;

  select * into v_billing_patch
  from jsonb_populate_record(null::public.member_billing_settings, coalesce(p_billing_payload, '{}'::jsonb));
  v_billing_id := nullif(coalesce(p_billing_payload ->> 'id', ''), '');
  if v_billing_id is null then
    v_billing_id := 'member-billing-' || replace(gen_random_uuid()::text, '-', '');
    insert into public.member_billing_settings (
      id, member_id, payor_id, use_center_default_billing_mode, billing_mode, monthly_billing_basis,
      use_center_default_rate, custom_daily_rate, flat_monthly_rate, bill_extra_days,
      transportation_billing_status, bill_ancillary_arrears, active, effective_start_date, effective_end_date,
      billing_notes, updated_by_user_id, updated_by_name, created_at, updated_at
    )
    values (
      v_billing_id, p_member_id, v_billing_patch.payor_id, coalesce(v_billing_patch.use_center_default_billing_mode, true),
      v_billing_patch.billing_mode, coalesce(v_billing_patch.monthly_billing_basis, 'ScheduledMonthBehind'),
      coalesce(v_billing_patch.use_center_default_rate, false), v_billing_patch.custom_daily_rate, v_billing_patch.flat_monthly_rate,
      coalesce(v_billing_patch.bill_extra_days, true), coalesce(v_billing_patch.transportation_billing_status, 'BillNormally'),
      coalesce(v_billing_patch.bill_ancillary_arrears, true), coalesce(v_billing_patch.active, true),
      v_billing_patch.effective_start_date, v_billing_patch.effective_end_date, v_billing_patch.billing_notes,
      p_actor_user_id, nullif(trim(coalesce(p_actor_name, '')), ''), v_now, v_now
    );
  else
    update public.member_billing_settings
    set
      payor_id = v_billing_patch.payor_id,
      use_center_default_billing_mode = coalesce(v_billing_patch.use_center_default_billing_mode, true),
      billing_mode = v_billing_patch.billing_mode,
      monthly_billing_basis = coalesce(v_billing_patch.monthly_billing_basis, 'ScheduledMonthBehind'),
      use_center_default_rate = coalesce(v_billing_patch.use_center_default_rate, false),
      custom_daily_rate = v_billing_patch.custom_daily_rate,
      flat_monthly_rate = v_billing_patch.flat_monthly_rate,
      bill_extra_days = coalesce(v_billing_patch.bill_extra_days, true),
      transportation_billing_status = coalesce(v_billing_patch.transportation_billing_status, 'BillNormally'),
      bill_ancillary_arrears = coalesce(v_billing_patch.bill_ancillary_arrears, true),
      active = coalesce(v_billing_patch.active, true),
      effective_start_date = v_billing_patch.effective_start_date,
      effective_end_date = v_billing_patch.effective_end_date,
      billing_notes = v_billing_patch.billing_notes,
      updated_by_user_id = p_actor_user_id,
      updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
      updated_at = v_now
    where id = v_billing_id;
  end if;

  select * into v_template_patch
  from jsonb_populate_record(null::public.billing_schedule_templates, coalesce(p_template_payload, '{}'::jsonb));
  v_template_id := nullif(coalesce(p_template_payload ->> 'id', ''), '');
  if v_template_id is null then
    v_template_id := 'schedule-template-' || replace(gen_random_uuid()::text, '-', '');
    insert into public.billing_schedule_templates (
      id, member_id, effective_start_date, effective_end_date, monday, tuesday, wednesday, thursday, friday,
      saturday, sunday, active, notes, updated_by_user_id, updated_by_name, created_at, updated_at
    )
    values (
      v_template_id, p_member_id, v_template_patch.effective_start_date, v_template_patch.effective_end_date,
      coalesce(v_template_patch.monday, false), coalesce(v_template_patch.tuesday, false), coalesce(v_template_patch.wednesday, false),
      coalesce(v_template_patch.thursday, false), coalesce(v_template_patch.friday, false), coalesce(v_template_patch.saturday, false),
      coalesce(v_template_patch.sunday, false), coalesce(v_template_patch.active, true), v_template_patch.notes,
      p_actor_user_id, nullif(trim(coalesce(p_actor_name, '')), ''), v_now, v_now
    );
  else
    update public.billing_schedule_templates
    set
      effective_start_date = v_template_patch.effective_start_date,
      effective_end_date = v_template_patch.effective_end_date,
      monday = coalesce(v_template_patch.monday, false),
      tuesday = coalesce(v_template_patch.tuesday, false),
      wednesday = coalesce(v_template_patch.wednesday, false),
      thursday = coalesce(v_template_patch.thursday, false),
      friday = coalesce(v_template_patch.friday, false),
      saturday = coalesce(v_template_patch.saturday, false),
      sunday = coalesce(v_template_patch.sunday, false),
      active = coalesce(v_template_patch.active, true),
      notes = v_template_patch.notes,
      updated_by_user_id = p_actor_user_id,
      updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
      updated_at = v_now
    where id = v_template_id;
  end if;

  attendance_schedule_id := v_schedule_id;
  billing_setting_id := v_billing_id;
  billing_schedule_template_id := v_template_id;
  return next;
end;
$$;


