    transport_friday_pm_door_to_door_address = v_schedule_patch.transport_friday_pm_door_to_door_address,
    transport_friday_pm_bus_number = v_schedule_patch.transport_friday_pm_bus_number,
    transport_friday_pm_bus_stop = v_schedule_patch.transport_friday_pm_bus_stop,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  where id = v_schedule_id;

  if jsonb_typeof(coalesce(p_bus_stop_names, '[]'::jsonb)) = 'array' then
    for v_name in select nullif(trim(value), '') from jsonb_array_elements_text(coalesce(p_bus_stop_names, '[]'::jsonb))
    loop
      if v_name is null then
        continue;
      end if;
      insert into public.bus_stop_directory (
        id, bus_stop_name, created_by_user_id, created_by_name, created_at, updated_at
      )
      values (
        'bus-stop-' || replace(gen_random_uuid()::text, '-', ''), v_name, p_actor_user_id,
        nullif(trim(coalesce(p_actor_name, '')), ''), v_now, v_now
      )
      on conflict ((lower(btrim(bus_stop_name))))
      do update
      set bus_stop_name = excluded.bus_stop_name, updated_at = excluded.updated_at;
    end loop;
  end if;

  attendance_schedule_id := v_schedule_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_save_member_command_center_transportation"("p_member_id" "uuid", "p_schedule_patch" "jsonb", "p_bus_stop_names" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_save_schedule_change_with_attendance_sync"("p_schedule_change_id" "text" DEFAULT NULL::"text", "p_member_id" "uuid" DEFAULT NULL::"uuid", "p_change_type" "text" DEFAULT NULL::"text", "p_effective_start_date" "date" DEFAULT NULL::"date", "p_effective_end_date" "date" DEFAULT NULL::"date", "p_original_days" "text"[] DEFAULT '{}'::"text"[], "p_new_days" "text"[] DEFAULT '{}'::"text"[], "p_suspend_base_schedule" boolean DEFAULT false, "p_reason" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_entered_by" "text" DEFAULT NULL::"text", "p_entered_by_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("id" "text", "member_id" "uuid", "change_type" "text", "effective_start_date" "date", "effective_end_date" "date", "original_days" "text"[], "new_days" "text"[], "suspend_base_schedule" boolean, "reason" "text", "notes" "text", "entered_by" "text", "entered_by_user_id" "uuid", "status" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "closed_at" timestamp with time zone, "closed_by" "text", "closed_by_user_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_schedule_change_id text := nullif(trim(coalesce(p_schedule_change_id, '')), '');
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
  v_entered_by text := nullif(trim(coalesce(p_entered_by, '')), '');
  v_previous public.schedule_changes%rowtype;
  v_saved public.schedule_changes%rowtype;
  v_member public.members%rowtype;
  v_attendance_schedule_id text;
  v_target_days text[] := null;
begin
  if p_member_id is null then
    raise exception 'rpc_save_schedule_change_with_attendance_sync requires p_member_id';
  end if;
  if nullif(trim(coalesce(p_change_type, '')), '') is null then
    raise exception 'rpc_save_schedule_change_with_attendance_sync requires p_change_type';
  end if;
  if p_change_type not in (
    'Scheduled Absence',
    'Makeup Day',
    'Day Swap',
    'Temporary Schedule Change',
    'Permanent Schedule Change'
  ) then
    raise exception 'Invalid schedule change type.';
  end if;
  if p_effective_start_date is null then
    raise exception 'rpc_save_schedule_change_with_attendance_sync requires p_effective_start_date';
  end if;
  if nullif(trim(coalesce(p_reason, '')), '') is null then
    raise exception 'rpc_save_schedule_change_with_attendance_sync requires p_reason';
  end if;

  select *
  into v_member
  from public.members as members
  where members.id = p_member_id
  for update;

  if not found then
    raise exception 'Member % not found for schedule change save.', p_member_id;
  end if;

  insert into public.member_attendance_schedules (
    id,
    member_id,
    enrollment_date,
    monday,
    tuesday,
    wednesday,
    thursday,
    friday,
    full_day,
    transportation_billing_status,
    attendance_days_per_week,
    make_up_days_available,
    created_at,
    updated_at
  )
  values (
    'attendance-' || p_member_id::text,
    p_member_id,
    coalesce(v_member.enrollment_date, (v_now at time zone 'America/New_York')::date),
    false,
    false,
    false,
    false,
    false,
    true,
    'BillNormally',
    0,
    0,
    v_now,
    v_now
  )
  on conflict on constraint member_attendance_schedules_member_id_key do nothing;

  select member_attendance_schedules.id
  into v_attendance_schedule_id
  from public.member_attendance_schedules as member_attendance_schedules
  where member_attendance_schedules.member_id = p_member_id
  for update;

  if v_schedule_change_id is not null then
    select *
    into v_previous
    from public.schedule_changes as schedule_changes
    where schedule_changes.id = v_schedule_change_id
    for update;

    if not found then
      raise exception 'Schedule change not found.';
    end if;
    if v_previous.status <> 'active' then
      raise exception 'Only active schedule changes can be edited. Completed or cancelled items stay locked as history.';
    end if;

    update public.schedule_changes as schedule_changes
    set
      member_id = p_member_id,
      change_type = p_change_type,
      effective_start_date = p_effective_start_date,
      effective_end_date = p_effective_end_date,
      original_days = coalesce(p_original_days, '{}'::text[]),
      new_days = coalesce(p_new_days, '{}'::text[]),
      suspend_base_schedule = coalesce(p_suspend_base_schedule, false),
      reason = trim(p_reason),
      notes = nullif(trim(coalesce(p_notes, '')), ''),
      updated_at = v_now
    where schedule_changes.id = v_schedule_change_id
    returning * into v_saved;
  else
    v_schedule_change_id := 'schedule-change-' || gen_random_uuid()::text;
    v_entered_by := coalesce(v_entered_by, v_actor_name, 'Unknown');

    insert into public.schedule_changes (
      id,
      member_id,
      change_type,
      effective_start_date,
      effective_end_date,
      original_days,
      new_days,
      suspend_base_schedule,
      reason,
      notes,
      entered_by,
      entered_by_user_id,
      status,
      created_at,
      updated_at,
      closed_at,
      closed_by,
      closed_by_user_id
    )
    values (
      v_schedule_change_id,
      p_member_id,
      p_change_type,
      p_effective_start_date,
      p_effective_end_date,
      coalesce(p_original_days, '{}'::text[]),
      coalesce(p_new_days, '{}'::text[]),
      coalesce(p_suspend_base_schedule, false),
      trim(p_reason),
      nullif(trim(coalesce(p_notes, '')), ''),
      v_entered_by,
      p_entered_by_user_id,
      'active',
      v_now,
      v_now,
      null,
      null,
      null
    )
    returning * into v_saved;
  end if;

  if v_saved.change_type = 'Permanent Schedule Change' then
    v_target_days := coalesce(v_saved.new_days, '{}'::text[]);
  elsif v_previous.id is not null and v_previous.change_type = 'Permanent Schedule Change' then
    v_target_days := coalesce(v_previous.original_days, '{}'::text[]);
  end if;

  if v_target_days is not null then
    update public.member_attendance_schedules as member_attendance_schedules
    set
      monday = 'monday' = any(v_target_days),
      tuesday = 'tuesday' = any(v_target_days),
      wednesday = 'wednesday' = any(v_target_days),
      thursday = 'thursday' = any(v_target_days),
      friday = 'friday' = any(v_target_days),
      attendance_days_per_week =
        case when 'monday' = any(v_target_days) then 1 else 0 end +
        case when 'tuesday' = any(v_target_days) then 1 else 0 end +
        case when 'wednesday' = any(v_target_days) then 1 else 0 end +
        case when 'thursday' = any(v_target_days) then 1 else 0 end +
        case when 'friday' = any(v_target_days) then 1 else 0 end,
      updated_by_user_id = p_actor_user_id,
      updated_by_name = v_actor_name,
      updated_at = v_now
    where member_attendance_schedules.id = v_attendance_schedule_id;
  end if;

  return query
  select
    v_saved.id,
    v_saved.member_id,
    v_saved.change_type,
    v_saved.effective_start_date,
    v_saved.effective_end_date,
    v_saved.original_days,
    v_saved.new_days,
    v_saved.suspend_base_schedule,
    v_saved.reason,
    v_saved.notes,
    v_saved.entered_by,
    v_saved.entered_by_user_id,
    v_saved.status,
    v_saved.created_at,
    v_saved.updated_at,
    v_saved.closed_at,
    v_saved.closed_by,
    v_saved.closed_by_user_id;
end;
$$;


ALTER FUNCTION "public"."rpc_save_schedule_change_with_attendance_sync"("p_schedule_change_id" "text", "p_member_id" "uuid", "p_change_type" "text", "p_effective_start_date" "date", "p_effective_end_date" "date", "p_original_days" "text"[], "p_new_days" "text"[], "p_suspend_base_schedule" boolean, "p_reason" "text", "p_notes" "text", "p_entered_by" "text", "p_entered_by_user_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_set_member_contact_payor"("p_member_id" "uuid", "p_contact_id" "text" DEFAULT NULL::"text") RETURNS TABLE("member_id" "uuid", "contact_id" "text", "is_payor" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_contact_id text := nullif(trim(coalesce(p_contact_id, '')), '');
  v_existing_contact_id text;
begin
  if p_member_id is null then
    raise exception 'rpc_set_member_contact_payor requires p_member_id';
  end if;

  if v_contact_id is not null then
    select mc.id
    into v_existing_contact_id
    from public.member_contacts as mc
    where mc.id = v_contact_id
      and mc.member_id = p_member_id
    for update;

    if v_existing_contact_id is null then
      raise exception 'Contact % does not belong to member %.', v_contact_id, p_member_id;
    end if;
  end if;

  update public.member_contacts as mc
  set
    is_payor = false,
    updated_at = now()
  where mc.member_id = p_member_id
    and mc.is_payor = true
    and (v_contact_id is null or mc.id <> v_contact_id);

  if v_contact_id is not null then
    update public.member_contacts as mc
    set
      is_payor = true,
      updated_at = now()
    where mc.member_id = p_member_id
      and mc.id = v_contact_id;
  end if;

  return query
  select
    p_member_id as member_id,
    v_contact_id as contact_id,
    (v_contact_id is not null) as is_payor;
end;
$$;


ALTER FUNCTION "public"."rpc_set_member_contact_payor"("p_member_id" "uuid", "p_contact_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_sign_physician_order"("p_pof_id" "uuid", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_signed_at" timestamp with time zone DEFAULT "now"(), "p_pof_request_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("physician_order_id" "uuid", "member_id" "uuid", "queue_id" "uuid", "queue_attempt_count" integer, "queue_next_retry_at" timestamp with time zone)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_member_id uuid;
  v_provider_name text;
  v_actor_name text;
  v_queue public.pof_post_sign_sync_queue%rowtype;
begin
  if p_pof_id is null then
    raise exception 'Physician order id is required.';
  end if;

  select po.member_id, po.provider_name
  into v_member_id, v_provider_name
  from public.physician_orders po
  where po.id = p_pof_id
  for update;

  if not found then
    raise exception 'Physician order not found.';
  end if;

  v_actor_name := nullif(trim(coalesce(p_actor_name, '')), '');

  update public.physician_orders as po
  set
    status = 'superseded',
    is_active_signed = false,
    superseded_by = p_pof_id,
    superseded_at = p_signed_at,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = p_signed_at
  where po.member_id = v_member_id
    and po.is_active_signed = true
    and po.id <> p_pof_id;

  update public.physician_orders as po
  set
    status = 'signed',
    is_active_signed = true,
    signed_at = p_signed_at,
    sent_at = p_signed_at,
    signed_by_name = coalesce(nullif(trim(coalesce(v_provider_name, '')), ''), v_actor_name, po.signed_by_name),
    effective_at = p_signed_at,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = p_signed_at
  where po.id = p_pof_id;

  insert into public.pof_post_sign_sync_queue as sync_queue (
    physician_order_id,
    member_id,
    pof_request_id,
    status,
    attempt_count,
    next_retry_at,
    last_error,
    last_error_at,
    last_failed_step,
    signature_completed_at,
    queued_by_user_id,
    queued_by_name,
    resolved_at,
    resolved_by_user_id,
    resolved_by_name
  )
  values (
    p_pof_id,
    v_member_id,
    p_pof_request_id,
    'queued',
    0,
    p_signed_at,
    null,
    null,
    null,
    p_signed_at,
    p_actor_user_id,
    v_actor_name,
    null,
    null,
    null
  )
  on conflict on constraint pof_post_sign_sync_queue_physician_order_id_key
  do update
  set
    member_id = excluded.member_id,
    pof_request_id = coalesce(excluded.pof_request_id, sync_queue.pof_request_id),
    signature_completed_at = excluded.signature_completed_at,
    queued_by_user_id = coalesce(excluded.queued_by_user_id, sync_queue.queued_by_user_id),
    queued_by_name = coalesce(excluded.queued_by_name, sync_queue.queued_by_name)
  returning * into v_queue;

  return query
  select
    p_pof_id,
    v_member_id,
    v_queue.id,
    coalesce(v_queue.attempt_count, 0),
    v_queue.next_retry_at;
end;
$$;


ALTER FUNCTION "public"."rpc_sign_physician_order"("p_pof_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_signed_at" timestamp with time zone, "p_pof_request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_sync_active_prn_medication_orders"("p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("synced_orders" integer, "inactivated_orders" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_inactivated_current integer := 0;
  v_inactivated_stale integer := 0;
begin
  with active_signed_orders as (
    select
      po.id,
      po.member_id,
      po.provider_name,
      po.created_by_user_id,
      po.created_by_name,
      po.updated_by_user_id,
      po.updated_by_name,
      po.medications,
      po.standing_orders
    from public.physician_orders po
    where po.status = 'signed'
      and coalesce(po.is_active_signed, false) = true
  ), medication_source_rows as (
    select
      aso.member_id,
      aso.id as physician_order_id,
      pm.id as pof_medication_id,
      src.source_medication_id,
      nullif(trim(src.item ->> 'name'), '') as medication_name,
      coalesce(nullif(trim(src.item ->> 'strength'), ''), nullif(trim(src.item ->> 'quantity'), ''), pm.strength) as strength,
      nullif(trim(src.item ->> 'form'), '') as form,
      nullif(trim(src.item ->> 'route'), '') as route,
      coalesce(nullif(trim(src.item ->> 'instructions'), ''), nullif(trim(src.item ->> 'comments'), ''), pm.instructions) as directions,
      nullif(trim(src.item ->> 'prnInstructions'), '') as prn_reason,
      nullif(trim(src.item ->> 'frequency'), '') as frequency_text,
      null::integer as min_interval_minutes,
      null::integer as max_doses_per_24h,
      null::numeric as max_daily_dose,
      nullif(trim(src.item ->> 'startDate'), '')::date as start_date,
      nullif(trim(src.item ->> 'endDate'), '')::date as end_date,
      coalesce(nullif(trim(src.item ->> 'provider'), ''), pm.provider, aso.provider_name) as provider_name,
      case
        when coalesce(nullif(trim(src.item ->> 'active'), '')::boolean, true) = false then 'inactive'
        when nullif(trim(src.item ->> 'endDate'), '')::date is not null and nullif(trim(src.item ->> 'endDate'), '')::date < (v_now at time zone 'America/New_York')::date then 'expired'
        else 'active'
      end as status,
      aso.created_by_user_id as created_by,
      aso.updated_by_user_id as verified_by,
      aso.created_by_name,
      aso.updated_by_name as verified_by_name,
      jsonb_build_object(
        'source', 'pof',
        'subsource', 'medications',
        'physician_order_id', aso.id,
        'source_medication_id', src.source_medication_id,
        'medication_json', src.item
      ) as source_payload
    from active_signed_orders aso
    cross join lateral (
      select
        med.item,
        coalesce(nullif(trim(med.item ->> 'id'), ''), format('medication-%s', med.ordinality)) as source_medication_id
      from jsonb_array_elements(coalesce(aso.medications, '[]'::jsonb)) with ordinality as med(item, ordinality)
    ) src
    left join public.pof_medications pm
      on pm.physician_order_id = aso.id
     and pm.source_medication_id = src.source_medication_id
    where nullif(trim(src.item ->> 'name'), '') is not null
      and coalesce(nullif(trim(src.item ->> 'prn'), '')::boolean, false) = true
      and coalesce(nullif(trim(src.item ->> 'givenAtCenter'), '')::boolean, false) = true
  ), standing_order_source_rows as (
    select
      aso.member_id,
      aso.id as physician_order_id,
      null::uuid as pof_medication_id,
      standing.source_medication_id,
      standing.medication_name,
      standing.strength,
      null::text as form,
      standing.route,
      standing.directions,
      standing.prn_reason,
      standing.frequency_text,
      standing.min_interval_minutes,
      null::integer as max_doses_per_24h,
      null::numeric as max_daily_dose,
      null::date as start_date,
      null::date as end_date,
      aso.provider_name as provider_name,
      'active'::text as status,
      aso.created_by_user_id as created_by,
      aso.updated_by_user_id as verified_by,
      aso.created_by_name,
      aso.updated_by_name as verified_by_name,
      jsonb_build_object(
        'source', 'pof',
        'subsource', 'standing_orders',
        'physician_order_id', aso.id,
        'source_medication_id', standing.source_medication_id,
        'standing_order_label', standing.label
      ) as source_payload
    from active_signed_orders aso
    cross join lateral jsonb_array_elements_text(coalesce(aso.standing_orders, '[]'::jsonb)) as selected(label)
    cross join lateral (
      select *
      from (
        values
          ('Tylenol 650mg by mouth every 4 hrs for pain/fever', 'standing-order:tylenol', 'Tylenol', '650mg', 'By mouth', 'Every 4 hrs for pain/fever', 'pain/fever', 'Every 4 hrs', 240),
          ('Ibuprofen 200mg by mouth every 8 hrs for pain', 'standing-order:ibuprofen', 'Ibuprofen', '200mg', 'By mouth', 'Every 8 hrs for pain', 'pain', 'Every 8 hrs', 480),
          ('Mylanta 10mL by mouth every 4 hrs for indigestion', 'standing-order:mylanta', 'Mylanta', '10mL', 'By mouth', 'Every 4 hrs for indigestion', 'indigestion', 'Every 4 hrs', 240),
          ('Benadryl 25mg by mouth every 6 hrs for itching', 'standing-order:benadryl', 'Benadryl', '25mg', 'By mouth', 'Every 6 hrs for itching', 'itching', 'Every 6 hrs', 360)
      ) as template(label, source_medication_id, medication_name, strength, route, directions, prn_reason, frequency_text, min_interval_minutes)
      where template.label = selected.label
    ) standing
  ), source_rows as (
    select * from medication_source_rows
    union all
    select * from standing_order_source_rows
  ), upserted as (
    insert into public.medication_orders (
      member_id,
      physician_order_id,
      pof_medication_id,
      source_medication_id,
      order_type,
      medication_name,
      strength,
      form,
      route,
      directions,
      prn_reason,
      frequency_text,
      min_interval_minutes,
      max_doses_per_24h,
      max_daily_dose,
      start_date,
      end_date,
      provider_name,
      order_source,
      status,
      created_by,
      verified_by,
      requires_review,
      requires_effectiveness_followup,
      created_by_name,
      verified_by_name,
      source_payload,
      created_at,
      updated_at
    )
    select
      source_rows.member_id,
      source_rows.physician_order_id,
      source_rows.pof_medication_id,
      source_rows.source_medication_id,
      'prn',
      source_rows.medication_name,
      source_rows.strength,
      source_rows.form,
      source_rows.route,
      source_rows.directions,
      source_rows.prn_reason,
      source_rows.frequency_text,
      source_rows.min_interval_minutes,
      source_rows.max_doses_per_24h,
      source_rows.max_daily_dose,
      source_rows.start_date,
      source_rows.end_date,
      source_rows.provider_name,
      'pof',
      source_rows.status,
      source_rows.created_by,
      source_rows.verified_by,
      false,
      true,
      source_rows.created_by_name,
      source_rows.verified_by_name,
      source_rows.source_payload,
      v_now,
      v_now
    from source_rows
    on conflict (physician_order_id, source_medication_id)
    do update
    set
      member_id = excluded.member_id,
      pof_medication_id = excluded.pof_medication_id,
      medication_name = excluded.medication_name,
      strength = excluded.strength,
      form = excluded.form,
      route = excluded.route,
      directions = excluded.directions,
      prn_reason = excluded.prn_reason,
      frequency_text = excluded.frequency_text,
      min_interval_minutes = excluded.min_interval_minutes,
      max_doses_per_24h = excluded.max_doses_per_24h,
      max_daily_dose = excluded.max_daily_dose,
      start_date = excluded.start_date,
      end_date = excluded.end_date,
      provider_name = excluded.provider_name,
      order_source = excluded.order_source,
      status = excluded.status,
      verified_by = excluded.verified_by,
      requires_effectiveness_followup = excluded.requires_effectiveness_followup,
      verified_by_name = excluded.verified_by_name,
      source_payload = excluded.source_payload,
      updated_at = excluded.updated_at
    returning 1
  )
  select count(*) into synced_orders from upserted;

  update public.medication_orders mo
  set
    status = case
      when mo.end_date is not null and mo.end_date < (v_now at time zone 'America/New_York')::date then 'expired'
      else 'inactive'
    end,
    updated_at = v_now
  where mo.order_source = 'pof'
    and exists (
      select 1
      from public.physician_orders po
      where po.id = mo.physician_order_id
        and po.status = 'signed'
        and coalesce(po.is_active_signed, false) = true
    )
    and not exists (
      select 1
      from (
        select
          po.id as physician_order_id,
          coalesce(nullif(trim(med.item ->> 'id'), ''), format('medication-%s', med.ordinality)) as source_medication_id
        from public.physician_orders po
        cross join lateral jsonb_array_elements(coalesce(po.medications, '[]'::jsonb)) with ordinality as med(item, ordinality)
        where po.status = 'signed'
          and coalesce(po.is_active_signed, false) = true
          and nullif(trim(med.item ->> 'name'), '') is not null
          and coalesce(nullif(trim(med.item ->> 'prn'), '')::boolean, false) = true
          and coalesce(nullif(trim(med.item ->> 'givenAtCenter'), '')::boolean, false) = true
        union all
        select
          po.id as physician_order_id,
          standing.source_medication_id
        from public.physician_orders po
        cross join lateral jsonb_array_elements_text(coalesce(po.standing_orders, '[]'::jsonb)) as selected(label)
        cross join lateral (
          select *
          from (
            values
              ('Tylenol 650mg by mouth every 4 hrs for pain/fever', 'standing-order:tylenol'),
              ('Ibuprofen 200mg by mouth every 8 hrs for pain', 'standing-order:ibuprofen'),
              ('Mylanta 10mL by mouth every 4 hrs for indigestion', 'standing-order:mylanta'),
              ('Benadryl 25mg by mouth every 6 hrs for itching', 'standing-order:benadryl')
          ) as template(label, source_medication_id)
          where template.label = selected.label
        ) standing
        where po.status = 'signed'
          and coalesce(po.is_active_signed, false) = true
      ) active_prn_sources
      where active_prn_sources.physician_order_id = mo.physician_order_id
        and active_prn_sources.source_medication_id = mo.source_medication_id
    );
  get diagnostics v_inactivated_current = row_count;

  update public.medication_orders mo
  set
    status = case
      when mo.end_date is not null and mo.end_date < (v_now at time zone 'America/New_York')::date then 'expired'
      else 'inactive'
    end,
    updated_at = v_now
  where mo.order_source = 'pof'
    and not exists (
      select 1
      from public.physician_orders po
      where po.id = mo.physician_order_id
        and po.status = 'signed'
        and coalesce(po.is_active_signed, false) = true
    );
  get diagnostics v_inactivated_stale = row_count;

  inactivated_orders := v_inactivated_current + v_inactivated_stale;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_sync_active_prn_medication_orders"("p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_sync_command_center_to_member_health_profile"("p_member_id" "uuid", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("member_id" "uuid", "member_health_profile_id" "uuid", "member_command_center_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
begin
  if p_member_id is null then
    raise exception 'rpc_sync_command_center_to_member_health_profile requires p_member_id';
  end if;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    p_member_id,
    v_now,
    v_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict do nothing;

  update public.member_health_profiles as mhp
  set
    gender = case
      when lower(trim(coalesce(mcc.gender, ''))) in ('m', 'male') then 'M'
      when lower(trim(coalesce(mcc.gender, ''))) in ('f', 'female') then 'F'
      else null
    end,
    original_referral_source = mcc.original_referral_source,
    photo_consent = mcc.photo_consent,
    profile_image_url = mcc.profile_image_url,
    code_status = mcc.code_status,
    dnr = mcc.dnr,
    dni = mcc.dni,
    polst_molst_colst = mcc.polst_molst_colst,
    hospice = mcc.hospice,
    advanced_directives_obtained = mcc.advanced_directives_obtained,
    power_of_attorney = mcc.power_of_attorney,
    legal_comments = mcc.legal_comments,
    diet_type = mcc.diet_type,
    dietary_restrictions = mcc.dietary_preferences_restrictions,
    swallowing_difficulty = mcc.swallowing_difficulty,
    supplements = mcc.supplements,
    foods_to_omit = mcc.foods_to_omit,
    diet_texture = mcc.diet_texture,
    important_alerts = mcc.command_center_notes,
    source_assessment_id = mcc.source_assessment_id,
    source_assessment_at = mcc.source_assessment_at,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  from public.member_command_centers as mcc
  where mcc.member_id = p_member_id
    and mhp.member_id = p_member_id;

  update public.members as m
  set code_status = mcc.code_status
  from public.member_command_centers as mcc
  where mcc.member_id = p_member_id
    and m.id = p_member_id
    and nullif(trim(coalesce(mcc.code_status, '')), '') is not null;

  return query
  select
    p_member_id as member_id,
    mhp.id as member_health_profile_id,
    mcc.id as member_command_center_id
  from public.member_health_profiles as mhp
  join public.member_command_centers as mcc
    on mcc.member_id = mhp.member_id
  where mhp.member_id = p_member_id;
end;
$$;


ALTER FUNCTION "public"."rpc_sync_command_center_to_member_health_profile"("p_member_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_sync_mar_medications_from_member_profile"("p_member_id" "uuid", "p_preferred_physician_order_id" "uuid" DEFAULT NULL::"uuid", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("anchor_physician_order_id" "uuid", "synced_medications" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_anchor_physician_order_id uuid;
  v_profile_order_id uuid;
  v_member_name text;
begin
  if p_member_id is null then
    raise exception 'rpc_sync_mar_medications_from_member_profile requires p_member_id';
  end if;

  perform pg_advisory_xact_lock(hashtext(p_member_id::text)::bigint);

  if p_preferred_physician_order_id is not null then
    v_anchor_physician_order_id := p_preferred_physician_order_id;
  else
    select active_physician_order_id
    into v_profile_order_id
    from public.member_health_profiles
    where member_id = p_member_id;

    v_anchor_physician_order_id := v_profile_order_id;
  end if;

  if v_anchor_physician_order_id is null then
    select po.id
    into v_anchor_physician_order_id
    from public.physician_orders po
    where po.member_id = p_member_id
    order by po.version_number desc, po.created_at desc
    limit 1;
  end if;

  if v_anchor_physician_order_id is null then
    select m.display_name
    into v_member_name
    from public.members m
    where m.id = p_member_id
    for update;

    if v_member_name is null then
      raise exception 'Member % not found for MAR medication sync', p_member_id;
    end if;

    insert into public.physician_orders (
      member_id,
      version_number,
      status,
      is_active_signed,
      superseded_at,
      signed_at,
      effective_at,
      member_name_snapshot,
      signature_metadata,
      created_by_name,
      updated_by_name,
      created_at,
      updated_at
    )
    values (
      p_member_id,
      1,
      'superseded',
      false,
      v_now,
      v_now,
      v_now,
      v_member_name,
      jsonb_build_object(
        'system_generated_for', 'mar_anchor',
        'generated_by_service', 'mar-workflow',
        'generated_at', v_now
      ),
      'System MAR Anchor',
      'System MAR Anchor',
      v_now,
      v_now
    )
    returning id into v_anchor_physician_order_id;
  end if;

  with source_rows as (
    select
      'mhp-' || mm.id::text as source_medication_id,
      mm.medication_name,
      mm.dose,
      mm.route,
      mm.frequency,
      coalesce(mm.scheduled_times, '{}'::text[]) as scheduled_times,
      coalesce(mm.prn, false) as prn,
      mm.prn_instructions,
      mm.date_started,
      mm.inactivated_at,
      mm.comments
    from public.member_medications mm
    where mm.member_id = p_member_id
      and mm.medication_status = 'active'
      and coalesce(mm.given_at_center, false) = true
      and nullif(trim(coalesce(mm.medication_name, '')), '') is not null
  ), upserted as (
    insert into public.pof_medications (
      physician_order_id,
      member_id,
      source_medication_id,
      medication_name,
      strength,
      dose,
      route,
      frequency,
      scheduled_times,
      given_at_center,
      prn,
      prn_instructions,
      start_date,
      end_date,
      active,
      provider,
      instructions,
      created_by_user_id,
      created_by_name,
      updated_by_user_id,
      updated_by_name,
      created_at,
      updated_at
    )
    select
      v_anchor_physician_order_id,
      p_member_id,
      source_rows.source_medication_id,
      source_rows.medication_name,
      null,
      source_rows.dose,
      source_rows.route,
      source_rows.frequency,
      source_rows.scheduled_times,
      true,
      source_rows.prn,
      source_rows.prn_instructions,
      source_rows.date_started,
      source_rows.inactivated_at,
      true,
      null,
      source_rows.comments,
      null,
      null,
      null,
      null,
      v_now,
      v_now
    from source_rows
    on conflict (physician_order_id, source_medication_id)
    do update
    set
      medication_name = excluded.medication_name,
      dose = excluded.dose,
      route = excluded.route,
      frequency = excluded.frequency,
      scheduled_times = excluded.scheduled_times,
      given_at_center = excluded.given_at_center,
      prn = excluded.prn,
      prn_instructions = excluded.prn_instructions,
      start_date = excluded.start_date,
      end_date = excluded.end_date,
      active = true,
      instructions = excluded.instructions,
      updated_at = excluded.updated_at
    returning 1
  )
  select count(*) into synced_medications from upserted;

  update public.pof_medications pm
  set
    active = false,
    updated_at = v_now
  where pm.member_id = p_member_id
    and pm.active = true
    and pm.source_medication_id like 'mhp-%'
    and (
      pm.physician_order_id <> v_anchor_physician_order_id
      or not exists (
        select 1
        from public.member_medications mm
        where mm.member_id = p_member_id
          and mm.medication_status = 'active'
          and coalesce(mm.given_at_center, false) = true
          and ('mhp-' || mm.id::text) = pm.source_medication_id
      )
    );

  anchor_physician_order_id := v_anchor_physician_order_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_sync_mar_medications_from_member_profile"("p_member_id" "uuid", "p_preferred_physician_order_id" "uuid", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_sync_member_health_profile_to_command_center"("p_member_id" "uuid", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("member_id" "uuid", "member_health_profile_id" "uuid", "member_command_center_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
begin
  if p_member_id is null then
    raise exception 'rpc_sync_member_health_profile_to_command_center requires p_member_id';
  end if;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    p_member_id,
    v_now,
    v_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict do nothing;

  insert into public.member_command_centers (
    id,
    member_id,
    primary_language,
    updated_by_user_id,
    updated_by_name,
    created_at,
    updated_at
  )
  values (
    'mcc-' || p_member_id::text,
    p_member_id,
    'English',
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    v_now,
    v_now
  )
  on conflict do nothing;

  update public.member_command_centers as mcc
  set
    gender = case
      when lower(trim(coalesce(mhp.gender, ''))) in ('m', 'male') then 'M'
      when lower(trim(coalesce(mhp.gender, ''))) in ('f', 'female') then 'F'
      else null
    end,
    original_referral_source = mhp.original_referral_source,
    photo_consent = mhp.photo_consent,
    profile_image_url = mhp.profile_image_url,
    code_status = mhp.code_status,
    dnr = mhp.dnr,
    dni = mhp.dni,
    polst_molst_colst = mhp.polst_molst_colst,
    hospice = mhp.hospice,
    advanced_directives_obtained = mhp.advanced_directives_obtained,
    power_of_attorney = mhp.power_of_attorney,
    legal_comments = mhp.legal_comments,
    diet_type = mhp.diet_type,
    dietary_preferences_restrictions = mhp.dietary_restrictions,
    swallowing_difficulty = mhp.swallowing_difficulty,
    supplements = mhp.supplements,
    foods_to_omit = mhp.foods_to_omit,
    diet_texture = mhp.diet_texture,
    command_center_notes = mhp.important_alerts,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  from public.member_health_profiles as mhp
  where mhp.member_id = p_member_id
    and mcc.member_id = p_member_id;

  update public.members as m
  set code_status = mhp.code_status
  from public.member_health_profiles as mhp
  where mhp.member_id = p_member_id
    and m.id = p_member_id
    and nullif(trim(coalesce(mhp.code_status, '')), '') is not null;

  return query
  select
    p_member_id as member_id,
    mhp.id as member_health_profile_id,
    mcc.id as member_command_center_id
  from public.member_health_profiles as mhp
  join public.member_command_centers as mcc
    on mcc.member_id = mhp.member_id
  where mhp.member_id = p_member_id;
end;
$$;


ALTER FUNCTION "public"."rpc_sync_member_health_profile_to_command_center"("p_member_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_sync_signed_pof_to_member_clinical_profile"("p_pof_id" "uuid", "p_synced_at" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("member_id" "uuid", "member_health_profile_id" "uuid", "member_command_center_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_order public.physician_orders%rowtype;
  v_now timestamptz := coalesce(p_synced_at, now());
  v_signed_date date;
  v_actor_user_id uuid;
  v_actor_name text;
  v_nutrition_diets jsonb;
  v_primary_diet text;
  v_food_allergies text;
  v_medication_allergies text;
  v_environmental_allergies text;
  v_code_status text;
  v_mhp_operational_flags jsonb;
begin
  if p_pof_id is null then
    raise exception 'p_pof_id is required';
  end if;

  select *
  into v_order
  from public.physician_orders
  where id = p_pof_id
  for update;

  if not found then
    raise exception 'Signed physician order % was not found for post-sign sync.', p_pof_id;
  end if;

  if coalesce(lower(v_order.status), '') <> 'signed' then
    raise exception 'Signed physician order sync requires status=signed. Current status=%', coalesce(v_order.status, 'null');
  end if;

  v_signed_date := coalesce((v_order.signed_at at time zone 'America/New_York')::date, (v_now at time zone 'America/New_York')::date);
  v_actor_user_id := v_order.updated_by_user_id;
  v_actor_name := coalesce(nullif(trim(v_order.updated_by_name), ''), nullif(trim(v_order.created_by_name), ''));
  v_nutrition_diets := coalesce((v_order.clinical_support -> 'nutritionDiets'), '[]'::jsonb);
  v_primary_diet :=
    coalesce(
      (
        select value
        from jsonb_array_elements_text(v_nutrition_diets) as diets(value)
        where lower(value) <> 'regular'
        limit 1
      ),
      (
        select value
        from jsonb_array_elements_text(v_nutrition_diets) as diets(value)
        limit 1
      ),
      'Regular'
    );
  v_code_status := case when coalesce(v_order.dnr_selected, false) then 'DNR' else 'Full Code' end;
  v_mhp_operational_flags := coalesce(v_order.operational_flags, '{}'::jsonb) || jsonb_build_object('dnr', coalesce(v_order.dnr_selected, false));

  insert into public.member_health_profiles (
    member_id,
    active_physician_order_id,
    diagnoses,
    allergies,
    medications,
    diet,
    mobility,
    adl_support,
    continence,
    behavior_orientation,
    clinical_support,
    operational_flags,
    profile_notes,
    joy_sparks,
    code_status,
    dnr,
    last_synced_at,
    updated_at
  )
  values (
    v_order.member_id,
    v_order.id,
    coalesce(v_order.diagnoses, '[]'::jsonb),
    coalesce(v_order.allergies, '[]'::jsonb),
    coalesce(v_order.medications, '[]'::jsonb),
    jsonb_build_object(
      'nutritionDiets', coalesce(v_order.clinical_support -> 'nutritionDiets', '[]'::jsonb),
      'nutritionDietOther', v_order.clinical_support -> 'nutritionDietOther'
    ),
    jsonb_build_object(
      'ambulatoryStatus', v_order.clinical_support -> 'ambulatoryStatus',
      'mobilityIndependent', v_order.clinical_support -> 'mobilityIndependent',
      'mobilityWalker', v_order.clinical_support -> 'mobilityWalker',
      'mobilityWheelchair', v_order.clinical_support -> 'mobilityWheelchair',
      'mobilityScooter', v_order.clinical_support -> 'mobilityScooter',
      'mobilityOther', v_order.clinical_support -> 'mobilityOther',
      'mobilityOtherText', v_order.clinical_support -> 'mobilityOtherText'
    ),
    coalesce(v_order.clinical_support -> 'adlProfile', '{}'::jsonb),
    jsonb_build_object(
      'bladderContinent', v_order.clinical_support -> 'bladderContinent',
      'bladderIncontinent', v_order.clinical_support -> 'bladderIncontinent',
      'bowelContinent', v_order.clinical_support -> 'bowelContinent',
      'bowelIncontinent', v_order.clinical_support -> 'bowelIncontinent'
    ),
    coalesce(v_order.clinical_support -> 'orientationProfile', '{}'::jsonb),
    coalesce(v_order.clinical_support, '{}'::jsonb),
    v_mhp_operational_flags,
    nullif(trim(coalesce(v_order.clinical_support -> 'orientationProfile' ->> 'cognitiveBehaviorComments', '')), ''),
    nullif(trim(coalesce(v_order.clinical_support ->> 'joySparksNotes', '')), ''),
    v_code_status,
    coalesce(v_order.dnr_selected, false),
    v_now,
    v_now
  )
  on conflict on constraint member_health_profiles_member_id_key
  do update
  set
    active_physician_order_id = excluded.active_physician_order_id,
    diagnoses = excluded.diagnoses,
    allergies = excluded.allergies,
    medications = excluded.medications,
    diet = excluded.diet,
    mobility = excluded.mobility,
    adl_support = excluded.adl_support,
    continence = excluded.continence,
    behavior_orientation = excluded.behavior_orientation,
    clinical_support = excluded.clinical_support,
    operational_flags = excluded.operational_flags,
    profile_notes = excluded.profile_notes,
    joy_sparks = excluded.joy_sparks,
    code_status = excluded.code_status,
    dnr = excluded.dnr,
    last_synced_at = excluded.last_synced_at,
    updated_at = excluded.updated_at;

  delete from public.member_diagnoses as member_diagnoses where member_diagnoses.member_id = v_order.member_id;
  insert into public.member_diagnoses (
    id,
    member_id,
    diagnosis_type,
    diagnosis_name,
    diagnosis_code,
    date_added,
    comments,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_at
  )
  select
    gen_random_uuid(),
    v_order.member_id,
    case
      when lower(coalesce(item ->> 'diagnosisType', '')) = 'secondary' then 'secondary'
      else 'primary'
    end,
    item ->> 'diagnosisName',
    null,
    v_signed_date,
    null,
    v_actor_user_id,
    v_actor_name,
    v_now,
    v_now
  from jsonb_array_elements(coalesce(v_order.diagnoses, '[]'::jsonb)) item
  where nullif(trim(coalesce(item ->> 'diagnosisName', '')), '') is not null;

  delete from public.member_medications as member_medications where member_medications.member_id = v_order.member_id;
  insert into public.member_medications (
    id,
    member_id,
    medication_name,
    date_started,
    medication_status,
    inactivated_at,
    dose,
    quantity,
    form,
    frequency,
    route,
    route_laterality,
    comments,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_at
  )
  select
    gen_random_uuid(),
    v_order.member_id,
    item ->> 'name',
    v_signed_date,
    'active',
    null,
    nullif(trim(coalesce(item ->> 'dose', '')), ''),
    nullif(trim(coalesce(item ->> 'quantity', '')), ''),
    nullif(trim(coalesce(item ->> 'form', '')), ''),
    nullif(trim(coalesce(item ->> 'frequency', '')), ''),
    nullif(trim(coalesce(item ->> 'route', '')), ''),
    nullif(trim(coalesce(item ->> 'routeLaterality', '')), ''),
    nullif(trim(coalesce(item ->> 'comments', '')), ''),
    v_actor_user_id,
    v_actor_name,
    v_now,
    v_now
  from jsonb_array_elements(coalesce(v_order.medications, '[]'::jsonb)) item
  where nullif(trim(coalesce(item ->> 'name', '')), '') is not null;

  delete from public.member_allergies as member_allergies where member_allergies.member_id = v_order.member_id;
  insert into public.member_allergies (
    id,
    member_id,
    allergy_group,
    allergy_name,
    severity,
    comments,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_at
  )
  select
    'allergy-' || replace(gen_random_uuid()::text, '-', ''),
    v_order.member_id,
    case
      when lower(coalesce(item ->> 'allergyGroup', '')) in ('food', 'medication', 'environmental') then lower(item ->> 'allergyGroup')
      else 'environmental'
    end,
    item ->> 'allergyName',
    nullif(trim(coalesce(item ->> 'severity', '')), ''),
    nullif(trim(coalesce(item ->> 'comments', '')), ''),
    v_actor_user_id,
    v_actor_name,
    v_now,
    v_now
  from jsonb_array_elements(coalesce(v_order.allergies, '[]'::jsonb)) item
  where nullif(trim(coalesce(item ->> 'allergyName', '')), '') is not null;

  insert into public.member_command_centers (
    id,
    member_id,
    primary_language,
    updated_by_user_id,
    updated_by_name,
    created_at,
    updated_at
  )
  values (
    'mcc-' || v_order.member_id::text,
    v_order.member_id,
    'English',
    v_actor_user_id,
    v_actor_name,
    v_now,
    v_now
  )
  on conflict on constraint member_command_centers_member_id_key
  do nothing;

  select string_agg(member_allergies.allergy_name, ', ' order by member_allergies.allergy_name)
  into v_food_allergies
  from public.member_allergies as member_allergies
  where member_allergies.member_id = v_order.member_id
    and member_allergies.allergy_group = 'food';

  select string_agg(member_allergies.allergy_name, ', ' order by member_allergies.allergy_name)
  into v_medication_allergies
  from public.member_allergies as member_allergies
  where member_allergies.member_id = v_order.member_id
    and member_allergies.allergy_group = 'medication';

  select string_agg(member_allergies.allergy_name, ', ' order by member_allergies.allergy_name)
  into v_environmental_allergies
  from public.member_allergies as member_allergies
  where member_allergies.member_id = v_order.member_id
    and member_allergies.allergy_group = 'environmental';

  update public.member_command_centers as member_command_centers
  set
    code_status = v_code_status,
    dnr = coalesce(v_order.dnr_selected, false),
    diet_type = v_primary_diet,
    dietary_preferences_restrictions = nullif(
      concat_ws(
        ' | ',
        nullif(trim(coalesce(v_order.clinical_support ->> 'nutritionDietOther', '')), ''),
        nullif(trim(coalesce(v_order.clinical_support ->> 'joySparksNotes', '')), '')
      ),
      ''
    ),
    no_known_allergies = not exists (
      select 1 from public.member_allergies as member_allergies where member_allergies.member_id = v_order.member_id
    ),
    medication_allergies = nullif(coalesce(v_medication_allergies, ''), ''),
    food_allergies = nullif(coalesce(v_food_allergies, ''), ''),
    environmental_allergies = nullif(coalesce(v_environmental_allergies, ''), ''),
    source_assessment_id = v_order.intake_assessment_id,
    source_assessment_at = (v_order.signed_at at time zone 'America/New_York')::date,
    updated_by_user_id = v_actor_user_id,
    updated_by_name = v_actor_name,
    updated_at = v_now
  where member_command_centers.member_id = v_order.member_id;

  return query
  select
    v_order.member_id,
    member_health_profiles.id,
    member_command_centers.id
  from public.member_health_profiles as member_health_profiles
  left join public.member_command_centers as member_command_centers
    on member_command_centers.member_id = member_health_profiles.member_id
  where member_health_profiles.member_id = v_order.member_id;
end;
$$;


ALTER FUNCTION "public"."rpc_sync_signed_pof_to_member_clinical_profile"("p_pof_id" "uuid", "p_synced_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_transition_care_plan_caregiver_status"("p_care_plan_id" "uuid", "p_status" "text", "p_updated_at" timestamp with time zone DEFAULT "now"(), "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_caregiver_sent_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_caregiver_viewed_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_caregiver_signature_error" "text" DEFAULT NULL::"text", "p_expected_current_statuses" "text"[] DEFAULT NULL::"text"[]) RETURNS TABLE("care_plan_id" "uuid", "caregiver_signature_status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status text := trim(coalesce(p_status, ''));
  v_expected_statuses text[] := (
    select case
      when p_expected_current_statuses is null then null
      else array_agg(nullif(trim(value), ''))
    end
    from unnest(coalesce(p_expected_current_statuses, array[]::text[])) as value
    where nullif(trim(value), '') is not null
  );
  v_current_status text;
begin
  if p_care_plan_id is null then
    raise exception 'rpc_transition_care_plan_caregiver_status requires p_care_plan_id';
  end if;
  if v_status = '' then
    raise exception 'rpc_transition_care_plan_caregiver_status requires p_status';
  end if;

  select cp.caregiver_signature_status
  into v_current_status
  from public.care_plans as cp
  where cp.id = p_care_plan_id
  for update;

  if not found then
    raise exception 'Care plan was not found.';
  end if;

  if v_expected_statuses is null and v_status in ('viewed', 'expired') then
    v_expected_statuses := array['ready_to_send', 'send_failed', 'sent', 'viewed', 'expired'];
  end if;

  if coalesce(v_current_status, '') = 'signed'
     and v_status in ('send_failed', 'viewed', 'expired', 'ready_to_send', 'sent') then
    raise exception 'Care plan % caregiver signature is already signed and cannot move backward to %.', p_care_plan_id, v_status;
  end if;

  if v_expected_statuses is not null and coalesce(array_length(v_expected_statuses, 1), 0) > 0 then
    if coalesce(v_current_status, '') <> all(v_expected_statuses) then
      raise exception
        'Care plan % caregiver signature transition expected current status % but found %.',
        p_care_plan_id,
        array_to_string(v_expected_statuses, ', '),
        coalesce(v_current_status, 'null');
    end if;
  end if;

  update public.care_plans
  set
    caregiver_signature_status = v_status,
    caregiver_sent_at = case when p_caregiver_sent_at is distinct from null then p_caregiver_sent_at else caregiver_sent_at end,
    caregiver_viewed_at = case when p_caregiver_viewed_at is distinct from null then p_caregiver_viewed_at else caregiver_viewed_at end,
    caregiver_signature_error = case
      when p_caregiver_signature_error is null then null
      else nullif(trim(p_caregiver_signature_error), '')
    end,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = p_updated_at
  where id = p_care_plan_id;

  return query
  select
    p_care_plan_id,
    v_status;
end;
$$;


ALTER FUNCTION "public"."rpc_transition_care_plan_caregiver_status"("p_care_plan_id" "uuid", "p_status" "text", "p_updated_at" timestamp with time zone, "p_actor_user_id" "uuid", "p_actor_name" "text", "p_caregiver_sent_at" timestamp with time zone, "p_caregiver_viewed_at" timestamp with time zone, "p_caregiver_signature_error" "text", "p_expected_current_statuses" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_transition_enrollment_packet_delivery_state"("p_packet_id" "uuid", "p_delivery_status" "text", "p_attempt_at" timestamp with time zone DEFAULT "now"(), "p_status" "text" DEFAULT NULL::"text", "p_sent_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_delivery_error" "text" DEFAULT NULL::"text", "p_expected_current_status" "text" DEFAULT NULL::"text") RETURNS TABLE("packet_id" "uuid", "status" "text", "delivery_status" "text", "did_transition" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.enrollment_packet_requests%rowtype;
  v_status text;
begin
  if p_packet_id is null then
    raise exception 'rpc_transition_enrollment_packet_delivery_state requires p_packet_id';
  end if;
  if nullif(trim(coalesce(p_delivery_status, '')), '') is null then
    raise exception 'rpc_transition_enrollment_packet_delivery_state requires p_delivery_status';
  end if;

  select *
  into v_request
  from public.enrollment_packet_requests
  where id = p_packet_id
  for update;

  if not found then
    raise exception 'Enrollment packet request was not found.';
  end if;

  if nullif(trim(coalesce(p_expected_current_status, '')), '') is not null
     and v_request.status is distinct from trim(p_expected_current_status) then
    return query
    select
      p_packet_id,
      v_request.status,
      v_request.delivery_status,
      false;
    return;
  end if;

  v_status := coalesce(nullif(trim(coalesce(p_status, '')), ''), v_request.status);

  update public.enrollment_packet_requests
  set
    status = v_status,
    delivery_status = trim(p_delivery_status),
    last_delivery_attempt_at = p_attempt_at,
    delivery_failed_at = case when trim(p_delivery_status) = 'send_failed' then p_attempt_at else null end,
    delivery_error = nullif(trim(coalesce(p_delivery_error, '')), ''),
    sent_at = case when p_sent_at is distinct from null then p_sent_at else sent_at end,
    updated_at = p_attempt_at
  where id = p_packet_id;

  return query
  select
    p_packet_id,
    v_status,
    trim(p_delivery_status),
    true;
end;
$$;


ALTER FUNCTION "public"."rpc_transition_enrollment_packet_delivery_state"("p_packet_id" "uuid", "p_delivery_status" "text", "p_attempt_at" timestamp with time zone, "p_status" "text", "p_sent_at" timestamp with time zone, "p_delivery_error" "text", "p_expected_current_status" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_transition_enrollment_packet_delivery_state"("p_packet_id" "uuid", "p_delivery_status" "text", "p_attempt_at" timestamp with time zone DEFAULT "now"(), "p_status" "text" DEFAULT NULL::"text", "p_sent_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_opened_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_delivery_error" "text" DEFAULT NULL::"text", "p_expected_current_status" "text" DEFAULT NULL::"text") RETURNS TABLE("packet_id" "uuid", "status" "text", "delivery_status" "text", "did_transition" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.enrollment_packet_requests%rowtype;
  v_status text;
begin
  if p_packet_id is null then
    raise exception 'rpc_transition_enrollment_packet_delivery_state requires p_packet_id';
  end if;
  if nullif(trim(coalesce(p_delivery_status, '')), '') is null then
    raise exception 'rpc_transition_enrollment_packet_delivery_state requires p_delivery_status';
  end if;

  select *
  into v_request
  from public.enrollment_packet_requests
  where id = p_packet_id
  for update;

  if not found then
    raise exception 'Enrollment packet request was not found.';
  end if;

  if nullif(trim(coalesce(p_expected_current_status, '')), '') is not null
     and v_request.status is distinct from trim(p_expected_current_status) then
    return query
    select
      p_packet_id,
      v_request.status,
      v_request.delivery_status,
      false;
    return;
  end if;

  v_status := coalesce(nullif(trim(coalesce(p_status, '')), ''), v_request.status);

  update public.enrollment_packet_requests
  set
    status = v_status,
    delivery_status = trim(p_delivery_status),
    last_delivery_attempt_at = p_attempt_at,
    delivery_failed_at = case when trim(p_delivery_status) = 'send_failed' then p_attempt_at else null end,
    delivery_error = nullif(trim(coalesce(p_delivery_error, '')), ''),
    sent_at = case when p_sent_at is distinct from null then p_sent_at else sent_at end,
    opened_at = case when p_opened_at is distinct from null then coalesce(opened_at, p_opened_at) else opened_at end,
    last_family_activity_at = case
      when p_opened_at is distinct from null then coalesce(last_family_activity_at, p_opened_at)
      else last_family_activity_at
    end,
    updated_at = p_attempt_at
  where id = p_packet_id;

  return query
  select
    p_packet_id,
    v_status,
    trim(p_delivery_status),
    true;
end;
