ALTER FUNCTION "public"."rpc_transition_enrollment_packet_delivery_state"("p_packet_id" "uuid", "p_delivery_status" "text", "p_attempt_at" timestamp with time zone, "p_status" "text", "p_sent_at" timestamp with time zone, "p_opened_at" timestamp with time zone, "p_delivery_error" "text", "p_expected_current_status" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_transition_lead_stage"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text" DEFAULT NULL::"text", "p_additional_lead_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_now" timestamp with time zone DEFAULT "now"(), "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("lead_id" "uuid", "from_stage" "text", "to_stage" "text", "from_status" "text", "to_status" "text", "business_status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_lead public.leads%rowtype;
  v_patch jsonb := (coalesce(p_additional_lead_patch, '{}'::jsonb) - 'stage' - 'status');
  v_now timestamptz := coalesce(p_now, now());
  v_today date := coalesce(p_today, current_date);
  v_next_stage text := nullif(trim(coalesce(p_to_stage, '')), '');
  v_next_status text := nullif(trim(coalesce(p_to_status, '')), '');
  v_business_status text := nullif(trim(coalesce(p_business_status, '')), '');
begin
  if p_lead_id is null then
    raise exception 'rpc_transition_lead_stage requires p_lead_id';
  end if;
  if v_next_stage is null then
    raise exception 'rpc_transition_lead_stage requires p_to_stage';
  end if;
  if v_next_status is null then
    raise exception 'rpc_transition_lead_stage requires p_to_status';
  end if;
  if v_business_status is null then
    raise exception 'rpc_transition_lead_stage requires p_business_status';
  end if;

  select *
  into v_lead
  from public.leads
  where id = p_lead_id
  for update;

  if not found then
    raise exception 'Lead not found.';
  end if;

  update public.leads
  set
    stage = v_next_stage,
    status = v_next_status::public.lead_status,
    stage_updated_at = case
      when v_patch ? 'stage_updated_at' then nullif(trim(coalesce(v_patch ->> 'stage_updated_at', '')), '')::timestamptz
      else v_now
    end,
    inquiry_date = case
      when v_patch ? 'inquiry_date' then nullif(trim(coalesce(v_patch ->> 'inquiry_date', '')), '')::date
      else inquiry_date
    end,
    tour_date = case
      when v_patch ? 'tour_date' then nullif(trim(coalesce(v_patch ->> 'tour_date', '')), '')::date
      else tour_date
    end,
    tour_completed = case
      when v_patch ? 'tour_completed' then coalesce((v_patch ->> 'tour_completed')::boolean, false)
      else tour_completed
    end,
    discovery_date = case
      when v_patch ? 'discovery_date' then nullif(trim(coalesce(v_patch ->> 'discovery_date', '')), '')::date
      else discovery_date
    end,
    member_start_date = case
      when v_patch ? 'member_start_date' then nullif(trim(coalesce(v_patch ->> 'member_start_date', '')), '')::date
      else member_start_date
    end,
    caregiver_name = case
      when v_patch ? 'caregiver_name' then nullif(trim(coalesce(v_patch ->> 'caregiver_name', '')), '')
      else caregiver_name
    end,
    caregiver_relationship = case
      when v_patch ? 'caregiver_relationship' then nullif(trim(coalesce(v_patch ->> 'caregiver_relationship', '')), '')
      else caregiver_relationship
    end,
    caregiver_email = case
      when v_patch ? 'caregiver_email' then nullif(trim(coalesce(v_patch ->> 'caregiver_email', '')), '')
      else caregiver_email
    end,
    caregiver_phone = case
      when v_patch ? 'caregiver_phone' then nullif(trim(coalesce(v_patch ->> 'caregiver_phone', '')), '')
      else caregiver_phone
    end,
    member_name = case
      when v_patch ? 'member_name' then nullif(trim(coalesce(v_patch ->> 'member_name', '')), '')
      else member_name
    end,
    member_dob = case
      when v_patch ? 'member_dob' then nullif(trim(coalesce(v_patch ->> 'member_dob', '')), '')::date
      else member_dob
    end,
    lead_source = case
      when v_patch ? 'lead_source' then nullif(trim(coalesce(v_patch ->> 'lead_source', '')), '')
      else lead_source
    end,
    lead_source_other = case
      when v_patch ? 'lead_source_other' then nullif(trim(coalesce(v_patch ->> 'lead_source_other', '')), '')
      else lead_source_other
    end,
    partner_id = case
      when v_patch ? 'partner_id' then nullif(trim(coalesce(v_patch ->> 'partner_id', '')), '')
      else partner_id::text
    end::text,
    referral_source_id = case
      when v_patch ? 'referral_source_id' then nullif(trim(coalesce(v_patch ->> 'referral_source_id', '')), '')
      else referral_source_id::text
    end::text,
    referral_name = case
      when v_patch ? 'referral_name' then nullif(trim(coalesce(v_patch ->> 'referral_name', '')), '')
      else referral_name
    end,
    likelihood = case
      when v_patch ? 'likelihood' then nullif(trim(coalesce(v_patch ->> 'likelihood', '')), '')
      else likelihood
    end,
    next_follow_up_date = case
      when v_patch ? 'next_follow_up_date' then nullif(trim(coalesce(v_patch ->> 'next_follow_up_date', '')), '')::date
      else next_follow_up_date
    end,
    next_follow_up_type = case
      when v_patch ? 'next_follow_up_type' then nullif(trim(coalesce(v_patch ->> 'next_follow_up_type', '')), '')
      else next_follow_up_type
    end,
    notes_summary = case
      when v_patch ? 'notes_summary' then nullif(trim(coalesce(v_patch ->> 'notes_summary', '')), '')
      else notes_summary
    end,
    lost_reason = case
      when v_patch ? 'lost_reason' then nullif(trim(coalesce(v_patch ->> 'lost_reason', '')), '')
      when lower(v_business_status) = 'lost' then lost_reason
      else null
    end,
    closed_date = case
      when v_patch ? 'closed_date' then nullif(trim(coalesce(v_patch ->> 'closed_date', '')), '')::date
      when lower(v_business_status) in ('won', 'lost') then v_today
      else null
    end,
    updated_at = case
      when v_patch ? 'updated_at' then nullif(trim(coalesce(v_patch ->> 'updated_at', '')), '')::timestamptz
      else v_now
    end
  where id = p_lead_id;

  if coalesce(v_lead.stage, '') is distinct from v_next_stage
    or coalesce(v_lead.status, '') is distinct from v_next_status then
    insert into public.lead_stage_history (
      lead_id,
      from_stage,
      to_stage,
      from_status,
      to_status,
      changed_by_user_id,
      changed_by_name,
      reason,
      source,
      changed_at,
      created_at
    )
    values (
      p_lead_id,
      nullif(trim(coalesce(v_lead.stage, '')), ''),
      v_next_stage,
      nullif(trim(coalesce(v_lead.status, '')), ''),
      v_next_status,
      p_actor_user_id,
      nullif(trim(coalesce(p_actor_name, '')), ''),
      nullif(trim(coalesce(p_reason, '')), ''),
      nullif(trim(coalesce(p_source, '')), ''),
      v_now,
      v_now
    );
  end if;

  return query
  select
    p_lead_id,
    nullif(trim(coalesce(v_lead.stage, '')), ''),
    v_next_stage,
    nullif(trim(coalesce(v_lead.status, '')), ''),
    v_next_status,
    v_business_status;
end;
$$;


ALTER FUNCTION "public"."rpc_transition_lead_stage"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text", "p_additional_lead_patch" "jsonb", "p_now" timestamp with time zone, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_transition_lead_stage_v2"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text" DEFAULT NULL::"text", "p_additional_lead_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_now" timestamp with time zone DEFAULT "now"(), "p_today" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("lead_id" "uuid", "from_stage" "text", "to_stage" "text", "from_status" "text", "to_status" "text", "business_status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_lead public.leads%rowtype;
  v_patch jsonb := (coalesce(p_additional_lead_patch, '{}'::jsonb) - 'stage' - 'status');
  v_now timestamptz := coalesce(p_now, now());
  v_today date := coalesce(p_today, current_date);
  v_next_stage text := nullif(trim(coalesce(p_to_stage, '')), '');
  v_next_status public.lead_status;
  v_business_status text := nullif(trim(coalesce(p_business_status, '')), '');
begin
  if p_lead_id is null then
    raise exception 'rpc_transition_lead_stage_v2 requires p_lead_id';
  end if;
  if v_next_stage is null then
    raise exception 'rpc_transition_lead_stage_v2 requires p_to_stage';
  end if;
  if nullif(trim(coalesce(p_to_status, '')), '') is null then
    raise exception 'rpc_transition_lead_stage_v2 requires p_to_status';
  end if;
  if v_business_status is null then
    raise exception 'rpc_transition_lead_stage_v2 requires p_business_status';
  end if;

  v_next_status := trim(p_to_status)::public.lead_status;

  select *
  into v_lead
  from public.leads
  where id = p_lead_id
  for update;

  if not found then
    raise exception 'Lead not found.';
  end if;

  update public.leads
  set
    stage = v_next_stage,
    status = v_next_status,
    stage_updated_at = case
      when v_patch ? 'stage_updated_at' then nullif(trim(coalesce(v_patch ->> 'stage_updated_at', '')), '')::timestamptz
      else v_now
    end,
    inquiry_date = case
      when v_patch ? 'inquiry_date' then nullif(trim(coalesce(v_patch ->> 'inquiry_date', '')), '')::date
      else inquiry_date
    end,
    tour_date = case
      when v_patch ? 'tour_date' then nullif(trim(coalesce(v_patch ->> 'tour_date', '')), '')::date
      else tour_date
    end,
    tour_completed = case
      when v_patch ? 'tour_completed' then coalesce((v_patch ->> 'tour_completed')::boolean, false)
      else tour_completed
    end,
    discovery_date = case
      when v_patch ? 'discovery_date' then nullif(trim(coalesce(v_patch ->> 'discovery_date', '')), '')::date
      else discovery_date
    end,
    member_start_date = case
      when v_patch ? 'member_start_date' then nullif(trim(coalesce(v_patch ->> 'member_start_date', '')), '')::date
      else member_start_date
    end,
    caregiver_name = case
      when v_patch ? 'caregiver_name' then nullif(trim(coalesce(v_patch ->> 'caregiver_name', '')), '')
      else caregiver_name
    end,
    caregiver_relationship = case
      when v_patch ? 'caregiver_relationship' then nullif(trim(coalesce(v_patch ->> 'caregiver_relationship', '')), '')
      else caregiver_relationship
    end,
    caregiver_email = case
      when v_patch ? 'caregiver_email' then nullif(trim(coalesce(v_patch ->> 'caregiver_email', '')), '')
      else caregiver_email
    end,
    caregiver_phone = case
      when v_patch ? 'caregiver_phone' then nullif(trim(coalesce(v_patch ->> 'caregiver_phone', '')), '')
      else caregiver_phone
    end,
    member_name = case
      when v_patch ? 'member_name' then nullif(trim(coalesce(v_patch ->> 'member_name', '')), '')
      else member_name
    end,
    member_dob = case
      when v_patch ? 'member_dob' then nullif(trim(coalesce(v_patch ->> 'member_dob', '')), '')::date
      else member_dob
    end,
    lead_source = case
      when v_patch ? 'lead_source' then nullif(trim(coalesce(v_patch ->> 'lead_source', '')), '')
      else lead_source
    end,
    lead_source_other = case
      when v_patch ? 'lead_source_other' then nullif(trim(coalesce(v_patch ->> 'lead_source_other', '')), '')
      else lead_source_other
    end,
    partner_id = case
      when v_patch ? 'partner_id' then nullif(trim(coalesce(v_patch ->> 'partner_id', '')), '')
      else partner_id::text
    end::text,
    referral_source_id = case
      when v_patch ? 'referral_source_id' then nullif(trim(coalesce(v_patch ->> 'referral_source_id', '')), '')
      else referral_source_id::text
    end::text,
    referral_name = case
      when v_patch ? 'referral_name' then nullif(trim(coalesce(v_patch ->> 'referral_name', '')), '')
      else referral_name
    end,
    likelihood = case
      when v_patch ? 'likelihood' then nullif(trim(coalesce(v_patch ->> 'likelihood', '')), '')
      else likelihood
    end,
    next_follow_up_date = case
      when v_patch ? 'next_follow_up_date' then nullif(trim(coalesce(v_patch ->> 'next_follow_up_date', '')), '')::date
      else next_follow_up_date
    end,
    next_follow_up_type = case
      when v_patch ? 'next_follow_up_type' then nullif(trim(coalesce(v_patch ->> 'next_follow_up_type', '')), '')
      else next_follow_up_type
    end,
    notes_summary = case
      when v_patch ? 'notes_summary' then nullif(trim(coalesce(v_patch ->> 'notes_summary', '')), '')
      else notes_summary
    end,
    lost_reason = case
      when v_patch ? 'lost_reason' then nullif(trim(coalesce(v_patch ->> 'lost_reason', '')), '')
      when lower(v_business_status) = 'lost' then lost_reason
      else null
    end,
    closed_date = case
      when v_patch ? 'closed_date' then nullif(trim(coalesce(v_patch ->> 'closed_date', '')), '')::date
      when lower(v_business_status) in ('won', 'lost') then v_today
      else null
    end,
    updated_at = case
      when v_patch ? 'updated_at' then nullif(trim(coalesce(v_patch ->> 'updated_at', '')), '')::timestamptz
      else v_now
    end
  where id = p_lead_id;

  if coalesce(v_lead.stage, '') is distinct from v_next_stage
    or coalesce(v_lead.status::text, '') is distinct from v_next_status::text then
    insert into public.lead_stage_history (
      lead_id,
      from_stage,
      to_stage,
      from_status,
      to_status,
      changed_by_user_id,
      changed_by_name,
      reason,
      source,
      changed_at,
      created_at
    )
    values (
      p_lead_id,
      nullif(trim(coalesce(v_lead.stage, '')), ''),
      v_next_stage,
      nullif(trim(coalesce(v_lead.status::text, '')), ''),
      v_next_status::text,
      p_actor_user_id,
      nullif(trim(coalesce(p_actor_name, '')), ''),
      nullif(trim(coalesce(p_reason, '')), ''),
      nullif(trim(coalesce(p_source, '')), ''),
      v_now,
      v_now
    );
  end if;

  return query
  select
    p_lead_id,
    nullif(trim(coalesce(v_lead.stage, '')), ''),
    v_next_stage,
    nullif(trim(coalesce(v_lead.status::text, '')), ''),
    v_next_status::text,
    v_business_status;
end;
$$;


ALTER FUNCTION "public"."rpc_transition_lead_stage_v2"("p_lead_id" "uuid", "p_to_stage" "text", "p_to_status" "text", "p_business_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_source" "text", "p_reason" "text", "p_additional_lead_patch" "jsonb", "p_now" timestamp with time zone, "p_today" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_transition_pof_request_delivery_state"("p_request_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_delivery_status" "text", "p_attempt_at" timestamp with time zone DEFAULT "now"(), "p_status" "text" DEFAULT NULL::"text", "p_sent_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_opened_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_signed_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_delivery_error" "text" DEFAULT NULL::"text", "p_provider_name" "text" DEFAULT NULL::"text", "p_update_physician_order_sent" boolean DEFAULT false, "p_expected_current_status" "text" DEFAULT NULL::"text", "p_expected_current_delivery_status" "text" DEFAULT NULL::"text", "p_require_opened_at_null" boolean DEFAULT false) RETURNS TABLE("request_id" "uuid", "status" "text", "delivery_status" "text", "physician_order_id" "uuid", "did_transition" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.pof_requests%rowtype;
  v_status text;
  v_sent_at timestamptz;
begin
  if p_request_id is null then
    raise exception 'rpc_transition_pof_request_delivery_state requires p_request_id';
  end if;
  if nullif(trim(coalesce(p_delivery_status, '')), '') is null then
    raise exception 'rpc_transition_pof_request_delivery_state requires p_delivery_status';
  end if;

  select *
  into v_request
  from public.pof_requests
  where id = p_request_id
  for update;

  if not found then
    raise exception 'POF signature request was not found.';
  end if;

  if nullif(trim(coalesce(p_expected_current_status, '')), '') is not null
     and v_request.status is distinct from trim(p_expected_current_status) then
    return query
    select
      p_request_id,
      v_request.status,
      v_request.delivery_status,
      v_request.physician_order_id,
      false;
    return;
  end if;

  if nullif(trim(coalesce(p_expected_current_delivery_status, '')), '') is not null
     and coalesce(v_request.delivery_status, '') is distinct from trim(p_expected_current_delivery_status) then
    return query
    select
      p_request_id,
      v_request.status,
      v_request.delivery_status,
      v_request.physician_order_id,
      false;
    return;
  end if;

  if p_require_opened_at_null and v_request.opened_at is not null then
    return query
    select
      p_request_id,
      v_request.status,
      v_request.delivery_status,
      v_request.physician_order_id,
      false;
    return;
  end if;

  v_status := coalesce(nullif(trim(coalesce(p_status, '')), ''), v_request.status);
  v_sent_at := coalesce(p_sent_at, v_request.sent_at);

  update public.pof_requests as pof_requests
  set
    status = v_status,
    delivery_status = trim(p_delivery_status),
    last_delivery_attempt_at = p_attempt_at,
    delivery_failed_at = case when trim(p_delivery_status) = 'send_failed' then p_attempt_at else null end,
    delivery_error = nullif(trim(coalesce(p_delivery_error, '')), ''),
    sent_at = case when p_sent_at is distinct from null then p_sent_at else pof_requests.sent_at end,
    opened_at = case when p_opened_at is distinct from null then p_opened_at else pof_requests.opened_at end,
    signed_at = case when p_signed_at is distinct from null then p_signed_at else pof_requests.signed_at end,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = p_attempt_at
  where pof_requests.id = p_request_id;

  if p_update_physician_order_sent and v_status = 'sent' then
    update public.physician_orders as physician_orders
    set
      status = 'sent',
      provider_name = coalesce(nullif(trim(coalesce(p_provider_name, '')), ''), v_request.provider_name),
      sent_at = coalesce(v_sent_at, p_attempt_at),
      updated_by_user_id = p_actor_user_id,
      updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
      updated_at = p_attempt_at
    where physician_orders.id = v_request.physician_order_id
      and physician_orders.status <> 'signed';
  end if;

  return query
  select
    p_request_id,
    v_status,
    trim(p_delivery_status),
    v_request.physician_order_id,
    true;
end;
$$;


ALTER FUNCTION "public"."rpc_transition_pof_request_delivery_state"("p_request_id" "uuid", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_delivery_status" "text", "p_attempt_at" timestamp with time zone, "p_status" "text", "p_sent_at" timestamp with time zone, "p_opened_at" timestamp with time zone, "p_signed_at" timestamp with time zone, "p_delivery_error" "text", "p_provider_name" "text", "p_update_physician_order_sent" boolean, "p_expected_current_status" "text", "p_expected_current_delivery_status" "text", "p_require_opened_at_null" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_update_member_command_center_bundle"("p_member_id" "uuid", "p_mcc_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_member_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("member_command_center_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_mcc_patch public.member_command_centers%rowtype;
  v_member_patch public.members%rowtype;
begin
  if p_member_id is null then
    raise exception 'rpc_update_member_command_center_bundle requires p_member_id';
  end if;

  insert into public.member_command_centers (
    id,
    member_id,
    primary_language,
    updated_by_user_id,
    updated_by_name,
    created_at,
    updated_at
  )
  values (
    'mcc-' || p_member_id::text,
    p_member_id,
    'English',
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    v_now,
    v_now
  )
  on conflict (member_id) do nothing;

  select *
  into v_mcc_patch
  from jsonb_populate_record(null::public.member_command_centers, coalesce(p_mcc_patch, '{}'::jsonb));

  update public.member_command_centers
  set
    original_referral_source = case when p_mcc_patch ? 'original_referral_source' then v_mcc_patch.original_referral_source else original_referral_source end,
    photo_consent = case when p_mcc_patch ? 'photo_consent' then v_mcc_patch.photo_consent else photo_consent end,
    location = case when p_mcc_patch ? 'location' then v_mcc_patch.location else location end,
    profile_image_url = case when p_mcc_patch ? 'profile_image_url' then v_mcc_patch.profile_image_url else profile_image_url end,
    gender = case when p_mcc_patch ? 'gender' then v_mcc_patch.gender else gender end,
    street_address = case when p_mcc_patch ? 'street_address' then v_mcc_patch.street_address else street_address end,
    city = case when p_mcc_patch ? 'city' then v_mcc_patch.city else city end,
    state = case when p_mcc_patch ? 'state' then v_mcc_patch.state else state end,
    zip = case when p_mcc_patch ? 'zip' then v_mcc_patch.zip else zip end,
    marital_status = case when p_mcc_patch ? 'marital_status' then v_mcc_patch.marital_status else marital_status end,
    primary_language = case when p_mcc_patch ? 'primary_language' then v_mcc_patch.primary_language else primary_language end,
    secondary_language = case when p_mcc_patch ? 'secondary_language' then v_mcc_patch.secondary_language else secondary_language end,
    religion = case when p_mcc_patch ? 'religion' then v_mcc_patch.religion else religion end,
    ethnicity = case when p_mcc_patch ? 'ethnicity' then v_mcc_patch.ethnicity else ethnicity end,
    is_veteran = case when p_mcc_patch ? 'is_veteran' then v_mcc_patch.is_veteran else is_veteran end,
    veteran_branch = case when p_mcc_patch ? 'veteran_branch' then v_mcc_patch.veteran_branch else veteran_branch end,
    code_status = case when p_mcc_patch ? 'code_status' then v_mcc_patch.code_status else code_status end,
    dnr = case when p_mcc_patch ? 'dnr' then v_mcc_patch.dnr else dnr end,
    dni = case when p_mcc_patch ? 'dni' then v_mcc_patch.dni else dni end,
    polst_molst_colst = case when p_mcc_patch ? 'polst_molst_colst' then v_mcc_patch.polst_molst_colst else polst_molst_colst end,
    hospice = case when p_mcc_patch ? 'hospice' then v_mcc_patch.hospice else hospice end,
    advanced_directives_obtained = case when p_mcc_patch ? 'advanced_directives_obtained' then v_mcc_patch.advanced_directives_obtained else advanced_directives_obtained end,
    power_of_attorney = case when p_mcc_patch ? 'power_of_attorney' then v_mcc_patch.power_of_attorney else power_of_attorney end,
    legal_comments = case when p_mcc_patch ? 'legal_comments' then v_mcc_patch.legal_comments else legal_comments end,
    diet_type = case when p_mcc_patch ? 'diet_type' then v_mcc_patch.diet_type else diet_type end,
    dietary_preferences_restrictions = case when p_mcc_patch ? 'dietary_preferences_restrictions' then v_mcc_patch.dietary_preferences_restrictions else dietary_preferences_restrictions end,
    swallowing_difficulty = case when p_mcc_patch ? 'swallowing_difficulty' then v_mcc_patch.swallowing_difficulty else swallowing_difficulty end,
    supplements = case when p_mcc_patch ? 'supplements' then v_mcc_patch.supplements else supplements end,
    food_dislikes = case when p_mcc_patch ? 'food_dislikes' then v_mcc_patch.food_dislikes else food_dislikes end,
    foods_to_omit = case when p_mcc_patch ? 'foods_to_omit' then v_mcc_patch.foods_to_omit else foods_to_omit end,
    diet_texture = case when p_mcc_patch ? 'diet_texture' then v_mcc_patch.diet_texture else diet_texture end,
    command_center_notes = case when p_mcc_patch ? 'command_center_notes' then v_mcc_patch.command_center_notes else command_center_notes end,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  where member_id = p_member_id;

  select *
  into v_member_patch
  from jsonb_populate_record(null::public.members, coalesce(p_member_patch, '{}'::jsonb));

  update public.members
  set
    locker_number = case when p_member_patch ? 'locker_number' then v_member_patch.locker_number else locker_number end,
    city = case when p_member_patch ? 'city' then v_member_patch.city else city end,
    display_name = case when p_member_patch ? 'display_name' then v_member_patch.display_name else display_name end,
    dob = case when p_member_patch ? 'dob' then v_member_patch.dob else dob end,
    enrollment_date = case when p_member_patch ? 'enrollment_date' then v_member_patch.enrollment_date else enrollment_date end,
    code_status = case when p_member_patch ? 'code_status' then v_member_patch.code_status else code_status end
  where id = p_member_id;

  return query
  select id
  from public.member_command_centers
  where member_id = p_member_id;
end;
$$;


ALTER FUNCTION "public"."rpc_update_member_command_center_bundle"("p_member_id" "uuid", "p_mcc_patch" "jsonb", "p_member_patch" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_update_member_health_profile_bundle"("p_member_id" "uuid", "p_mhp_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_member_patch" "jsonb" DEFAULT '{}'::"jsonb", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"(), "p_sync_to_mcc" boolean DEFAULT true, "p_hospital_name" "text" DEFAULT NULL::"text") RETURNS TABLE("member_health_profile_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_mhp_patch public.member_health_profiles%rowtype;
  v_member_patch public.members%rowtype;
  v_profile_id uuid;
begin
  if p_member_id is null then
    raise exception 'rpc_update_member_health_profile_bundle requires p_member_id';
  end if;

  insert into public.member_health_profiles (
    member_id, created_at, updated_at, updated_by_user_id, updated_by_name
  )
  values (
    p_member_id, v_now, v_now, p_actor_user_id, nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict (member_id) do nothing;

  select id into v_profile_id
  from public.member_health_profiles
  where member_id = p_member_id
  for update;

  select * into v_mhp_patch
  from jsonb_populate_record(null::public.member_health_profiles, coalesce(p_mhp_patch, '{}'::jsonb));

  update public.member_health_profiles
  set
    gender = case
      when p_mhp_patch ? 'gender' then
        case
          when lower(trim(coalesce(v_mhp_patch.gender, ''))) in ('m', 'male') then 'M'
          when lower(trim(coalesce(v_mhp_patch.gender, ''))) in ('f', 'female') then 'F'
          else null
        end
      else gender
    end,
    payor = case when p_mhp_patch ? 'payor' then v_mhp_patch.payor else payor end,
    original_referral_source = case when p_mhp_patch ? 'original_referral_source' then v_mhp_patch.original_referral_source else original_referral_source end,
    photo_consent = case when p_mhp_patch ? 'photo_consent' then v_mhp_patch.photo_consent else photo_consent end,
    profile_image_url = case when p_mhp_patch ? 'profile_image_url' then v_mhp_patch.profile_image_url else profile_image_url end,
    primary_caregiver_name = case when p_mhp_patch ? 'primary_caregiver_name' then v_mhp_patch.primary_caregiver_name else primary_caregiver_name end,
    primary_caregiver_phone = case when p_mhp_patch ? 'primary_caregiver_phone' then v_mhp_patch.primary_caregiver_phone else primary_caregiver_phone end,
    responsible_party_name = case when p_mhp_patch ? 'responsible_party_name' then v_mhp_patch.responsible_party_name else responsible_party_name end,
    responsible_party_phone = case when p_mhp_patch ? 'responsible_party_phone' then v_mhp_patch.responsible_party_phone else responsible_party_phone end,
    important_alerts = case when p_mhp_patch ? 'important_alerts' then v_mhp_patch.important_alerts else important_alerts end,
    diet_type = case when p_mhp_patch ? 'diet_type' then v_mhp_patch.diet_type else diet_type end,
    dietary_restrictions = case when p_mhp_patch ? 'dietary_restrictions' then v_mhp_patch.dietary_restrictions else dietary_restrictions end,
    swallowing_difficulty = case when p_mhp_patch ? 'swallowing_difficulty' then v_mhp_patch.swallowing_difficulty else swallowing_difficulty end,
    diet_texture = case when p_mhp_patch ? 'diet_texture' then v_mhp_patch.diet_texture else diet_texture end,
    supplements = case when p_mhp_patch ? 'supplements' then v_mhp_patch.supplements else supplements end,
    foods_to_omit = case when p_mhp_patch ? 'foods_to_omit' then v_mhp_patch.foods_to_omit else foods_to_omit end,
    ambulation = case when p_mhp_patch ? 'ambulation' then v_mhp_patch.ambulation else ambulation end,
    transferring = case when p_mhp_patch ? 'transferring' then v_mhp_patch.transferring else transferring end,
    bathing = case when p_mhp_patch ? 'bathing' then v_mhp_patch.bathing else bathing end,
    dressing = case when p_mhp_patch ? 'dressing' then v_mhp_patch.dressing else dressing end,
    eating = case when p_mhp_patch ? 'eating' then v_mhp_patch.eating else eating end,
    bladder_continence = case when p_mhp_patch ? 'bladder_continence' then v_mhp_patch.bladder_continence else bladder_continence end,
    bowel_continence = case when p_mhp_patch ? 'bowel_continence' then v_mhp_patch.bowel_continence else bowel_continence end,
    toileting = case when p_mhp_patch ? 'toileting' then v_mhp_patch.toileting else toileting end,
    toileting_needs = case when p_mhp_patch ? 'toileting_needs' then v_mhp_patch.toileting_needs else toileting_needs end,
    toileting_comments = case when p_mhp_patch ? 'toileting_comments' then v_mhp_patch.toileting_comments else toileting_comments end,
    hearing = case when p_mhp_patch ? 'hearing' then v_mhp_patch.hearing else hearing end,
    vision = case when p_mhp_patch ? 'vision' then v_mhp_patch.vision else vision end,
    dental = case when p_mhp_patch ? 'dental' then v_mhp_patch.dental else dental end,
    speech_verbal_status = case when p_mhp_patch ? 'speech_verbal_status' then v_mhp_patch.speech_verbal_status else speech_verbal_status end,
    speech_comments = case when p_mhp_patch ? 'speech_comments' then v_mhp_patch.speech_comments else speech_comments end,
    personal_appearance_hygiene_grooming = case when p_mhp_patch ? 'personal_appearance_hygiene_grooming' then v_mhp_patch.personal_appearance_hygiene_grooming else personal_appearance_hygiene_grooming end,
    may_self_medicate = case when p_mhp_patch ? 'may_self_medicate' then v_mhp_patch.may_self_medicate else may_self_medicate end,
    medication_manager_name = case when p_mhp_patch ? 'medication_manager_name' then v_mhp_patch.medication_manager_name else medication_manager_name end,
    orientation_dob = case when p_mhp_patch ? 'orientation_dob' then v_mhp_patch.orientation_dob else orientation_dob end,
    orientation_city = case when p_mhp_patch ? 'orientation_city' then v_mhp_patch.orientation_city else orientation_city end,
    orientation_current_year = case when p_mhp_patch ? 'orientation_current_year' then v_mhp_patch.orientation_current_year else orientation_current_year end,
    orientation_former_occupation = case when p_mhp_patch ? 'orientation_former_occupation' then v_mhp_patch.orientation_former_occupation else orientation_former_occupation end,
    memory_impairment = case when p_mhp_patch ? 'memory_impairment' then v_mhp_patch.memory_impairment else memory_impairment end,
    memory_severity = case when p_mhp_patch ? 'memory_severity' then v_mhp_patch.memory_severity else memory_severity end,
    wandering = case when p_mhp_patch ? 'wandering' then v_mhp_patch.wandering else wandering end,
    combative_disruptive = case when p_mhp_patch ? 'combative_disruptive' then v_mhp_patch.combative_disruptive else combative_disruptive end,
    sleep_issues = case when p_mhp_patch ? 'sleep_issues' then v_mhp_patch.sleep_issues else sleep_issues end,
    self_harm_unsafe = case when p_mhp_patch ? 'self_harm_unsafe' then v_mhp_patch.self_harm_unsafe else self_harm_unsafe end,
    impaired_judgement = case when p_mhp_patch ? 'impaired_judgement' then v_mhp_patch.impaired_judgement else impaired_judgement end,
    delirium = case when p_mhp_patch ? 'delirium' then v_mhp_patch.delirium else delirium end,
    disorientation = case when p_mhp_patch ? 'disorientation' then v_mhp_patch.disorientation else disorientation end,
    agitation_resistive = case when p_mhp_patch ? 'agitation_resistive' then v_mhp_patch.agitation_resistive else agitation_resistive end,
    screaming_loud_noises = case when p_mhp_patch ? 'screaming_loud_noises' then v_mhp_patch.screaming_loud_noises else screaming_loud_noises end,
    exhibitionism_disrobing = case when p_mhp_patch ? 'exhibitionism_disrobing' then v_mhp_patch.exhibitionism_disrobing else exhibitionism_disrobing end,
    exit_seeking = case when p_mhp_patch ? 'exit_seeking' then v_mhp_patch.exit_seeking else exit_seeking end,
    cognitive_behavior_comments = case when p_mhp_patch ? 'cognitive_behavior_comments' then v_mhp_patch.cognitive_behavior_comments else cognitive_behavior_comments end,
    code_status = case when p_mhp_patch ? 'code_status' then v_mhp_patch.code_status else code_status end,
    dnr = case when p_mhp_patch ? 'dnr' then v_mhp_patch.dnr else dnr end,
    dni = case when p_mhp_patch ? 'dni' then v_mhp_patch.dni else dni end,
    polst_molst_colst = case when p_mhp_patch ? 'polst_molst_colst' then v_mhp_patch.polst_molst_colst else polst_molst_colst end,
    hospice = case when p_mhp_patch ? 'hospice' then v_mhp_patch.hospice else hospice end,
    advanced_directives_obtained = case when p_mhp_patch ? 'advanced_directives_obtained' then v_mhp_patch.advanced_directives_obtained else advanced_directives_obtained end,
    power_of_attorney = case when p_mhp_patch ? 'power_of_attorney' then v_mhp_patch.power_of_attorney else power_of_attorney end,
    hospital_preference = case when p_mhp_patch ? 'hospital_preference' then v_mhp_patch.hospital_preference else hospital_preference end,
    legal_comments = case when p_mhp_patch ? 'legal_comments' then v_mhp_patch.legal_comments else legal_comments end,
    updated_by_user_id = p_actor_user_id,
    updated_by_name = nullif(trim(coalesce(p_actor_name, '')), ''),
    updated_at = v_now
  where id = v_profile_id;

  select * into v_member_patch
  from jsonb_populate_record(null::public.members, coalesce(p_member_patch, '{}'::jsonb));

  update public.members
  set
    dob = case when p_member_patch ? 'dob' then v_member_patch.dob else dob end,
    code_status = case when p_member_patch ? 'code_status' then v_member_patch.code_status else code_status end
  where id = p_member_id;

  if nullif(trim(coalesce(p_hospital_name, '')), '') is not null then
    insert into public.hospital_preference_directory (
      id, hospital_name, created_by_user_id, created_by_name, created_at, updated_at
    )
    values (
      'hospital-' || replace(gen_random_uuid()::text, '-', ''), nullif(trim(coalesce(p_hospital_name, '')), ''),
      p_actor_user_id, nullif(trim(coalesce(p_actor_name, '')), ''), v_now, v_now
    )
    on conflict ((lower(btrim(hospital_name))))
    do update
    set hospital_name = excluded.hospital_name, updated_at = excluded.updated_at;
  end if;

  if coalesce(p_sync_to_mcc, true) then
    perform 1
    from public.rpc_sync_member_health_profile_to_command_center(
      p_member_id, p_actor_user_id, p_actor_name, v_now
    );
  end if;

  member_health_profile_id := v_profile_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_update_member_health_profile_bundle"("p_member_id" "uuid", "p_mhp_patch" "jsonb", "p_member_patch" "jsonb", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone, "p_sync_to_mcc" boolean, "p_hospital_name" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_update_member_track_with_note"("p_member_id" "uuid", "p_track" "text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("changed" boolean, "member_note_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_existing_track text;
  v_note_id uuid;
begin
  if p_member_id is null then
    raise exception 'rpc_update_member_track_with_note requires p_member_id';
  end if;

  if p_track is null or p_track not in ('Track 1', 'Track 2', 'Track 3') then
    raise exception 'rpc_update_member_track_with_note requires a valid track';
  end if;

  select latest_assessment_track
  into v_existing_track
  from public.members
  where id = p_member_id
  for update;

  if not found then
    raise exception 'Member % not found', p_member_id;
  end if;

  if coalesce(v_existing_track, '') = p_track then
    changed := false;
    member_note_id := null;
    return next;
    return;
  end if;

  update public.members
  set latest_assessment_track = p_track
  where id = p_member_id;

  insert into public.member_notes (
    member_id,
    note_type,
    note_text,
    created_by_user_id,
    created_by_name,
    created_at,
    updated_at
  )
  values (
    p_member_id,
    'Care Plan',
    format('Track changed to %s. Care plan review requested.', p_track),
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), ''),
    v_now,
    v_now
  )
  returning id into v_note_id;

  insert into public.member_health_profiles (
    member_id,
    created_at,
    updated_at,
    updated_by_user_id,
    updated_by_name
  )
  values (
    p_member_id,
    v_now,
    v_now,
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_name, '')), '')
  )
  on conflict (member_id) do update
  set
    updated_at = excluded.updated_at,
    updated_by_user_id = excluded.updated_by_user_id,
    updated_by_name = excluded.updated_by_name;

  changed := true;
  member_note_id := v_note_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_update_member_track_with_note"("p_member_id" "uuid", "p_track" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_update_schedule_change_status_with_attendance_sync"("p_schedule_change_id" "text", "p_status" "text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("id" "text", "member_id" "uuid", "change_type" "text", "effective_start_date" "date", "effective_end_date" "date", "original_days" "text"[], "new_days" "text"[], "suspend_base_schedule" boolean, "reason" "text", "notes" "text", "entered_by" "text", "entered_by_user_id" "uuid", "status" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "closed_at" timestamp with time zone, "closed_by" "text", "closed_by_user_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := coalesce(p_now, now());
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
  v_schedule_change_id text := nullif(trim(coalesce(p_schedule_change_id, '')), '');
  v_saved public.schedule_changes%rowtype;
  v_member public.members%rowtype;
  v_attendance_schedule_id text;
  v_target_days text[] := null;
begin
  if v_schedule_change_id is null then
    raise exception 'rpc_update_schedule_change_status_with_attendance_sync requires p_schedule_change_id';
  end if;
  if p_status not in ('active', 'cancelled', 'completed') then
    raise exception 'Invalid schedule change status.';
  end if;

  select *
  into v_saved
  from public.schedule_changes as schedule_changes
  where schedule_changes.id = v_schedule_change_id
  for update;

  if not found then
    raise exception 'Schedule change not found.';
  end if;

  select *
  into v_member
  from public.members as members
  where members.id = v_saved.member_id
  for update;

  if not found then
    raise exception 'Member % not found for schedule change status update.', v_saved.member_id;
  end if;

  insert into public.member_attendance_schedules (
    id,
    member_id,
    enrollment_date,
    monday,
    tuesday,
    wednesday,
    thursday,
    friday,
    full_day,
    transportation_billing_status,
    attendance_days_per_week,
    make_up_days_available,
    created_at,
    updated_at
  )
  values (
    'attendance-' || v_saved.member_id::text,
    v_saved.member_id,
    coalesce(v_member.enrollment_date, (v_now at time zone 'America/New_York')::date),
    false,
    false,
    false,
    false,
    false,
    true,
    'BillNormally',
    0,
    0,
    v_now,
    v_now
  )
  on conflict on constraint member_attendance_schedules_member_id_key do nothing;

  select member_attendance_schedules.id
  into v_attendance_schedule_id
  from public.member_attendance_schedules as member_attendance_schedules
  where member_attendance_schedules.member_id = v_saved.member_id
  for update;

  update public.schedule_changes as schedule_changes
  set
    status = p_status,
    closed_at = case when p_status = 'active' then null else v_now end,
    closed_by = case when p_status = 'active' then null else v_actor_name end,
    closed_by_user_id = case when p_status = 'active' then null else p_actor_user_id end,
    updated_at = v_now
  where schedule_changes.id = v_schedule_change_id
  returning * into v_saved;

  if v_saved.change_type = 'Permanent Schedule Change' then
    if p_status = 'cancelled' then
      v_target_days := coalesce(v_saved.original_days, '{}'::text[]);
    elsif p_status in ('active', 'completed') then
      v_target_days := coalesce(v_saved.new_days, '{}'::text[]);
    end if;
  end if;

  if v_target_days is not null then
    update public.member_attendance_schedules as member_attendance_schedules
    set
      monday = 'monday' = any(v_target_days),
      tuesday = 'tuesday' = any(v_target_days),
      wednesday = 'wednesday' = any(v_target_days),
      thursday = 'thursday' = any(v_target_days),
      friday = 'friday' = any(v_target_days),
      attendance_days_per_week =
        case when 'monday' = any(v_target_days) then 1 else 0 end +
        case when 'tuesday' = any(v_target_days) then 1 else 0 end +
        case when 'wednesday' = any(v_target_days) then 1 else 0 end +
        case when 'thursday' = any(v_target_days) then 1 else 0 end +
        case when 'friday' = any(v_target_days) then 1 else 0 end,
      updated_by_user_id = p_actor_user_id,
      updated_by_name = v_actor_name,
      updated_at = v_now
    where member_attendance_schedules.id = v_attendance_schedule_id;
  end if;

  return query
  select
    v_saved.id,
    v_saved.member_id,
    v_saved.change_type,
    v_saved.effective_start_date,
    v_saved.effective_end_date,
    v_saved.original_days,
    v_saved.new_days,
    v_saved.suspend_base_schedule,
    v_saved.reason,
    v_saved.notes,
    v_saved.entered_by,
    v_saved.entered_by_user_id,
    v_saved.status,
    v_saved.created_at,
    v_saved.updated_at,
    v_saved.closed_at,
    v_saved.closed_by,
    v_saved.closed_by_user_id;
end;
$$;


ALTER FUNCTION "public"."rpc_update_schedule_change_status_with_attendance_sync"("p_schedule_change_id" "text", "p_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_upsert_care_plan_core"("p_care_plan_id" "uuid", "p_member_id" "uuid", "p_track" "text", "p_enrollment_date" "date", "p_review_date" "date", "p_last_completed_date" "date", "p_next_due_date" "date", "p_status" "text", "p_care_team_notes" "text", "p_no_changes_needed" boolean, "p_modifications_required" boolean, "p_modifications_description" "text", "p_caregiver_name" "text", "p_caregiver_email" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone DEFAULT "now"(), "p_diagnosis_ids" "jsonb" DEFAULT '[]'::"jsonb", "p_sections" "jsonb" DEFAULT '[]'::"jsonb") RETURNS TABLE("care_plan_id" "uuid", "was_created" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_care_plan_id uuid;
  v_now timestamptz := coalesce(p_now, now());
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
begin
  if p_member_id is null then
    raise exception 'rpc_upsert_care_plan_core requires p_member_id';
  end if;
  if nullif(trim(coalesce(p_track, '')), '') is null then
    raise exception 'rpc_upsert_care_plan_core requires p_track';
  end if;
  if p_enrollment_date is null or p_review_date is null or p_next_due_date is null then
    raise exception 'rpc_upsert_care_plan_core requires enrollment, review, and next due dates';
  end if;
  if jsonb_typeof(coalesce(p_sections, '[]'::jsonb)) <> 'array' then
    raise exception 'rpc_upsert_care_plan_core requires p_sections to be a JSON array';
  end if;
  if jsonb_typeof(coalesce(p_diagnosis_ids, '[]'::jsonb)) <> 'array' then
    raise exception 'rpc_upsert_care_plan_core requires p_diagnosis_ids to be a JSON array';
  end if;
  if exists (
    select 1
    from jsonb_array_elements(coalesce(p_sections, '[]'::jsonb)) section
    where nullif(trim(coalesce(section ->> 'sectionType', '')), '') is null
      or nullif(trim(coalesce(section ->> 'shortTermGoals', '')), '') is null
      or nullif(trim(coalesce(section ->> 'longTermGoals', '')), '') is null
      or nullif(trim(coalesce(section ->> 'displayOrder', '')), '') is null
  ) then
    raise exception 'rpc_upsert_care_plan_core requires populated sectionType, shortTermGoals, longTermGoals, and displayOrder values';
  end if;
  if exists (
    select 1
    from jsonb_array_elements_text(coalesce(p_diagnosis_ids, '[]'::jsonb)) diagnosis_id(value)
    where nullif(trim(value), '') is null
       or trim(value) !~* '^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$'
  ) then
    raise exception 'rpc_upsert_care_plan_core requires diagnosis ids to be UUID strings';
  end if;
  if exists (
    select 1
    from (
      select distinct trim(value)::uuid as diagnosis_id
      from jsonb_array_elements_text(coalesce(p_diagnosis_ids, '[]'::jsonb)) diagnosis_id(value)
    ) diagnosis_ids
    left join public.member_diagnoses as md
      on md.id = diagnosis_ids.diagnosis_id
     and md.member_id = p_member_id
    where md.id is null
  ) then
    raise exception 'rpc_upsert_care_plan_core received diagnosis ids that do not belong to member %', p_member_id;
  end if;

  if p_care_plan_id is null then
    insert into public.care_plans (
      member_id,
      track,
      enrollment_date,
      review_date,
      last_completed_date,
      next_due_date,
      status,
      completed_by,
      date_of_completion,
      responsible_party_signature,
      responsible_party_signature_date,
      administrator_signature,
      administrator_signature_date,
      care_team_notes,
      no_changes_needed,
      modifications_required,
      modifications_description,
      nurse_designee_user_id,
      nurse_designee_name,
      nurse_signed_at,
      nurse_signature_status,
      nurse_signed_by_user_id,
      nurse_signed_by_name,
      nurse_signature_artifact_storage_path,
      nurse_signature_artifact_member_file_id,
      nurse_signature_metadata,
      caregiver_name,
      caregiver_email,
      caregiver_signature_status,
      caregiver_sent_at,
      caregiver_sent_by_user_id,
      caregiver_viewed_at,
      caregiver_signed_at,
      caregiver_signature_request_token,
      caregiver_signature_expires_at,
      caregiver_signature_request_url,
      caregiver_signed_name,
      caregiver_signature_image_url,
      caregiver_signature_ip,
      caregiver_signature_user_agent,
      final_member_file_id,
      legacy_cleanup_flag,
      created_by_user_id,
      created_by_name,
      updated_by_user_id,
      updated_by_name,
      created_at,
      updated_at
    )
    values (
      p_member_id,
      p_track,
      p_enrollment_date,
      p_review_date,
      p_last_completed_date,
      p_next_due_date,
      p_status,
      null,
      null,
      null,
      null,
      null,
      null,
      coalesce(p_care_team_notes, ''),
      coalesce(p_no_changes_needed, false),
      coalesce(p_modifications_required, false),
      coalesce(p_modifications_description, ''),
      null,
      null,
      null,
      'unsigned',
      null,
      null,
      null,
      null,
      '{}'::jsonb,
      nullif(trim(coalesce(p_caregiver_name, '')), ''),
      nullif(trim(coalesce(p_caregiver_email, '')), ''),
      'not_requested',
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      null,
      false,
      p_actor_user_id,
      v_actor_name,
      p_actor_user_id,
      v_actor_name,
      v_now,
      v_now
    )
    returning id into v_care_plan_id;
    was_created := true;
  else
    select cp.id
    into v_care_plan_id
    from public.care_plans as cp
    where cp.id = p_care_plan_id
    for update;

    if v_care_plan_id is null then
      raise exception 'Care plan % not found for update', p_care_plan_id;
    end if;

    update public.care_plans
    set
      track = p_track,
      enrollment_date = p_enrollment_date,
      review_date = p_review_date,
      last_completed_date = p_last_completed_date,
      next_due_date = p_next_due_date,
      status = p_status,
      completed_by = null,
      date_of_completion = null,
      responsible_party_signature = null,
      responsible_party_signature_date = null,
      administrator_signature = null,
      administrator_signature_date = null,
      care_team_notes = coalesce(p_care_team_notes, ''),
      no_changes_needed = coalesce(p_no_changes_needed, false),
      modifications_required = coalesce(p_modifications_required, false),
      modifications_description = coalesce(p_modifications_description, ''),
      nurse_designee_user_id = null,
      nurse_designee_name = null,
      nurse_signed_at = null,
      nurse_signature_status = 'unsigned',
      nurse_signed_by_user_id = null,
      nurse_signed_by_name = null,
      nurse_signature_artifact_storage_path = null,
      nurse_signature_artifact_member_file_id = null,
      nurse_signature_metadata = '{}'::jsonb,
      caregiver_name = nullif(trim(coalesce(p_caregiver_name, '')), ''),
      caregiver_email = nullif(trim(coalesce(p_caregiver_email, '')), ''),
      caregiver_signature_status = 'not_requested',
      caregiver_sent_at = null,
      caregiver_sent_by_user_id = null,
      caregiver_viewed_at = null,
      caregiver_signed_at = null,
      caregiver_signature_request_token = null,
      caregiver_signature_expires_at = null,
      caregiver_signature_request_url = null,
      caregiver_signed_name = null,
      caregiver_signature_image_url = null,
      caregiver_signature_ip = null,
      caregiver_signature_user_agent = null,
      final_member_file_id = null,
      legacy_cleanup_flag = false,
      updated_by_user_id = p_actor_user_id,
      updated_by_name = v_actor_name,
      updated_at = v_now
    where id = v_care_plan_id;

    was_created := false;
  end if;

  delete from public.care_plan_sections as cps
  where cps.care_plan_id = v_care_plan_id;

  insert into public.care_plan_sections (
    care_plan_id,
    section_type,
    short_term_goals,
    long_term_goals,
    display_order
  )
  select
    v_care_plan_id,
    section ->> 'sectionType',
    section ->> 'shortTermGoals',
    section ->> 'longTermGoals',
    (section ->> 'displayOrder')::integer
  from jsonb_array_elements(coalesce(p_sections, '[]'::jsonb)) section;

  delete from public.care_plan_diagnoses as cpd
  where cpd.care_plan_id = v_care_plan_id;

  insert into public.care_plan_diagnoses (
    care_plan_id,
    member_id,
    member_diagnosis_id,
    created_at,
    updated_at,
    created_by_user_id,
    created_by_name,
    updated_by_user_id,
    updated_by_name
  )
  select
    v_care_plan_id,
    p_member_id,
    md.id,
    v_now,
    v_now,
    p_actor_user_id,
    v_actor_name,
    p_actor_user_id,
    v_actor_name
  from (
    select distinct trim(value)::uuid as diagnosis_id
    from jsonb_array_elements_text(coalesce(p_diagnosis_ids, '[]'::jsonb)) diagnosis_id(value)
  ) diagnosis_ids
  join public.member_diagnoses as md
    on md.id = diagnosis_ids.diagnosis_id
   and md.member_id = p_member_id;

  care_plan_id := v_care_plan_id;
  return next;
end;
$_$;


ALTER FUNCTION "public"."rpc_upsert_care_plan_core"("p_care_plan_id" "uuid", "p_member_id" "uuid", "p_track" "text", "p_enrollment_date" "date", "p_review_date" "date", "p_last_completed_date" "date", "p_next_due_date" "date", "p_status" "text", "p_care_team_notes" "text", "p_no_changes_needed" boolean, "p_modifications_required" boolean, "p_modifications_description" "text", "p_caregiver_name" "text", "p_caregiver_email" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_now" timestamp with time zone, "p_diagnosis_ids" "jsonb", "p_sections" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_upsert_member_file_by_source"("p_member_id" "uuid", "p_document_source" "text", "p_member_file_id" "text" DEFAULT NULL::"text", "p_file_name" "text" DEFAULT NULL::"text", "p_file_type" "text" DEFAULT NULL::"text", "p_file_data_url" "text" DEFAULT NULL::"text", "p_storage_object_path" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT NULL::"text", "p_category_other" "text" DEFAULT NULL::"text", "p_uploaded_by_user_id" "uuid" DEFAULT NULL::"uuid", "p_uploaded_by_name" "text" DEFAULT NULL::"text", "p_uploaded_at" timestamp with time zone DEFAULT "now"(), "p_updated_at" timestamp with time zone DEFAULT "now"(), "p_care_plan_id" "uuid" DEFAULT NULL::"uuid", "p_pof_request_id" "uuid" DEFAULT NULL::"uuid", "p_enrollment_packet_request_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("member_file_id" "text", "was_created" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_existing_id text;
  v_member_file_id text;
begin
  if p_member_id is null then
    raise exception 'rpc_upsert_member_file_by_source requires p_member_id';
  end if;

  if nullif(trim(coalesce(p_member_file_id, '')), '') is not null then
    select id
    into v_existing_id
    from public.member_files
    where id = trim(p_member_file_id)
      and member_id = p_member_id
    for update;
  end if;

  if v_existing_id is null and nullif(trim(coalesce(p_document_source, '')), '') is null then
    raise exception 'rpc_upsert_member_file_by_source requires p_document_source';
  end if;

  if v_existing_id is null then
    select id
    into v_existing_id
    from public.member_files
    where member_id = p_member_id
      and document_source = trim(p_document_source)
    for update;
  end if;

  if v_existing_id is not null then
    update public.member_files
    set
      file_name = coalesce(p_file_name, file_name),
      file_type = coalesce(p_file_type, file_type),
      file_data_url = p_file_data_url,
      storage_object_path = p_storage_object_path,
      category = coalesce(p_category, category),
      category_other = p_category_other,
      document_source = coalesce(nullif(trim(coalesce(p_document_source, '')), ''), document_source),
      uploaded_by_user_id = p_uploaded_by_user_id,
      uploaded_by_name = p_uploaded_by_name,
      uploaded_at = coalesce(p_uploaded_at, uploaded_at),
      updated_at = coalesce(p_updated_at, p_uploaded_at, updated_at),
      care_plan_id = p_care_plan_id,
      pof_request_id = p_pof_request_id,
      enrollment_packet_request_id = p_enrollment_packet_request_id
    where id = v_existing_id;

    member_file_id := v_existing_id;
    was_created := false;
    return next;
    return;
  end if;

  v_member_file_id := coalesce(
    nullif(trim(coalesce(p_member_file_id, '')), ''),
    'mf_' || replace(gen_random_uuid()::text, '-', '')
  );

  insert into public.member_files (
    id,
    member_id,
    file_name,
    file_type,
    file_data_url,
    storage_object_path,
    category,
    category_other,
    document_source,
    uploaded_by_user_id,
    uploaded_by_name,
    uploaded_at,
    updated_at,
    care_plan_id,
    pof_request_id,
    enrollment_packet_request_id
  )
  values (
    v_member_file_id,
    p_member_id,
    coalesce(p_file_name, v_member_file_id),
    coalesce(p_file_type, 'application/octet-stream'),
    p_file_data_url,
    p_storage_object_path,
    coalesce(p_category, 'Other'),
    p_category_other,
    trim(p_document_source),
    p_uploaded_by_user_id,
    p_uploaded_by_name,
    coalesce(p_uploaded_at, now()),
    coalesce(p_updated_at, p_uploaded_at, now()),
    p_care_plan_id,
    p_pof_request_id,
    p_enrollment_packet_request_id
  );

  member_file_id := v_member_file_id;
  was_created := true;
  return next;
end;
$$;


ALTER FUNCTION "public"."rpc_upsert_member_file_by_source"("p_member_id" "uuid", "p_document_source" "text", "p_member_file_id" "text", "p_file_name" "text", "p_file_type" "text", "p_file_data_url" "text", "p_storage_object_path" "text", "p_category" "text", "p_category_other" "text", "p_uploaded_by_user_id" "uuid", "p_uploaded_by_name" "text", "p_uploaded_at" timestamp with time zone, "p_updated_at" timestamp with time zone, "p_care_plan_id" "uuid", "p_pof_request_id" "uuid", "p_enrollment_packet_request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_upsert_physician_order"("p_pof_id" "uuid" DEFAULT NULL::"uuid", "p_member_id" "uuid" DEFAULT NULL::"uuid", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_target_status" "text" DEFAULT 'draft'::"text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_name" "text" DEFAULT NULL::"text", "p_signed_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_pof_request_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("physician_order_id" "uuid", "member_id" "uuid", "version_number" integer, "status" "text", "queue_id" "uuid", "queue_attempt_count" integer, "queue_next_retry_at" timestamp with time zone, "created_new" boolean)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_member public.members%rowtype;
  v_existing public.physician_orders%rowtype;
  v_order public.physician_orders%rowtype;
  v_target_status text := lower(trim(coalesce(p_target_status, 'draft')));
  v_actor_name text := nullif(trim(coalesce(p_actor_name, '')), '');
  v_attempted_at timestamptz := coalesce(p_signed_at, now());
  v_signed_at timestamptz := coalesce(p_signed_at, v_attempted_at);
  v_version_number integer;
  v_sign_result record;
  v_created_new boolean := false;
begin
  if p_member_id is null then
    raise exception 'member id is required';
  end if;
  if p_payload is null or jsonb_typeof(p_payload) <> 'object' then
    raise exception 'p_payload must be a JSON object';
  end if;
  if v_target_status not in ('draft', 'sent', 'signed') then
    raise exception 'target status must be draft, sent, or signed';
  end if;

  select *
  into v_member
  from public.members
  where id = p_member_id
  for update;

  if not found then
    raise exception 'Member % was not found.', p_member_id;
  end if;

  perform pg_advisory_xact_lock(hashtext(format('physician-order-member:%s', p_member_id))::bigint);

  if p_pof_id is not null then
    select *
    into v_existing
    from public.physician_orders
    where id = p_pof_id
    for update;

    if not found then
      raise exception 'Physician order % was not found.', p_pof_id;
    end if;

    if v_existing.member_id is distinct from p_member_id then
      raise exception 'Physician order % does not belong to member %.', p_pof_id, p_member_id;
    end if;

    if coalesce(lower(v_existing.status), '') = 'signed' then
      raise exception 'Signed physician orders are locked. Create a new order to make updates.';
    end if;

    v_order := jsonb_populate_record(v_existing, p_payload);
    v_order.id := v_existing.id;
    v_order.member_id := p_member_id;
    v_order.version_number := v_existing.version_number;
    v_order.created_at := v_existing.created_at;
    v_order.created_by_user_id := v_existing.created_by_user_id;
    v_order.created_by_name := v_existing.created_by_name;
  else
    select coalesce(max(po.version_number), 0) + 1
    into v_version_number
    from public.physician_orders as po
    where po.member_id = p_member_id;

    v_order := jsonb_populate_record(null::public.physician_orders, p_payload);
    v_order.id := coalesce(v_order.id, gen_random_uuid());
    v_order.member_id := p_member_id;
    v_order.version_number := v_version_number;
    v_order.created_at := coalesce(v_order.created_at, v_attempted_at);
    v_order.created_by_user_id := coalesce(v_order.created_by_user_id, p_actor_user_id);
    v_order.created_by_name := coalesce(nullif(trim(coalesce(v_order.created_by_name, '')), ''), v_actor_name);
    v_created_new := true;
  end if;

  v_order.status := case
    when v_target_status = 'signed' then 'sent'
    else v_target_status
  end;
  v_order.is_active_signed := false;
  v_order.superseded_by := null;
  v_order.superseded_at := null;
  v_order.signed_at := null;
  v_order.effective_at := null;
  v_order.signed_by_name := null;
  v_order.signature_metadata := coalesce(v_order.signature_metadata, '{}'::jsonb);
  v_order.dnr_selected := coalesce(v_order.dnr_selected, false);
  v_order.diagnoses := coalesce(v_order.diagnoses, '[]'::jsonb);
  v_order.allergies := coalesce(v_order.allergies, '[]'::jsonb);
  v_order.medications := coalesce(v_order.medications, '[]'::jsonb);
  v_order.standing_orders := coalesce(v_order.standing_orders, '[]'::jsonb);
  v_order.diet_order := coalesce(v_order.diet_order, '{}'::jsonb);
  v_order.mobility_order := coalesce(v_order.mobility_order, '{}'::jsonb);
  v_order.adl_support := coalesce(v_order.adl_support, '{}'::jsonb);
  v_order.continence_support := coalesce(v_order.continence_support, '{}'::jsonb);
  v_order.behavior_orientation := coalesce(v_order.behavior_orientation, '{}'::jsonb);
  v_order.clinical_support := coalesce(v_order.clinical_support, '{}'::jsonb);
  v_order.nutrition_orders := coalesce(v_order.nutrition_orders, '{}'::jsonb);
  v_order.operational_flags := coalesce(v_order.operational_flags, '{}'::jsonb);
  v_order.sent_at := case
    when v_order.status = 'sent' then coalesce(v_order.sent_at, v_attempted_at)
    else null
  end;
  v_order.next_renewal_due_date := case
    when v_order.status = 'sent' then v_order.next_renewal_due_date
    else null
  end;
  v_order.updated_by_user_id := coalesce(p_actor_user_id, v_order.updated_by_user_id);
  v_order.updated_by_name := coalesce(v_actor_name, nullif(trim(coalesce(v_order.updated_by_name, '')), ''));
  v_order.updated_at := v_attempted_at;

  if v_created_new then
    insert into public.physician_orders (
      id,
      member_id,
      intake_assessment_id,
      version_number,
      status,
      is_active_signed,
      superseded_by,
      superseded_at,
      sent_at,
      signed_at,
      effective_at,
      next_renewal_due_date,
      member_name_snapshot,
      member_dob_snapshot,
      sex,
      level_of_care,
      dnr_selected,
      vitals_blood_pressure,
      vitals_pulse,
      vitals_oxygen_saturation,
      vitals_respiration,
      diagnoses,
      allergies,
      medications,
      standing_orders,
      diet_order,
      mobility_order,
      adl_support,
      continence_support,
      behavior_orientation,
      clinical_support,
      nutrition_orders,
      operational_flags,
      provider_name,
      provider_signature,
      provider_signature_date,
      signed_by_name,
      signature_metadata,
      created_by_user_id,
      created_by_name,
      updated_by_user_id,
      updated_by_name,
      created_at,
      updated_at
    )
    values (
      v_order.id,
      v_order.member_id,
      v_order.intake_assessment_id,
      v_order.version_number,
      v_order.status,
      v_order.is_active_signed,
      v_order.superseded_by,
      v_order.superseded_at,
      v_order.sent_at,
      v_order.signed_at,
      v_order.effective_at,
      v_order.next_renewal_due_date,
      v_order.member_name_snapshot,
      v_order.member_dob_snapshot,
      v_order.sex,
      v_order.level_of_care,
      v_order.dnr_selected,
      v_order.vitals_blood_pressure,
      v_order.vitals_pulse,
      v_order.vitals_oxygen_saturation,
      v_order.vitals_respiration,
      v_order.diagnoses,
      v_order.allergies,
      v_order.medications,
      v_order.standing_orders,
      v_order.diet_order,
      v_order.mobility_order,
      v_order.adl_support,
      v_order.continence_support,
      v_order.behavior_orientation,
      v_order.clinical_support,
      v_order.nutrition_orders,
      v_order.operational_flags,
      v_order.provider_name,
      v_order.provider_signature,
      v_order.provider_signature_date,
      v_order.signed_by_name,
      v_order.signature_metadata,
      v_order.created_by_user_id,
      v_order.created_by_name,
      v_order.updated_by_user_id,
      v_order.updated_by_name,
      v_order.created_at,
      v_order.updated_at
    );
  else
    update public.physician_orders
    set
      intake_assessment_id = v_order.intake_assessment_id,
      status = v_order.status,
      is_active_signed = v_order.is_active_signed,
      superseded_by = v_order.superseded_by,
      superseded_at = v_order.superseded_at,
      sent_at = v_order.sent_at,
      signed_at = v_order.signed_at,
      effective_at = v_order.effective_at,
      next_renewal_due_date = v_order.next_renewal_due_date,
      member_name_snapshot = v_order.member_name_snapshot,
      member_dob_snapshot = v_order.member_dob_snapshot,
      sex = v_order.sex,
      level_of_care = v_order.level_of_care,
      dnr_selected = v_order.dnr_selected,
      vitals_blood_pressure = v_order.vitals_blood_pressure,
      vitals_pulse = v_order.vitals_pulse,
      vitals_oxygen_saturation = v_order.vitals_oxygen_saturation,
      vitals_respiration = v_order.vitals_respiration,
      diagnoses = v_order.diagnoses,
      allergies = v_order.allergies,
      medications = v_order.medications,
      standing_orders = v_order.standing_orders,
      diet_order = v_order.diet_order,
      mobility_order = v_order.mobility_order,
      adl_support = v_order.adl_support,
      continence_support = v_order.continence_support,
      behavior_orientation = v_order.behavior_orientation,
      clinical_support = v_order.clinical_support,
      nutrition_orders = v_order.nutrition_orders,
      operational_flags = v_order.operational_flags,
      provider_name = v_order.provider_name,
      provider_signature = v_order.provider_signature,
      provider_signature_date = v_order.provider_signature_date,
      signed_by_name = v_order.signed_by_name,
      signature_metadata = v_order.signature_metadata,
      updated_by_user_id = v_order.updated_by_user_id,
      updated_by_name = v_order.updated_by_name,
      updated_at = v_order.updated_at
    where id = v_order.id;
  end if;

  if v_target_status = 'signed' then
    select *
    into v_sign_result
    from public.rpc_sign_physician_order(
      p_pof_id => v_order.id,
      p_actor_user_id => p_actor_user_id,
      p_actor_name => v_actor_name,
      p_signed_at => v_signed_at,
      p_pof_request_id => p_pof_request_id
    );
  end if;

  return query
  select
    v_order.id,
    p_member_id,
    v_order.version_number,
    case when v_target_status = 'signed' then 'signed' else v_order.status end,
    case when v_target_status = 'signed' then (v_sign_result.queue_id)::uuid else null end,
    case when v_target_status = 'signed' then coalesce((v_sign_result.queue_attempt_count)::integer, 0) else null end,
    case when v_target_status = 'signed' then (v_sign_result.queue_next_retry_at)::timestamptz else null end,
    v_created_new;
end;
$$;


ALTER FUNCTION "public"."rpc_upsert_physician_order"("p_pof_id" "uuid", "p_member_id" "uuid", "p_payload" "jsonb", "p_target_status" "text", "p_actor_user_id" "uuid", "p_actor_name" "text", "p_signed_at" timestamp with time zone, "p_pof_request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rpc_void_enrollment_packet_request"("p_packet_id" "uuid", "p_actor_user_id" "uuid", "p_actor_email" "text" DEFAULT NULL::"text", "p_void_reason" "text" DEFAULT NULL::"text", "p_voided_at" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("packet_id" "uuid", "status" "text", "voided_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request public.enrollment_packet_requests%rowtype;
  v_void_reason text := nullif(trim(coalesce(p_void_reason, '')), '');
  v_voided_at timestamptz := coalesce(p_voided_at, now());
begin
  if p_packet_id is null then
    raise exception 'rpc_void_enrollment_packet_request requires p_packet_id';
  end if;
  if p_actor_user_id is null then
    raise exception 'rpc_void_enrollment_packet_request requires p_actor_user_id';
  end if;
  if v_void_reason is null then
    raise exception 'A void reason is required.';
  end if;

  select *
  into v_request
  from public.enrollment_packet_requests
  where id = p_packet_id
  for update;

  if not found then
    raise exception 'Enrollment packet request was not found.';
  end if;

  if coalesce(v_request.status, '') = 'voided' then
    return query
    select
      v_request.id,
      v_request.status,
      v_request.voided_at;
    return;
  end if;

  if coalesce(v_request.status, '') in ('completed', 'expired') then
    raise exception 'Completed or expired enrollment packets cannot be voided.';
  end if;

  update public.enrollment_packet_requests
  set
    status = 'voided',
    voided_at = v_voided_at,
    voided_by_user_id = p_actor_user_id,
    void_reason = v_void_reason,
    token_expires_at = coalesce(least(token_expires_at, v_voided_at), v_voided_at),
    updated_at = v_voided_at
  where id = p_packet_id;

  insert into public.enrollment_packet_events (
    packet_id,
    event_type,
    actor_user_id,
    actor_email,
    timestamp,
    metadata
  )
  values (
    p_packet_id,
    'voided',
    p_actor_user_id,
    nullif(trim(coalesce(p_actor_email, '')), ''),
    v_voided_at,
    jsonb_build_object(
      'reason',
      v_void_reason,
      'voided_at',
      v_voided_at
    )
  );

  return query
  select
    p_packet_id,
    'voided',
    v_voided_at;
end;
$$;


ALTER FUNCTION "public"."rpc_void_enrollment_packet_request"("p_packet_id" "uuid", "p_actor_user_id" "uuid", "p_actor_email" "text", "p_void_reason" "text", "p_voided_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  new.updated_at = now();
  return new;
end;
$$;


ALTER FUNCTION "public"."set_updated_at"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_profile_auth_lifecycle_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  new.auth_user_id := coalesce(new.auth_user_id, new.id);
  new.active := coalesce(new.active, new.is_active, true);
  new.is_active := coalesce(new.is_active, new.active, true);
  new.status := coalesce(nullif(lower(new.status), ''), case when new.active = false then 'disabled' else 'active' end);

  if new.status = 'disabled' then
    new.disabled_at := coalesce(new.disabled_at, now());
  else
    new.disabled_at := null;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."sync_profile_auth_lifecycle_fields"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_time_punch_to_canonical_punch"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_staff_name text;
begin
  select p.full_name into v_staff_name
  from public.profiles p
  where p.id = new.staff_user_id;

  insert into public.punches (
    employee_id,
    employee_name,
    "timestamp",
    type,
    source,
    status,
    note,
    created_by,
    created_at,
    updated_at,
    linked_time_punch_id
  )
  values (
    new.staff_user_id,
    coalesce(v_staff_name, 'Unknown Staff'),
    new.punch_at,
    new.punch_type,
    'employee',
    'active',
    new.note,
    coalesce(v_staff_name, 'System'),
    now(),
    now(),
    new.id
  )
  on conflict on constraint punches_linked_time_punch_id_key do nothing;

  return new;
end;
$$;


