CREATE OR REPLACE VIEW "public"."billing_payor_backfill_review" WITH ("security_invoker"='true') AS
 WITH "current_flags" AS (
         SELECT "member_contacts"."member_id",
            "count"(*) AS "flagged_payor_count"
           FROM "public"."member_contacts"
          WHERE ("member_contacts"."is_payor" = true)
          GROUP BY "member_contacts"."member_id"
        ), "latest_active_setting" AS (
         SELECT DISTINCT ON ("settings"."member_id") "settings"."member_id",
            "settings"."payor_id"
           FROM "public"."member_billing_settings" "settings"
          WHERE (("settings"."active" = true) AND ("settings"."payor_id" IS NOT NULL))
          ORDER BY "settings"."member_id", "settings"."effective_start_date" DESC, "settings"."updated_at" DESC
        ), "legacy_matches" AS (
         SELECT "setting"."member_id",
            "setting"."payor_id",
            "payors"."payor_name",
            "payors"."billing_contact_name",
            "array_remove"("array_agg"(DISTINCT "contacts"."id"), NULL::"text") AS "matching_contact_ids",
            "array_remove"("array_agg"(DISTINCT "contacts"."contact_name"), NULL::"text") AS "matching_contact_names"
           FROM (("latest_active_setting" "setting"
             JOIN "public"."payors" "payors" ON (("payors"."id" = "setting"."payor_id")))
             LEFT JOIN "public"."member_contacts" "contacts" ON ((("contacts"."member_id" = "setting"."member_id") AND (("lower"("btrim"(COALESCE("contacts"."contact_name", ''::"text"))) = "lower"("btrim"(COALESCE("payors"."billing_contact_name", "payors"."payor_name", ''::"text")))) OR ((NULLIF("lower"("btrim"(COALESCE("payors"."billing_email", ''::"text"))), ''::"text") IS NOT NULL) AND ("lower"("btrim"(COALESCE("contacts"."email", ''::"text"))) = "lower"("btrim"("payors"."billing_email")))) OR ((NULLIF("regexp_replace"(COALESCE("payors"."billing_phone", ''::"text"), '\D'::"text", ''::"text", 'g'::"text"), ''::"text") IS NOT NULL) AND ("regexp_replace"(COALESCE("contacts"."cellular_number", "contacts"."work_number", "contacts"."home_number", ''::"text"), '\D'::"text", ''::"text", 'g'::"text") = "regexp_replace"(COALESCE("payors"."billing_phone", ''::"text"), '\D'::"text", ''::"text", 'g'::"text")))))))
          GROUP BY "setting"."member_id", "setting"."payor_id", "payors"."payor_name", "payors"."billing_contact_name"
        )
 SELECT "members"."id" AS "member_id",
    "members"."display_name" AS "member_name",
    "legacy"."payor_id" AS "legacy_payor_id",
    "legacy"."payor_name" AS "legacy_payor_name",
    "legacy"."billing_contact_name" AS "legacy_billing_contact_name",
    "legacy"."matching_contact_ids",
    "legacy"."matching_contact_names",
    COALESCE("flags"."flagged_payor_count", (0)::bigint) AS "flagged_payor_count",
        CASE
            WHEN (COALESCE("flags"."flagged_payor_count", (0)::bigint) > 1) THEN 'multiple_payor_contacts'::"text"
            WHEN (("legacy"."payor_id" IS NOT NULL) AND ("cardinality"(COALESCE("legacy"."matching_contact_ids", ARRAY[]::"text"[])) = 0)) THEN 'legacy_payor_has_no_contact_match'::"text"
            WHEN (("legacy"."payor_id" IS NOT NULL) AND ("cardinality"(COALESCE("legacy"."matching_contact_ids", ARRAY[]::"text"[])) > 1)) THEN 'legacy_payor_matches_multiple_contacts'::"text"
            WHEN (("legacy"."payor_id" IS NOT NULL) AND (COALESCE("flags"."flagged_payor_count", (0)::bigint) = 0)) THEN 'legacy_payor_requires_manual_review'::"text"
            ELSE NULL::"text"
        END AS "review_reason"
   FROM (("public"."members" "members"
     LEFT JOIN "current_flags" "flags" ON (("flags"."member_id" = "members"."id")))
     LEFT JOIN "legacy_matches" "legacy" ON (("legacy"."member_id" = "members"."id")))
  WHERE ((COALESCE("flags"."flagged_payor_count", (0)::bigint) > 1) OR (("legacy"."payor_id" IS NOT NULL) AND (("cardinality"(COALESCE("legacy"."matching_contact_ids", ARRAY[]::"text"[])) <> 1) OR (COALESCE("flags"."flagged_payor_count", (0)::bigint) = 0))));


ALTER VIEW "public"."billing_payor_backfill_review" OWNER TO "postgres";


