    CONSTRAINT "incidents_submitter_signature_status_scope" CHECK (((("status" = ANY (ARRAY['submitted'::"text", 'approved'::"text", 'closed'::"text"])) AND ("submitter_signature_attested" = true) AND (NULLIF(TRIM(BOTH FROM COALESCE("submitter_signature_name", ''::"text")), ''::"text") IS NOT NULL) AND ("submitter_signed_at" IS NOT NULL) AND (NULLIF(TRIM(BOTH FROM COALESCE("submitter_signature_artifact_storage_path", ''::"text")), ''::"text") IS NOT NULL)) OR (("status" = ANY (ARRAY['draft'::"text", 'returned'::"text"])) AND (COALESCE("submitter_signature_attested", false) = false) AND ("submitter_signature_name" IS NULL) AND ("submitter_signed_at" IS NULL) AND ("submitter_signature_artifact_storage_path" IS NULL)))),
    CONSTRAINT "incidents_unsafe_conditions_required" CHECK ((("unsafe_conditions_present" = false) OR (NULLIF(TRIM(BOTH FROM COALESCE("unsafe_conditions_description", ''::"text")), ''::"text") IS NOT NULL)))
);


