    CONSTRAINT "mar_not_given_reason_required" CHECK (((("status" = 'Not Given'::"text") AND ("not_given_reason" IS NOT NULL)) OR (("status" = 'Given'::"text") AND ("not_given_reason" IS NULL)))),
    CONSTRAINT "mar_prn_ineffective_note_required" CHECK ((("prn_outcome" IS DISTINCT FROM 'Ineffective'::"text") OR (NULLIF(TRIM(BOTH FROM COALESCE("prn_followup_note", ''::"text")), ''::"text") IS NOT NULL))),
    CONSTRAINT "mar_prn_outcome_assessed_at_required" CHECK (((("prn_outcome" IS NULL) AND ("prn_outcome_assessed_at" IS NULL)) OR (("prn_outcome" IS NOT NULL) AND ("prn_outcome_assessed_at" IS NOT NULL)))),
    CONSTRAINT "mar_prn_outcome_scope" CHECK ((("source" = 'prn'::"text") OR (("prn_outcome" IS NULL) AND ("prn_outcome_assessed_at" IS NULL) AND ("prn_followup_note" IS NULL)))),
    CONSTRAINT "mar_prn_reason_required" CHECK (((("source" = 'prn'::"text") AND ("prn_reason" IS NOT NULL)) OR (("source" = 'scheduled'::"text") AND ("prn_reason" IS NULL)))),
    CONSTRAINT "mar_schedule_source_alignment" CHECK (((("source" = 'scheduled'::"text") AND ("mar_schedule_id" IS NOT NULL)) OR (("source" = 'prn'::"text") AND ("mar_schedule_id" IS NULL))))
);


