CREATE OR REPLACE VIEW "public"."v_ancillary_charge_logs_detailed" WITH ("security_invoker"='true') AS
 SELECT "l"."id",
    "l"."member_id",
    "m"."display_name" AS "member_name",
    "l"."category_id",
    "c"."name" AS "category_name",
    ("round"((COALESCE("l"."amount", (((COALESCE("l"."quantity", (1)::numeric) * (COALESCE("c"."price_cents", 0))::numeric) / 100.0))::numeric(12,2), (0)::numeric) * 100.0)))::integer AS "amount_cents",
    (COALESCE("l"."quantity", (1)::numeric))::numeric(10,2) AS "quantity",
    "l"."source_entity",
    "l"."source_entity_id",
    "l"."service_date",
    "l"."late_pickup_time",
    "l"."staff_user_id",
    "p"."full_name" AS "staff_name",
    "l"."notes",
    COALESCE(NULLIF("l"."reconciliation_status", ''::"text"), 'open'::"text") AS "reconciliation_status",
    "l"."reconciled_by",
    "l"."reconciled_at",
    "l"."reconciliation_note",
    "l"."created_at"
   FROM ((("public"."ancillary_charge_logs" "l"
     JOIN "public"."members" "m" ON (("m"."id" = "l"."member_id")))
     JOIN "public"."ancillary_charge_categories" "c" ON (("c"."id" = "l"."category_id")))
     LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "l"."staff_user_id")));


ALTER VIEW "public"."v_ancillary_charge_logs_detailed" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_biweekly_totals" WITH ("security_invoker"='true') AS
 WITH "ordered" AS (
         SELECT "tp"."id",
            "tp"."staff_user_id",
            "tp"."site_id",
            "tp"."punch_type",
            "tp"."punch_at",
            "tp"."lat",
            "tp"."lng",
            "tp"."distance_meters",
            "tp"."within_fence",
            "tp"."meal_deduct_minutes",
            "tp"."note",
            "tp"."created_at",
            "row_number"() OVER (PARTITION BY "tp"."staff_user_id" ORDER BY "tp"."punch_at") AS "rn"
           FROM "public"."time_punches" "tp"
          WHERE ("tp"."punch_at" >= ("now"() - '14 days'::interval))
        ), "pairs" AS (
         SELECT "i"."staff_user_id",
            "i"."punch_at" AS "in_at",
            "o"."punch_at" AS "out_at",
            GREATEST((EXTRACT(epoch FROM ("o"."punch_at" - "i"."punch_at")) / 3600.0), (0)::numeric) AS "raw_hours"
           FROM ("ordered" "i"
             JOIN "ordered" "o" ON ((("o"."staff_user_id" = "i"."staff_user_id") AND ("o"."rn" = ("i"."rn" + 1)))))
          WHERE (("i"."punch_type" = 'in'::"public"."punch_type") AND ("o"."punch_type" = 'out'::"public"."punch_type"))
        )
 SELECT "p"."full_name" AS "staff_name",
    "round"(COALESCE("sum"("pairs"."raw_hours"), (0)::numeric), 2) AS "regular_hours",
    "round"(COALESCE("sum"(
        CASE
            WHEN ("pairs"."raw_hours" >= (6)::numeric) THEN 0.5
            ELSE (0)::numeric
        END), (0)::numeric), 2) AS "meal_deduct_hours",
    "round"(COALESCE("sum"(("pairs"."raw_hours" -
        CASE
            WHEN ("pairs"."raw_hours" >= (6)::numeric) THEN 0.5
            ELSE (0)::numeric
        END)), (0)::numeric), 2) AS "payable_hours",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM "public"."time_punch_exceptions" "tpe"
          WHERE (("tpe"."staff_user_id" = "pairs"."staff_user_id") AND ("tpe"."resolved" = false))), (0)::bigint) AS "exception_count"
   FROM ("pairs"
     JOIN "public"."profiles" "p" ON (("p"."id" = "pairs"."staff_user_id")))
  GROUP BY "pairs"."staff_user_id", "p"."full_name";


ALTER VIEW "public"."v_biweekly_totals" OWNER TO "postgres";


