CREATE OR REPLACE VIEW "public"."v_last_toileted" WITH ("security_invoker"='true') AS
 SELECT "m"."display_name" AS "member_name",
    "lt"."last_toileted_at",
    "lt"."staff_name"
   FROM ("public"."members" "m"
     LEFT JOIN LATERAL ( SELECT "t"."event_at" AS "last_toileted_at",
            "p"."full_name" AS "staff_name"
           FROM ("public"."toilet_logs" "t"
             LEFT JOIN "public"."profiles" "p" ON (("p"."id" = "t"."staff_user_id")))
          WHERE ("t"."member_id" = "m"."id")
          ORDER BY "t"."event_at" DESC
         LIMIT 1) "lt" ON (true));


