CREATE OR REPLACE VIEW "public"."v_mar_today" WITH ("security_invoker"='true') AS
 SELECT "ms"."id" AS "mar_schedule_id",
    "ms"."member_id",
    "m"."display_name" AS "member_name",
    "ms"."pof_medication_id",
    "ms"."medication_name",
    "ms"."dose",
    "ms"."route",
    "ms"."frequency",
    "ms"."instructions",
    "ms"."prn",
    "ms"."scheduled_time",
    "ms"."active" AS "schedule_active",
    "ma"."id" AS "administration_id",
    "ma"."status",
    "ma"."not_given_reason",
    "ma"."prn_reason",
    "ma"."notes",
    "ma"."administered_by",
    "ma"."administered_by_user_id",
    "ma"."administered_at",
    "ma"."source"
   FROM (("public"."mar_schedules" "ms"
     JOIN "public"."members" "m" ON (("m"."id" = "ms"."member_id")))
     LEFT JOIN "public"."mar_administrations" "ma" ON (("ma"."mar_schedule_id" = "ms"."id")))
  WHERE (("ms"."active" = true) AND (("timezone"('America/New_York'::"text", "ms"."scheduled_time"))::"date" = ("timezone"('America/New_York'::"text", "now"()))::"date"))
  ORDER BY "ms"."scheduled_time", "m"."display_name", "ms"."medication_name";


ALTER VIEW "public"."v_mar_today" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_monthly_ancillary_summary" WITH ("security_invoker"='true') AS
 SELECT "to_char"("date_trunc"('month'::"text", ("l"."service_date")::timestamp with time zone), 'Mon-YYYY'::"text") AS "month_label",
    "c"."name" AS "category_name",
    ("count"(*))::integer AS "total_count",
    ("sum"("c"."price_cents"))::integer AS "total_amount_cents"
   FROM ("public"."ancillary_charge_logs" "l"
     JOIN "public"."ancillary_charge_categories" "c" ON (("c"."id" = "l"."category_id")))
  GROUP BY ("date_trunc"('month'::"text", ("l"."service_date")::timestamp with time zone)), "c"."name"
  ORDER BY ("date_trunc"('month'::"text", ("l"."service_date")::timestamp with time zone)) DESC, "c"."name";


ALTER VIEW "public"."v_monthly_ancillary_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_timely_docs_summary" WITH ("security_invoker"='true') AS
 SELECT "p"."full_name" AS "staff_name",
    "count"(*) FILTER (WHERE ("de"."event_at" <= ("date_trunc"('day'::"text", "de"."event_at") + '20:00:00'::interval))) AS "on_time",
    "count"(*) FILTER (WHERE ("de"."event_at" > ("date_trunc"('day'::"text", "de"."event_at") + '20:00:00'::interval))) AS "late",
    "count"(*) AS "total",
    COALESCE((("count"(*) FILTER (WHERE ("de"."event_at" <= ("date_trunc"('day'::"text", "de"."event_at") + '20:00:00'::interval))))::numeric / (NULLIF("count"(*), 0))::numeric), (0)::numeric) AS "on_time_percent"
   FROM ("public"."documentation_events" "de"
     JOIN "public"."profiles" "p" ON (("p"."id" = "de"."staff_user_id")))
  GROUP BY "p"."id", "p"."full_name";


ALTER VIEW "public"."v_timely_docs_summary" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_today_at_a_glance" WITH ("security_invoker"='true') AS
 SELECT "p"."full_name" AS "staff_name",
    "count"(*) FILTER (WHERE ("de"."event_table" = 'daily_activity_logs'::"text")) AS "participation_count",
    "count"(*) FILTER (WHERE ("de"."event_table" = 'toilet_logs'::"text")) AS "toilet_count",
    "count"(*) FILTER (WHERE ("de"."event_table" = 'shower_logs'::"text")) AS "shower_count",
    "count"(*) FILTER (WHERE ("de"."event_table" = 'transportation_logs'::"text")) AS "transport_count",
    "count"(*) FILTER (WHERE ("de"."event_table" = 'ancillary_charge_logs'::"text")) AS "ancillary_count",
    "count"(*) AS "total_count",
    ("count"(*) > 0) AS "uploaded_today"
   FROM ("public"."profiles" "p"
     LEFT JOIN "public"."documentation_events" "de" ON ((("de"."staff_user_id" = "p"."id") AND ("de"."event_at" >= "date_trunc"('day'::"text", "now"())) AND ("de"."event_at" < ("date_trunc"('day'::"text", "now"()) + '1 day'::interval)))))
  WHERE ("p"."active" = true)
  GROUP BY "p"."id", "p"."full_name";


ALTER VIEW "public"."v_today_at_a_glance" OWNER TO "postgres";


